window.__QUIZ_SUBJECT__=[{"id": "objective>Economics>1993>1", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Economics is the study of how to", "images": [], "options": {"A": "choose between alternatives, given limited resources", "B": "regulate the money that is in circulation in a country", "C": "be prudent in the use of available resources", "D": "improve the standard of living of the society at large"}, "answer": "A", "explanation": "Economics is fundamentally about making choices between alternatives due to limited resources. This concept is known as opportunity cost, which emphasizes that every choice has a trade-off.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1993>2", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Scarcity in Economics arises because", "images": [], "options": {"A": "the resources available are adequate", "B": "individuals have limited time", "C": "resources are limited in supply", "D": "human beings have limited wants"}, "answer": "C", "explanation": "Scarcity in economics arises because resources are limited in supply while human wants are virtually unlimited. This fundamental economic problem forces individuals and societies to make choices about how to allocate their limited resources.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1993>3", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "The real cost of a commodity is", "images": [], "options": {"A": "the cost of the alternative that has to be sacrificed for it", "B": "the alternative that has to be forgone in order to purchase it", "C": "its market price", "D": "the alternative cost involved when the opportunity of buying the commodity is missed"}, "answer": "A", "explanation": "The real cost of a commodity is defined as the opportunity cost, which is the cost of the alternative that has to be sacrificed in order to obtain it. This concept highlights the trade-offs involved in economic decision-making.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>4", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "Public corporations in West Africa are set up to", "images": [], "options": {"A": "make maximum profit", "B": "provide jobs for the people", "C": "provide welfare services for the people", "D": "show that the government can do business"}, "answer": "C", "explanation": "Public corporations in West Africa are typically established to provide welfare services for the people, rather than to maximize profit. They aim to serve the public interest and address social needs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>5", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Supply in Economics means making", "images": [], "options": {"A": "goods and services available to consumers", "B": "goods available to the market at a given price and at a given period", "C": "available the goods and services which consumers require", "D": "the circulation of goods"}, "answer": "B", "explanation": "In economics, supply refers to the quantity of goods available to the market at a given price and at a given period. This definition captures the essence of supply as it relates to market dynamics.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1993>6", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "An inferior good is one", "images": [], "options": {"A": "that is too bad for consumption", "B": "whose price is lower than the prices of other goods", "C": "that is easily perishable", "D": "whose demand falls when the income of its consumers increases"}, "answer": "D", "explanation": "An inferior good is defined as a type of good whose demand increases when consumer incomes fall, and conversely, whose demand decreases when consumer incomes rise. Therefore, the correct option is that an inferior good is one whose demand falls when the income of its consumers increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>7", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "Price elasticity of demand is defined as the", "images": [], "options": {"A": "responsiveness of demand to changes in price", "B": "responsiveness of price to change in demand", "C": "increase in demand resulting from a rise in price", "D": "unit decrease in price resulting from a fall in demand"}, "answer": "A", "explanation": "Price elasticity of demand measures how much the quantity demanded of a good responds to a change in the price of that good. It is defined as the responsiveness of demand to changes in price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>8", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "The rural areas of West African countries lack industries because", "images": [], "options": {"A": "rural people are not meant to work in industries", "B": "rural people are uneducated", "C": "of inadequate infrastructure", "D": "of low population density"}, "answer": "C", "explanation": "The lack of industries in rural areas of West African countries is primarily due to inadequate infrastructure. This includes poor transportation, lack of utilities, and insufficient facilities that are necessary for industrial development. Therefore, option 3 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>9", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "An entrepreneur will locate his industry in a place", "images": [], "options": {"A": "nearest to his home town", "B": "where the cost of production will be minimized", "C": "nearest to his wife's home town", "D": "where the government directs him to locate it"}, "answer": "B", "explanation": "An entrepreneur typically locates their industry where the cost of production will be minimized. This is crucial for maximizing profits and ensuring the sustainability of the business. Thus, option 2 is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>10", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION", "question": "Which important economic principle is illustrated by the graph above", "images": ["Economics/imgs/1993/NNM92C.jpg"], "options": {"A": "Law of Comparative Cost", "B": "Law of Diminishing Marginal Utility", "C": "Law of Diminishing Returns", "D": "Malthusian Law of Population"}, "answer": "C", "explanation": "The graph illustrates the law of diminishing returns which is also known as the law of variable proportion. The law is applied to the short run analysis is production which shows the relationship between total product and marginal product.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1993>11", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "Which of the following reasons is mainly responsible for the inefficient distribution of goods in West African countries? The", "images": [], "options": {"A": "large number of distribution companies", "B": "import and export restrictions by the government", "C": "narrow market for commodities produced", "D": "poor transport and communication systems"}, "answer": "D", "explanation": "The poor transport and communication systems in West African countries significantly hinder the efficient distribution of goods. These systems are crucial for moving products from producers to consumers, and inefficiencies in these areas can lead to delays, increased costs, and ultimately, an inability to meet market demand effectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>12", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Which of the following does not apply to private companies?", "images": [], "options": {"A": "The number of shareholders is limited", "B": "The liability of shareholders is limited", "C": "Accounts have to be publicized", "D": "The companies are separate legal entities"}, "answer": "C", "explanation": "Private companies are not required to publicize their accounts, which is a key distinction from public companies. Public companies must disclose financial information to the public to ensure transparency for shareholders and potential investors, while private companies have more privacy regarding their financial affairs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>13", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "In Economics, the reward for labour is in the form of", "images": [], "options": {"A": "wages", "B": "profit", "C": "rent", "D": "dividends"}, "answer": "A", "explanation": "In Economics, the reward for labor is typically in the form of wages. Wages are the compensation paid to workers for their labor, reflecting the value of their work in the production process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1993>14", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "A nation with a working population that is insufficient to exploit its resources is said to be", "images": [], "options": {"A": "over -populated", "B": "under-populated", "C": "experiencing decreasing population", "D": "experiencing increasing population"}, "answer": "B", "explanation": "A nation with a working population that is insufficient to exploit its resources is described as under-populated. This means that there are not enough people to utilize the available resources effectively, leading to potential economic inefficiencies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>15", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "Which of the following may not be included in explaining the term production?", "images": [], "options": {"A": "Provision of services", "B": "Manufacture of goods", "C": "Changing raw materials to finished goods", "D": "Use of consumer goods"}, "answer": "D", "explanation": "The use of consumer goods is not typically included in the definition of production. Production generally refers to the processes involved in creating goods and services, while consumer goods are the end products that result from production processes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>16", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES", "question": "Which of the following business establishments are not motivated mainly by profit?", "images": [], "options": {"A": "Public Limited Companies", "B": "Private Limited Companies", "C": "Partnerships", "D": "Co-operatives"}, "answer": "D", "explanation": "Co-operatives are business establishments that are not primarily motivated by profit. Instead, they are formed to meet the needs of their members, who are also the owners. This contrasts with profit-driven entities like public and private limited companies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>17", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER", "question": "Production is not complete until the", "images": [], "options": {"A": "goods get to the wholesalers", "B": "goods reach the final consumer", "C": "factors of production are combined", "D": "goods are ready for transportation"}, "answer": "B", "explanation": "Production is considered complete when goods reach the final consumer. This is because the ultimate goal of production is to satisfy consumer needs, and until the goods are in the hands of the consumer, the production process is not fully realized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>18", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "Which of the following is the correct way to calculate total cost?", "images": [], "options": {"A": "Addition of fixed cost to variable cost", "B": "Division of total cost by total output", "C": "Multiplication of fixed cost by variable cost", "D": "Subtraction of fixed cost from total cost"}, "answer": "A", "explanation": "Total cost is calculated by adding fixed costs to variable costs. Fixed costs are expenses that do not change with the level of output, while variable costs fluctuate with production levels. Together, they represent the total expenditure incurred in the production process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>19", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "POPULATION : THEORIES OF POPULATION", "question": "Robert T. Malthus postulated in his population theory that", "images": [], "options": {"A": "the death rate may become so high that people may not survive", "B": "people will migrate from one place to another in search of food", "C": "positive efforts should be made to increase population", "D": "population growth rate may out-grow the means of subsistence"}, "answer": "D", "explanation": "Robert T. Malthus postulated in his population theory that population growth tends to outpace food production, leading to inevitable checks on population such as famine, disease, and war.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>20", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "Division of labour may be restricted when", "images": [], "options": {"A": "an ailing economy has improved", "B": "producers live in villages", "C": "market is small", "D": "there is full employment"}, "answer": "C", "explanation": "Division of labour may be restricted when the market is small. A small market limits the demand for goods, which in turn restricts the extent to which tasks can be divided among workers, as there may not be enough work to justify specialization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>21", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Land is often distinguished as a factor of production because it", "images": [], "options": {"A": "is a free gift of nature", "B": "constitutes one -third of the entire world", "C": "is unlimited in supply", "D": "is owned by individuals"}, "answer": "A", "explanation": "Land is distinguished as a factor of production because it is considered a free gift of nature. Unlike labor and capital, which require human effort and investment, land is naturally occurring and provides the resources necessary for production.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1993>22", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "Which of the following is not an advantage of division of labour? It", "images": [], "options": {"A": "saves time", "B": "makes possible the use of machines", "C": "is monotonous", "D": "leads to specialization"}, "answer": "C", "explanation": "The option 'is monotonous' is not an advantage of division of labour. While division of labour increases efficiency and productivity by allowing workers to specialize in specific tasks, it can also lead to monotony and a lack of job satisfaction due to repetitive tasks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>23", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "The location of timber and plywood industries in West Africa is mainly influenced by the", "images": [], "options": {"A": "availability of transport", "B": "availability of power supply", "C": "adequate labour supply", "D": "presence of a luxuriant forest"}, "answer": "D", "explanation": "The presence of a luxuriant forest is the primary factor influencing the location of timber and plywood industries in West Africa. These industries rely heavily on the availability of raw materials, which in this case are trees from forests.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>24", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "The occupational distribution of population in most West African countries shows the highest concentration in", "images": [], "options": {"A": "agriculture and allied industries", "B": "mining and manufacturing", "C": "the distributive trade", "D": "commerce and industry"}, "answer": "A", "explanation": "The occupational distribution of population in most West African countries shows the highest concentration in agriculture and allied industries. This is due to the agrarian nature of many West African economies, where a significant portion of the population is engaged in farming and related activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>25", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "POPULATION : INTRODUCTION", "question": "The growth rate of population is the", "images": [], "options": {"A": "annual increase in population", "B": "addition to the total population over a given period", "C": "increase in the working population over a given period", "D": "percentage increase in population in a given year"}, "answer": "D", "explanation": "The growth rate of population is defined as the percentage increase in population in a given year. This metric helps to understand how quickly a population is growing relative to its size.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1993>26", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "A situation in which an increase in the demand for certain goods leads to a fall in the demand for other goods is known as", "images": [], "options": {"A": "joint supply", "B": "derived demand", "C": "competitive demand", "D": "competitive supply"}, "answer": "C", "explanation": "The situation where an increase in the demand for certain goods leads to a fall in the demand for other goods is known as competitive demand. This occurs when goods are substitutes for each other, meaning that as one becomes more desirable, the other becomes less so.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>27", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "A market equilibrium exists when", "images": [], "options": {"A": "demand and supply are equal", "B": "the market is large", "C": "the price is fluctuating", "D": "no buyers goes home empty-handed"}, "answer": "A", "explanation": "A market equilibrium exists when demand and supply are equal. This is the fundamental principle of market equilibrium, where the quantity of goods supplied matches the quantity of goods demanded at a certain price level.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1993>28", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "The price system is", "images": [], "options": {"A": "the market price of commodities", "B": "a market where a single price rules", "C": "a system of price allocation to the products of the same firm", "D": "a system of resource allocation through supply and demand interactions"}, "answer": "D", "explanation": "The price system is a system of resource allocation through supply and demand interactions. It reflects how prices are determined in a market economy based on the interaction between buyers and sellers, which influences the distribution of resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>29", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "The main objective of production by an entrepreneur is to", "images": [], "options": {"A": "equate marginal revenue with marginal cost", "B": "provide employment opportunities", "C": "equate total revenue with total cost", "D": "equate average revenue with average cost"}, "answer": "A", "explanation": "The main objective of production by an entrepreneur is to equate marginal revenue with marginal cost. This is a key principle in economics where firms maximize profit by producing up to the point where the additional revenue from selling one more unit equals the additional cost of producing that unit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>30", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THEORY OF SUPPLY : DISTINCTION BETWEEN CHANGE IN QUANTITY SUPPLIED AND CHANGE IN SUPPLY", "question": "If price falls below the equilibrium", "images": [], "options": {"A": "demand will equal supply", "B": "demand will be greater than supply", "C": "supply will be greater than demand", "D": "price will become indeterminate"}, "answer": "B", "explanation": "If price falls below the equilibrium, demand will be greater than supply. This situation creates a shortage in the market, as consumers want to buy more at the lower price, but producers are not willing to supply enough at that price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>31", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "Which of the following is not a source of finance for a one-man business?", "images": [], "options": {"A": "Money lenders", "B": "Loans from insurance companies", "C": "Loans from banks", "D": "Sale of shares"}, "answer": "D", "explanation": "The sale of shares is not a source of finance for a one-man business because a one-man business typically does not issue shares. Shares are associated with corporations or partnerships where ownership is divided among multiple shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>32", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "Land is a most significant factor in terms of contribution to the economy because", "images": [], "options": {"A": "it enables us to build industries", "B": "all our highways are constructed on it", "C": "we get a lot of fishes from it", "D": "vital resources from it enrich the economy"}, "answer": "D", "explanation": "Land is a significant factor in the economy because it provides vital resources such as minerals, agricultural products, and timber, which enrich the economy. These resources are essential for various industries and contribute to economic growth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>33", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Capital as a factor of production is important because", "images": [], "options": {"A": "it enables us to carry out tasks which cannot be done by human effort only", "B": "most tasks can be done with bare hands", "C": "people can work without capital", "D": "without capital all other factors are useless"}, "answer": "A", "explanation": "Capital as a factor of production is important because it enables us to carry out tasks that cannot be done by human effort alone. For example, machinery and technology (forms of capital) enhance productivity and efficiency in production processes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>34", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "A firm's compulsory cost whether it is in production or not, is referred to as its", "images": [], "options": {"A": "prime cost", "B": "variable cost", "C": "marginal cost", "D": "fixed cost"}, "answer": "D", "explanation": "A firm's compulsory cost, whether it is in production or not, is referred to as its fixed cost. Fixed costs are expenses that do not change with the level of output, such as rent and salaries, and must be paid regardless of production levels.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>35", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT", "question": "A scale of preference is a list", "images": [], "options": {"A": "of consumer's wants arranged in order of importance", "B": "that helps the individual to make a rational choice", "C": "that enables the consumers to make a wise decision about his choice", "D": "that is necessary because human beings are faced eith competing wants"}, "answer": "A", "explanation": "A scale of preference is a list of consumer's wants arranged in order of importance. It helps individuals prioritize their needs and make rational choices based on limited resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>36", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "An economic system in which the state owns and controls the means of production is known as", "images": [], "options": {"A": "free enterprise", "B": "socialist economy", "C": "mixed economy", "D": "capitalist economy"}, "answer": "B", "explanation": "An economic system in which the state owns and controls the means of production is known as a socialist economy. In this system, the government typically manages resources and production to promote equality and meet the needs of the population.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1993>37", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "Which of the following is not a middleman in the distribution channel? The", "images": [], "options": {"A": "wholesaler", "B": "distributor", "C": "agent", "D": "consumer"}, "answer": "D", "explanation": "The consumer is not a middleman in the distribution channel. Middlemen, such as wholesalers, distributors, agents, and retailers, facilitate the movement of goods from producers to consumers. The consumer is the end-user of the product and does not play a role in the distribution process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>38", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "Division of labour gives rise to", "images": [], "options": {"A": "the exchange of goods and services", "B": "the use of a barter system", "C": "the production of limited good", "D": "unemployment"}, "answer": "A", "explanation": "Division of labour leads to the exchange of goods and services as it allows individuals to specialize in specific tasks, increasing efficiency and productivity. This specialization enables the production of surplus goods, which can then be exchanged in the market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>39", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "One-man business are popular in West Africa because of all of the following, except the", "images": [], "options": {"A": "ease of entry", "B": "small capital required", "C": "limited entrepreneurial skill needed", "D": "tendency to become joint stock company"}, "answer": "D", "explanation": "One-man businesses are popular in West Africa due to factors like ease of entry, small capital requirements, limited entrepreneurial skills needed, and ease of decision-making. However, the tendency to become a joint stock company is not a reason for their popularity; rather, it is often the opposite, as one-man businesses typically remain small and do not transition into joint stock companies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1993>40", "subject": "Economics", "year": "1993", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "Which of the following is not a reason why statutory corporations are run only by the government?", "images": [], "options": {"A": "The duplication of some services will lead to resource wastage", "B": "All corporations provide services which individuals cannot provide", "C": "Essential services must be provided irrespective of the economic system adopted", "D": "Some corporations require large financial capital which may not be easy to  acquire by individuals"}, "answer": "A", "explanation": "The duplication of some services leading to resource wastage is not a reason why statutory corporations are run only by the government. Statutory corporations are typically established to provide essential services that may not be profitable for private entities, protect consumers, and ensure that large-scale services requiring significant capital are managed effectively. The concern about resource wastage is more relevant to the efficiency of service delivery rather than a justification for government operation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1994>1", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The definition of Economics as \"the science which studies human behaviour as a relationship between ends and scarce means which have alternative uses\" was given by", "images": [], "options": {"A": "Adam Smith", "B": "David Ricardo", "C": "Lionel Robbins", "D": "Thomas R. Malthus"}, "answer": "C", "explanation": "The definition of Economics as \"the science which studies human behaviour as a relationship between ends and scarce means which have alternative uses\" was given by Lionel Robbins. This definition emphasizes the allocation of limited resources to satisfy various human wants, which is a fundamental concept in economics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>2", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "The concept of economic efficiency primarily implies", "images": [], "options": {"A": "obtaining the maximum output from available resources at the lowest possible cost", "B": "conserving our petroleum resources", "C": "equity in the distribution of the nation's wealth", "D": "producing without waste"}, "answer": "A", "explanation": "The concept of economic efficiency primarily implies obtaining the maximum output from available resources at the lowest possible cost. This is known as productive efficiency, where resources are utilized in the most effective way to produce goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>3", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "Which of the following is true of NEPA as a public corporation in NIgeria? It is", "images": [], "options": {"A": "a solar energy distributor", "B": "a duopoly", "C": "a monopolistically competitive industry", "D": "a monopoly"}, "answer": "D", "explanation": "NEPA (National Electric Power Authority) in Nigeria is classified as a monopoly. A monopoly exists when a single firm is the sole provider of a product or service in a market, which is the case for NEPA in the electricity supply sector in Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>4", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "A situation of full employment exists when", "images": [], "options": {"A": "every adult is employed", "B": "all adults who can work are employed", "C": "all persons who have attained the age of I5 years and above are employed", "D": "all those who are able and eligible to work are employed"}, "answer": "D", "explanation": "A situation of full employment exists when all those who are able and eligible to work are employed. This does not mean that every adult is employed, as some may choose not to work or may be unable to work due to various reasons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>5", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "Which of the following functions of money makes it possible for any person to provide for old age?", "images": [], "options": {"A": "Medium of exchange", "B": "Store of value", "C": "Measure of value", "D": "Unit of account"}, "answer": "B", "explanation": "The function of money that makes it possible for any person to provide for old age is the 'Store of value'. This function allows individuals to save money and preserve its value over time, enabling them to use it in the future for retirement or old age needs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>6", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : ROLES", "question": "The primary objective of the Agricultural Credit Guarantee Scheme is the provision of", "images": [], "options": {"A": "guarantee for loans granted by banks for agricultural purposes", "B": "agricultural inputs to facilitate credit from banks", "C": "loans for every farmer", "D": "agricultural products for farmers"}, "answer": "A", "explanation": "The primary objective of the Agricultural Credit Guarantee Scheme is to provide a guarantee for loans granted by banks for agricultural purposes. This scheme is designed to encourage banks to lend to farmers by reducing the risk associated with agricultural loans.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>7", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Which of the following is not an advantage of localization of industries?", "images": [], "options": {"A": "Enjoyment of external economies", "B": "Development of subsidiary industries", "C": "Development of organized markets", "D": "Growth of conurbation"}, "answer": "D", "explanation": "Growth of conurbation is not an advantage of localization of industries. While localization can lead to benefits such as external economies and the development of organized markets, conurbation refers to the merging of urban areas, which can lead to challenges such as congestion and pollution rather than advantages.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>8", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "Which of the following is not an advantage of government ownership of enterprises?", "images": [], "options": {"A": "More capital is provided", "B": "Pricing policy may be in the interest of consumers", "C": "Government workers may be indifferent towards the public", "D": "Infrastructures are rapidly developed"}, "answer": "C", "explanation": "The statement that government workers may be indifferent towards the public is not an advantage of government ownership of enterprises. In fact, this can be a disadvantage, as it may lead to inefficiencies and a lack of responsiveness to consumer needs, unlike private enterprises that are driven by profit motives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>9", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "If the foreign exchange rate is #8 to ₤1, then a bicycle bought for ₤40 will cost", "images": [], "options": {"A": "#15.00", "B": "#60.00", "C": "#100.00", "D": "#250.00"}, "answer": "C", "explanation": "If the foreign exchange rate is #8 to ₤1, then a bicycle bought for ₤40 will cost #320.   This is calculated by multiplying the price in pounds by the exchange rate: ₤40 x #8/₤1   = #320.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>10", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "All of the following are assets of a commercial bank except", "images": [], "options": {"A": "cash", "B": "bills discounted", "C": "bank deposits", "D": "investment"}, "answer": "C", "explanation": "Bank deposits are not considered assets of a commercial bank; rather, they are liabilities. Assets include cash, bills discounted, investments, and advances to customers, while deposits represent money owed to customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>11", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "The Central Bank controls commercial banks through all the following except measures except", "images": [], "options": {"A": "the use of directives", "B": "the use of bank rate", "C": "open market operations", "D": "accepting deposits"}, "answer": "D", "explanation": "The Central Bank controls commercial banks through various measures, but accepting deposits is not a control measure. Instead, it is a function of commercial banks. The other options (directives, bank rate, open market operations, and demanding special deposits) are all tools used by the Central Bank to influence the banking system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>12", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "If a person supplements his current income by drawing on past savings in order to make both ends meet, he is said to be living", "images": [], "options": {"A": "good life", "B": "an average life", "C": "on his savings", "D": "a reckless life"}, "answer": "C", "explanation": "When a person draws on past savings to meet current expenses, they are said to be living on their savings. This indicates that they are using previously accumulated funds rather than current income to sustain their lifestyle.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1994>13", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "Which of the following is not a set of measures of central tendency?", "images": [], "options": {"A": "Mode and median", "B": "Mean and median", "C": "Mean and mode", "D": "Median and percentage"}, "answer": "D", "explanation": "The median is a measure of central tendency, but 'median and percentage' does not represent a set of measures of central tendency. Percentages are not measures of central tendency; they are a way to express a number as a fraction of 100.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>14", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS: REPRESENTATION OF DATA", "question": "The diagram below is a", "images": ["Economics/imgs/1994/KHE6CC.jpg"], "options": {"A": "bar chart", "B": "pie chart", "C": "ball chart", "D": "histogram"}, "answer": "B", "explanation": "The diagram above represent a pie chart which is also known as circle chart. It is a graphical representation of data where the circle is divided into slices, each slice representing a proportion of the whole.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>15", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "Which of the following pairs can be referred to as middlemen?", "images": [], "options": {"A": "Wholesalers and agents", "B": "Retailers and consumers", "C": "Consumers and agents", "D": "Wholesalers and retailers"}, "answer": "A", "explanation": "Wholesalers and agents can be referred to as middlemen because they act as intermediaries between producers and retailers or consumers. They facilitate the distribution of goods and services, making them essential in the supply chain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>16", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "Mono-product economies are those that", "images": [], "options": {"A": "have rich cultural heritage", "B": "produce only raw materials", "C": "live on the exportation of their products", "D": "produce one main commodity"}, "answer": "D", "explanation": "Mono-product economies are characterized by their production of one main commodity. This means that the economy relies heavily on a single product for its economic activities, which can lead to vulnerabilities if the demand for that product fluctuates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>17", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "In the figure above, the broken line labelled PM is the Marginal Revenue Curve of a", "images": ["Economics/imgs/1994/RW7NGD.jpg"], "options": {"A": "monopoly", "B": "competitive firm", "C": "state corporation", "D": "partnership"}, "answer": "A", "explanation": "The Marginal Revenue Curve (MR) is typically associated with a monopoly, as monopolies are the only market structure where the MR curve is downward sloping and lies below the demand curve. This is due to the fact that a monopolist must lower the price to sell additional units, which affects the revenue generated from all units sold.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1994>18", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND", "question": "A Nigeria household's demand curve for semovita is downward sloping because", "images": [], "options": {"A": "the demand for semovita is high", "B": "the local markets are flood with semovita", "C": "semovita is produced in Nigeria", "D": "the higher the price of semovita, the lower the quantity demanded"}, "answer": "D", "explanation": "A downward sloping demand curve indicates that as the price of semovita increases, the quantity demanded decreases. This is a fundamental principle of demand in economics, known as the law of demand, which states that there is an inverse relationship between price and quantity demanded.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>19", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT", "question": "To the economist, a stock of goods existing at a particular time and conforming to certain requirements such as having utility, money, value and being limited in supply, is known as", "images": [], "options": {"A": "consumer goods", "B": "products", "C": "wealth", "D": "commercial goods"}, "answer": "C", "explanation": "In economics, a stock of goods that has utility, monetary value, and is limited in supply is referred to as wealth. Wealth encompasses all valuable resources that can be owned and used to generate further economic benefits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>20", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The decision to consume more of one product will under normal circumstances imply that", "images": [], "options": {"A": "more of another product will be consumed", "B": "less of something else will be consumed", "C": "no other product will be consumed", "D": "decision-making is basic in Economics"}, "answer": "B", "explanation": "The decision to consume more of one product typically implies that less of another product will be consumed, due to the concept of opportunity cost. This principle states that choosing to allocate resources (such as time or money) to one option means forgoing the opportunity to use those resources for another option.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>21", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The difference between the Gross Domestic Product and the Gross National Product is the", "images": [], "options": {"A": "allowance for total depreciation", "B": "total interest payment", "C": "net income from abroad", "D": "total tax and interest payments"}, "answer": "C", "explanation": "The difference between Gross Domestic Product (GDP) and Gross National Product (GNP) is primarily due to net income from abroad. GDP measures the total value of all goods and services produced within a country's borders, while GNP includes the value of goods and services produced by the residents of a country, regardless of where they are located, minus the income earned by foreign residents in the country. Therefore, the correct answer is 'net income from abroad'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>22", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "One of the functions of a commercial bank is that it", "images": [], "options": {"A": "is responsible for formulating monetary policies", "B": "accepts demand and time deposits from customers", "C": "is the lender of last resort", "D": "is the banker of the government"}, "answer": "B", "explanation": "One of the primary functions of a commercial bank is to accept demand and time deposits from customers. This function allows banks to provide a safe place for individuals and businesses to store their money while also enabling them to lend out these deposits to generate interest income. Therefore, the correct answer is 'accepts demand and time deposits from customers'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1994>23", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "Which of the following is not a problem of distribution of goods in Nigeria?", "images": [], "options": {"A": "Poor communication network", "B": "Inadequate storage facilities", "C": "Ignorance of consumers", "D": "Dishonesty of middlemen"}, "answer": "C", "explanation": "Among the options provided, 'Ignorance of consumers' is not typically considered a problem of distribution of goods. The other options, such as poor communication network, inadequate storage facilities, dishonesty of middlemen, and inadequate market, directly affect the distribution process. Ignorance of consumers may affect purchasing decisions but does not directly impact the distribution logistics. Therefore, the correct answer is 'Ignorance of consumers'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>24", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Mr. Idowu need a television and a refrigerator. Each cost #500.00, the exact  amount he has. if Mr. Idowu buys the television, the refrigerator would be regarded as the", "images": [], "options": {"A": "marginal cost", "B": "inferior item", "C": "opportunity cost", "D": "supplementary item"}, "answer": "C", "explanation": "If Mr. Idowu buys the television for #500, the refrigerator, which he cannot afford now, represents the opportunity cost of his decision. Opportunity cost is defined as the value of the next best alternative that is forgone when making a choice. In this case, the refrigerator is the next best alternative that he cannot purchase because he chose to buy the television. Therefore, the correct answer is 'opportunity cost'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>25", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Petro-chemical industries are located in Rivers State of Nigeria due to the presence of", "images": [], "options": {"A": "a favourable climate", "B": "coal deposits", "C": "oil palm products", "D": "oil deposits"}, "answer": "D", "explanation": "Petro-chemical industries are primarily located in Rivers State of Nigeria due to the presence of oil deposits. The availability of raw materials, such as crude oil, is crucial for the petrochemical industry, which processes these materials into various chemical products. Therefore, the correct answer is 'oil deposits'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>26", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "Foreign exchange control in Nigeria is enforced by the", "images": [], "options": {"A": "Commercial Banks", "B": "Mechant Banks", "C": "Mortgage Banks", "D": "Central Bank"}, "answer": "D", "explanation": "Foreign exchange control in Nigeria is enforced by the Central Bank. The Central Bank is responsible for regulating the country's monetary policy and managing the foreign exchange reserves, which includes implementing controls on foreign exchange transactions to stabilize the currency and manage the economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>27", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "The difference between the number of immigrants and emigrants is", "images": [], "options": {"A": "internal mobility", "B": "internal migration", "C": "net migration", "D": "marginal migration"}, "answer": "C", "explanation": "The difference between the number of immigrants (people coming into a country) and emigrants (people leaving a country) is known as net migration. This term reflects the overall change in population due to migration, indicating whether a country is gaining or losing population through migration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>28", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Risk bearing and marginal control are the main functions of the", "images": [], "options": {"A": "managing director", "B": "manager", "C": "entrepreneur", "D": "chief executive"}, "answer": "C", "explanation": "Risk bearing and marginal control are primarily functions of the entrepreneur. An entrepreneur is someone who takes on the risk of starting and managing a business, making decisions that affect the business's operations and profitability. They are responsible for innovating and managing resources effectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>29", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "In the table below, the marginal cost when output is 2 units is,     Output Total Cost (#)1 202 563 964 1445 160", "images": [], "options": {"A": "#16.00", "B": "#20.00", "C": "#36.00", "D": "#40.00"}, "answer": "C", "explanation": "To find the marginal cost when output is 2 units, we calculate the change in total cost when output increases from 1 unit to 2 units.     The total cost at 1 unit is #20 and at 2 units is #56.     Therefore, the marginal cost is #56 - #20   = #36.00.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>30", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION", "question": "If successive units of labour are added to a piece of land while capital and technology remain constant, a point will be reached in the level of production when each each additional unit of labour will add less to the output than previous units. This concept is known as the", "images": [], "options": {"A": "productivity of labour", "B": "law of diminishing marginal utility", "C": "law of diminishing returns", "D": "law of diminishing returns of a variable factor"}, "answer": "C", "explanation": "The concept described is known as the law of diminishing returns. This economic principle states that if one factor of production (like labor) is increased while other factors (like capital and technology) remain constant, the incremental output gained from each additional unit of that factor will eventually decrease. This is a fundamental concept in production theory.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1994>31", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "Fixed Unit of Land (hectares) Variable Unit of Labour  Total Output Marginal Product5110105225155 3 X 215 4 60145 5 73 135 6 82 Y  Which of the following pairs gives the values of X and Y in the table above?", "images": [], "options": {"A": "X =20, Y = 6", "B": "X = 10, Y = 10", "C": "X = 38, Y = 9", "D": "X = 46, Y = 9"}, "answer": "D", "explanation": "Since, average product is missing, then TP will be calculated by adding the 2nd unit + the MP 3rd unit.  TP = 25 + 21  = 46    MP = change in TP/change in variable unit  = 82 - 73/ 6 - 5  = 9", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>32", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "When a firm's total revenue is at the maximum, marginal revenue is", "images": [], "options": {"A": "at the maximum", "B": "negative", "C": "zero", "D": "positive"}, "answer": "C", "explanation": "When a firm's total revenue is at its maximum, the marginal revenue (MR) is zero. This is because marginal revenue is the additional revenue generated from selling one more unit of a good. At the maximum total revenue point, selling additional units does not increase total revenue, hence MR equals zero. This concept is fundamental in understanding revenue maximization in economics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>33", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "Under normal circumstances, a producer will bear the entire burden of taxation on his output if the", "images": [], "options": {"A": "supply of his goods is more elastic than the demand", "B": "demand for his product is completely elastic", "C": "production of his commodities is subject to diminishing returns", "D": "demand for his product is completely inelastic"}, "answer": "D", "explanation": "A producer will bear the entire burden of taxation on his output if the demand for his product is completely inelastic. This means that consumers will continue to buy the same quantity regardless of price changes, so the producer cannot pass the tax burden onto consumers. Therefore, the correct option is that the demand for his product is completely inelastic", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1994>34", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Limited liability means that", "images": [], "options": {"A": "the debts of a company can only be paid from its own assets", "B": "the debts of a company are paid from business as well as private funds of the owners", "C": "a company does not have to pay its debts", "D": "the debts of a company must be paid from private funds only"}, "answer": "A", "explanation": "Limited liability means that the debts of a company can only be paid from its own assets, and the personal assets of the owners are protected. This is a fundamental principle of corporate law that limits the financial liability of the owners to the amount they have invested in the company. Therefore, the correct option is that the debts of a company can only be paid from its own assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>35", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Factory buildings, machinery and raw materials are known in Economics as", "images": [], "options": {"A": "personal wealth", "B": "social wealth", "C": "government wealth", "D": "business wealth"}, "answer": "D", "explanation": "Factory buildings, machinery, and raw materials are known in economics as business wealth. This term refers to the physical assets that a business uses to produce goods and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1994>36", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Abstention from consumption enables capital to be produced . Such abstention is called", "images": [], "options": {"A": "saving", "B": "production", "C": "accumulation", "D": "factors of production"}, "answer": "A", "explanation": "Abstention from consumption refers to the act of saving, which allows resources to be set aside for future use, enabling capital to be produced. Saving is the correct term for this concept.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>37", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "PUBLIC FINANCE : TAX", "question": "Tax evasion in Economics means", "images": [], "options": {"A": "false declaration of assets", "B": "paying tax only as and when due", "C": "declaration of assets", "D": "tax payment according to income received"}, "answer": "A", "explanation": "Tax evasion refers to the illegal act of not paying taxes owed, often through false declaration of assets. This is a deliberate attempt to reduce tax liability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>38", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "The Quantity Theory of Money states that an increase in the quantity of money would bring about", "images": [], "options": {"A": "a geometrical rise in prices", "B": "an unequal rise in prices", "C": "a proportionate rise in prices", "D": "an absolute rise in prices"}, "answer": "C", "explanation": "The Quantity Theory of Money posits that an increase in the money supply will lead to a proportionate increase in prices, assuming that the velocity of money and output remain constant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>39", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The magnitude of the national income of a country depends on all the following except the", "images": [], "options": {"A": "quantity of natural resources available", "B": "level of technical know-how", "C": "mobility of labour", "D": "level of productivity"}, "answer": "C", "explanation": "The magnitude of national income is influenced by various factors, but the mobility of labor is not a direct determinant of national income. It affects how resources are allocated but does not directly determine the income level itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1994>40", "subject": "Economics", "year": "1994", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "Under the ECOWAS agreement, a Nigerian can enter and stay in Ghana without a visa for a period of", "images": [], "options": {"A": "14 days", "B": "30 days", "C": "60 days", "D": "90 days"}, "answer": "D", "explanation": "Under the ECOWAS agreement, Nigerian citizens can enter and stay in Ghana without a visa for a period of 90 days.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1995>1", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Economics is a social science which studies how", "images": [], "options": {"A": "to redistribute income", "B": "human beings behave", "C": "the market price is fixed", "D": "scarce resources are allocated to satisfy human wants"}, "answer": "D", "explanation": "Economics is a social science that studies how scarce resources are allocated to satisfy human wants. This involves making choices about the distribution of resources to meet the needs and wants of individuals and society as a whole. The other options do not fully capture the essence of what economics studies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1995>2", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Scarcity in economics means", "images": [], "options": {"A": "shortage of commodity", "B": "unlimited demands for consumer goods", "C": "limited supply of goods and services", "D": "total absence of a commodity in the market"}, "answer": "C", "explanation": "Scarcity in economics refers to the basic economic problem, the gap between limited resources and theoretically limitless wants. This situation requires people to make decisions about how to allocate resources efficiently, in order to satisfy basic needs and as many additional wants as possible. The other options are either too specific or not entirely correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1995>3", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "The decision on what to produce is a problem in", "images": [], "options": {"A": "all economics system", "B": "a mixed economic system only", "C": "a democratic socialist economy only", "D": "a free enterprise system only"}, "answer": "A", "explanation": "The decision on what to produce is a problem in all economic systems, not just in a mixed, democratic socialist, or free enterprise system. This is because all economies must decide what goods and services to produce with the limited resources available. This is one of the fundamental problems of economics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>4", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "The law of demand states that", "images": [], "options": {"A": "as price increases, quantity demanded remains constant", "B": "demand increases as price increases", "C": "as price falls, quantity demanded also falls", "D": "as price falls, quantity demanded increases"}, "answer": "D", "explanation": "The law of demand is a fundamental principle in economics which states that, all else being equal, as the price of a product increases, quantity demanded falls; likewise, as the price of a product decreases, quantity demanded increases. Therefore, option 4 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>5", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "Which of the following is an important limiting factor in the application of division of labour?", "images": [], "options": {"A": "market size", "B": "availability of an infrastructure", "C": "wage rate", "D": "Raw materials"}, "answer": "A", "explanation": "The division of labour is the separation of tasks in any economic system or organisation so that participants may specialize (specialization). Individuals, organizations, and nations are endowed with or acquire specialized capabilities and either form combinations or trade to take advantage of the capabilities of others in addition to their own. The limiting factor in the application of division of labour is the market size. If the market size is small, the division of labour may not be fully utilized. Therefore, option 1 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>6", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Which of the following factors does not encourage the location of industries?", "images": [], "options": {"A": "Nearness to the market", "B": "Availability of infrastructural facilities", "C": "Government influence in sitting industries", "D": "political instability"}, "answer": "D", "explanation": "The location of industries is influenced by a variety of factors including nearness to the market, availability of infrastructural facilities, and government influence in sitting industries. However, political instability does not encourage the location of industries. In fact, it discourages it because it creates an uncertain environment for business. Therefore, option 4 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>7", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "All the underlisted factors directly affects the supply of a commodity except", "images": [], "options": {"A": "price", "B": "improved production method", "C": "access to capital", "D": "level of income"}, "answer": "D", "explanation": "The supply of a commodity is directly affected by factors such as price, production methods, and access to capital. However, the level of income is a factor that affects demand, not supply. Therefore, the level of income does not directly affect the supply of a commodity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>8", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "Which of the following economic system is in operation in Nigeria?", "images": [], "options": {"A": "Capitalist economy", "B": "Socialist cum Marxist economy", "C": "Socialist economy", "D": "mixed economy"}, "answer": "D", "explanation": "Nigeria operates a mixed economy. A mixed economy is an economic system that combines aspects of both capitalism and socialism. This means that in Nigeria, both private and public sectors co-exist and operate together.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>9", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "Giffen commodities are those commodities", "images": [], "options": {"A": "which gives rise to a cobweb situation", "B": "for which demand increases as price increases", "C": "which have a low price elasticity of demand", "D": "which are in short supply"}, "answer": "B", "explanation": "Giffen commodities are those commodities for which demand increases as price increases. This is a paradoxical situation that contradicts the law of demand. It is named after the economist Sir Robert Giffen, who first proposed this concept.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1995>10", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Effective demand in economics means", "images": [], "options": {"A": "the desire for a commodity", "B": "a proposal to purchase a good on credit", "C": "the desire for a commodity or service backed by purchasing power", "D": "an irrevocable instruction to the seller to meet up the need of the buyers"}, "answer": "C", "explanation": "Effective demand in economics refers to the desire for a good or service backed by the ability to pay for it, i.e., purchasing power. It is not just about wanting a commodity but also having the means to acquire it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>11", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "Government can influence aggregate demand through all the following measures except", "images": [], "options": {"A": "reduction in personal income tax", "B": "retirement of director-general in the public service", "C": "creation of employment opportunities", "D": "compulsory deduction from salaries of all categories of workers"}, "answer": "B", "explanation": "Government can influence aggregate demand through fiscal policies such as reduction in personal income tax, creation of employment opportunities, and compulsory deduction from salaries. However, retirement of a director-general in the public service does not directly influence aggregate demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>12", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "The term production in Economics means", "images": [], "options": {"A": "manufacturing of goods", "B": "the creation of utilities", "C": "giving birth to children", "D": "the distribution of goods and services"}, "answer": "B", "explanation": "In economics, production refers to the creation of utilities. It is the process of adding value to a product or service by transforming inputs into outputs that satisfy human wants. It is not limited to manufacturing of goods, giving birth to children, or the distribution of goods and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1995>13", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "Under the socialist economy , the decision on what to produce is determined by the", "images": [], "options": {"A": "producer", "B": "level of expected profit", "C": "price", "D": "Government"}, "answer": "D", "explanation": "In a socialist economy, the government makes all economic decisions including what to produce, how to produce, and for whom to produce. Therefore, the decision on what to produce is determined by the government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>14", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Credit creation by banks is limited by", "images": [], "options": {"A": "an increase in bank deposits", "B": "the establishment of specialized banks", "C": "the non-availability of collateral security", "D": "the use of cheques for all transactions of the banks"}, "answer": "A", "explanation": "Credit creation by banks is limited by the amount of deposits they have. Banks use deposits to lend out money and create credit. If there is an increase in bank deposits, banks have more funds to lend out, which can lead to more credit creation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1995>15", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM", "question": "Which of the following explains marginal cost?", "images": [], "options": {"A": "Overhead costs plus variable costs resulting from production", "B": "the average cost of producing more units of the product", "C": "the extra cost of producing more units of the product", "D": "the addition to total cost resulting from the production of an additional unit"}, "answer": "C", "explanation": "Marginal cost is the cost of producing one more unit of a good. In other words, it is the extra cost of producing more units of the product. It is an important concept in economics because it helps businesses decide how much of a good to produce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>16", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "The effect of an increase in price on the demand for a commodity with elastic demand will be", "images": [], "options": {"A": "an increase in the demand for the commodity", "B": "a decrease in the demand for the commodity", "C": "a further increase in the price of the commodity", "D": "reduction in the number of the distributors of the commodity"}, "answer": "B", "explanation": "Price elasticity of demand measures how the quantity demanded of a good responds to a change in the price of that good. If a commodity has elastic demand, it means that the quantity demanded is highly responsive to changes in price. Therefore, an increase in price will lead to a decrease in the demand for the commodity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>17", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS", "question": "If AC = Average cost of production, FC = Fixed cost of production, VC = Variable cost of production, and TC = Total cost of production, then", "images": [], "options": {"A": "VC = TC/FC", "B": "VC = FC + AC", "C": "VC = TC - AC", "D": "VC = TC - FC"}, "answer": "D", "explanation": "Variable cost (VC) is the portion of the total cost (TC) that varies with the level of output. Fixed cost (FC) is the portion of the total cost that does not vary with output. Therefore, the variable cost can be calculated by subtracting the fixed cost from the total cost. Hence, VC = TC - FC.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1995>18", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "MARKET STRUCTURE : PERFECT MARKET", "question": "In perfect competition , the marginal cost curve intersects the average cost curve", "images": [], "options": {"A": "from below at its lowest point", "B": "from above at its lowest point", "C": "from below before the lowest point", "D": "at the zero point"}, "answer": "A", "explanation": "In perfect competition, the marginal cost curve intersects the average cost curve from below at its lowest point. This is because when the average cost is at its minimum, any additional unit of output will increase the average cost, hence the marginal cost (the cost of producing an additional unit of output) is equal to the average cost at this point.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1995>19", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "POPULATION : INTRODUCTION", "question": "Which of the following does not require the use of information from census?", "images": [], "options": {"A": "allocating central government revenue among states or regions", "B": "planning for development in the states of regions", "C": "Demarcating constituencies for election in the states or regions", "D": "Controlling geographical mobility of labour among the states or regions"}, "answer": "D", "explanation": "Controlling geographical mobility of labour among the states or regions does not require the use of information from census. Census data is typically used for planning, resource allocation, and demarcating constituencies for elections. However, the movement of labour is determined by factors such as job opportunities, wages, and living conditions, not census data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>20", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "FINANCIAL INSTITUTION : INSURANCE COMPANY", "question": "Which of the following is not a function of an insurance company?", "images": [], "options": {"A": "Mobilization of funds through premiums collected", "B": "Encouragement of savings habits through life assurances", "C": "Collection of deposits from the public for investment", "D": "Granting of loans on long-term basis for investment"}, "answer": "C", "explanation": "Collection of deposits from the public is not a function of an insurance company. Insurance companies operate by collecting premiums from policyholders, which are used to pay out claims. They do not collect deposits like banks do. Their primary functions include risk management, mobilization of funds through premiums, encouraging savings habits through life assurances, and granting loans for investment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>21", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "POPULATION : THEORIES OF POPULATION", "question": "Malthus observed in his theory that population was growing", "images": [], "options": {"A": "at a regular rate", "B": "in arithmetical progression", "C": "in geometrical progression", "D": "in mathematical progression"}, "answer": "C", "explanation": "According to Malthus's theory of population, population was growing in geometrical progression. This means that the population would double every generation, leading to an exponential increase. On the other hand, he believed that food production could only increase in an arithmetical progression, leading to a potential crisis if population growth was not checked.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>22", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "At optimum population level, a country has its", "images": [], "options": {"A": "maximum population", "B": "ageing population", "C": "highest birth rate", "D": "highest output per head"}, "answer": "D", "explanation": "At optimum population level, a country has its highest output per head. This is because the optimum population is the size of population that produces the maximum output per head. It is the population size that results in the highest standard of living for the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>23", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "MONEY : CHARACTERISTICS OF MONEY", "question": "Which of the following does not give a characteristics of money?", "images": [], "options": {"A": "Durable", "B": "Portable", "C": "Divisible into small units", "D": "Medium of exchange"}, "answer": "D", "explanation": "The option 'Medium of exchange' does not give a characteristic of money but rather a function of money. Characteristics of money include being durable, portable, divisible into small units, and others. However, being a medium of exchange is a function of money, not a characteristic.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1995>24", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "MONEY : SUPPLY OF MONEY", "question": "Which of the following constitute the major components of money supply in a development economy?", "images": [], "options": {"A": "Demand deposits", "B": "Paper money", "C": "Bank drafts", "D": "Coins"}, "answer": "A", "explanation": "The major components of money supply in a developed economy are demand deposits and currency in circulation (which includes paper money and coins). Bank drafts are not a component of the money supply. They are instruments of credit and are not counted as part of the money supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>25", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "A point along a consumer's indifference curve shows", "images": [], "options": {"A": "the difference commodities he can consume", "B": "a combination of all commodities he is willing to buy", "C": "a combination of two commodities from which he derive the same satisfaction", "D": "the quantity of commodities demanded by him"}, "answer": "C", "explanation": "An indifference curve in economics is a graph showing different bundles of goods between which a consumer is indifferent. That is, at each point on the curve, the consumer has no preference for one bundle over another. One can also refer to each point on the indifference curve as rendering the same level of utility (satisfaction) for the consumer. Therefore, a point along a consumer's indifference curve shows a combination of two commodities from which he derives the same satisfaction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1995>26", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "If a monopolist is attempting to maximize profit , which of the following should he attempt to do?", "images": [], "options": {"A": "Equate average cost to average revenue", "B": "Equate marginal cost to marginal revenue", "C": "Equate marginal cost to average revenue", "D": "fix price and output"}, "answer": "B", "explanation": "In economics, a monopolist maximizes profit by producing at the quantity where marginal cost equals marginal revenue. This is because the cost of producing an additional unit of output (marginal cost) is exactly balanced by the revenue gained from selling that additional unit (marginal revenue). Therefore, the monopolist should attempt to equate marginal cost to marginal revenue.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1995>27", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "The greatest foreign exchange earner for Nigeria before the advent of petroleum was", "images": [], "options": {"A": "mining", "B": "handicraft", "C": "agriculture", "D": "manufacturing"}, "answer": "C", "explanation": "Before the advent of petroleum, agriculture was the mainstay of Nigeria's economy and the greatest foreign exchange earner. The country was a leading exporter of agricultural products like cocoa, groundnut, rubber, palm oil, etc. Therefore, the greatest foreign exchange earner for Nigeria before the advent of petroleum was agriculture.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>28", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "A budget is define as a", "images": [], "options": {"A": "Summary of expected expenditure by individuals and government", "B": "summary of expected income", "C": "record of value of services rendered in a year", "D": "summary of expected income and expenditure"}, "answer": "D", "explanation": "A budget is a financial plan for a defined period, often one year. It may also include planned sales volumes and revenues, resource quantities, costs and expenses, assets, liabilities and cash flows. It is a summary of expected income and expenditure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1995>29", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "The real value of money is", "images": [], "options": {"A": "its face value", "B": "what it can buy at a particular time", "C": "its rate of exchange with other currencies", "D": "its intrinsic worth"}, "answer": "B", "explanation": "The real value of money is what it can buy at a particular time. This is also known as the purchasing power of money. It is not the face value or the rate of exchange with other currencies or its intrinsic worth. The real value of money can change over time due to factors like inflation or changes in the supply and demand for goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>30", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "A tax whose rate increases as income increases is", "images": [], "options": {"A": "an indirect tax", "B": "a progressive tax", "C": "a regressive tax", "D": "a direct tax"}, "answer": "B", "explanation": "A progressive tax is a tax in which the tax rate increases as the taxable amount increases. The term 'progressive' refers to the way the tax rate progresses from low to high, with the result that a taxpayer's average tax rate is less than the person's marginal tax rate. The term can be applied to individual taxes or to a tax system as a whole. This is different from a regressive tax, where the tax rate decreases as the amount subject to taxation increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>31", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER", "question": "Which of the following best describes the multiplier?", "images": [], "options": {"A": "products of income and expenditure", "B": "Curves of savings and expenditure", "C": "Ratio of change in income to the expenditure that brought it about", "D": "Constant level of income"}, "answer": "C", "explanation": "The multiplier in economics is a concept that describes how an initial change in spending can lead to a larger change in income. It is the ratio of the change in income to the change in investment that brought it about. Therefore, the correct answer is 'Ratio of change in income to the expenditure that brought it about'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1995>32", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Net National Product (NNP) is equal to the", "images": [], "options": {"A": "Gross Domestic Product (GDP) less depreciation", "B": "Gross National Products (GNP) less depreciation", "C": "Gross Domestic Products (GDP) plus depreciation", "D": "Gross National Products (GNP) plus depreciation"}, "answer": "B", "explanation": "Net National Product (NNP) is the total market value of all final goods and services produced by the citizens of a country. It is calculated by subtracting depreciation (the value of wear and tear on capital equipment) from the Gross National Product (GNP). Therefore, the correct answer is 'Gross National Products (GNP) less depreciation'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>33", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "Terms of trade simply means the price", "images": [], "options": {"A": "ratio of import to export", "B": "ratio of export multiplied by import", "C": "ratio of export to import", "D": "ratio of export multiplied by price ratio of import"}, "answer": "C", "explanation": "Terms of trade refer to the relative price of exports in terms of imports and is defined as the ratio of export prices to import prices. It can be interpreted as the amount of import goods an economy can purchase per unit of export goods. Therefore, the correct answer is 'ratio of export to import'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>34", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Balance of trade can be define as", "images": [], "options": {"A": "the value of import in relation to the value of a country's exports", "B": "the price ratio of imports as against that of exports", "C": "equality in the total receipts and payments of a country in a year", "D": "percentage value of imports over percentage value of exports"}, "answer": "A", "explanation": "The balance of trade is the difference between the value of a country's exports and the value of its imports. Therefore, it can be defined as the value of import in relation to the value of a country's exports. The other options do not accurately define the balance of trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>35", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "MARKET STRUCTURE : PERFECT MARKET", "question": "Which of the following is not a feature of a perfect market?", "images": [], "options": {"A": "large number of buyers and sellers", "B": "Homogeneity of products", "C": "Preferential treatment", "D": "Absence of transport cost"}, "answer": "C", "explanation": "A perfect market, also known as a perfectly competitive market, is characterized by a large number of buyers and sellers, homogeneity of products, and absence of transport cost. However, preferential treatment is not a feature of a perfect market because all firms are price takers and cannot influence the market price. Therefore, no firm receives preferential treatment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>36", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Which of the following is not a source of raising funds for a public limited liability company in West Africa?", "images": [], "options": {"A": "Bank loans", "B": "issue of shares", "C": "issue of debentures", "D": "Sales of bonds"}, "answer": "D", "explanation": "A public limited liability company in West Africa can raise funds through bank loans, issue of shares, and issue of debentures. However, the sale of bonds is not a common method of raising funds for such companies in West Africa. Therefore, the correct answer is 'Sales of bonds'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>37", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION", "question": "Which of the following is not an objective of the Indigenisaton policy in Nigeria? To", "images": [], "options": {"A": "Make Nigerians dominate their economy", "B": "increase Nigerians participation in the economy", "C": "prevent foreign monopoly of the economy", "D": "eliminate foreign participation in the Nigerian economy"}, "answer": "D", "explanation": "The Indigenisation policy in Nigeria was not aimed at eliminating foreign participation in the Nigerian economy. Rather, it was designed to increase Nigerian participation and control in the economy, and to prevent foreign monopoly. While it sought to reduce foreign dominance, it did not aim to completely eliminate foreign participation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1995>38", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : ONSHORE & OFFSHORE OF THE OIL SECTOR", "question": "Where was oil first discovered in commercial quantities in Nigeria?", "images": [], "options": {"A": "Oloibiri", "B": "Warri", "C": "Elesa Eleme", "D": "Onitsha"}, "answer": "A", "explanation": "Oil was first discovered in commercial quantities in Nigeria at Oloibiri in Bayelsa State in 1956. The discovery was made by Shell-BP, at the time the sole concessionaire. Oloibiri Oilfield is an onshore oilfield located in Oloibiri in Ogbia LGA of Bayelsa State, Nigeria, about 45 miles (72 kilometers) east of Port Harcourt in the Niger Delta.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1995>39", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "Where is the headquarter of the African Development Bank (ADB) located?", "images": [], "options": {"A": "Lome", "B": "Adis Ababa", "C": "Accra", "D": "Abdijan"}, "answer": "D", "explanation": "The headquarters of the African Development Bank (ADB) is located in Abidjan, Côte d'Ivoire. The bank was established in 1964 and its main aim is to spur sustainable economic development and social progress in its regional member countries, thus contributing to poverty reduction. The bank was first headquartered in Abidjan, but due to the Ivorian civil war, it was temporarily relocated to Tunis, Tunisia, in 2003. It returned to Abidjan in 2014.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1995>40", "subject": "Economics", "year": "1995", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "International trade takes place because of difference in", "images": [], "options": {"A": "production cost", "B": "language", "C": "government policy", "D": "currency"}, "answer": "A", "explanation": "International trade takes place because of differences in production costs. Countries trade with each other when they have a comparative advantage, which means they can produce a good or service at a lower opportunity cost than other countries. This is not necessarily related to language, government policy, or currency.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>1", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The basic problem that economics attempts to solve is the", "images": [], "options": {"A": "ranking of goods and services", "B": "pricing of goods and services", "C": "scarcity of resources", "D": "foregoing of alternatives"}, "answer": "C", "explanation": "The basic problem that economics attempts to solve is the scarcity of resources. Economics is the study of how societies use scarce resources to produce valuable commodities and distribute them among different people. It's not about ranking or pricing of goods and services, or foregoing of alternatives.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1996>2", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT", "question": "The ranking of a consumer's need in order of importance is termed", "images": [], "options": {"A": "An opportunity cost", "B": "Economies of scale", "C": "A scale of preference", "D": "The making of choice"}, "answer": "C", "explanation": "The ranking of a consumer's needs in order of importance is termed a scale of preference. It's a basic concept in economics that refers to listing of wants in order of importance. It's not an opportunity cost, economies of scale, or the making of choice.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1996>3", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "The total number of fruits consumed by a family in a year is 720, and this is represented by the pie chart below        The quantity of banana consumed by the family is", "images": ["Economics/imgs/1996/bbbbm.png"], "options": {"A": "60", "B": "120", "C": "200", "D": "250"}, "answer": "B", "explanation": "The quantity of banana consumed by the family is:    = 60/360  x 720    = 120", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>4", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "The total number of fruits consumed by a family in a year is 720, and this is represented by the pie chart below      The sum total of the quantity of mango and orange consumed by the family is", "images": ["Economics/imgs/1996/bbbbm.png"], "options": {"A": "120", "B": "200", "C": "360", "D": "400"}, "answer": "D", "explanation": "Mango = 80/360   x 720    = 160    Oranges = 120 / 360   x 720    = 240    Total = 160 + 240  = 400", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>5", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "The total number of fruits consumed by a family in a year is 720, and this is represented by the pie chart below      The quantity of carrot consumed by the family is", "images": ["Economics/imgs/1996/bbbbm.png"], "options": {"A": "200", "B": "360", "C": "400", "D": "520"}, "answer": "A", "explanation": "The quantity of carrot consumed by the family is =   100/ 360  x 720    = 200", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>6", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "If the price of a commodity rises from N2.00 to N4.00 and its supply increases from 100 to 125, then the co-efficient of elasticity of supply is", "images": [], "options": {"A": "0.025", "B": "0.24", "C": "0.22", "D": "0.25"}, "answer": "D", "explanation": "The coefficient of elasticity of supply is calculated using the formula: (percentage change in quantity supplied) / (percentage change in price). In this case, the percentage change in quantity supplied is 25%, and the percentage change in price is 100%. Therefore, the coefficient of elasticity of supply is 0.25.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>7", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "If as a result of fall in price of the commodity X, the quantity demanded of commodity Y falls, then commodities X and Y are", "images": [], "options": {"A": "complementary", "B": "in joint demand", "C": "luxuries", "D": "substitutes"}, "answer": "D", "explanation": "Substitute goods are two alternative goods that could be used for the same purpose, for example,  Android Phones  and Apple iPhone.    In the diagram on the left, there is a fall in the price of Android Phones causing consumers to demand more. (movement along the demand curve). As a result, there is a fall in demand for the substitute (Apple iPhone) leading to less demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>8", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "MUX = PX ( where X and Y = good X and Good Y; MU = Marginal Utility;P= Price)MUY = PY. The above represents the", "images": [], "options": {"A": "marginal utility equation", "B": "equation for consumer dis-equlibruim", "C": "utility maximization equation", "D": "equation for total utility"}, "answer": "C", "explanation": "The equation MUX = PX and MUY = PY represents the utility maximization equation. This is because, according to the utility maximization rule, a consumer is in equilibrium when the ratio of the marginal utility (MU) of a good to its price (P) is equal for all goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>9", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "Subsistence agriculture means", "images": [], "options": {"A": "cultivation for external use", "B": "cultivation for local industries", "C": "farming for the urban dwellers", "D": "cultivation for household consumption"}, "answer": "D", "explanation": "Subsistence agriculture refers to farming in which the farmers focus on growing enough food to feed themselves and their families. Therefore, it means cultivation for household consumption.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1996>10", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS", "question": "Farm produce are graded, packed and distributed by", "images": [], "options": {"A": "purchasing co-operatives", "B": "agricultural co-operative banks", "C": "consumer co-operative society", "D": "marketing co-operatives"}, "answer": "D", "explanation": "Marketing cooperatives are responsible for the grading, packing, and distribution of farm produce. They are formed by farmers to market their products collectively and get the best possible prices. The other options do not perform these functions. Purchasing cooperatives are formed by businesses to buy in bulk and get discounts. Agricultural cooperative banks provide financial services to their members. Consumer cooperative societies are formed by consumers to gain bargaining power and lower prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>11", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Localization of industries is", "images": [], "options": {"A": "the industrialization of a country", "B": "the concentration of the firm of an industry in a particular area", "C": "the location of a firm at a particular locality", "D": "the economic development of a locality"}, "answer": "B", "explanation": "Localization of industries refers to the concentration of firms from a particular industry in a specific area. This is often due to factors such as availability of raw materials, skilled labor, infrastructure, and favorable government policies. The other options do not accurately define localization of industries. Industrialization of a country refers to the process of developing industries on a wide scale. The location of a firm at a particular locality is a decision made by individual firms and does not necessarily indicate localization. The economic development of a locality is a broader concept that includes not just industrial development but also improvements in infrastructure, education, health, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>12", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER", "question": "Which of the following correctly illustrates the chain of distribution?", "images": [], "options": {"A": "Manufacturer -> wholesaler -> retailer--> consumer", "B": "Consumer -> retailer -> wholesaler -> manufacturer", "C": "Wholesaler -> manufacturer -> retailer -> consumer", "D": "Distributor -> consumer -> wholesaler -> manufacturer"}, "answer": "A", "explanation": "The correct chain of distribution is Manufacturer -> Wholesaler -> Retailer -> Consumer. The manufacturer produces the goods, the wholesaler buys in bulk from the manufacturer and sells in smaller quantities to the retailer, and the retailer sells directly to the consumer. The other options do not correctly represent the chain of distribution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1996>13", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "The natural growth rate of a population is the", "images": [], "options": {"A": "Death rate plus net immigration", "B": "Rate of migration divided by birth rate", "C": "Birth rate minus death rate", "D": "Sum of birth rate and net immigration rate"}, "answer": "C", "explanation": "The natural growth rate of a population is the difference between the birth rate and the death rate. This is because the natural growth rate is determined by the number of births and deaths in a population, not considering migration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>14", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION", "question": "Decreasing returns to scale implies that if all factors of production are doubled, output will be", "images": [], "options": {"A": "More than doubled", "B": "Less than doubled", "C": "Doubled", "D": "Unchanged"}, "answer": "B", "explanation": "Decreasing returns to scale implies that if all factors of production are doubled, output will be less than doubled. This is because in the case of decreasing returns to scale, an increase in the scale of production leads to a less than proportionate increase in output.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>15", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Rents and interest are rewards to", "images": [], "options": {"A": "Land and capital respectively", "B": "Land only", "C": "Capital only", "D": "Labour and land respectively"}, "answer": "A", "explanation": "Rents and interest are rewards to land and capital respectively. Rent is the reward for the use of land, while interest is the reward for the use of capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>16", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "The process that leads to an agreement on the condition of service between employer and employee is termed", "images": [], "options": {"A": "Salary negotiation", "B": "Arbitration", "C": "Collective bargaining", "D": "Conciliation"}, "answer": "C", "explanation": "Collective bargaining is the process that leads to an agreement on the conditions of service between employer and employee. It is a process of negotiation between employers and a group of employees aimed at agreements to regulate working salaries, working conditions, benefits, and other aspects of workers' compensation and rights for workers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>17", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM", "question": "Diminishing return occurs in short run when there is a reduction in the", "images": [], "options": {"A": "Average product of the fixed factor", "B": "Total product of the variable factor", "C": "Total product of the fixed factor", "D": "Marginal product of the fixed factor"}, "answer": "D", "explanation": "Diminishing returns, also called law of diminishing returns, occurs when an additional unit of the variable input (like labor) is less productive than its predecessor. That is, the marginal product of the variable factor decreases. This is a fundamental principle in the field of economics.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>18", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "In production, factory buildings are regarded as", "images": [], "options": {"A": "Variable cost", "B": "Average costs", "C": "Marginal costs", "D": "Fixed costs"}, "answer": "D", "explanation": "In production, factory buildings are regarded as fixed costs. Fixed costs are business expenses that are not dependent on the level of goods or services produced by the business. They tend to be time-related, such as salaries or rents being paid per month, and are often referred to as overhead costs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>19", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "The Ownership of a Public Limited Company is made up of", "images": [], "options": {"A": "Two to twenty persons", "B": "A minimum of seven shareholders", "C": "A minimum of 2 and  no limit as maximum", "D": "Two to fifty shareholders"}, "answer": "B", "explanation": "A public limited company is a type of company that is permitted to offer its shares to the public. They require a minimum of seven shareholders. There is no upper limit on the number of shareholders. Therefore, the correct answer is 'A minimum of seven shareholders'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1996>20", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "All the following are the economic reasons for establishing public enterprises except the provision of", "images": [], "options": {"A": "An avenue for expressing national prestige", "B": "Services at a cheaper cost", "C": "Socially necessary facilities", "D": "Services which are natural monopolies"}, "answer": "A", "explanation": "Public enterprises are established for various economic reasons such as providing services at a cheaper cost, providing socially necessary facilities, and services which are natural monopolies. However, expressing national prestige is not an economic reason for establishing public enterprises. It is more of a political or social reason. Therefore, the correct answer is 'An avenue for expressing national prestige'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>21", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "The unemployment associated with decrease in demand is referred to as", "images": [], "options": {"A": "Disguised", "B": "Imposed", "C": "Cyclical", "D": "Voluntary"}, "answer": "C", "explanation": "Cyclical unemployment is a type of unemployment that occurs when the overall demand for goods and services in an economy cannot support full employment. It occurs during periods of slow economic growth or during times of economic contraction. Therefore, the correct answer is 'Cyclical'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>22", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "Monopoly can best be described as a market in which", "images": [], "options": {"A": "A single seller sells a product which has no close substitute", "B": "Few sellers sell a product s at different prices", "C": "The entry of other firms is restricted by the few firms in the market", "D": "Two or more sellers sell a product which is differentiated"}, "answer": "A", "explanation": "A monopoly is a market structure characterized by a single seller, selling a unique product in the market. In a monopoly market, the seller faces no competition, as he is the sole seller of goods with no close substitute. Hence, the correct answer is 'A single seller sells a product which has no close substitute'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>23", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "MARKET STRUCTURE : FORMS OF MARKET STRUCTURE", "question": "Which of the following market structure are imperfect in competition.   I monopoly   II duopoly   III oligopoly", "images": [], "options": {"A": "I only", "B": "II and III only", "C": "I and II only", "D": "I,II and III only"}, "answer": "D", "explanation": "Imperfect competition is a market structure that does not meet the conditions of perfect competition. It is characterized by product differentiation, sellers and buyers with imperfect information, and high barriers to entry and exit. Monopoly, duopoly, and oligopoly are all examples of imperfect competition. Hence, the correct answer is 'I,II and III only'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>24", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Demand-pull inflation results when there is", "images": [], "options": {"A": "inadequate improvement in the wage rate of workers", "B": "excessive demand due to high purchasing power", "C": "excessive supply of raw materials for production", "D": "rise in productivity of the factors of production"}, "answer": "B", "explanation": "Demand-pull inflation is asserted to arise when demand in an economy outpaces supply. It involves inflation rising as real gross domestic product rises and unemployment falls, as the economy moves along the Phillips curve. This is commonly described as 'too much money chasing too few goods'. Hence, the correct answer is 'excessive demand due to high purchasing power'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>25", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "Changes in the value of money can be measured by", "images": [], "options": {"A": "The distributors", "B": "A price index", "C": "A demand index", "D": "A supply index"}, "answer": "B", "explanation": "Changes in the value of money can be measured by a price index. A price index is a measure that examines the weighted average of prices of a basket of consumer goods and services, such as transportation, food, and medical care. It is calculated by taking price changes for each item in the predetermined basket of goods and averaging them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>26", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "The efficiency of a country's labour force depends on all the following except", "images": [], "options": {"A": "improved working conditions", "B": "better and health care facilities", "C": "adequate training", "D": "frequent strikes and lock-outs"}, "answer": "D", "explanation": "The efficiency of a country's labour force does not depend on frequent strikes and lock-outs. In fact, these are detrimental to the efficiency of the labour force as they disrupt work, cause loss of income, and can lead to a decrease in productivity. Improved working conditions, better health care facilities, and adequate training, on the other hand, can enhance the efficiency of the labour force.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>27", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Which of the following is a bank's responsibility to it's shareholders?", "images": [], "options": {"A": "making profits", "B": "creating money", "C": "paying high interest rate", "D": "preventing inflation"}, "answer": "A", "explanation": "A bank's primary responsibility to its shareholders is to make profits. This is because shareholders invest in a company with the expectation of receiving a return on their investment, which comes from the profits the company makes. While banks do play a role in creating money through lending and can influence interest rates, their primary responsibility is not to prevent inflation, but to operate in a way that maximizes shareholder value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>28", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Deficit financing means", "images": [], "options": {"A": "receiving grants from the IMF", "B": "having budget surplus", "C": "excessive government spending on banks", "D": "borrowing to finance a budget"}, "answer": "D", "explanation": "Deficit financing refers to the method used by a government to finance its budget deficit. This is done through borrowing, which means taking on debt to cover the shortfall. Therefore, the correct answer is 'borrowing to finance a budget'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>29", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "Development banks mainly provides", "images": [], "options": {"A": "savings account facilities for a developing economy", "B": "foreign exchange facilities for importers and exporters", "C": "capital for development of specific sectors", "D": "capital for hire-purchase of machinery"}, "answer": "C", "explanation": "Development banks are financial institutions that provide long-term capital to boost economic development in specific sectors. They do not provide savings account facilities or foreign exchange facilities. Therefore, the correct answer is 'capital for development of specific sectors'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>30", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "In calculating the Gross National Product (GNP) by the income approach , all the following are included except", "images": [], "options": {"A": "wages and salaries", "B": "direct taxes paid by persons and companies", "C": "rents on houses", "D": "retirement benefits"}, "answer": "B", "explanation": "The income approach to calculating Gross National Product (GNP) includes all income earned by the factors of production, i.e., rent, wages, interest, and profit. Direct taxes paid by persons and companies are not included in the calculation of GNP. Therefore, the correct answer is 'direct taxes paid by persons and companies'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>31", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "Exchange control is a weapon used in regulating", "images": [], "options": {"A": "Internal trade", "B": "Stock exchange", "C": "Foreign trade", "D": "Barter trade"}, "answer": "C", "explanation": "Exchange control is a measure used by governments to regulate the inflow and outflow of foreign currency in the country. It is a tool used to control foreign exchange, not internal trade, stock exchange, or barter trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>32", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "The current and capital accounts in Nigeria's balance of payments contain all the following items except", "images": [], "options": {"A": "oil export", "B": "receipts for shipping services", "C": "cost of aviation", "D": "IMF Standard Drawing Right (SDR)"}, "answer": "C", "explanation": "The current and capital accounts in Nigeria's balance of payments contain items related to trade, services, income, and transfers. The cost of aviation is not directly related to these accounts. Oil export, receipts for shipping services, and IMF Standard Drawing Right (SDR) are all items that could be included in these accounts. Therefore, the correct answer is 'cost of aviation'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>33", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Who bears the greater burden of the indirect tax when the demand for a commodity is inelastic? The", "images": [], "options": {"A": "wholesaler", "B": "shareholders", "C": "retailer", "D": "consumers"}, "answer": "D", "explanation": "When the demand for a commodity is inelastic, it means that the quantity demanded does not change significantly when the price changes. Therefore, when an indirect tax is imposed on such a commodity, the consumers bear the greater burden of the tax because they continue to purchase the commodity despite the price increase due to the tax. The wholesaler, shareholders, and retailer do not bear the greater burden of the tax. Therefore, the correct answer is 'consumers'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>34", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "Economic growth specifically refers to the", "images": [], "options": {"A": "reliance on imported goods in preference to home-made goods", "B": "sustained increase in the output of goods and services per head", "C": "change in technical and institutional arrangement of the economy", "D": "continued increase in the depletion of a country's natural resources"}, "answer": "B", "explanation": "Economic growth refers to a sustained increase in the output of goods and services per head. It is a measure of the increase in the amount of goods and services produced by an economy over a period of time, adjusted for population (per capita). It does not refer to reliance on imported goods, changes in technical and institutional arrangements, or depletion of natural resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>35", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "The hourly wages of four employees of the Nigerian Port Authority are N2.52, N3.96, N9.20, and N3.75 respectively. The median hourly wage is", "images": [], "options": {"A": "N2.52", "B": "N3.28", "C": "N3.85", "D": "N3.96"}, "answer": "C", "explanation": "The median is the middle value in a list of numbers. To find the median, you need to list the numbers in numerical order, so you rearrange the wages as N2.52, N3.75, N3.96, and N9.20. If there is an even number of observations, as in this case, the median is the average of the two middle numbers, which is (N3.75 + N3.96) / 2 = N3.85.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1996>36", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "The petroleum industry in Nigeria is an example of a", "images": [], "options": {"A": "capital-intensive industry", "B": "service industry", "C": "labour-intensive industry", "D": "tertiary production industry"}, "answer": "A", "explanation": "The petroleum industry in Nigeria is an example of a capital-intensive industry. A capital-intensive industry is one that requires a significant amount of capital to start and maintain. These industries are characterized by high levels of automation and large production scales. The petroleum industry requires a large investment in machinery, technology, and infrastructure, making it capital-intensive. It is not primarily a service or labour-intensive industry, and while it is part of the tertiary sector, the term 'tertiary production industry' is not commonly used.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>37", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "The international cartel formed to stabilize the world oil market is the", "images": [], "options": {"A": "Economic Commissioner for Africa", "B": "International Monetary Fund", "C": "Organization of Petroleum Exporting Countries", "D": "Organization of Petroleum Importing Countries"}, "answer": "C", "explanation": "The Organization of Petroleum Exporting Countries (OPEC) is an international cartel that was established to coordinate the petroleum policies of its members and to provide member states with technical and economic aid. It was created to stabilize the world oil market, ensuring a steady income to producers and a regular supply of oil to consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1996>38", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "The United Nation Conference on Trade and Development (UNCTAD) is a forum designed specifically for discussing the", "images": [], "options": {"A": "political conflicts in the United Nation Security Council", "B": "educational needs of the developed countries", "C": "religious affairs in the Southern Africa", "D": "better terms of trade in the world"}, "answer": "D", "explanation": "The United Nations Conference on Trade and Development (UNCTAD) is a permanent intergovernmental body established by the United Nations General Assembly in 1964. Its main goal is to maximize the trade, investment and development opportunities of developing countries and assist them in their efforts to integrate into the world economy on an equitable basis. Therefore, it is a forum designed specifically for discussing better terms of trade in the world.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>39", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "The International Monetary Fund (IMF) is an international organization which", "images": [], "options": {"A": "gives annual grants to all developing countries", "B": "assist countries to solve their balance of payment problems", "C": "execute their development projects", "D": "help to promote regional economic groupings"}, "answer": "B", "explanation": "The International Monetary Fund (IMF) is an international organization that was initiated in 1944 at the Bretton Woods Conference and formally created in 1945 by 29 member countries. The IMF's primary purpose is to ensure the stability of the international monetary system—the system of exchange rates and international payments that enables countries (and their citizens) to transact with each other. It does this by assisting countries to solve their balance of payment problems.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1996>40", "subject": "Economics", "year": "1996", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "An economic system in which most means of production are owned and controlled by the State is known as a", "images": [], "options": {"A": "socialist economy", "B": "capitalist economy", "C": "mixed economy", "D": "political economy"}, "answer": "A", "explanation": "A socialist economy is an economic system in which the state owns and controls the major means of production. In a socialist economy, the state is the primary employer. Under this system, the state and not the market decides what to produce, how to produce, and distribution of resources. Therefore, the correct answer is a socialist economy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>1", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Economics is often described as a science because it", "images": [], "options": {"A": "adopts the use of laboratory experiments", "B": "involves accurate predictions of human beings", "C": "makes use of controlled experiment", "D": "use scientific methods to explain observed phenomena"}, "answer": "D", "explanation": "Economics is often described as a science because it uses scientific methods to explain observed phenomena. Economists observe the economic behavior of individuals and firms, and try to establish patterns and relationships. They then develop theories and models to explain these patterns, and use these models to predict future economic behavior. Therefore, the correct answer is that economics uses scientific methods to explain observed phenomena.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>2", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Scarcity in Economics means that", "images": [], "options": {"A": "the economy can scarcely produce anything", "B": "human wants are limitless", "C": "the economy has very few resources", "D": "resources are limited relative to wants"}, "answer": "D", "explanation": "Scarcity in economics refers to the basic economic problem, the gap between limited resources and theoretically limitless wants. This situation requires people to make decisions about how to allocate resources efficiently, in order to satisfy basic needs and as many additional wants as possible. Therefore, the correct answer is that resources are limited relative to wants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>3", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following has a derived demand?", "images": [], "options": {"A": "labour", "B": "butter", "C": "television set", "D": "breads"}, "answer": "A", "explanation": "Derived demand refers to the demand for a good or service that results from the demand for a different, or related, good or service. It is a demand for some physical or intangible thing where a market exists for both related goods and services in question. Labour is a good example of derived demand because businesses need labour to function and produce goods or services. The demand for labour is therefore derived from the demand for the goods or services that businesses produce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>4", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "In Economics production is complete when", "images": [], "options": {"A": "Goods are manufactured in the factories", "B": "commodities  are sold to the final consumer", "C": "goods and services are distributed by the government", "D": "producers fixed the price of goods produced"}, "answer": "B", "explanation": "In economics, production is considered complete when commodities are sold to the final consumer. This is because the production process includes not just the manufacturing of goods, but also their distribution and sale. Until a good is sold to the final consumer, it is still considered part of the production process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>5", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Goods are said to be in competitive demand when they", "images": [], "options": {"A": "Are substitutes", "B": "Are complementary to each other", "C": "Are jointly demanded", "D": "Have equal coefficient of elasticity"}, "answer": "A", "explanation": "Goods are said to be in competitive demand when they are substitutes for each other. This means that the goods can be used in place of one another. If the price of one good rises, consumers may switch to the substitute good, thereby increasing its demand. This is the concept of competitive demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>6", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "The formula for calculating price elasticity of demand coefficient is", "images": [], "options": {"A": "Percentage change in pricepercentage change in quantity demanded", "B": "Absolute decline in priceabsolute increase in quantity demanded", "C": "Percentage change in quantity demandedpercentage change in price", "D": "Absolute decline in quantity demandedabsolute increase in price"}, "answer": "C", "explanation": "The formula for calculating price elasticity of demand coefficient is the percentage change in quantity demanded divided by the percentage change in price. This measures how responsive the quantity demanded of a good is to a change in its price. The formula is often expressed as E = (ΔQ/Q) / (ΔP/P), where E is the elasticity, ΔQ is the change in quantity demanded, Q is the initial quantity demanded, ΔP is the change in price, and P is the initial price.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1997>7", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "When the price of a given product is reduced from N100 to N90, the quantity demanded increases from 50 to 60 units. From this we can conclude that the product's", "images": [], "options": {"A": "demand is elastic", "B": "demand is inelastic", "C": "demand is perfectly inelastic", "D": "supply is not elastic"}, "answer": "A", "explanation": "The price elasticity of demand can be calculated using the formula: % change in quantity demanded / % change in price. In this case, the % change in quantity demanded is (60-50)/50 = 20% and the % change in price is (90-100)/100 = -10%. The price elasticity of demand is therefore -20% / -10% = 2, which is greater than 1. This means the demand is elastic, as a 1% decrease in price leads to more than a 1% increase in quantity demanded.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1997>8", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "A shift in supply curve to the right will result in a", "images": [], "options": {"A": "fall in both the price and supply", "B": "fall in price but an increase in supply", "C": "rise in both price and supply", "D": "rise in price and fall in supply"}, "answer": "B", "explanation": "A shift in the supply curve to the right represents an increase in supply. This is usually caused by a decrease in the costs of production, technological advancements, or an increase in the number of sellers in the market. When supply increases, it leads to a surplus of goods in the market, which puts downward pressure on the price. Therefore, a shift in the supply curve to the right will result in a fall in price but an increase in supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>9", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "One of the disadvantages of the division of labour is that it", "images": [], "options": {"A": "saves time", "B": "makes work monotonous", "C": "encourages full utilization of capital", "D": "makes workers skilled at their work"}, "answer": "B", "explanation": "Division of labour refers to the breaking down of the production process into different stages enabling workers to focus on specific tasks. While it can increase efficiency, one of its main disadvantages is that it can make work monotonous because workers repeatedly perform the same task.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>10", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "The value of money is affected by the", "images": [], "options": {"A": "speculative motive", "B": "price level", "C": "transactionary motive", "D": "precautionary motive"}, "answer": "B", "explanation": "The value of money is primarily affected by the price level. When the price level rises (inflation), the value of money falls because each unit of money buys fewer goods and services. This is known as the purchasing power of money. The other options - speculative motive, transactionary motive, and precautionary motive - are related to the demand for money, not its value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>11", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "MONEY : INTRODUCTION", "question": "Which of the following is not a problem in the barter economy?", "images": [], "options": {"A": "multiple exchange rate", "B": "indivisibility of goods and services", "C": "double coincidence of wants", "D": "inflation"}, "answer": "D", "explanation": "Inflation is not a problem in a barter economy. Inflation is a general increase in prices and fall in the purchasing value of money. But in a barter economy, where goods and services are directly exchanged without the use of money, inflation does not occur. The other options - multiple exchange rate, indivisibility of goods and services, and double coincidence of wants - are indeed problems associated with a barter economy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>12", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "The optimum population of a country is reached when the", "images": [], "options": {"A": "production of goodsand services is less than optimum", "B": "output per head is at its highest with a given volume of resources", "C": "total production increases with a given volume of resources", "D": "national resources increases as population increases"}, "answer": "B", "explanation": "The optimum population of a country is reached when the output per head is at its highest with a given volume of resources. This is because the optimum population is the size of population that produces the maximum output per head, given the country's stock of resources. It is the population size at which the average standard of living or the per capita real income is maximized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>13", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION", "question": "When the death rate for old people and the infant mortality rate are high , with no migration , there will be in the population a higher number of", "images": [], "options": {"A": "younger people in the population", "B": "children in the population", "C": "old people in the population", "D": "women in the population"}, "answer": "A", "explanation": "When the death rate for old people and the infant mortality rate are high, with no migration, there will be a higher number of younger people in the population. This is because the high death rate for old people reduces the number of old people in the population, and the high infant mortality rate reduces the number of infants. Therefore, the majority of the population will be composed of younger people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>14", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INTRODUCTION", "question": "In the long-run, potential GNP is variable because.     I technological change takes place   II the quantity of labour and capital is not fixed   III. unemployment is not constant", "images": [], "options": {"A": "I only", "B": "II only", "C": "I and II only", "D": "I and III only"}, "answer": "C", "explanation": "In the long-run, potential GNP (Gross National Product) is variable because technological change takes place and the quantity of labour and capital is not fixed. Technological change can increase the productivity of labour and capital, thereby increasing potential GNP. Similarly, changes in the quantity of labour and capital can also affect potential GNP. Unemployment is not a factor in determining potential GNP because potential GNP is the level of output that an economy can produce at a high rate of resource use.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1997>15", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "For two commodities A and B, MA and MB are the respective marginal utilities while PA and PB are the respective prices. Marginal utilities of the commodities are maximized when", "images": [], "options": {"A": "MA/PA = MB/PB", "B": "MA/PA > MB/PB", "C": "MA/PA", "D": "PA/MA"}, "answer": "A", "explanation": "The law of equi-marginal utility states that a consumer will distribute his money income in such a way that the utility derived from the last rupee spent on each commodity is equal. This is achieved when the ratio of marginal utility to price is the same for all goods. Hence, the correct answer is MA/PA = MB/PB.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1997>16", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "If the price of product K declines , the demand curve for the complementary product J will", "images": [], "options": {"A": "remain unchanged", "B": "shift to the right", "C": "decrease", "D": "shift to the left"}, "answer": "B", "explanation": "Complementary goods are goods that are used together. If the price of one good (in this case, product K) decreases, the demand for its complementary good (product J) will increase because consumers can now afford to buy more of product K and, therefore, will need more of product J. This is represented by a shift to the right of the demand curve for product J.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>17", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "FINANCIAL INSTITUTION : INTRODUCTION", "question": "A stock exchange is a market that", "images": [], "options": {"A": "deals with the exchange of commodities", "B": "deals with purchase and sales of securities", "C": "exchanges stockfish for lady fish", "D": "exchanges treasury bills for bills of exchange"}, "answer": "B", "explanation": "A stock exchange is a market where stock buyers and sellers meet to trade stocks, bonds, and other securities. It does not deal with the exchange of commodities or the exchange of different types of fish. Treasury bills and bills of exchange are types of securities, but a stock exchange does not specifically exchange one for the other.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>18", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "The situation whereby government revenue is less than government expenditure is referred to as", "images": [], "options": {"A": "budget deficit", "B": "balanced budget", "C": "budget surplus", "D": "budget statement"}, "answer": "A", "explanation": "A budget deficit occurs when government expenditure exceeds government revenue. This is the opposite of a budget surplus, which occurs when government revenue exceeds expenditure. A balanced budget is when government revenue equals expenditure. A budget statement is a formal statement of the estimated government revenue and expenditure for the forthcoming fiscal year.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>19", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "Which of the following will not increase the population of a country?", "images": [], "options": {"A": "an increase in birth rate", "B": "a decrease in death rate", "C": "better medical services", "D": "Emigration"}, "answer": "D", "explanation": "Emigration refers to the act of leaving one's own country to reside in another. This would decrease the population of a country, not increase it. An increase in birth rate, a decrease in death rate, and better medical services would all potentially increase a country's population.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>20", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The actual output of an economy is the output", "images": [], "options": {"A": "which would exist if all resources were fully employed", "B": "produced by currently employed labour, capital and land", "C": "produced in the consumer goods sector", "D": "produced in the capital goods sector"}, "answer": "B", "explanation": "The actual output of an economy is the output produced by currently employed labour, capital and land. This is different from the potential output, which is the output that would exist if all resources were fully employed. The output produced in the consumer goods sector and the capital goods sector are parts of the actual output, but they do not define it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>21", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET", "question": "One of the instruments of protection of infants industries is the", "images": [], "options": {"A": "price control board", "B": "open market operation", "C": "tariff", "D": "GDP-deflator"}, "answer": "C", "explanation": "Infant industries are those industries which are newly born and are not able to compete with the established industries in the foreign country. One of the ways to protect these industries is by imposing tariffs. A tariff is a tax or duty to be paid on a particular class of imports or exports. It is used to restrict imports by increasing the price of goods and services purchased from another country, making them less attractive to consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>22", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Inflation caused by increase in demand can be curbed by", "images": [], "options": {"A": "exporting more goods and services", "B": "hoarding of goods", "C": "increasing the level of output", "D": "increasing the level of money supply"}, "answer": "C", "explanation": "Inflation caused by an increase in demand can be curbed by increasing the level of output. This is because inflation is a situation where the demand for goods and services exceeds their supply in the economy. By increasing the level of output, the supply of goods and services in the economy will increase, which will help to meet the increased demand and thus curb inflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>23", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Which of the following is a function of commercial banks?", "images": [], "options": {"A": "issuing currencies", "B": "accepts deposits", "C": "Are the bankers' bank", "D": "Determine the rate of interest"}, "answer": "B", "explanation": "One of the primary functions of commercial banks is to accept deposits. Commercial banks provide a safe place for individuals and businesses to deposit their money that can be withdrawn on demand. The bank then uses these deposits to lend money to other customers, earning a profit from the interest charged on these loans.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>24", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "Division of labour leads to", "images": [], "options": {"A": "employment of everybody", "B": "decrease in output", "C": "monotony of work", "D": "increase of time in workshops"}, "answer": "C", "explanation": "Division of labour refers to the breaking down of the production process into different stages enabling workers to focus on specific tasks. While it can lead to monotony of work due to the repetitive nature of tasks, it increases efficiency and productivity, not a decrease in output. It doesn't necessarily mean employment for everybody or increase of time in workshops.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>25", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "The largest employment sector in a typical West African country is", "images": [], "options": {"A": "construction", "B": "transportation", "C": "petroleum", "D": "agriculture"}, "answer": "D", "explanation": "In a typical West African country, the largest employment sector is agriculture. This is because a significant portion of the population is involved in farming, either for subsistence or commercial purposes. The other sectors like construction, transportation, and petroleum, although important, do not employ as many people as agriculture.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>26", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION", "question": "The indigenisation policy in Nigeria is aimed at", "images": [], "options": {"A": "nationalising foreign businesses", "B": "alternating foreign investors", "C": "commandeering foreign businesses in Nigeria", "D": "increasing equity participation and control by Nigerians"}, "answer": "D", "explanation": "The indigenisation policy in Nigeria is aimed at increasing equity participation and control by Nigerians. This means that the policy is designed to give Nigerians more control over businesses and industries in the country. It is not about nationalising foreign businesses, alternating foreign investors, or commandeering foreign businesses in Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>27", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The foregone alternative in Economics is simply the", "images": [], "options": {"A": "marginal cost", "B": "cost of foreign products", "C": "total cost", "D": "opportunity cost"}, "answer": "D", "explanation": "The foregone alternative in Economics is referred to as the 'opportunity cost'. Opportunity cost is a key concept in economics, and it has been described as expressing 'the basic relationship between scarcity and choice'. It is the cost of forgoing the next best alternative when making a decision.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>28", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "MONEY : TYPES OF MONEY", "question": "All the following are different forms of money except", "images": [], "options": {"A": "bank notes", "B": "demand deposits", "C": "coins", "D": "bank sellers"}, "answer": "D", "explanation": "Bank sellers are not a form of money. Money in economics is typically understood as a medium of exchange, a unit of accounting, and a store of value. Bank notes, demand deposits, and coins all fit these criteria, but bank sellers do not.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>29", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "The developments banks are essentially different from commercial banks because they", "images": [], "options": {"A": "medium and long term loans", "B": "open current accounts for their customers", "C": "discount bills of exchange", "D": "are lenders of last resort"}, "answer": "A", "explanation": "Development banks are different from commercial banks primarily because they provide medium and long term loans. Commercial banks typically provide short term loans. Development banks are usually government or international institution funded and are designed to provide capital for long-term projects that might be risky for commercial banks.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1997>30", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "The outward shift to the production possibility curve could be due to", "images": [], "options": {"A": "military conquest", "B": "increased money supply", "C": "inflation", "D": "economic growth"}, "answer": "D", "explanation": "The outward shift of the production possibility curve could be due to economic growth. The production possibility curve (PPC) is a graphical representation showing all possible combinations of two goods that can be produced with available resources and technology. An outward shift of the PPC represents an increase in an economy's capacity to produce goods and services, which is typically due to economic growth. Economic growth can be caused by factors such as an increase in physical capital, improvements in technology, or an increase in the labor force, all of which can increase the economy's production capacity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>31", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM", "question": "Which of the following is not true of a firm in equilibrium condition in perfect competition?", "images": [], "options": {"A": "MC is rising", "B": "MC curves cuts AC curves from below", "C": "MR>AR", "D": "MC = AC"}, "answer": "C", "explanation": "The statement 'MR>AR' is not true of a firm in equilibrium condition in perfect competition. In perfect competition, a firm is in equilibrium when it maximizes its profit, which occurs when marginal cost (MC) equals marginal revenue (MR). Additionally, in perfect competition, the price is given and is equal to average revenue (AR) and marginal revenue (MR). Therefore, it is not possible for MR to be greater than AR in perfect competition.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1997>32", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : INTRODUCTION", "question": "Hoarding in distributive trade leads to", "images": [], "options": {"A": "non-availabilty of commodities", "B": "production of inferior goods", "C": "increase in the supply of goods", "D": "artificial scarcity of goods"}, "answer": "D", "explanation": "Hoarding in distributive trade leads to artificial scarcity of goods. Hoarding is the practice of accumulating items in an effort to control the supply and manipulate the market price. When traders hoard goods, they create an artificial scarcity, which can lead to increased prices. This is not a result of a decrease in the actual supply of the goods, but rather a manipulation of the available supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>33", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "If an economy grows at an annual rate of 6% of which 4% is deemed to be due to improvement in the productivity of labour and capital combined, the remaining 2% is generally attributed to the", "images": [], "options": {"A": "amount of natural resources", "B": "improvement in banking services", "C": "size of the population", "D": "quality of human resources"}, "answer": "D", "explanation": "The remaining 2% is generally attributed to the quality of human resources. This is because economic growth is often attributed to three main factors: increase in physical capital, increase in labor, and improvement in technology or human capital. In this case, the increase in physical capital and labor has been accounted for, leaving the improvement in human capital or the quality of human resources.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1997>34", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "PUBLIC FINANCE : TAX", "question": "When the government imposes a unit tax on a commodity with perfectly inelastic demand, the", "images": [], "options": {"A": "tax is borne entirely by the seller", "B": "tax is shared equally between the buyer and the seller", "C": "seller bears 70% and the consumer bears 30% of the tax", "D": "tax is borne entirely by the consumer"}, "answer": "D", "explanation": "When the demand for a commodity is perfectly inelastic, it means that the quantity demanded does not change regardless of the price. Therefore, if the government imposes a unit tax on such a commodity, the tax will be borne entirely by the consumer because the seller can pass on the entire tax to the consumer without affecting the quantity demanded.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>35", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Free Trade means", "images": [], "options": {"A": "producers are free to determine their prices", "B": "market forces are allowed to determine prices", "C": "non-restriction of international trade", "D": "goods are to be sold free of charge"}, "answer": "C", "explanation": "Free Trade means non-restriction of international trade. It is a policy followed by some international markets in which countries' governments do not restrict imports from, or exports to, other countries. It allows for the unrestricted import and export of goods and services between two or more countries.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1997>36", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "In a public company , entrepreneural function are performed by the", "images": [], "options": {"A": "workers", "B": "shareholders", "C": "creditors", "D": "board of directors"}, "answer": "D", "explanation": "In a public company, the entrepreneurial functions are performed by the board of directors. The board of directors is a group of individuals that are elected as representatives of the shareholders to establish corporate management related policies and to make decisions on major company issues. They are responsible for the strategic management of the company, making key decisions, and overseeing the work of the executive management team.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>37", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "Terms of trade is the", "images": [], "options": {"A": "ratio of capital movement to export movements", "B": "ratio of import to short-term export", "C": "difference between export and import", "D": "ratio of index of export prices to index of import prices"}, "answer": "D", "explanation": "Terms of trade is the ratio of an index of a country's export prices to an index of its import prices. It is a measure of a country's trading potential in the international market. If a country's terms of trade fall, it has to export more goods to buy the same amount of imports. Conversely, if the terms of trade rise, it can buy more imports for any given level of exports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>38", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Tariff can be define as a compulsory levy on", "images": [], "options": {"A": "goods that are produced and consumed locally", "B": "foreign exchange earnings", "C": "imported but inferior goods", "D": "imports and exports"}, "answer": "D", "explanation": "A tariff is a tax or duty to be paid on a particular class of imports or exports. It is a compulsory levy on goods that are imported or exported. Tariffs are used to restrict trade, as they increase the price of imported goods and services, making them more expensive for consumers. It provides a price advantage to locally-produced goods and services over similar goods which are imported, and it raises revenues for the government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>39", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "INTERNATIONAL TRADE : INTRODUCTION", "question": "International trade is different from internal trade because of the", "images": [], "options": {"A": "manufactured goods involved", "B": "currency differentials", "C": "homogeneity of products", "D": "heterogeneity of products"}, "answer": "B", "explanation": "International trade is different from internal trade primarily because of currency differentials. While internal trade is conducted within the same country and thus uses the same currency, international trade involves trading between different countries, each with their own currency. This introduces exchange rates and currency risk into the equation, making international trade more complex.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1997>40", "subject": "Economics", "year": "1997", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Which of the following is not a visible item in international trade payments?", "images": [], "options": {"A": "payments for imported cars", "B": "receipts from cocoa exports", "C": "receipts from oil exports", "D": "payments to foreign shipping companies"}, "answer": "D", "explanation": "Payments to foreign shipping companies are not a visible item in international trade payments. Visible items in international trade payments refer to physical goods that are exported or imported, such as cars, cocoa, or oil. Payments to foreign shipping companies, on the other hand, are considered 'invisible' because they are payments for services, not physical goods.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1998>1", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The study of Economics enables the individuals to", "images": [], "options": {"A": "be misserly in the spending of his money", "B": "derive maximum satisfaction from the money he spends", "C": "determines the right market to visit", "D": "avoids purchase of luxurious items"}, "answer": "B", "explanation": "The study of Economics enables individuals to derive maximum satisfaction from the money they spend. This is because economics is the study of how individuals, businesses, and societies choose to use their scarce resources. By understanding economics, individuals can make informed decisions about how to allocate their resources (including money) to maximize their satisfaction or utility.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1998>2", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "One way of solving the problem of scarcity that faces the individuals is for", "images": [], "options": {"A": "the government to import goods massively so that the citizen can get all they want", "B": "them to work very hard so that they are able to buy all their wants", "C": "them to choose between alternative since they cannot meet all their wants", "D": "the government to study people's behaviour in order to know their wants"}, "answer": "C", "explanation": "Scarcity is a fundamental concept in economics that refers to the basic economic problem - the gap between limited resources and theoretically limitless wants. This situation requires people to make decisions about how to allocate resources efficiently, in order to satisfy basic needs and as many additional wants as possible. Any resource that is not infinite faces the problem of scarcity. Therefore, the best way to solve the problem of scarcity is for individuals to make choices between alternatives since they cannot meet all their wants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>3", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "Use the table below to answer the question     Score (X) 0 2 4 5 6 7 8Frequency (f)  711 6 7 7 4 3     In the distribution above the mode is", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": "A", "explanation": "From the distribution, The mode is 2, with the frequency of 11", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>4", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "Use the table below to answer the question     Score (X) 0 2 4 5 6 7 8Frequency (f)  711 6 7 7 4 3   The median is", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": "C", "explanation": "Add the frequency: 7 + 11 +6 +7 +7 + 4+3  = 45  Therefore,45+12  = 23rd position.    From the frequency, add up to determine where the 23rd position lies i.e 7 + 11 + 6  = 24  Therefore, 23 is in 24 which lies in 6 with the score of 4.  Median = 4", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>5", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "At what price will a trader be ready to sell 6 oranges using the equilibrium below.  p=12q+2wherepispriceandqisquantity?", "images": [], "options": {"A": "N3.00", "B": "N4.00", "C": "N5.00", "D": "N6.00"}, "answer": "C", "explanation": "The equilibrium equation given is p = 1/2q + 2. To find the price at which a trader will be ready to sell 6 oranges, we substitute q = 6 into the equation to get p = 1/2*6 + 2 = 5. Therefore, the trader will be ready to sell 6 oranges at N5.00.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1998>6", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "If the last Naira spent on each commodity by a consumer gave him equal satisfaction , it means the consumer has been able to", "images": [], "options": {"A": "cut costs", "B": "maximize costs", "C": "increase profits", "D": "maximize utility"}, "answer": "D", "explanation": "This concept is known as the law of equi-marginal utility. It states that a consumer will distribute his income among various goods and services in such a way that the utility derived from the last unit of money spent on each good is equal. This is done to maximize total utility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>7", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Which of the following will shift the demand curve for Milo to the right?", "images": [], "options": {"A": "an increase in consumer's income", "B": "a rise in the price of Milo", "C": "fall in the price of Milo", "D": "a fall in the quantity demanded of Milo"}, "answer": "A", "explanation": "An increase in consumer's income will shift the demand curve for a normal good like Milo to the right. This is because as income increases, consumers have more purchasing power and are able to buy more of the good, increasing demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>8", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "An exceptional demand is one in which the", "images": [], "options": {"A": "supplier sells all that he takes to the market", "B": "consumers do not buy from the market", "C": "quantity demanded falls as price falls", "D": "purchase of services and not products is considered"}, "answer": "C", "explanation": "An exceptional demand is a situation where the law of demand, which states that as the price of a good or service increases, consumer demand for the good or service will decrease, and vice versa, does not apply. In this case, the quantity demanded falls as price falls, which is contrary to the law of demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>9", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "The equilibrium price of mangoes is N1.00. If the price fall to 50k, there will be", "images": [], "options": {"A": "an excess demand", "B": "an excess supply", "C": "a surplus in the market", "D": "many sellers in the market"}, "answer": "A", "explanation": "The equilibrium price is the price at which the quantity demanded equals the quantity supplied. If the price falls below the equilibrium price, the quantity demanded will exceed the quantity supplied, leading to an excess demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>10", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "The introduction of division of labour in a firm will lead to?", "images": [], "options": {"A": "a fall in output", "B": "a decline in the efficiency of labour", "C": "an increase output", "D": "the separation of ownership from management"}, "answer": "C", "explanation": "The division of labour is a method of production where a process is broken down into a series of tasks, each performed by a different worker. This leads to increased efficiency and productivity, hence an increase in output.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>11", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "Total cost is the addition of", "images": [], "options": {"A": "real cost and money cost", "B": "price and taxes", "C": "fixed cost and variable cost", "D": "average cost and marginal cost"}, "answer": "C", "explanation": "Total cost in economics is the sum of all the costs incurred in producing a product or service. This includes both fixed costs, which do not change with the level of output, and variable costs, which do. Therefore, the correct answer is 'fixed cost and variable cost'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>12", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "External economies refer to the", "images": [], "options": {"A": "cost-saving advantage a firm enjoys by being close to other firm in the same industry", "B": "disadvantage to a firm that is close to other firms", "C": "economies of large scale production", "D": "economies of low scale production"}, "answer": "A", "explanation": "External economies refer to the cost-saving advantages that a firm can enjoy due to its location or proximity to other firms in the same industry. This can include benefits such as shared infrastructure, access to a larger pool of skilled workers, and the ability to share knowledge and innovation. Therefore, the correct answer is 'cost-saving advantage a firm enjoys when by being close to other firm in the same industry'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1998>13", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "To the economist, efficiency of resource use means", "images": [], "options": {"A": "the maximum use of resource to achieve minimum objectives", "B": "the reduction of cost for adequate output", "C": "relating value of input to that of output", "D": "maximizing output from a given amount of resource"}, "answer": "D", "explanation": "In economics, efficiency of resource use refers to the optimal use of resources to achieve the maximum possible output. This means using a given amount of resources to produce as much as possible. Therefore, the correct answer is 'maximizing output from a given amount of resource'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>14", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "The shape of the average cost (AC) shows that as production increases", "images": [], "options": {"A": "total cost decreases", "B": "average cost decreases and then increases", "C": "average cost increases", "D": "marginal cost steadily increase"}, "answer": "B", "explanation": "The shape of the average cost (AC) curve in economics is typically U-shaped. This is because as production increases, average cost decreases due to economies of scale. However, after a certain point, average cost starts to increase due to diseconomies of scale. Economies of scale refer to the cost advantage that a business obtains due to expansion. Diseconomies of scale occur when a company or business grows so large that the costs per unit increase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>15", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "One of the advantages of localization of industry is that firms", "images": [], "options": {"A": "make abnormal profits", "B": "are given tax holidays", "C": "are unified under one management", "D": "can have a large pool of skilled labours"}, "answer": "D", "explanation": "Localization of industry refers to the concentration of an industry in a particular area or region. One of the advantages of this is that firms can have a large pool of skilled labor. This is because workers in the area become specialized in the industry, leading to increased efficiency and productivity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>16", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Which of the following is not a type of industry?", "images": [], "options": {"A": "export", "B": "construction", "C": "Mining", "D": "Manufacturing"}, "answer": "A", "explanation": "In the context of economics, an industry refers to a sector of the economy that produces goods or services. The options construction, mining, and manufacturing are all types of industries. However, export is not a type of industry. It is a term used to describe the act of sending goods or services from one country to another.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1998>17", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "In a joint-stock company the shareholders are the", "images": [], "options": {"A": "owners", "B": "managers", "C": "chief executives", "D": "company advisers"}, "answer": "A", "explanation": "In a joint-stock company, the shareholders are indeed the owners. They own shares in the company's stock, which gives them a claim on part of the company's assets and earnings. The managers, chief executives, and company advisers are employees of the company who are hired by the shareholders to run the company on their behalf.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1998>18", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : INTRODUCTION", "question": "The distribution of goods by the price system is distorted when", "images": [], "options": {"A": "there is a high degree of competition among producers", "B": "producers and consumers operate freely", "C": "factors of production are mobile", "D": "there is price control measure in the system"}, "answer": "D", "explanation": "The distribution of goods by the price system is distorted when there is price control measure in the system. Price controls are governmental restrictions on the prices that can be charged for goods and services in a market. They can cause shortages or surpluses and disrupt the balance between supply and demand.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1998>19", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "An appropriate industrialization strategy in an under-populated country is", "images": [], "options": {"A": "import substitution", "B": "capital intensive", "C": "the contract method", "D": "the use of foreigners in the factories"}, "answer": "B", "explanation": "In an under-populated country, an appropriate industrialization strategy would be capital intensive. This means that the production process relies more heavily on machinery and equipment than on human labor. This would be appropriate in an under-populated country where labor might be scarce. Import substitution, the contract method, and the use of foreigners in the factories are not necessarily appropriate strategies for an under-populated country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1998>20", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION", "question": "The power of trade union may be weakened when there is", "images": [], "options": {"A": "optimum population", "B": "a weak government in power", "C": "over population", "D": "a civilian government in power"}, "answer": "C", "explanation": "The power of a trade union may be weakened when there is overpopulation. This is because when there is overpopulation, there is a surplus of labor. This surplus of labor means that employers have a larger pool of workers to choose from, which can weaken the bargaining power of trade unions. Trade unions are organizations that represent the interests of workers and their power is often linked to the scarcity of labor. When labor is abundant, as in the case of overpopulation, their power can be diminished.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>21", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "POPULATION : THEORIES OF POPULATION", "question": "Malthus' contention is that", "images": [], "options": {"A": "population increase in arithmetic progression while food production increased in geometric progresion", "B": "population increased in geometric progression while food production increased in arithmetic progression", "C": "population and food growth rate will, in future, be at par", "D": "nations have to get enough manpower to cultivate available land for food"}, "answer": "B", "explanation": "Thomas Malthus, an English economist, proposed that while food production increases at an arithmetic rate (1, 2, 3, 4, 5...), population increases at a geometric rate (1, 2, 4, 8, 16...). This is known as the Malthusian Theory of Population. According to this theory, if left unchecked, the population would exceed the availability of food resources.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1998>22", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "ECONOMIC INTEGRATION : PROBLEMS OF ECONOMIC INTEGRATION IN WEST AFRICA- ECOWAS", "question": "The problem of small markets in West Africa can be solved through", "images": [], "options": {"A": "separate planning among the West African countries", "B": "meaningful- co-operation among the West African countries", "C": "political stability in West Africa", "D": "imposing of high tariffs on West African exports"}, "answer": "B", "explanation": "The problem of small markets in West Africa can be solved through meaningful cooperation among the West African countries. This can be achieved through regional integration, which involves the unification of economic policies between different states through the partial or full abolition of tariff and non-tariff restrictions on trade taking place among them. This would lead to the creation of a larger market, promoting trade and economic growth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>23", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "An imperfect competitor is in equilibrium when", "images": [], "options": {"A": "Marginal cost (MC) is equal to Marginal Revenue (MR)", "B": "Marginal Revenue (MR) equal to Price (P)", "C": "Average Revenue(AR) is equal to Average Cost (AC)", "D": "Output (Q) is equal to Average Revenue (AR)"}, "answer": "A", "explanation": "An imperfect competitor is in equilibrium when the Marginal Cost (MC) is equal to Marginal Revenue (MR). This is because, in economics, a firm is said to be in equilibrium when it has no tendency to either increase or decrease its output. This state is achieved when MC=MR. This is because, at this point, the cost of producing an additional unit of output (MC) is exactly equal to the revenue gained from selling that additional unit (MR). Therefore, the firm has no incentive to change its level of output.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>24", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "INFLATION & DEFLATION : INTRODUCTION", "question": "Which of the following is used to measure inflation?", "images": [], "options": {"A": "Open market operation", "B": "Cash-deposit ratio", "C": "price index", "D": "Multiplier"}, "answer": "C", "explanation": "Inflation is measured using a price index. A price index is a measure that examines the weighted average of prices of a basket of consumer goods and services, such as transportation, food, and medical care. It is calculated by taking price changes for each item in the predetermined basket of goods and averaging them. Changes in the price index are used to assess price changes associated with the cost of living.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1998>25", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "If a government which owned a company N10,000 in 1916 paid the debt fully in 1985 when the value of money has depreciated by 20 Percent , such a government had", "images": [], "options": {"A": "lost", "B": "been placed at par with the company", "C": "gained", "D": "stabilizing the value of money"}, "answer": "C", "explanation": "The government has gained in this scenario. This is because the value of money has depreciated by 20 percent from 1916 to 1985. This means that the real value of the N10,000 debt the government owed in 1916 is less in 1985. Therefore, by paying off the debt in 1985, the government effectively paid less in real terms than it would have in 1916.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1998>26", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Banks create money by", "images": [], "options": {"A": "giving drafts to customers", "B": "printing more money", "C": "lending our deposits to borrowers", "D": "issuing cheques"}, "answer": "C", "explanation": "Banks create money through the process of lending out deposits to borrowers. This is known as the money multiplier effect. When a bank receives a deposit, it keeps a portion of it as reserves and lends out the rest. The money lent out is then deposited back into the bank, and the process repeats. This cycle of lending and depositing increases the money supply in the economy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1998>27", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "The West African house was established to", "images": [], "options": {"A": "finance development projects in Africa", "B": "enhance financial transaction among members countries", "C": "provide technical assistance to members countries", "D": "stabilize price in developing countries"}, "answer": "B", "explanation": "The West African Clearing House was established to enhance financial transactions among member countries. It was set up to facilitate trade and payments among West African countries, thereby promoting economic integration and cooperation in the region.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>28", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Which of the following is a factor affecting the size of national income?", "images": [], "options": {"A": "size of the active population", "B": "taste of the consumers", "C": "Number of registered trade unions", "D": "Credit-worthiness of the neighbouring countries"}, "answer": "A", "explanation": "The size of the active population is a factor affecting the size of national income. The active population refers to the number of people who are able and willing to work. The larger the active population, the higher the potential for production and hence the higher the national income. The other options do not directly affect the size of national income.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>29", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : INVESTMENT FUNCTION", "question": "The expenditure of a firm on goods and services for the expansion of its productive capacity is known as", "images": [], "options": {"A": "income", "B": "investment", "C": "savings", "D": "profits"}, "answer": "B", "explanation": "The expenditure of a firm on goods and services for the expansion of its productive capacity is known as investment. This is because investment in economics refers to the purchase of goods that are not consumed today but are used in the future to create wealth. In finance, investment is buying or creating an asset with the expectation of capital appreciation, dividends (profit), interest earnings, rents, or some combination of these returns.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>30", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : SAVINGS FUNCTION", "question": "An increase in marginal propensity to save will lead to", "images": [], "options": {"A": "an increase in marginal propensity to consume", "B": "a decrease in the level of consumption", "C": "an immediate decrease in the net national income", "D": "an increase in the level of consumption"}, "answer": "B", "explanation": "An increase in marginal propensity to save will lead to a decrease in the level of consumption. The marginal propensity to save (MPS) refers to the increase in household savings (economy-wide total savings) caused by an increase in national income. If the propensity to save increases, it means people are choosing to save more and therefore are spending less, leading to a decrease in the level of consumption.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>31", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION", "question": "Progressive system of taxation implies that the", "images": [], "options": {"A": "poor pay relatively more", "B": "tax rate falls as the tax base increases", "C": "tax rate increases as the tax base increases", "D": "average and marginal rate of tax will be the same"}, "answer": "C", "explanation": "Progressive system of taxation implies that the tax rate increases as the tax base increases. A progressive tax is a tax in which the tax rate increases as the taxable amount increases. The term 'progressive' refers to the way the tax rate progresses from low to high, with the result that a taxpayer's average tax rate is less than the person's marginal tax rate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>32", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Development plans in Nigeria have deviated from their targets due to", "images": [], "options": {"A": "lack of manpower", "B": "political instability", "C": "high population growth rate", "D": "brain drain in the country"}, "answer": "B", "explanation": "The main reason for the deviation of development plans in Nigeria from their targets is political instability. Political instability often leads to changes in policies and priorities, which can disrupt the implementation of development plans. Lack of manpower, high population growth rate, and brain drain can also affect development plans, but they are not the primary reasons for the deviation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1998>33", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "The level of economic development is low in Nigeria because", "images": [], "options": {"A": "planning has no practical relevance", "B": "of the pattern of the consumers' spending", "C": "the country is too large", "D": "of ineffective plan implementation"}, "answer": "D", "explanation": "The level of economic development is low in Nigeria mainly because of ineffective plan implementation. This could be due to a variety of factors, including corruption, lack of resources, and poor governance. While the other options may have some impact, they are not the main reasons for the low level of economic development.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1998>34", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INTRODUCTION", "question": "The stability of Nigerian economy depends mainly on the export price of", "images": [], "options": {"A": "groundnut", "B": "cotton", "C": "cocoa", "D": "mineral oil"}, "answer": "D", "explanation": "The stability of the Nigerian economy depends mainly on the export price of mineral oil. Nigeria is one of the largest oil producers in the world, and the economy is heavily dependent on oil exports. Changes in the price of oil can therefore have a significant impact on the economy. The other options, groundnut, cotton, and cocoa, are also exported by Nigeria, but they do not have as much impact on the economy as oil.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>35", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Which of the following countries is a major trading partner of Nigeria?", "images": [], "options": {"A": "Britain", "B": "Canada", "C": "Japan", "D": "China"}, "answer": "A", "explanation": "Britain is a major trading partner of Nigeria. The trade relationship between Nigeria and Britain dates back to the colonial era. Nigeria exports oil and gas, sesame seeds, cocoa, leather, etc., to Britain and imports machinery, chemicals, and manufactured goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>36", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "The instrument used in many countries to restrict imports includes", "images": [], "options": {"A": "high tariffs", "B": "price index", "C": "excise duties", "D": "bank rate"}, "answer": "A", "explanation": "High tariffs are often used by countries to restrict imports. A tariff is a tax imposed on imported goods and services. High tariffs make imported goods more expensive, thereby discouraging imports and protecting domestic industries from foreign competition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>37", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "One of the major objectives of the African Development Bank (ADB) is the mobilization of", "images": [], "options": {"A": "blacks in development countries to assist Africa", "B": "qualified manpower for member states", "C": "foreigners to assist africa", "D": "africans towards economic progress"}, "answer": "B", "explanation": "One of the major objectives of the African Development Bank (ADB) is the mobilization of qualified manpower for member states. The ADB aims to promote sustainable economic growth and reduce poverty in Africa by providing financial and technical assistance to projects that improve the economic and social outlook in the region.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1998>38", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Which of the following constitutes the largest exports of the developing countries to the developed ones?", "images": [], "options": {"A": "Raw materials", "B": "finished consumer goods", "C": "labour services", "D": "arms and ammunition"}, "answer": "A", "explanation": "Developing countries are typically rich in natural resources but lack the industrial base to process these resources. As a result, they often export raw materials to developed countries, which have the necessary industries to process them. This makes raw materials the largest export of developing countries to developed ones.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>39", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "The economic system in which the decision is about what to produce , how to produce and for whom to produce are made by private firms is called", "images": [], "options": {"A": "socialism", "B": "Welfarism", "C": "communism", "D": "capitalism"}, "answer": "D", "explanation": "In a capitalist economic system, private firms or individuals own and control the means of production. They make decisions about what to produce, how to produce it, and for whom to produce based on market forces of supply and demand. Therefore, the economic system in which decisions about what to produce, how to produce, and for whom to produce are made by private firms is called capitalism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1998>40", "subject": "Economics", "year": "1998", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "A major setback in any mixed economy is", "images": [], "options": {"A": "that is combined both the capitalist and socialist systems", "B": "the freedom of choice in the production and consumption of goods and services", "C": "that government intervenes to secure full utilization of resources", "D": "that the absence of profit motive in the public sector may reduce incentives for hard work"}, "answer": "D", "explanation": "A mixed economy combines elements of both capitalism and socialism. It allows for private enterprise and ownership, but also has government intervention to ensure social welfare and economic stability. One of the major setbacks in a mixed economy is that the absence of a profit motive in the public sector may reduce incentives for hard work. This is because, in the public sector, profits are not the primary goal, and therefore, employees may not have the same motivation to work hard and be efficient as they would in a private sector where profits and performance are closely linked.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1999>1", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "The money payment made to owners of land and labour are", "images": [], "options": {"A": "rent and wages", "B": "interest and profits", "C": "wages and interest", "D": "dividends and salary"}, "answer": "A", "explanation": "The money payment made to owners of land is rent and to labour is wages. This is a basic economic concept where each factor of production receives a type of payment for its use. Land receives rent, labor receives wages, capital receives interest, and entrepreneurship receives profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>2", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "The price elasticity of coefficient indicates", "images": [], "options": {"A": "how far business can reduce cost", "B": "the degree of competition", "C": "the extent to which curve shifts", "D": "consumer responsiveness to price changes"}, "answer": "D", "explanation": "The price elasticity of demand coefficient measures the responsiveness of the quantity demanded to a change in price. It is used to see how sensitive the demand for a good is to a price change. The higher the price elasticity, the more sensitive consumers are to price changes.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1999>3", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "Every society strive to pursue all the following economic objectives except", "images": [], "options": {"A": "increase production", "B": "price stability", "C": "an inequitable distribution of income", "D": "sustainable growth and income"}, "answer": "C", "explanation": "An inequitable distribution of income is not an economic objective that societies strive to pursue. In fact, most societies aim for a more equitable distribution of income to reduce income inequality. The other options, such as increasing production, price stability, and sustainable growth and income, are common economic objectives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>4", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following best describes capital as a factor of production?", "images": [], "options": {"A": "a natural resources found everywhere", "B": "a stock of physical assets used for production", "C": "the organization of human and material resources for production", "D": "resources used in training labour"}, "answer": "B", "explanation": "Capital as a factor of production refers to the stock of physical assets used in the production of goods and services. These assets include machinery, tools, buildings, and vehicles that are used to produce goods and services. This does not refer to natural resources, the organization of resources, or resources used in training labour.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>5", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES", "question": "The system whereby goods are exchanged for goods is known as", "images": [], "options": {"A": "stock exchange", "B": "barter system", "C": "banking", "D": "co-operative system"}, "answer": "B", "explanation": "The barter system is a method of exchange where goods or services are directly exchanged for other goods or services without using a medium of exchange, such as money. It is distinguishable from gift economies in many ways; one of them is that the reciprocal exchange is immediate and not delayed in time. It is usually bilateral, but may be multilateral, and usually exists parallel to monetary systems in most developed countries, though to a very limited extent. Barter usually replaces money as the method of exchange in times of monetary crisis, such as when the currency may be either unstable or simply unavailable for conducting commerce.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1999>6", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH", "question": "The graph of the function X = a + bY is", "images": [], "options": {"A": "linear", "B": "quadratic", "C": "cubical", "D": "exponential"}, "answer": "A", "explanation": "The function X = a + bY is a linear function. In mathematics, a linear function is a polynomial function of degree zero or one, or is the zero polynomial. In linear algebra and functional analysis, a linear function is a linear map. In calculus and related areas, a linear function is a polynomial of degree one or less. When the function is of only one variable, it is of the form f(x) = mx + c, where m and c are constants. The graph of such a function of one variable is a nonvertical line. m is the slope of the line, and c is the y-intercept.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1999>7", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "Productivity , per worker, is best measured by", "images": [], "options": {"A": "total output less number of workers", "B": "total output multiplied by number of workers", "C": "number of workers less total output", "D": "total output divided by number of workers"}, "answer": "D", "explanation": "Productivity per worker is calculated by dividing the total output by the number of workers. This gives the average amount of output that each worker produces. It is a measure of efficiency and effectiveness of the workforce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>8", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS", "question": "In determining cost economists considers", "images": [], "options": {"A": "implicit cost only", "B": "explicit cost only", "C": "implicit and explicit costs", "D": "explicit cost less implicit"}, "answer": "C", "explanation": "In economics, both implicit and explicit costs are considered when determining the total cost. Explicit costs are direct, out-of-pocket expenses for a firm, such as wages, rent, and materials. Implicit costs, on the other hand, represent the opportunity cost of using resources already owned by the firm. They are not direct cash outlays but are still costs because they represent foregone opportunities.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1999>9", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "The precautionary motive for holding money is to enable the holder to", "images": [], "options": {"A": "buy stocks when interest are high", "B": "overcome unforseen contingencies", "C": "buy goods and services on daily basis", "D": "buy fixed assets"}, "answer": "B", "explanation": "The precautionary motive for holding money refers to holding money to meet unforeseen contingencies or emergencies. This could include unexpected expenses or opportunities. It is one of the reasons people hold money, along with the transactional motive (for day-to-day expenses) and the speculative motive (to take advantage of future changes in interest rates or prices).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>10", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCTION FUNCTIONS AND LAWS OF RETURNS", "question": "In the long run, all factors inputs are", "images": [], "options": {"A": "variable", "B": "diminishing", "C": "constant", "D": "fixed"}, "answer": "A", "explanation": "In the long run, all factors of production are variable. This means that a firm can adjust all its inputs in response to market conditions. This is in contrast to the short run, where at least one factor of production is fixed. Therefore, the correct answer is 'variable'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1999>11", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "The benefits that result from concentrating similar firms in an area is referred to as", "images": [], "options": {"A": "external diseconomies of scales", "B": "internal diseconomies of scales", "C": "internal economies of scales", "D": "external economies of scales"}, "answer": "D", "explanation": "The benefits that result from concentrating similar firms in an area is referred to as external economies of scale. External economies of scale occur when an industry's scope of operations expands due to the concentration of similar firms in a particular area. This can lead to benefits such as shared resources and knowledge, increased market size, and improved infrastructure. Therefore, the correct answer is 'external economies of scales'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>12", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Per capita income in any West African country is measured by", "images": [], "options": {"A": "dividing the GNP by total population", "B": "adding the total savings to the GNP", "C": "multiplying the GNP by the total population", "D": "subtracting the GNP fron the GDP"}, "answer": "A", "explanation": "Per capita income in any country is measured by dividing the Gross National Product (GNP) by the total population. GNP is the total value of all final goods and services produced by the residents of a country in a given period. Dividing this by the total population gives the average income per person, or per capita income. Therefore, the correct answer is 'dividing the GNP by total population'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>13", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "A priority rating of aggregate individuals wants is called", "images": [], "options": {"A": "Scarcity", "B": "choice", "C": "A scale of preference", "D": "opportunity cost"}, "answer": "C", "explanation": "A priority rating of aggregate individuals wants is called a scale of preference. A scale of preference is an economic concept that refers to the listing of wants or needs by individuals in order of importance. It is used to understand consumer behavior and choice.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1999>14", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION", "question": "Profits can be calculated by", "images": [], "options": {"A": "subtracting total cost from total revenue", "B": "subtracting average revenue from total cost", "C": "dividing total revenue from total output", "D": "dividing marginal revenue by marginal cost"}, "answer": "A", "explanation": "Profits can be calculated by subtracting total cost from total revenue. This is because profit is the financial gain realized when the amount of revenue gained from a business activity exceeds the expenses, costs, and taxes needed to sustain the activity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>15", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "The marginal revenue curve of a monopolist is", "images": [], "options": {"A": "upward sloping from the right to left", "B": "downward sloping from left to right", "C": "parallel to the quantity axis", "D": "downward sloping from right to left"}, "answer": "B", "explanation": "The marginal revenue curve of a monopolist is downward sloping from left to right. This is because in a monopoly, as more units are sold, the price must be lowered to sell additional units, causing marginal revenue to decrease.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1999>16", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "When all factor inputs are doubled , the production possibly curve will", "images": [], "options": {"A": "shift from left to right and return to its orignal position", "B": "shift from left to right", "C": "remain in its former position", "D": "shift from right to left"}, "answer": "B", "explanation": "Doubling all factor inputs is a concept related to returns to scale in economics. If the production function has constant returns to scale, doubling all inputs will double the output, shifting the production possibility curve to the right. The production possibility curve will not return to its original position or remain in its former position, and it certainly won't shift from right to left.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>17", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "Income elasticity of demand is measurement of the responsiveness of", "images": [], "options": {"A": "price to change in income", "B": "quantity demanded to change in income", "C": "change in expenditure to change in income", "D": "change in expenditure to change in price of the commodity"}, "answer": "B", "explanation": "Income elasticity of demand measures the responsiveness of the quantity demanded for a good to a change in the income of the people demanding the good. It is calculated as the ratio of the % change in quantity demanded to the % change in income. So, it's the responsiveness of quantity demanded to change in income.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1999>18", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "The establishmenat of industries in rural areas will help to reduce", "images": [], "options": {"A": "urban-rural migration", "B": "urban-urban migration", "C": "rural-urban migration", "D": "rural-rural migration"}, "answer": "C", "explanation": "Establishing industries in rural areas creates job opportunities, which can help to reduce rural-urban migration. This is because one of the main reasons people migrate from rural to urban areas is to seek better employment opportunities. If these opportunities are available in rural areas, the rate of rural-urban migration would decrease.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>19", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Government imposes taxes mainly to", "images": [], "options": {"A": "punish the citizens", "B": "provide social amenities", "C": "donates to poorer countries", "D": "execute white elephant projects"}, "answer": "B", "explanation": "Government imposes taxes mainly to provide social amenities. Taxes are a primary source of revenue for the government. This revenue is used to fund various public services and infrastructure, including education, healthcare, public transportation, and other social amenities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1999>20", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET", "question": "In a perfect market price and quantity to be bought are determined by the", "images": [], "options": {"A": "consumers and retailers", "B": "producers and wholesalers", "C": "forces of demand and supply", "D": "interest of government and producers"}, "answer": "C", "explanation": "In a perfect market, price and quantity to be bought are determined by the forces of demand and supply. A perfect market, also known as a competitive market, is characterized by many buyers and sellers, free entry and exit, and perfect information. In such a market, no single buyer or seller has the power to influence the price. Instead, the price is determined by the overall forces of demand and supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>21", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "When price elasticity of supply is equal to 0.4, supply is said to be", "images": [], "options": {"A": "inelastic", "B": "elastic", "C": "unitary elastic", "D": "public utilities"}, "answer": "A", "explanation": "When price elasticity of supply is equal to 0.4, supply is said to be inelastic. Price elasticity of supply measures the responsiveness of the quantity supplied to a change in the price of a good. If the price elasticity of supply is less than 1, it means that the quantity supplied is not very responsive to price changes, and we say that supply is inelastic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>22", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "FINANCIAL INSTITUTION : INTRODUCTION", "question": "In the money market , money can only be borrowed for", "images": [], "options": {"A": "long term", "B": "short term", "C": "capital project", "D": "public utilities"}, "answer": "B", "explanation": "In the money market, money is typically borrowed for short-term needs. This is because the money market is a sector of the financial market in which financial instruments with high liquidity and short maturities are traded. The money market is used by participants as a means for borrowing and lending in the short term, with maturities that usually range from overnight to just under a year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>23", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Deflation can be controlled by increase in", "images": [], "options": {"A": "the bank rate", "B": "income tax", "C": "the price level", "D": "the budget deficit"}, "answer": "C", "explanation": "Deflation is a decrease in the general price level in the economy.  When deflation occurs, the overall price level across the economy falls. This means that the purchasing power of an individual's money actually increased. Therefore, to control deflation, the price level must increase.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1999>24", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "Mortgage banks give loan to investors on long term basis to", "images": [], "options": {"A": "finance agriculture", "B": "establish banks", "C": "acquire machinery", "D": "build houses"}, "answer": "D", "explanation": "Mortgage banks give loans to investors on a long-term basis primarily to build houses. A mortgage is a loan secured by real property through the use of a mortgage note which evidences the existence of the loan and the encumbrance of that realty through the granting of a mortgage which secures the loan.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>25", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "The situation where by a government spends more than its budgets for a fiscal year is known as", "images": [], "options": {"A": "extra budget", "B": "surplus budget", "C": "mid-year budget", "D": "deficit budget"}, "answer": "D", "explanation": "A deficit budget refers to a situation where a government's expenditure exceeds its revenue for a fiscal year. This is different from a surplus budget where the government's revenue exceeds its expenditure, and a mid-year budget which is a revised budget presented in the middle of the fiscal year. An extra budget is not a recognized term in economics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>26", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "In a socialist economy, factors of production are owned and controlled by the", "images": [], "options": {"A": "citizens", "B": "businessmen", "C": "government", "D": "foreigners"}, "answer": "C", "explanation": "In a socialist economy, the government owns and controls the factors of production. This is different from a capitalist economy where private individuals or businesses own and control the factors of production. Citizens and foreigners do not collectively own or control the factors of production in a socialist economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>27", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "MONEY : CHARACTERISTICS OF MONEY", "question": "One quality of money which makes it possible to be carried easily is its", "images": [], "options": {"A": "Scarcity", "B": "Durability", "C": "portability", "D": "acceptability"}, "answer": "C", "explanation": "Portability is a key quality of money which makes it easy to carry around. This is different from scarcity, which refers to the limited availability of resources, durability, which refers to the ability of money to withstand wear and tear, and acceptability, which refers to the widespread acceptance of money for transactions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1999>28", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "A form of tax in which the poor pay a higher rate than the rich is known as", "images": [], "options": {"A": "regressive tax", "B": "backward tax", "C": "oppressive tax", "D": "retrogressive tax"}, "answer": "A", "explanation": "A regressive tax is a tax that takes a larger percentage of income from low-income earners than from high-income earners. It is in opposition to a progressive tax, which takes a larger percentage from high-income earners. This is because a regressive tax is applied uniformly to all situations, regardless of the payer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>29", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "The reduction in the value of a country's currency in relation to the value of the currencies of other nations is known as", "images": [], "options": {"A": "deflation", "B": "devaluation", "C": "inflation", "D": "revaluation"}, "answer": "B", "explanation": "Devaluation is the deliberate downward adjustment to the value of a country's currency relative to another currency, group of currencies, or standard. Devaluation is a monetary policy tool of countries that have a fixed exchange rate or semi-fixed exchange rate. It is often used to correct a trade imbalance.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1999>30", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "The creation of utility can be referred to as", "images": [], "options": {"A": "value added", "B": "profit maximization", "C": "entrepreneurship", "D": "production"}, "answer": "D", "explanation": "In economics, production is the process of combining various material inputs and immaterial inputs (plans, know-how) in order to make something for consumption (output). It is the act of creating an output, a good or service which has value and contributes to the utility of individuals. So, the creation of utility can be referred to as production.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1999>31", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "Government revenue will increase if tax is imposed on a good whose demand is", "images": [], "options": {"A": "elastic", "B": "inelastic", "C": "unitary elastic", "D": "perfectly elastic"}, "answer": "B", "explanation": "Government revenue will increase if tax is imposed on a good whose demand is inelastic. Inelastic demand refers to a situation where the demand for a good does not significantly change with a change in price. Therefore, if a tax is imposed on such a good, consumers will continue to buy it despite the increase in price, leading to an increase in government revenue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>32", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "Occupational distribution of population is mainly influenced by", "images": [], "options": {"A": "economic factors", "B": "religious factors", "C": "geographical factors", "D": "social factors"}, "answer": "A", "explanation": "Occupational distribution of population is mainly influenced by economic factors. This is because the type of jobs and industries available in a particular area are largely determined by the economic activities prevalent in that area. For instance, areas with a lot of agricultural activities will have a higher population of farmers, while areas with a lot of industries will have a higher population of factory workers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>33", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Proportional tax refers to", "images": [], "options": {"A": "taxation of the rich only", "B": "equal tax rate for all people", "C": "unequal tax rate for all people", "D": "taxation of civil servants only"}, "answer": "B", "explanation": "Proportional tax refers to a tax system where all individuals or entities are taxed at the same rate, regardless of their income levels. This means that everyone pays the same proportion of their income in taxes, hence the term 'proportional tax'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>34", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Which of the following is not an item of capital expenditure?", "images": [], "options": {"A": "Construction of highways", "B": "Building of dams", "C": "payment of salaries and wages", "D": "building of a new university"}, "answer": "C", "explanation": "Capital expenditure refers to the funds used by a company to acquire, upgrade, and maintain physical assets such as property, buildings, an industrial plant, technology, or equipment. This can include everything from repairing a roof to building, from purchasing a piece of equipment to improving an industrial plant. So, options 1, 2 and 4 are capital expenditures. However, 'payment of salaries and wages' is not a capital expenditure but an operational expenditure. Operational expenditures are the costs for a company to do its everyday business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>35", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "The population which yields the highest level of income per head is known as", "images": [], "options": {"A": "over-population", "B": "under-population", "C": "extreme population", "D": "optimum population"}, "answer": "D", "explanation": "Optimum population has been defined as that size of population enabling per capita output of the maximum orders accompanied by the highest possible standards of living under a given set of economic and technological conditions. Therefore, optimum population lies between two extremes, i.e. over-population and under-population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>36", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "Price discrimination can only occur when there is", "images": [], "options": {"A": "perfect competition", "B": "imperfect competition", "C": "a merge", "D": "partnership"}, "answer": "B", "explanation": "Price discrimination refers to the strategy of selling the same product at different prices to different groups of consumers. This can only occur in markets characterized by imperfect competition. In a perfectly competitive market, all firms are price takers and cannot influence the price of the product or service. Therefore, they cannot engage in price discrimination. On the other hand, in an imperfectly competitive market, firms have some control over the price of the product or service, which allows them to engage in price discrimination.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>1999>37", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : INTRODUCTION", "question": "Commodity market can best be described as a market in which", "images": [], "options": {"A": "goods are sold", "B": "labour is sold and bought", "C": "short-term loans are obtained", "D": "quoted stocks are bought"}, "answer": "A", "explanation": "A commodity market is a physical or virtual marketplace for buying, selling, and trading raw or primary products. There are currently about 50 major commodity markets worldwide that facilitate investment trade in nearly 100 primary commodities. Commodities are split into two types: hard and soft commodities. Hard commodities are typically natural resources that must be mined or extracted (such as gold, rubber, and oil), whereas soft commodities are agricultural products or livestock (such as corn, wheat, coffee, sugar, soybeans, and pork). Therefore, a commodity market can best be described as a market in which goods are sold.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1999>38", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Provision of services is classified under", "images": [], "options": {"A": "primary production", "B": "secondary production", "C": "tertiary production", "D": "production possibilities"}, "answer": "C", "explanation": "Provision of services is classified under tertiary production. The tertiary sector of the economy, also known as the service sector or the service industry, is involved in the provision of services to businesses as well as final consumers. Such services include accounting, tradesmanship (like mechanic or plumber services), computer services, restaurants, tourism, etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1999>39", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "BUSINESS ORGANISATION : PARTNERSHIP", "question": "In ordinary partnership, the risks are", "images": [], "options": {"A": "borne by the workers", "B": "borne by the creditors", "C": "shared among the partners", "D": "undertaken by the active partners"}, "answer": "C", "explanation": "In an ordinary partnership, the risks are shared among the partners. A partnership is a type of business where two or more people share ownership, as well as the responsibility for managing the company and the income or losses the business generates. That income is paid to partners, who then claim it on their personal tax returns – because the partnership itself does not pay income taxes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>40", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Balance of trade is define as the relationship between", "images": [], "options": {"A": "invisible imports and exports", "B": "visible and invisible exports", "C": "imports and exports of services", "D": "visible exports and visible imports"}, "answer": "D", "explanation": "Balance of trade is defined as the relationship between visible exports and visible imports. The balance of trade is the difference between the value of a country's imports and its exports for a given period. The balance of trade is the largest component of a country's balance of payments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>41", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION", "question": "Which of the following combination of qualities ensures a good tax system?", "images": [], "options": {"A": "Deflationary, equity, certainty and convenience", "B": "Economy, convenience, certainty and equity", "C": "Economy, deflationary, inflationary and certainty", "D": "Economy, convenience, certainty and inflationary"}, "answer": "B", "explanation": "A good tax system is characterized by four main principles: economy, convenience, certainty, and equity. Economy means the cost of collecting the tax should be kept to a minimum. Convenience refers to the ease with which the tax can be paid. Certainty means that taxpayers should know in advance how much tax they have to pay, when and where to pay it. Equity means the tax burden should be distributed fairly among taxpayers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>42", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "The quantity demanded of a commodity is influenced only by changes", "images": [], "options": {"A": "tastes", "B": "weather", "C": "price of the commodity", "D": "Price of other commodities"}, "answer": "C", "explanation": "The quantity demanded of a commodity is primarily influenced by its price. This is based on the law of demand which states that, all else being equal, as the price of a product increases, quantity demanded falls; likewise, as the price of a product decreases, quantity demanded increases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1999>43", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Which of the following is an indirect tax", "images": [], "options": {"A": "income tax", "B": "company tax", "C": "profit tax", "D": "sales tax"}, "answer": "D", "explanation": "Sales tax is an example of an indirect tax. An indirect tax is a tax that is levied on goods or services rather than on individuals or companies. Other examples of indirect taxes include Value Added Tax (VAT), excise taxes, and customs duties. On the other hand, income tax, company tax, and profit tax are examples of direct taxes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1999>44", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "When a pen and a book is demanded together, the demand is said to be", "images": [], "options": {"A": "composite", "B": "competitive", "C": "joint", "D": "derived"}, "answer": "C", "explanation": "The demand for two or more goods used together is referred to as joint demand. In this case, a pen and a book are often used together, hence the demand is joint.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>45", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "The reward for capital is", "images": [], "options": {"A": "interest", "B": "rent", "C": "risk premium", "D": "premium"}, "answer": "A", "explanation": "In economics, the reward for capital (money invested in a business venture) is interest. This is the return that capital owners receive for the use of their capital.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1999>46", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Infant industries are industries that", "images": [], "options": {"A": "deals in the production of infant books", "B": "are in their earlier stage of production", "C": "produce dresses for infants", "D": "are well established"}, "answer": "B", "explanation": "Infant industries are those that are new or in their early stages of development. They are often characterized by small scale production and may lack the economies of scale enjoyed by established competitors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>47", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "The most common form of business enterprise in West Africa is the", "images": [], "options": {"A": "Sole proprietorship", "B": "Co-operative", "C": "Partnership", "D": "joint stock company"}, "answer": "A", "explanation": "The most common form of business enterprise in West Africa is the Sole proprietorship. This is because it is easy to set up, requires less capital, and the owner has full control of the business. The other options such as Co-operative, Partnership, and joint stock company are less common due to their complexity and higher capital requirements.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>1999>48", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "In order to boost agriculture, West African countries should pay more attention to", "images": [], "options": {"A": "shifting cultivation", "B": "animal husbandry", "C": "seed multiplication", "D": "mechanization"}, "answer": "D", "explanation": "In order to boost agriculture, West African countries should pay more attention to mechanization. Mechanization refers to the use of machines to perform agricultural tasks which were previously done manually. This can significantly increase productivity and efficiency in agriculture. The other options such as shifting cultivation, animal husbandry, and seed multiplication are important but they do not have the same level of impact as mechanization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>49", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Gross National Product (GNP) less depreciation is known as", "images": [], "options": {"A": "Gross Domestic Products", "B": "Gross National Income", "C": "Fixed National Income", "D": "Net National Income"}, "answer": "D", "explanation": "Gross National Product (GNP) less depreciation is known as Net National Income. Depreciation refers to the decrease in the value of physical capital (machinery, buildings etc.) over time due to wear and tear. When we subtract this depreciation from GNP, we get Net National Income which represents the total income of a nation's residents (including businesses, individuals, and government) after accounting for the loss of value in physical capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>1999>50", "subject": "Economics", "year": "1999", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "West African economy can best be described as", "images": [], "options": {"A": "agricultural", "B": "backward", "C": "developed", "D": "industrialized"}, "answer": "A", "explanation": "The West African economy is primarily agricultural. This is because a significant portion of the population is engaged in farming, either for subsistence or for commercial purposes. The other options do not accurately describe the West African economy. It is not 'backward' as it is growing and developing, albeit at a slower pace than some other regions. It is not 'developed' or 'industrialized' as these terms typically refer to economies with a high level of technological advancement and industrial production, which is not the case in West Africa.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>1", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Scarcity implies that?", "images": [], "options": {"A": "Goods cannot be produced efficiently", "B": "Human wants are unlimited", "C": "Goods and services are limited in supply", "D": "Commodities are evenly distributed within the economy"}, "answer": "C", "explanation": "Scarcity in economics refers to the basic economic problem, the gap between limited resources and theoretically limitless wants. This situation requires people to make decisions about how to allocate resources efficiently, in order to satisfy basic needs and as many additional wants as possible. The other options do not accurately define scarcity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>2", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "Economic problems arise mainly as a result of?", "images": [], "options": {"A": "Inaccurate statistical data in West Africa", "B": "Excessive wastage of available resources", "C": "Lack of foresight on the part of resource users", "D": "Limitations in availability of resources"}, "answer": "D", "explanation": "Economic problems mainly arise due to the limitations in the availability of resources. Resources are scarce, and the wants and needs of people are unlimited. This creates a situation where choices must be made about how to allocate and use resources efficiently. The other options are factors that can contribute to economic problems, but they are not the main cause.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>3", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "Basic extractive activities are classified as?", "images": [], "options": {"A": "Manufacturing production", "B": "Tertiary production", "C": "Secondary production", "D": "Primary production"}, "answer": "D", "explanation": "Basic extractive activities such as mining, fishing, and agriculture are classified as primary production. This is because they involve the extraction of raw materials directly from the earth, which is the first stage of the production process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>4", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT", "question": "The entire satisfaction that a consumer derives from a successive consumption of a particular commodity is known as?", "images": [], "options": {"A": "Marginal utility", "B": "Total utility", "C": "Average utility", "D": "Diminishing utility"}, "answer": "B", "explanation": "The entire satisfaction that a consumer derives from a successive consumption of a particular commodity is known as total utility. Total utility refers to the total satisfaction received from consuming a given total quantity of a good or service, while marginal utility refers to the satisfaction gained from consuming an additional unit of that item.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>5", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH", "question": "A collection of data which has not been processed is referred to as?", "images": [], "options": {"A": "Disjointed data", "B": "Raw data", "C": "Class intervals", "D": "Frequency"}, "answer": "B", "explanation": "A collection of data which has not been processed is referred to as raw data. Raw data is data that has not been processed for use. A distinction is sometimes made between data and information to the effect that information is the end product of data processing. Raw data that has undergone processing is sometimes referred to as cooked data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>6", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "Which of the following is a measure of central tendency?", "images": [], "options": {"A": "Percentage", "B": "Graph", "C": "Variance", "D": "Median"}, "answer": "D", "explanation": "A measure of central tendency is a single value that attempts to describe a set of data by identifying the central position within that set of data. The Median is a measure of central tendency. It is the middle score for a set of data that has been arranged in order of magnitude.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>7", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "The quantity supply of book per week is represented by the function:Qs= Qs= 70+1/2p. At the price of N8.00, the quantity supplied is?", "images": [], "options": {"A": "70", "B": "74", "C": "76", "D": "86"}, "answer": "B", "explanation": "The quantity supplied of a book per week is represented by the function Qs = 70 + 2p. If the price is N8.00, then the quantity supplied is Qs = 70 + 2*8 = 74.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2000>8", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "In production the formula total product divided by the number of men employed is used to calculate", "images": [], "options": {"A": "Total product", "B": "Average product", "C": "Marginal product", "D": "Fixed product"}, "answer": "B", "explanation": "In production, the formula total product divided by the number of men employed is used to calculate the Average Product. The Average Product is the output per unit of input, in this case, the output per worker.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>9", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "One of the internal economies of large scale production is?", "images": [], "options": {"A": "Administrative economies", "B": "Market economies", "C": "Regional economies", "D": "Horizontal economies"}, "answer": "A", "explanation": "Internal economies of scale are the cost-saving advantages that a firm can achieve by increasing output. Administrative economies are one of the internal economies of large scale production. They refer to the cost savings that result from managerial specialization. As a firm grows in size, it can afford to hire specialists to manage various aspects of the business, which can lead to increased efficiency and lower costs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>10", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "Dividing total variable cost by quantity of product gives?", "images": [], "options": {"A": "Total Cost (TC)", "B": "Total Fixed Cost (TFC)", "C": "Variable Cost (VC)", "D": "Average Variable Cost (AVC)"}, "answer": "D", "explanation": "Average Variable Cost (AVC) is calculated by dividing total variable cost (TVC) by the quantity of output. Variable costs are those that change with the level of output, such as raw materials and direct labor. By dividing the total variable cost by the quantity of output, we get the average variable cost per unit of output.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>11", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "Public enterprises are established mainly to?", "images": [], "options": {"A": "Provide basic amenities for the people", "B": "Make goods available in the market", "C": "Make profit for the government", "D": "Compete with foreigners in the industrial sector"}, "answer": "A", "explanation": "Public enterprises are primarily established to provide basic amenities for the people. These are government-owned and operated entities that are created to provide goods or services that are either not being supplied by the market or are being supplied inadequately. They are often responsible for providing essential public services like water, electricity, and transportation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>12", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "One important feature of sole proprietorship is that?", "images": [], "options": {"A": "It is a limited liability business", "B": "The business is owned by share holders", "C": "One person bears all the risk", "D": "It is a legal entity"}, "answer": "C", "explanation": "A sole proprietorship is a type of business entity that is owned and run by one individual. There is no legal distinction between the owner and the business. Therefore, the owner bears all the risks and enjoys all the profits of the business. This is different from a limited liability business where the business is a separate legal entity from its owners, and the owners' liability for the business's debts is limited. Hence, the correct answer is 'One person bears all the risk'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>13", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "The maximum amount of money a company is allowed to raise by issuing shares to the public is called?", "images": [], "options": {"A": "Paid-up capital", "B": "Fixed capital", "C": "Working capital", "D": "Authorised capital"}, "answer": "D", "explanation": "Authorised capital, also known as registered capital, is the maximum amount of share capital that a company is authorised by its constitutional documents to issue (allocate) to shareholders. This is different from paid-up capital, which is the amount of money a company has received from shareholders in exchange for shares, and working capital, which is the difference between a company's current assets and current liabilities. Hence, the correct answer is 'Authorised capital'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2000>14", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES", "question": "The Consumers Co-operative society is owned by?", "images": [], "options": {"A": "A management committee", "B": "Members of the society", "C": "Debenture holders", "D": "The government"}, "answer": "B", "explanation": "A Consumers Co-operative society is a type of co-operative that is owned and controlled by the people who use its products, supplies or services. The members of the society are the owners and they elect the management committee. Therefore, the correct answer is 'Members of the society'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>15", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE RETAILER", "question": "Which of the following is a function of the retailers?", "images": [], "options": {"A": "Provision of storage facilities", "B": "Financing manufacturers", "C": "Stocking variety of good", "D": "Advertisement of goods"}, "answer": "C", "explanation": "Retailers play a crucial role in the distribution of goods and services. One of their primary functions is to stock a variety of goods. This allows consumers to have a wide range of options to choose from. They do not typically provide storage facilities or finance manufacturers, and while they may advertise their own stores or sales, they do not generally advertise the goods themselves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>16", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "The supply of labour can be influenced by the?", "images": [], "options": {"A": "Size of the population", "B": "Stage of economic development", "C": "Size of the country", "D": "Extent of the market"}, "answer": "A", "explanation": "The supply of labour in a country is primarily influenced by the size of the population. A larger population means a larger labour force, assuming other factors such as age distribution and labour force participation rates are constant. The stage of economic development, size of the country, and extent of the market can indirectly influence labour supply, but they are not direct determinants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>17", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "Majority of West African labour force is engaged in?", "images": [], "options": {"A": "Industrial production", "B": "Agricultural production", "C": "Mining industry", "D": "Construction industry"}, "answer": "B", "explanation": "In West Africa, the majority of the labour force is engaged in agricultural production. This is due to the region's favorable climate and fertile soil, which make it suitable for farming. Industrial production, mining, and construction also employ significant numbers of people, but not as many as agriculture.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>18", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "POPULATION : INTRODUCTION", "question": "Census of population is usually conducted every?", "images": [], "options": {"A": "20 years", "B": "15 years", "C": "10 years", "D": "7 years"}, "answer": "C", "explanation": "A census is typically conducted every 10 years. This is done to keep up with changes in the population, such as births, deaths, and migration. The data collected during a census is used for a variety of purposes, including determining the number of seats each state has in the U.S. House of Representatives and distributing billions in federal funds.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>19", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "One economic implication of over population is that it", "images": [], "options": {"A": "Leads to low demand of goods", "B": "Reduces balance of payment difficulties", "C": "Leads to a fall in per capital income", "D": "Reduces pressure on the available social facilities"}, "answer": "C", "explanation": "Overpopulation can lead to a fall in per capita income. This is because when the population is too high, resources become scarce and the demand for goods and services increases. This can lead to inflation and a decrease in the standard of living, which in turn can lead to a decrease in per capita income.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2000>20", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "Hassan, an economic teacher in Lagos, resigned his appointment and took up another job as a banker. The concept here involves", "images": [], "options": {"A": "Occupation mobility of labour", "B": "Horizontal mobility of labour", "C": "Vertical mobility of labour", "D": "Geographical mobility of labour"}, "answer": "A", "explanation": "This refers to the movement of workers from one type of job to another, involving a change in their occupation or profession.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>21", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "Net migration is the difference between", "images": [], "options": {"A": "Population and census", "B": "Immigrants and Emigrants", "C": "Per capita income and population", "D": "Internal and external migration"}, "answer": "B", "explanation": "Net migration is the difference between the number of immigrants (people coming into an area) and the number of emigrants (people leaving the area). Therefore, the correct answer is 'Immigrants and Emigrants'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>22", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "Wages are, to some extent, determined by the?", "images": [], "options": {"A": "Marginal utility of labour", "B": "Average utility of labour", "C": "the forces of demand and supply of labour", "D": "Internal and external migration"}, "answer": "C", "explanation": "Wages are determined by the forces of demand and supply of labour. When the demand for labour is high and the supply is low, wages tend to increase. Conversely, when the supply of labour is high and the demand is low, wages tend to decrease.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>23", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND", "question": "The movement along the same demand curve is also known as", "images": [], "options": {"A": "Change in demand", "B": "Change in quantity demanded", "C": "Shift in demand", "D": "Market demand"}, "answer": "B", "explanation": "The movement along the same demand curve is known as a 'Change in quantity demanded'. This occurs when the price of a good changes, leading to a change in the quantity demanded, but the demand curve itself does not shift. A 'Change in demand' or a 'Shift in demand', on the other hand, occurs when the entire demand curve shifts due to factors other than price, such as changes in income, tastes, or the prices of other goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>24", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "An industry can best be described as", "images": [], "options": {"A": "A place where goods are processed", "B": "A place where different firms produce different goods", "C": "An aggregation of individual firms producing similar commodities", "D": "The concentration of various firms in the same locality"}, "answer": "C", "explanation": "An industry is best described as an aggregation of individual firms producing similar commodities. This is because an industry refers to a sector of an economy that is characterized by a distinct mode of production. It includes all firms that produce similar goods or services. The other options are incorrect because they do not accurately define what an industry is.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>25", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES", "question": "An association of workers in a particular industry,firm or line of job is called?", "images": [], "options": {"A": "Trade Union", "B": "Trade Association", "C": "Chamber of Commerce", "D": "Assembly of Workers"}, "answer": "A", "explanation": "An association of workers in a particular industry, firm or line of job is called a Trade Union. Trade unions are organizations formed by workers from related fields that work for the common interest of its members. They help in protecting the integrity, rights, and interests of the members. The other options do not accurately define this concept.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>26", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "Average fixed Cost (AVC) curve", "images": [], "options": {"A": "Is U-shaped", "B": "Rises from left to right", "C": "falls as output increases", "D": "Is horizontal to the X-axis"}, "answer": "C", "explanation": "The average fixed cost curve falls as output increases but cannot touch the x - axis or be equal to zero.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>27", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "The income elasticity of a normal good is?", "images": [], "options": {"A": "Positive", "B": "Negative", "C": "Zero", "D": "Fixed"}, "answer": "A", "explanation": "The income elasticity of a normal good is positive. This is because normal goods are those goods for which demand increases with an increase in income and decreases with a decrease in income. Therefore, the income elasticity of demand, which measures the responsiveness of demand to changes in income, is positive for normal goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>28", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "The demand for a commodity that serves two or more purposes is?", "images": [], "options": {"A": "Competitive demand", "B": "Complementary demand", "C": "Composite demand", "D": "Derived demand"}, "answer": "C", "explanation": "The demand for a commodity that serves two or more purposes is called composite demand. Composite demand refers to the demand for a good or resource that has multiple uses. For example, electricity can be used for lighting, heating, and powering appliances, so the demand for electricity is a composite demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>29", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "The charging of different prices to different groups of buyers for the same goods or services is called?", "images": [], "options": {"A": "Monopolistic competition", "B": "Price determination", "C": "Price discrimination", "D": "Monopoly"}, "answer": "C", "explanation": "The charging of different prices to different groups of buyers for the same goods or services is called price discrimination. Price discrimination occurs when a seller charges different prices to different buyers for the same product or service, not based on the cost of production, but on the buyer's willingness to pay. This is often seen in industries where the seller has some degree of market power.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2000>30", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "A tax on a commodity Y whose demand is perfectly inelastic will fall heavily on the?", "images": [], "options": {"A": "Consumers", "B": "Manufacturers", "C": "Wholesalers", "D": "Retailers"}, "answer": "A", "explanation": "When demand is perfectly inelastic, consumers will buy the same quantity regardless of price. Therefore, if a tax is imposed on a commodity with perfectly inelastic demand, the burden of the tax will fall heavily on the consumers because they will continue to buy the same quantity even if the price increases due to the tax.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2000>31", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "The feature of regressive taxation is that its rate", "images": [], "options": {"A": "Is higher when income is higher", "B": "Is equal tax for all categories of people", "C": "Remains constant when income increases", "D": "Reduces when income increases"}, "answer": "D", "explanation": "Regressive taxation is a tax system where the tax rate decreases as the taxable amount increases. This means that as income increases, the tax rate reduces. This is the opposite of progressive taxation, where the tax rate increases as the taxable amount increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>32", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Which of the following is an item of government recurrent expenditure?", "images": [], "options": {"A": "Road construction", "B": "Port facilities", "C": "Wages and salaries", "D": "Telecommunication projects"}, "answer": "C", "explanation": "Recurrent expenditure refers to payments made by the government regularly which are not capital but operational expenses. These include salaries, interest payments on debt, subsidies, etc. Therefore, 'Wages and salaries' is an item of government recurrent expenditure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>33", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Deficit budget means that government's", "images": [], "options": {"A": "Expenditure is equal to its revenue", "B": "Planned expenditure is more than estimated income", "C": "Planned income and expenditure targets cannot be achieved", "D": "Expenditure is less than estimated government revenue"}, "answer": "B", "explanation": "A deficit budget refers to a situation where the government's planned expenditure exceeds its estimated income. This usually happens when a government decides to spend more than it earns in order to stimulate economic growth or manage a crisis. The excess expenditure is usually financed through borrowing.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2000>34", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "MONEY : CHARACTERISTICS OF MONEY", "question": "The most unique quality of money is its?", "images": [], "options": {"A": "Relative scarcity", "B": "Divisibility", "C": "Durability", "D": "General acceptability"}, "answer": "D", "explanation": "The most unique quality of money is its general acceptability. This means that it is widely accepted as a medium of exchange for goods and services. While other qualities like divisibility, durability, and relative scarcity are important, they are not unique to money. Other commodities can also possess these qualities. However, the general acceptability of money sets it apart.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>35", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : SAVINGS FUNCTION", "question": "Abstention from consumption which enables capital to be produced is called?", "images": [], "options": {"A": "Savings", "B": "Production", "C": "Accumulation", "D": "Opportunity cost"}, "answer": "A", "explanation": "Abstention from consumption which enables capital to be produced is called savings. When individuals or entities refrain from consuming all their income and set aside a portion of it, they are essentially saving. These savings can then be used to produce capital, either by investing in businesses or by lending to others who will use it for productive purposes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>36", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET", "question": "Which of the following will occur when the market is unstable?", "images": [], "options": {"A": "Prices will fluctuate", "B": "Demand will remain static", "C": "Unemployment will surely fall", "D": "Prices will remain static"}, "answer": "A", "explanation": "When the market is unstable, prices will fluctuate. This is because instability in the market often leads to uncertainty about future prices, which can cause both buyers and sellers to change their behavior, leading to price fluctuations. The other options are not necessarily true in an unstable market.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2000>37", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "FINANCIAL INSTITUTION : STOCK EXCHANGE", "question": "Shares and stocks can be bought in the?", "images": [], "options": {"A": "Commodity market", "B": "Stock exchange", "C": "Money market", "D": "Capital market"}, "answer": "B", "explanation": "Shares and stocks can be bought in the Stock exchange. A stock exchange is a marketplace where securities, including stocks and shares, are bought and sold. The other options are types of markets, but they do not primarily deal with stocks and shares.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>38", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Inflation can best be checked by?", "images": [], "options": {"A": "Allowing supply to remain constant", "B": "Decreasing supply and increasing wages", "C": "Increasing supply and holding wages constant", "D": "Decreasing supply and wages"}, "answer": "C", "explanation": "Inflation can best be checked by increasing supply and holding wages constant. Inflation is a general increase in prices and fall in the purchasing value of money. By increasing the supply of goods and services, prices can be kept from rising too quickly. Holding wages constant can also help to prevent inflation from spiraling out of control, as wage increases can lead to increased demand, which can further drive up prices.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2000>39", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "Foreign exchange control in most West African countries is enforced by the?", "images": [], "options": {"A": "Development bank", "B": "Merchant banks", "C": "Ministry of economic planning", "D": "Central banks"}, "answer": "D", "explanation": "Foreign exchange control is typically enforced by the Central Banks. This is because Central Banks are responsible for implementing monetary policy, which includes managing the country's foreign exchange reserves and controlling the exchange rate. Therefore, they have the authority to enforce foreign exchange control.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>40", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "Commercial banks settle their inter-bank indebtedness through", "images": [], "options": {"A": "Merchants banks", "B": "Central bank", "C": "Development bank", "D": "Stock exchange"}, "answer": "B", "explanation": "Commercial banks settle their inter-bank indebtedness through the Central Bank. The Central Bank acts as a clearing house for the commercial banks. When banks owe each other money (inter-bank indebtedness), they don't transfer money directly between themselves. Instead, they use accounts at the Central Bank to settle their debts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>41", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "Which of the following banks grant credit facilities to individuals wishing to build houses?", "images": [], "options": {"A": "Central Bank of Nigeria", "B": "Nigerian industrial Development Bank", "C": "Agricultural Credit Bank", "D": "Federal Mortgage Bank"}, "answer": "D", "explanation": "The Federal Mortgage Bank grants credit facilities to individuals wishing to build houses. This is because the primary function of a mortgage bank is to provide long-term financing to purchasers of real estate, typically in the form of home mortgages. Therefore, the Federal Mortgage Bank is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>42", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "Unemployment that arises because of introduction of new machines and equipment in production is called?", "images": [], "options": {"A": "Cyclical", "B": "Structural", "C": "Seasonal", "D": "Disguised"}, "answer": "B", "explanation": "Unemployment that arises because of the introduction of new machines and equipment in production is called Structural unemployment. This type of unemployment occurs when there is a long-term shift in the economy that eliminates some jobs while creating others for which the unemployed are unqualified.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>43", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "Mono-product economies are those that produce?", "images": [], "options": {"A": "Only intermediate products", "B": "Petroleum products", "C": "Agricultural products", "D": "One main commodity"}, "answer": "D", "explanation": "Mono-product economies are those that produce one main commodity. These economies are heavily dependent on a single product for their revenue and economic growth. This can make them vulnerable to fluctuations in the price of that commodity on the global market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>44", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "The primary objective of the Nigerian Industrial Development Bank (NIDB) is the provision of provision of loans to?", "images": [], "options": {"A": "Farmers", "B": "Manufacturers", "C": "Estate agents", "D": "Transporters"}, "answer": "B", "explanation": "The primary objective of the Nigerian Industrial Development Bank (NIDB) is the provision of loans to manufacturers. The NIDB was established to provide long-term financing to the industrial sector of the Nigerian economy. Its main function is to provide credit facilities to eligible industrial enterprises in the country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>45", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "Small enterprises find it difficult to expand due to?", "images": [], "options": {"A": "Inadequate capital", "B": "Lack of skilled manpower", "C": "The big level of technology required for expansion", "D": "Their inability to provide after sales services"}, "answer": "A", "explanation": "Small enterprises often struggle to expand due to inadequate capital. Capital is the money or wealth needed to produce goods and services. In the case of small enterprises, they often lack the necessary funds to invest in new equipment, hire more staff, or increase production levels. This lack of capital can limit their ability to grow and expand their operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>46", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "The Organization of Petrol Exporting Countries (OPEC) is a", "images": [], "options": {"A": "Cartel", "B": "Duopoly", "C": "Monopoly", "D": "Monopsony"}, "answer": "A", "explanation": "The Organization of Petroleum Exporting Countries (OPEC) is a cartel. A cartel is a group of independent market participants who collude with each other in order to improve their profits and maintain control over the market. OPEC, for example, coordinates policies among member countries to control oil prices on the global market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2000>47", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "One major export crop in West Africa is?", "images": [], "options": {"A": "Rice", "B": "Maize", "C": "Palm kernel", "D": "Cocoa"}, "answer": "D", "explanation": "Cocoa is a major export crop in West Africa. Countries like Ivory Coast and Ghana are among the world's largest producers and exporters of cocoa. Cocoa is used in the production of chocolate and other food products.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2000>48", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Balance of Payments deficit implies that a country is?", "images": [], "options": {"A": "Importing more than she is exporting", "B": "Consuming less than she is producing", "C": "Living below her means", "D": "More productive than others"}, "answer": "A", "explanation": "A Balance of Payments deficit occurs when the total of a country's foreign payments exceeds its foreign receipts. This is typically due to the country importing more goods, services, and capital than it exports. Therefore, the correct answer is 'Importing more than she is exporting'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2000>49", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "West African countries have low level of economic development due to", "images": [], "options": {"A": "Under-population", "B": "Inadequate labour", "C": "Failure to plan", "D": "Ineffective plan implementation"}, "answer": "D", "explanation": "The low level of economic development in West African countries can be attributed to several factors, including poor governance, corruption, and lack of infrastructure. However, among the given options, 'Ineffective plan implementation' is the most accurate. This refers to the inability to effectively execute economic development plans, which can hinder economic growth.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2000>50", "subject": "Economics", "year": "2000", "type": "Objective", "topic": "ECONOMIC INTEGRATION : PROBLEMS OF ECONOMIC INTEGRATION IN WEST AFRICA- ECOWAS", "question": "Which of the following countries is not a member of the Economic Community of West African States (ECOWAS)?", "images": [], "options": {"A": "Ghana", "B": "The Gambia", "C": "Cameroun", "D": "Guinea Bissau"}, "answer": "C", "explanation": "The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. Among the options given, Cameroun is not a member of ECOWAS. It is part of the Central African region.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>1", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "Economic problems arise because", "images": [], "options": {"A": "Resources are scarce relative to wants", "B": "Man is insatiable", "C": "Money is scarce", "D": "Man engages in too many economic activities"}, "answer": "A", "explanation": "Economic problems arise because resources are scarce relative to wants. This is the fundamental problem of economics. Resources are limited while human wants are unlimited, hence the need to allocate resources efficiently.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>2", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "The economic system in which resources are privately owned is known as?", "images": [], "options": {"A": "Capitalism", "B": "Socialism", "C": "Communism", "D": "Unitarism"}, "answer": "A", "explanation": "The economic system in which resources are privately owned is known as Capitalism. In a capitalist economy, property and businesses are owned and controlled by individuals. The production and prices of goods and services are determined by the free market, meaning supply and demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>3", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS", "question": "Quasi-rent refers to?", "images": [], "options": {"A": "Payment made on acquisition of a firm's premises", "B": "Payment made for the procurement of tools and equipments", "C": "Returns on investment", "D": "Payment made on any factor of production that is temporarily fixed in supply"}, "answer": "D", "explanation": "Quasi-rent refers to the payment made on any factor of production that is temporarily fixed in supply. It is a short-run concept and refers to the earnings of the producer's fixed factors of production.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2001>4", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "The reward for entrepreneurship is?", "images": [], "options": {"A": "Rent", "B": "Wages", "C": "Interest", "D": "Profit"}, "answer": "D", "explanation": "The reward for entrepreneurship is profit. Entrepreneurs take on the risk of creating, organizing, and managing a business with the hope of making a profit. This profit serves as their reward for the risks they take.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>5", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "Which of the following is a function of an entrepreneur?", "images": [], "options": {"A": "Avoidance of risks", "B": "Decision making", "C": "Employment control", "D": "Organizing unions"}, "answer": "B", "explanation": "One of the main functions of an entrepreneur is decision making. Entrepreneurs make key decisions about the business, including what products or services to offer, how to market them, and how to manage the business's finances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>6", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION", "question": "The difference between the highest number and lowest number in a set of data is the?", "images": [], "options": {"A": "Range", "B": "Median", "C": "Variance", "D": "Mode"}, "answer": "A", "explanation": "The difference between the highest number and the lowest number in a set of data is known as the range. The range is a measure of dispersion, or how spread out the data is. It is calculated by subtracting the smallest value in the set from the largest value.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>7", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "In which of the following economic system is the consumer referred to as king?", "images": [], "options": {"A": "Capitalist economy", "B": "Socialist economy", "C": "Communist economy", "D": "Mixed economy"}, "answer": "A", "explanation": "In a capitalist economy, the consumer is referred to as king because the forces of demand and supply, which are determined by the consumer, dictate the production and pricing of goods and services. This is not the case in socialist, communist, or mixed economies where the government plays a significant role in economic decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>8", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION", "question": "The dispersal of people in a country is called?", "images": [], "options": {"A": "Mobility of people", "B": "Geographical distribution", "C": "Occupational distribution", "D": "State distribution"}, "answer": "B", "explanation": "The dispersal of people in a country is referred to as geographical distribution. It describes the spread of people across a country, including where they live and work. The other options, mobility of people, occupational distribution, and state distribution, do not accurately describe the dispersal of people in a country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>9", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "POPULATION : POPULATION DENSITY, AGEING POPULATION", "question": "In a country with ageing population, the total population", "images": [], "options": {"A": "Comprises young school leavers only", "B": "Comprises mainly women", "C": "Is increasing at a low rate", "D": "Has reached the optimal level"}, "answer": "C", "explanation": "In a country with an ageing population, the total population is increasing at a low rate. This is because an ageing population implies that the majority of the population is older, and therefore, the birth rate is likely lower than in a country with a younger population. The other options do not accurately describe the characteristics of a country with an ageing population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>10", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "Population growth can be controlled by all the following except", "images": [], "options": {"A": "Legalizing abortion", "B": "Incentives on immigration", "C": "Family planning", "D": "Limiting number of children per family"}, "answer": "B", "explanation": "Population growth can be controlled by legalizing abortion, family planning, and limiting the number of children per family. However, incentives on immigration do not control population growth. Instead, they can increase the population if more people are encouraged to move into the country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2001>11", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "Performance of one task in a process is known as?", "images": [], "options": {"A": "Specialization", "B": "Standardization", "C": "Division of labour", "D": "Segmentation"}, "answer": "C", "explanation": "The performance of one task in a process is known as division of labour. Division of labour is a production technique where a task is broken down into separate tasks, each performed by a different worker or group of workers. It is a method used to increase efficiency and productivity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>12", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM", "question": "Use the table below to answer the question  Units of Variable factorTotal Product125231340448555    The marginal product at the fourth variable factor is?", "images": [], "options": {"A": "12", "B": "9", "C": "8", "D": "6"}, "answer": "C", "explanation": "The marginal product is the change in total product resulting from a one-unit change in a particular input while holding other inputs constant. In this case, the total product at the third variable factor is 40 and at the fourth variable factor is 48. Therefore, the marginal product at the fourth variable factor is 48 - 40 = 8.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2001>13", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM", "question": "Use the table below to answer the question  Units of Variable factorTotal Product125231340448555  The difference between the highest and the least marginal product of the variable factor is?", "images": [], "options": {"A": "3", "B": "8", "C": "10", "D": "12"}, "answer": "A", "explanation": "MP at output 2,  31- 25                                        2-1                                     = 6  at output 3,   40 - 31                                   3  - 2                           =  9  at output 4,    48 - 40                                    4 - 3                               = 8  at output 5,   55 - 48                                    5 - 4                            = 7  The difference between the highest MP and the lowest MP = 9- 6                                                                                                         = 3", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2001>14", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM", "question": "Use the table below to answer the question  Units of Variable factorTotal Product125231340448555  The average product of the variable factor when four units are employed is?", "images": [], "options": {"A": "6", "B": "8", "C": "12", "D": "48"}, "answer": "C", "explanation": "AP =  TP                          Q  At output 4,   48                                   4                        = 12", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2001>15", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "The cost incurred by using both fixed and variable factors production is called?", "images": [], "options": {"A": "Marginal cost", "B": "Fixed cost", "C": "Total cost", "D": "Average cost"}, "answer": "C", "explanation": "The cost incurred by using both fixed and variable factors of production is called Total cost. Total cost is the sum of all costs incurred in the production process, including both fixed costs (costs that do not change with the level of output) and variable costs (costs that change with the level of output).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>16", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Consumers buy more of a commodity at a lower price than at a higher price because?", "images": [], "options": {"A": "Producers like to produce more", "B": "In any given situation, people like to buy more", "C": "Consumers like to show off", "D": "With the same amount of money they will be able to buy more"}, "answer": "D", "explanation": "The law of demand states that, if all other factors remain equal, the higher the price of a good, the less people will demand that good. In other words, the higher the price, the lower the quantity demanded. The amount of a good that buyers purchase at a higher price is less because as the price of a good goes up, so does the opportunity cost of buying that good. As a result, people will naturally avoid buying a product that will force them to forgo the consumption of something else they value more. Hence, with the same amount of money, they will be able to buy more at a lower price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>17", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "The demand for a commodity not directly for immediate consumption but for the production of another commodity is?", "images": [], "options": {"A": "Competitive demand", "B": "Derived demand", "C": "Composite demand", "D": "Joint demand"}, "answer": "B", "explanation": "Derived demand is a term in economics, where demand for one good or service happens as a result of demand for another. This may occur as the former is a component of production for the latter. In other words, if a good is not demanded for its own sake but because it helps in the production of another good, it is said to have a derived demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>18", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Which of the following is a luxury item?", "images": [], "options": {"A": "Petrol", "B": "Textbook", "C": "Pencil", "D": "Gold"}, "answer": "D", "explanation": "A luxury item is a good for which demand increases more than proportionally as income rises, so that expenditures on the good become a greater proportion of overall spending. Luxury goods are in contrast to necessity goods, where demand increases proportionally less than income. Gold is considered a luxury item because it is not a necessity and demand for it increases more than proportionally as income rises.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>19", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "If the quantity demanded of a particular commodity is represented by the function Qd=30-2p. What is the quantity demanded at a price of twelve Naira?", "images": [], "options": {"A": "6 units", "B": "8 units", "C": "10 units", "D": "12 units"}, "answer": "A", "explanation": "Qd=30-2p.  when p =12  Qd= 30 - 2(12)       =30 - 24          = 6", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>20", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "The responsiveness of demand to a change in income is the measurement of?", "images": [], "options": {"A": "Foreign exchange rate", "B": "Cross elasticity of demand", "C": "Income elasticity of demand", "D": "Price elasticity of demand"}, "answer": "C", "explanation": "The responsiveness of demand to a change in income is measured by the income elasticity of demand. This is a measure of how much the quantity demanded of a good responds to a change in consumers' income. It is calculated as the percentage change in quantity demanded divided by the percentage change in income.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>21", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "The upward sloping of the supply curve indicates that?", "images": [], "options": {"A": "More will be supplied as price rises", "B": "Less will be supplied as price rises", "C": "Supply is not a function of price", "D": "Supply is static and demand is dynamic"}, "answer": "A", "explanation": "The upward slope of the supply curve indicates that as the price of a good increases, the quantity of the good that producers are willing and able to supply also increases. This is because higher prices provide an incentive for producers to supply more.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>22", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "Monocultural agriculture means", "images": [], "options": {"A": "The cultivation of seasonal crops", "B": "The cultivation of one major crop", "C": "Plantation agriculture", "D": "Shifting cultivation"}, "answer": "B", "explanation": "Monocultural agriculture refers to the practice of cultivating a single crop over a wide area for many consecutive years. It is often practiced in areas where a particular crop is economically beneficial and can be grown in large quantities. Therefore, the correct answer is 'The cultivation of one major crop'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>23", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Industries are not sited in most rural areas of Nigeria because of", "images": [], "options": {"A": "inadequate basic infrastructure", "B": "They lack raw materials", "C": "There is no appropriate government policy", "D": "The climate is not conducive"}, "answer": "A", "explanation": "Industries are often not sited in most rural areas of Nigeria due to inadequate basic infrastructure. This includes lack of good roads, electricity, water supply, and other facilities that are necessary for the operation of industries. While other factors like raw materials, government policy, and climate can also influence the location of industries, the lack of basic infrastructure is often the most significant barrier.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>24", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Which of the following business units can issue shares?", "images": [], "options": {"A": "Sole trader", "B": "Public limited company", "C": "Central Bank", "D": "Supermarket"}, "answer": "B", "explanation": "A public limited company (PLC) is a type of business entity that is allowed to issue shares to the public. This is different from a sole trader, which is owned and run by one individual and cannot issue shares. The Central Bank is a government institution and does not issue shares, while a supermarket is a type of business that typically does not issue shares. Therefore, the correct answer is 'Public limited company'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>25", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "When the government initiates measures to make an organization in which it has substantial interest more profit-oriented such a business is described as being?", "images": [], "options": {"A": "Indigenized", "B": "Restructured", "C": "Privatized", "D": "Commercialized"}, "answer": "D", "explanation": "When the government initiates measures to make an organization in which it has substantial interest more profit-oriented, such a business is described as being Commercialized. Commercialization is the process of managing or running something principally for financial gain. It involves the transformation of a public sector organization into a business enterprise in the private sector.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>26", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "Which of the following is not a trade union in Nigeria?", "images": [], "options": {"A": "Nigerian Labour Congress", "B": "Academic Staff Union of Universities", "C": "Nigerian Economic Society", "D": "Nigerian Union of journalists"}, "answer": "C", "explanation": "The Nigerian Economic Society is not a trade union. It is a professional association of trained economists and other practitioners in related fields, established for the purpose of promoting the understanding of economics and its applications among its members and the general public.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>27", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "The monopolist power can be controlled  by the government through?", "images": [], "options": {"A": "Labour union", "B": "Price legislation", "C": "Import restriction", "D": "Export promotion"}, "answer": "B", "explanation": "The monopolist power can be controlled by the government through Price legislation. Price legislation refers to the laws and regulations set by the government to control the prices of goods and services in the market. This is done to prevent monopolies from exploiting consumers by charging high prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>28", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "MARKET STRUCTURE : PERFECT MARKET", "question": "Which of the following is not a condition for a perfect market?", "images": [], "options": {"A": "Homogenous commodity", "B": "Ignorance of consumers", "C": "Perfect information", "D": "Free entry and exit"}, "answer": "B", "explanation": "A perfect market, also known as a competitive market, has certain characteristics. These include homogeneous commodities, perfect information, and free entry and exit. The ignorance of consumers is not a condition for a perfect market. In fact, it's the opposite. In a perfect market, all participants are assumed to have perfect knowledge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>29", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "The reward for shareholdership of a company is?", "images": [], "options": {"A": "Wages", "B": "Interest", "C": "Dividends", "D": "Profit"}, "answer": "C", "explanation": "Shareholdership in a company is rewarded with dividends. Dividends are a portion of a company's earnings that is paid to its shareholders. Wages are paid to employees, interest is paid on borrowed money, and profit is the financial gain realized when revenue exceeds expenses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>30", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "In a public corporation, the risks of business are borne by the?", "images": [], "options": {"A": "Workers", "B": "Tax payers", "C": "Board members", "D": "Treasury"}, "answer": "B", "explanation": "In a public corporation, the risks of business are borne by the taxpayers. This is because public corporations are owned and operated by the government, and any losses they incur are ultimately borne by the taxpayers. Workers, board members, and the treasury do not bear the risks of business in a public corporation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>31", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "One of the function of money is?", "images": [], "options": {"A": "Double coincidence of want", "B": "Unit of account", "C": "Indivisibility", "D": "Making payments through banks only"}, "answer": "B", "explanation": "One of the primary functions of money is to serve as a unit of account. It provides a standardised measure of value, which facilitates the comparison of goods and services. This function eliminates the need for a double coincidence of wants that would be necessary in a barter system. Indivisibility and making payments through banks only are not functions of money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>32", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "Money is demanded for which of the following reasons?", "images": [], "options": {"A": "To meet unforeseen contigences", "B": "To solve the problem of inflation", "C": "It is easily divisible", "D": "It is portable"}, "answer": "A", "explanation": "Money is demanded for several reasons, one of which is to meet unforeseen contingencies. This is known as the precautionary motive for holding money. It refers to holding money to meet unexpected expenses or emergencies. Solving the problem of inflation, divisibility, and portability are characteristics of money, not reasons for its demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>33", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "The Quantity Theory of money states that a reduction in the quantity of money in circulation would bring about?", "images": [], "options": {"A": "A geometrical fall in prices", "B": "A proportionate fall in prices", "C": "A rise in prices", "D": "An unequal fall in prices"}, "answer": "B", "explanation": "The Quantity Theory of Money states that there is a direct relationship between the quantity of money in an economy and the level of prices of goods and services. Therefore, a reduction in the quantity of money in circulation would bring about a proportionate fall in prices. This theory assumes that the velocity of money and real output remain constant.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2001>34", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "MONEY : TYPES OF MONEY", "question": "Which of the following is the most liquid asset?", "images": [], "options": {"A": "Bank notes", "B": "Silver", "C": "Bank deposit", "D": "Cheques"}, "answer": "A", "explanation": "Liquidity refers to the ease with which an asset can be converted into cash without affecting its market price. Among the given options, bank notes are the most liquid asset because they are already in cash form and can be used immediately for transactions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>35", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "INFLATION & DEFLATION : INTRODUCTION", "question": "The situation in which there is a persistent fall in the general price level is referred to as?", "images": [], "options": {"A": "Devaluation", "B": "Depreciation", "C": "Deflation", "D": "Inflation"}, "answer": "C", "explanation": "Deflation is a decrease in the general price level of goods and services. It occurs when the inflation rate falls below 0%. In deflation, the purchasing power of currency rises over time. Hence, the situation in which there is a persistent fall in the general price level is referred to as deflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>36", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Commercial banks settle their daily interbank indebtedness through the?", "images": [], "options": {"A": "Money Market", "B": "Finance House", "C": "Acceptance House", "D": "Clearing House"}, "answer": "D", "explanation": "A clearing house is a financial institution formed to facilitate the exchange (i.e., clearance) of payments, securities, or derivatives transactions. The clearing house stands between two clearing firms (also known as member firms or clearing participants) and its purpose is to reduce the risk of one (or more) clearing firm failing to honor its trade settlement obligations. Hence, commercial banks settle their daily interbank indebtedness through the Clearing House.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>37", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "One disadvantage of inflation is that?", "images": [], "options": {"A": "Fixed income earners gain", "B": "Fixed income earners lose", "C": "Businessmen lose", "D": "Standard of living rises"}, "answer": "B", "explanation": "Inflation is the rate at which the general level of prices for goods and services is rising, and subsequently, purchasing power is falling. Central banks attempt to limit inflation, and avoid deflation, in order to keep the economy running smoothly. For fixed income earners, inflation is a disadvantage because the purchasing power of their income decreases as prices rise.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>38", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Short-term loans can be sourced from?", "images": [], "options": {"A": "The central bank", "B": "Development banks", "C": "Mortgage banks", "D": "Commercial banks"}, "answer": "D", "explanation": "Short-term loans are typically sourced from commercial banks. These are financial institutions that provide services, such as accepting deposits, giving business loans and auto loans, mortgage lending, and basic investment products like savings accounts and certificates of deposit. The traditional commercial bank is a brick and mortar institution with tellers, safe deposit boxes, vaults and ATMs. However, some commercial banks do not have any physical branches and require consumers to complete all transactions by phone or Internet. In exchange, they generally offer higher interest rates on investments and lower rates on loans.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>39", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "If there is an increase in wages and salaries without a corresponding increase in the supply of goods and services, the situation will lead to?", "images": [], "options": {"A": "Reduction in aggregate demand", "B": "Inflation", "C": "Depression", "D": "Budget surplus"}, "answer": "B", "explanation": "If there is an increase in wages and salaries without a corresponding increase in the supply of goods and services, the situation will lead to inflation. Inflation is a sustained increase in the general price level of goods and services in an economy over a period of time. When the general price level rises, with each unit of currency buys fewer goods and services; consequently, inflation reflects a reduction in the purchasing power per unit of money – a loss of real value in the medium of exchange and unit of measure within an economy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2001>40", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Public expenditure can be financed from all the following sources except", "images": [], "options": {"A": "Borrowing", "B": "Grants and aids", "C": "Royalties and rents", "D": "Mobilization fees"}, "answer": "D", "explanation": "Public expenditure refers to the spending by the government of a country. It can be financed through various sources such as borrowing, grants and aids, and royalties and rents. However, mobilization fees are not a source of financing public expenditure. Mobilization fees are typically charges in construction contracts for the movement of machinery and equipment from and to the place of a project. Therefore, they are not a source of public expenditure.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2001>41", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Which of the following is a direct tax?", "images": [], "options": {"A": "Import duty", "B": "Export duty", "C": "Capital gains tax", "D": "Sales tax"}, "answer": "C", "explanation": "A direct tax is a tax that the taxpayer pays directly to the government. These taxes cannot be shifted to any other person or group. The individual or organization upon whom the tax is levied is responsible for the fulfillment of the tax payment. Capital gains tax is a type of direct tax. It is a tax on the profit realized on the sale of a non-inventory asset. The most common capital gains are realized from the sale of stocks, bonds, precious metals, real estate, and property. On the other hand, import duty, export duty, and sales tax are indirect taxes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>42", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "Tax evasion means", "images": [], "options": {"A": "Postponing payment of tax", "B": "Tax payment according to ability to pay", "C": "Making false declaration of taxable income", "D": "Paying little amount of money as tax"}, "answer": "C", "explanation": "Tax evasion is an illegal practice where a person, organization or corporation intentionally avoids paying his true tax liability. Those caught evading taxes are generally subject to criminal charges and substantial penalties. Making false declaration of taxable income is a form of tax evasion. It involves misrepresenting one's taxable income or profits to the tax authorities to reduce their tax liability, and it includes dishonest tax reporting, such as declaring less income, profits or gains than the amounts actually earned, or overstating deductions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>43", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "A greater burden of tax on a product with a perfectly elastic of demand rest mainly on the?", "images": [], "options": {"A": "Producer", "B": "Teacher", "C": "Civil servant", "D": "Middlemen"}, "answer": "A", "explanation": "In economics, when the demand for a product is perfectly elastic, it means that consumers are very sensitive to changes in price. If the price increases, consumers will stop buying the product. Therefore, if a tax is imposed on such a product, the producer will bear the greater burden of the tax because they cannot pass the cost onto consumers by raising the price. If they do, they will lose all their customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>44", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "An ad valorem tax refers to a tax", "images": [], "options": {"A": "Imposed on export", "B": "On goods manufactured in the country", "C": "Based on the value of the commodity", "D": "Levied on income"}, "answer": "C", "explanation": "An ad valorem tax is a tax that is based on the value of a commodity or property. The term 'ad valorem' is Latin for 'according to value', which means that it is flexible and based on the assessed value of an asset, product or service.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>45", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : ONSHORE & OFFSHORE OF THE OIL SECTOR", "question": "Which of the following is associated with the development of the petroleum industry in Nigeria?", "images": [], "options": {"A": "Neglect of agriculture", "B": "Increase in population growth", "C": "Increase in the rate of unemployment", "D": "Decrease in the rate of inflation"}, "answer": "A", "explanation": "The development of the petroleum industry in Nigeria has led to the neglect of agriculture. Prior to the discovery of oil, agriculture was the mainstay of Nigeria's economy. However, with the oil boom, attention shifted from agriculture to petroleum, leading to the neglect of the agricultural sector.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>46", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Balance of payments deficit can be corrected by?", "images": [], "options": {"A": "Purchasing foreign assets", "B": "Accumulating foreign reserves", "C": "Export promotion measures", "D": "Import promotion measures"}, "answer": "C", "explanation": "A balance of payments deficit occurs when a country imports more goods, services, and capital than it exports. One way to correct this deficit is by promoting exports. Export promotion measures can include government programs, incentives, and policies that encourage firms in a country to export more. This can help to increase the amount of foreign currency coming into the country, thereby correcting the balance of payments deficit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2001>47", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "INTERNATIONAL TRADE : INTRODUCTION", "question": "The exchange of goods and services across different countries can be described as?", "images": [], "options": {"A": "Bi-lateral trade", "B": "Multilateral trade", "C": "National trade", "D": "Home trade"}, "answer": "B", "explanation": "The exchange of goods and services across different countries is described as multilateral trade. Multilateral trade involves more than two countries. Each country can trade with any other country in the multilateral trade agreement. This is different from bi-lateral trade which involves only two countries.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2001>48", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Which of the following is a major barrier to international trade?", "images": [], "options": {"A": "Religious differences amongst nations", "B": "Uneven distribution of population across the world", "C": "Educational imbalance between the developed and developing countries", "D": "Ideological differences amongst nations"}, "answer": "D", "explanation": "Major barriers to international trade include tariffs, quotas, and non-tariff barriers such as regulations and standards. These barriers can restrict the free flow of goods and services between countries.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2001>49", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "A country is economically rich if", "images": [], "options": {"A": "There is a lot of money in circulation relative to its population", "B": "It has a large volume of goods and services relative to its population", "C": "It has a large reserve of idle skilled manpower", "D": "There is a large amount of reserved mineral resources"}, "answer": "B", "explanation": "A country is considered economically rich if it has a large volume of goods and services relative to its population. This is because the wealth of a country is determined by its production capacity, not by the amount of money in circulation or the amount of reserved resources. The production capacity is reflected in the volume of goods and services it can produce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2001>50", "subject": "Economics", "year": "2001", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "The main role of the Organisation Petroleum Exporting Countries(OPEC)", "images": [], "options": {"A": "Fixing oil production levels", "B": "Ensuring optimum production of oil", "C": "Promoting,efficiency in the management of oil", "D": "Supplying oil at affordable rates"}, "answer": "A", "explanation": "The main role of the Organisation Petroleum Exporting Countries (OPEC) is to coordinate and unify the petroleum policies of its Member Countries and ensure the stabilization of oil markets in order to secure an efficient, economic and regular supply of petroleum to consumers, a steady income to producers and a fair return on capital for those investing in the petroleum industry. This is achieved by fixing oil production levels.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>1", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Economics is best described as the study of?", "images": [], "options": {"A": "Wealth of nations", "B": "How man consumes his products", "C": "How man provides for his everyday needs", "D": "The distribution of wealth"}, "answer": "C", "explanation": "Economics is best described as the study of how man provides for his everyday needs. This includes how resources are allocated, how goods and services are produced and distributed, and how individuals and societies make decisions about these processes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>2", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION", "question": "The pie-chart below represents the total population of a school of 1,200. The shaded area of 600 shows the population of the underaged pupils. What is the population of the matured students?", "images": ["Economics/imgs/2002/h2.png"], "options": {"A": "600", "B": "800", "C": "1,000", "D": "1,200"}, "answer": "C", "explanation": "Matured students = 360 - 60                               =  300                    = 60/360    x   1200  = 1000", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>3", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "The most frequently occurring value in a given data. The", "images": [], "options": {"A": "Mode", "B": "Median", "C": "Mean", "D": "Range"}, "answer": "A", "explanation": "The most frequently occurring value in a given data is referred to as the Mode. This is a statistical term that refers to the most frequently occurring number found in a set of numbers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>4", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "Subsistence production means that goods and services are?", "images": [], "options": {"A": "Produced for consumption only", "B": "Sold to others", "C": "Sold in the country", "D": "Produced for the market"}, "answer": "A", "explanation": "Subsistence production means that goods and services are produced for consumption only. This is a type of economy where the goods and services are produced by the people for their own use, rather than for trade or sale.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>5", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER", "question": "Warehouse facilities in the distribution and marketing of products are provided by?", "images": [], "options": {"A": "Manufacturers", "B": "Wholesalers", "C": "Retailers", "D": "Advertisers"}, "answer": "B", "explanation": "Warehouse facilities in the distribution and marketing of products are provided by Wholesalers. Wholesalers are intermediaries between manufacturers and retailers. They buy goods from manufacturers in bulk and store them in their warehouses, from where they are distributed to retailers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>6", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following is a reward to a factor of production?", "images": [], "options": {"A": "Interest", "B": "Donation", "C": "Gift", "D": "Subsidy"}, "answer": "A", "explanation": "In economics, the factors of production are the inputs used in the production of goods or services in order to make an economic profit. These include land, labor, capital, and entrepreneurship. Each factor is compensated for its use in the production process: land is paid rent, labor is paid wages, capital is paid interest, and entrepreneurship is paid profit. Therefore, 'Interest' is a reward to a factor of production, specifically capital.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>7", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Land is a factor of production because it,", "images": [], "options": {"A": "Is a free gift of nature", "B": "Contains valuable mineral resources", "C": "Assists in the creation of utility", "D": "Is owned by individual and government"}, "answer": "C", "explanation": "In economics, land is considered a factor of production because it assists in the creation of utility. Utility in economics refers to the total satisfaction received from consuming a good or service. Land, in its original state, provides the space and resources necessary for the production of goods and services, thereby assisting in the creation of utility.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>8", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "One of the advantages of large scale production is that", "images": [], "options": {"A": "There is a rise in the cost of administration", "B": "Consumers sacrifice their individual tastes", "C": "The firm can use labour-saving machinery", "D": "The demand for a firm's products becomes localized"}, "answer": "C", "explanation": "Large scale production refers to the production of a large volume of a product. One of the advantages of large scale production is that the firm can use labour-saving machinery. This is because as the scale of production increases, it becomes economically viable to invest in more efficient, automated machinery, which can lead to significant cost savings in the long run. This is not possible in small scale production due to the high initial investment required.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>9", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "Which of the following is an advantage of division of labour?", "images": [], "options": {"A": "Production of specialised goods", "B": "Employment of experts", "C": "Monotony of work", "D": "Greater use of machinery"}, "answer": "A", "explanation": "Division of labour allows workers to focus on a specific part of the production process where they can develop their skills and increase efficiency, leading to the production of specialised goods. This is because each worker becomes an expert in their specific task and therefore can produce goods with a higher level of skill and precision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>10", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "Despite the benefits large firms enjoy it could be limited by the", "images": [], "options": {"A": "Desire to make maximum profits", "B": "Introduction of efficient transport system", "C": "Growth of specialization", "D": "Extent of the market"}, "answer": "D", "explanation": "The extent of the market can limit the benefits large firms enjoy. This is because the size of the market determines the potential sales of a firm. If the market is small, even a large firm may not be able to sell all its products, limiting its benefits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>11", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Localisation of industry refers to the", "images": [], "options": {"A": "Concentration of the firms of an industry in a particular area", "B": "Siting of industries in rural areas", "C": "Even spread of industries", "D": "Government policy of influencing the location of industries"}, "answer": "A", "explanation": "Localisation of industry refers to the concentration of firms of an industry in a particular area. This is often due to factors such as availability of raw materials, skilled labour, infrastructure, and favourable government policies that attract firms to a particular location.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>12", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Economics speak about 'opportunity cost' when a consumer", "images": [], "options": {"A": "has the chance to minimize costs", "B": "has to forgo one thing in order to have another", "C": "can equate his fixed costs with his variable cost", "D": "is able to save part of his income"}, "answer": "B", "explanation": "Opportunity cost in economics refers to the potential benefit an individual, investor, or business misses out on when choosing one alternative over another. It is the value of the next best alternative forgone. Therefore, when a consumer has to forgo one thing in order to have another, it is referred to as opportunity cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>13", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS", "question": "The costs which a firm will incur whether it is in production or not, is referred to as", "images": [], "options": {"A": "average cost", "B": "variable cost", "C": "opportunity cost", "D": "fixed cost"}, "answer": "D", "explanation": "Fixed costs are costs that do not change with the level of output. They are incurred even when the firm is not producing anything. Examples include rent, salaries, and insurance. These costs are incurred whether the firm is in production or not.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>14", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM", "question": "Which of the curve in the diagram below represents the firm's marginal cost (MC)?", "images": ["Economics/imgs/2002/h4.png"], "options": {"A": "Curve P", "B": "Curve N", "C": "Curve M", "D": "Curve L"}, "answer": "D", "explanation": "The curve L represent the marginal cost of a firm. The marginal cost determines the extra cost of the firm.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2002>15", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "The location of timber and plywood industries in West Africa is mainly influence by the availability of", "images": [], "options": {"A": "Transport", "B": "Water", "C": "Raw materials", "D": "Labour supply"}, "answer": "C", "explanation": "The location of industries is often influenced by the availability of raw materials. This is because the proximity to raw materials reduces transportation costs and ensures a steady supply of the materials needed for production. Therefore, the location of timber and plywood industries in West Africa is mainly influenced by the availability of raw materials.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>16", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "The main objective of setting up private businesses is to", "images": [], "options": {"A": "protect the interest of government", "B": "maximize profits", "C": "provide infrastructure", "D": "promote exports"}, "answer": "B", "explanation": "The main objective of setting up private businesses is to maximize profits. This is because the primary goal of any business is to generate a return on investment for its owners. The other options do not accurately reflect the main objective of private businesses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>17", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "Small firms are important for the development of a country because", "images": [], "options": {"A": "the prices of their products are usually high", "B": "they render personalized services to the consumers", "C": "they usually produce goods for the elite", "D": "they do not normally provide after sales services"}, "answer": "B", "explanation": "Small firms are important for the development of a country because they render personalized services to the consumers. Small firms are often more flexible and can tailor their services to meet the specific needs of their customers. This can lead to higher customer satisfaction and loyalty, which can contribute to economic development.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>18", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "A limited liability company is owned by the", "images": [], "options": {"A": "president of the country", "B": "workers", "C": "general manager", "D": "shareholders"}, "answer": "D", "explanation": "A limited liability company is owned by the shareholders. Shareholders are the individuals or entities that own shares in a company. The number of shares a shareholder owns determines their ownership stake in the company. The other options do not accurately reflect the ownership structure of a limited liability company.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>19", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "The National Electric Power Authority (NEPA) of Nigeria is a", "images": [], "options": {"A": "public limited company", "B": "private limited company", "C": "private authority", "D": "public corporation"}, "answer": "D", "explanation": "The National Electric Power Authority (NEPA) of Nigeria is a public corporation. A public corporation is a company that is owned by the government, which operates in the commercial sector. NEPA, now known as the Power Holding Company of Nigeria (PHCN), is owned and operated by the Nigerian government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>20", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "When elasticity is zero, the demand curve is", "images": [], "options": {"A": "perfectly elastic", "B": "perfectly inelastic", "C": "concave", "D": "downward sloping"}, "answer": "B", "explanation": "When elasticity is zero, the demand curve is perfectly inelastic. Elasticity measures the responsiveness of demand or supply to changes in price. If the elasticity is zero, it means that the quantity demanded does not respond at all to changes in price, hence the demand is perfectly inelastic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>21", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "What type of price elasticity of demand is the diagram below representing?", "images": ["Economics/imgs/2002/h3.png"], "options": {"A": "perfectly inelastic demand", "B": "perfectly elastic demand", "C": "fairly elastic demand", "D": "composite demand"}, "answer": "A", "explanation": "perfectly inelastic demand is also known zero demand curve which is parallel to axis of y as shown in the diagram above.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>22", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "An increase in the demand for butter reduces the demand for margarine;this type of demand is called", "images": [], "options": {"A": "competitive demand", "B": "elastic demand", "C": "derived demand", "D": "composite demand"}, "answer": "A", "explanation": "An increase in the demand for butter reduces the demand for margarine; this type of demand is called competitive demand. Competitive demand refers to goods that can be used in place of each other (substitutes). In this case, butter and margarine are substitutes, so an increase in the demand for one leads to a decrease in the demand for the other.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>23", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "A commodity is said to have derived demand when it", "images": [], "options": {"A": "has a joint demand with another commodity", "B": "is demanded by the rich only", "C": "is demanded for immediate consumption", "D": "is demanded because what it can produce"}, "answer": "D", "explanation": "Derived demand refers to the demand for goods and services not for their own sake, but for their use in the production of other goods and services. Hence, a commodity is said to have derived demand when it is demanded because of what it can produce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>24", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "Which of the following statements about population is correct?", "images": [], "options": {"A": "Optimum population whenever achieved does not change", "B": "Under-population implies that available resources are not used to full capacity", "C": "Over-population leads to a higher per capita output", "D": "Optimum population leads to overcrowding of cities"}, "answer": "B", "explanation": "Under-population implies that the population of a country is too small to fully utilize its resources, leading to lower productivity and economic output. Therefore, under-population implies that available resources are not used to full capacity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>25", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "POPULATION : THEORIES OF POPULATION", "question": "Malthus population theory stated that", "images": [], "options": {"A": "High death rate may lead to low productivity", "B": "Population may outgrow the means of subsistence", "C": "People will always decide to have children", "D": "Migration may leave some parts of the world barren"}, "answer": "B", "explanation": "Malthus' population theory, also known as the Malthusian Theory of Population, posits that population tends to grow at a faster rate than the means of subsistence (food, water, etc.), leading to overpopulation. Therefore, the statement that 'population may outgrow the means of subsistence' correctly summarizes Malthus' theory.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2002>26", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "One of the criticisms of population increase is that it results in", "images": [], "options": {"A": "Rise in people's standard of living", "B": "low level of illiteracy", "C": "low level of taxation", "D": "increase in government expenditure"}, "answer": "D", "explanation": "Population increase often results in an increase in government expenditure. This is because as the population increases, the government needs to spend more on public goods and services such as healthcare, education, infrastructure, etc. to cater to the increased population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>27", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "Which of the following is not likely to be an effect of a growing population?", "images": [], "options": {"A": "Rise in demand", "B": "Unemployment", "C": "Fall in standard of living", "D": "High per capita income"}, "answer": "D", "explanation": "A growing population is not likely to result in a high per capita income. Per capita income is the average income per person in a certain area. When the population increases, the total income may increase, but the per capita income may decrease if the total income is not increasing at the same rate as the population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>28", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "POPULATION : INTRODUCTION", "question": "Census figures of most countries in West Africa are inaccurate because of", "images": [], "options": {"A": "Low cost of enumeration", "B": "Low per capita income", "C": "High degree of illiteracy", "D": "High level of civilization"}, "answer": "C", "explanation": "Census figures of most countries in West Africa are inaccurate mainly due to factors such as logistical difficulties, lack of resources, and issues related to data collection and processing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>29", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "MONEY : INTRODUCTION", "question": "Which of the following is a problem of trade by barter?", "images": [], "options": {"A": "Exchange rate determination", "B": "Hoarding", "C": "How to produce", "D": "What to produce"}, "answer": "A", "explanation": "Exchange rate determination is one the problems of barter system i.e problem of exchange rate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>30", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CHEQUES", "question": "Cheques are not money because?", "images": [], "options": {"A": "Their use is confined to business hours", "B": "There are few banks in the rural areas", "C": "They are not generally acceptable as a medium of exchange", "D": "They are not issued by the government"}, "answer": "C", "explanation": "Cheques are not considered as money because they are not generally acceptable as a medium of exchange. A cheque is a document that orders a bank to pay a specific amount of money from a person's account to the person in whose name the cheque has been issued. The acceptability of a cheque depends on the credibility of the issuer and the willingness of the receiver to accept it as a form of payment. This is unlike money which is generally accepted as a medium of exchange.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>31", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Which of the following is a liability of a commercial bank?", "images": [], "options": {"A": "Deposits", "B": "Money at call", "C": "Loans to customers", "D": "Overdrafts"}, "answer": "A", "explanation": "In banking terms, a liability is something that a bank owes. Deposits made by customers are considered as liabilities for a bank because the bank is obligated to return the deposited money to the customer upon demand. Therefore, deposits are a liability of a commercial bank.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>32", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "The value of money is best determined by its", "images": [], "options": {"A": "Size", "B": "Purchasing power", "C": "Portability", "D": "Being recognized"}, "answer": "B", "explanation": "The value of money is best determined by its purchasing power because it is a measure of the quantity of goods or services that one unit of money can buy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>33", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "Which of the following is a function of the Central Bank of Nigeria?", "images": [], "options": {"A": "Serving as custodian of important valuables", "B": "Giving advice to customers", "C": "Serving as bankers bank", "D": "Creating credit"}, "answer": "C", "explanation": "The Central Bank of Nigeria serves as the banker's bank, which means it is the bank for commercial banks where they keep their reserves and it also regulates their operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>34", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "Who among the the following will benefit from inflation?", "images": [], "options": {"A": "Pensioners", "B": "Savings", "C": "Debtors", "D": "Creditors"}, "answer": "C", "explanation": "During inflation, debtors benefit because they repay their debts with money that is less valuable than the money they borrowed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>35", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Inflation can be controlled by increasing?", "images": [], "options": {"A": "Aggregate supply", "B": "Government expenditure", "C": "Aggregate demand", "D": "A deficit budget"}, "answer": "A", "explanation": "Inflation is a general increase in prices and fall in the purchasing value of money. It can be controlled by increasing the aggregate supply. When aggregate supply (total goods and services produced in an economy) increases, it helps to meet the demand and thus, reduces the price level, controlling inflation. Therefore, the correct answer is 'Aggregate supply'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2002>36", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "Which of the following is a function of merchants banks?", "images": [], "options": {"A": "Minting of coins", "B": "Preparation of government budget", "C": "Keeping watch on external reserves of the country", "D": "Acting as acceptance houses"}, "answer": "D", "explanation": "Merchant banks are financial institutions that provide capital to companies in the form of share ownership instead of loans. They also provide advisory on corporate matters to the firms they lend to. One of their functions is acting as acceptance houses. An acceptance house is a financial institution that guarantees bills of exchange, making them negotiable instruments. Therefore, the correct answer is 'Acting as acceptance houses'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>37", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "Personal savings are generally low in West Africa because of", "images": [], "options": {"A": "The level of income of the people", "B": "The refusal of banks to grant loans", "C": "Overpopulation", "D": "Cheaper foreign currencies"}, "answer": "A", "explanation": "Personal savings are generally low in West Africa because of the level of income of the people. Savings are a function of income, the higher the income, the higher the savings. In West Africa, many people earn low income, hence, they have little or no surplus to save after meeting their basic needs. Therefore, the correct answer is 'The level of income of the people'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>38", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES", "question": "Which business organization enjoys tax-free profits in West Africa?", "images": [], "options": {"A": "Co-operative societies", "B": "Private limited liability companies", "C": "Joint-stock companies", "D": "Partnership"}, "answer": "A", "explanation": "Co-operative societies are organizations owned and run jointly by its members, who share the profits or benefits. In many West African countries, co-operative societies enjoy tax-free profits as part of government incentives to encourage their growth and development.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>39", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "The greatest revenue earning industry in Nigeria is", "images": [], "options": {"A": "Construction", "B": "Agriculture", "C": "Manufacturing", "D": "Mining"}, "answer": "D", "explanation": "The greatest revenue earning industry in Nigeria is the Mining industry. This is because Nigeria is rich in mineral resources, especially oil and gas, which are major sources of revenue for the country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2002>40", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "A market equilibrium exists when", "images": [], "options": {"A": "No buyer goes home empty-handed", "B": "Demand and supply are increasing", "C": "Demand and supply are equal", "D": "The price is fluctuating"}, "answer": "C", "explanation": "Market equilibrium is a state in which the demand and supply of a product or service in the market is equal. This means that the quantity of the product that consumers are willing and able to buy equals the quantity that producers are willing and able to sell, resulting in a stable price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>41", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "The incidence of an increase in tax on a commodity with perfectly inelastic demand will be on the", "images": [], "options": {"A": "Wholesaler", "B": "Retailer", "C": "Government", "D": "Consumer"}, "answer": "D", "explanation": "In the case of perfectly inelastic demand, consumers are willing to buy the same quantity of a good regardless of its price. Therefore, if a tax is imposed on such a commodity, the entire burden of the tax will be borne by the consumer, as they will still buy the same quantity even if the price increases due to the tax. Hence, the incidence of an increase in tax on a commodity with perfectly inelastic demand will be on the consumer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2002>42", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Budget surplus implies that", "images": [], "options": {"A": "Expenditure equals revenue", "B": "Expenditure is less than revenue", "C": "Expenditure is greater than taxation", "D": "Direct tax is more than indirect tax"}, "answer": "B", "explanation": "A budget surplus occurs when income (or revenues) exceed expenses (or expenditures). This means that the government or organization is earning more than it is spending. Therefore, the statement 'Expenditure is less than revenue' correctly describes a situation where a budget surplus would occur.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>43", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "International trade is based on the law of", "images": [], "options": {"A": "Absolute cost advantage", "B": "Variable proportion", "C": "Comparative cost advantage", "D": "Mutual co-operation"}, "answer": "C", "explanation": "International trade is based on the law of comparative cost advantage. This law states that a country should specialize in the production and export of those goods and services it can produce more efficiently (at a lower opportunity cost), and import those goods and services it produces less efficiently. This allows for greater overall efficiency and mutual benefit among trading nations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>44", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "Terms of trade is used to describe", "images": [], "options": {"A": "The quality of exports", "B": "The direction of foreign trade", "C": "Purchases on deferred payment basis", "D": "The rate at which exports exchange for imports"}, "answer": "D", "explanation": "Terms of trade is an economic term that refers to the relative price of exports in terms of imports and is defined as the ratio of export prices to import prices. It can be interpreted as the amount of import goods an economy can purchase per unit of export goods. Therefore, the correct answer is 'The rate at which exports exchange for imports'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>45", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "A nation's net export is negative when her", "images": [], "options": {"A": "Stock of goods is declining", "B": "Depreciation exceeds investment", "C": "Exports is adjusted upwards", "D": "Imports exceed exports"}, "answer": "D", "explanation": "A nation's net export is the value of a country's total exports minus the value of its total imports. It is used to calculate the aggregate expenditure and gross domestic product in an open economy. If a country's imports exceed its exports, the net export value will be negative. Therefore, the correct answer is 'Imports exceed exports'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>46", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Deficit in the balance of payment is financed through", "images": [], "options": {"A": "Capital account", "B": "Current account", "C": "Invisible trade", "D": "Visible trade"}, "answer": "A", "explanation": "A deficit in the balance of payments occurs when more money is flowing out of the country than coming in, and it's often financed through the capital account. The capital account records all international purchases and sales of assets such as money, stocks, bonds, etc. When a country has a deficit in its balance of payments, it can borrow from other countries to make up the difference, which is recorded in the capital account. Therefore, the correct answer is 'Capital account'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2002>47", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "Devaluation of currency in the country is likely to lead to", "images": [], "options": {"A": "Increasing population", "B": "Increasing imports", "C": "Exports becoming cheaper", "D": "Reduced exports"}, "answer": "C", "explanation": "Devaluation of a country's currency makes its exports cheaper and more competitive in the global market. This is because the goods and services produced in the country become cheaper for foreign buyers due to the lower value of the country's currency.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2002>48", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : ONSHORE & OFFSHORE OF THE OIL SECTOR", "question": "Which of the following is not a benefit derived by Nigeria from the petroleum industry", "images": [], "options": {"A": "Increased foreign exchange earnings", "B": "Establishment of refineries and petrochemical industries", "C": "Employment of a greater proportion of the population", "D": "Development of airports,seaports and other social infrastructure"}, "answer": "C", "explanation": "While the petroleum industry does provide employment, it does not employ a greater proportion of the population in Nigeria. The industry is capital intensive, meaning it relies more on machinery than on human labor. Therefore, it does not provide employment to a large proportion of the population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>49", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Gross Domestic Product (GDP) at market prices plus net factor income from abroad gives", "images": [], "options": {"A": "Gross capital formation", "B": "Net capital formation", "C": "Disposable income", "D": "Gross national product"}, "answer": "D", "explanation": "Gross Domestic Product (GDP) at market prices plus net factor income from abroad gives Gross National Product (GNP). GDP is the total value of goods and services produced within a country's borders in a specific time period. Net factor income from abroad includes income from foreign investments minus income payments to foreign investors. When you add these two together, you get GNP, which is the total value of goods and services produced by a country's residents, regardless of the location of the production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2002>50", "subject": "Economics", "year": "2002", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "An economic system in which the state owns and controls the means of production is known as?", "images": [], "options": {"A": "Socialist economy", "B": "Mixed economy", "C": "Capitalist economy", "D": "Welfare economy"}, "answer": "A", "explanation": "A socialist economy is an economic system in which the state owns and controls the means of production. In this system, the government plans and controls the economy and a central authority directs the means and levels of production. The aim is to distribute wealth more evenly and to a fair society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>1", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Economics as a field of study is a", "images": [], "options": {"A": "pure science", "B": "political science", "C": "social science", "D": "physical science"}, "answer": "C", "explanation": "Economics is a social science because it deals with the study of the production, distribution, and consumption of goods and services. It studies how individuals, businesses, governments, and nations make choices on allocating resources to satisfy their wants and needs, trying to determine how these groups should organize and coordinate efforts to achieve maximum output.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>2", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "The three major agents of an economic system are the", "images": [], "options": {"A": "consumers, workers and producers.", "B": "market, telecommunication and banks.", "C": "schools, hospitals and universities", "D": "individuals, firms and government"}, "answer": "D", "explanation": "The three major agents of an economic system are the individuals, firms, and government. Individuals are the consumers who demand goods and services. Firms are the producers who supply goods and services. The government plays a role in regulating the economy, providing public goods and services, and redistributing income.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>3", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH", "question": "Which of the following is not an advantage of tabular presentation of data? It", "images": [], "options": {"A": "enables easy location of required figures", "B": "makes for easy comparison of figures", "C": "occupies more space than mathematical equation", "D": "shows whether the figures are increasing or decreasing"}, "answer": "C", "explanation": "Tabular presentation of data is a method of presenting data in rows and columns. It is a very efficient way of organizing data for easy access and comparison. However, it can occupy more space than a mathematical equation. This is because a table needs to provide space for each data point, while a mathematical equation can represent a large amount of data in a compact form.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>4", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "The problem of scarcity is reduced by", "images": [], "options": {"A": "controlling consumption of goods and services", "B": "producing everything needed by consumers", "C": "ensuring efficient allocation of resources", "D": "restricting consumer choices and tastes"}, "answer": "C", "explanation": "The problem of scarcity in economics refers to the basic economic problem, the gap between limited resources and theoretically limitless wants. This situation requires people to make decisions about how to allocate resources efficiently, in order to satisfy basic needs and as many additional wants as possible. Therefore, ensuring efficient allocation of resources can help to reduce the problem of scarcity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>5", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "The reward for labour is", "images": [], "options": {"A": "wages", "B": "profit", "C": "rent", "D": "dividends"}, "answer": "A", "explanation": "In economics, the reward for labour is wages. This is the payment made to workers for their services in production. Profit is the reward for entrepreneurship, rent is the reward for land, and dividends are the returns paid to shareholders from a company's profits.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>6", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following factors of production consists of man made goods?", "images": [], "options": {"A": "Land", "B": "Labour", "C": "Capital", "D": "Entrepreneur"}, "answer": "C", "explanation": "In economics, the factors of production are the inputs used in the production of goods or services in order to make an economic profit. These include land, labor, capital, and entrepreneurship. Capital refers to man-made goods or resources necessary for the production of other goods. These can include machinery, tools, buildings, or other infrastructure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>7", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "One major function of the entrepreneur is", "images": [], "options": {"A": "bearing of risk", "B": "maximizing profits", "C": "taking charge of day to day management", "D": "determining the selling price of his products"}, "answer": "A", "explanation": "An entrepreneur is an individual who creates a new business, bearing most of the risks and enjoying most of the rewards. The entrepreneur is commonly seen as an innovator, a source of new ideas, goods, services, and business/or procedures. One of the major functions of an entrepreneur is the bearing of risk. This means that the entrepreneur takes on the financial risks of starting and managing a business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>8", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "A major limiting factor of mass production is", "images": [], "options": {"A": "efficient management", "B": "adequate labour supply", "C": "small size of the market", "D": "adequate supply of raw materials"}, "answer": "C", "explanation": "Mass production is a method of producing goods in large quantities at a low cost per unit. The economy of scale is a major driver of mass production. However, one of the major limiting factors of mass production is the small size of the market. If the market for a product is small, mass production may lead to overproduction and losses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>9", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "Division of labour leads to", "images": [], "options": {"A": "improved craftsmanship", "B": "the production of standardized goods", "C": "increase in the cost of goods", "D": "trade by barter"}, "answer": "B", "explanation": "Division of labour refers to the breaking down of the production process into different stages where each worker specializes in one stage. This leads to the production of standardized goods because each worker becomes an expert in his/her specific task, thus maintaining a consistent quality of the product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>10", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Which of the following is an advantage of localization of industry?", "images": [], "options": {"A": "Development of subsidiary firms", "B": "Creation of parallel markets", "C": "Development of slums", "D": "Attraction of foreign capital"}, "answer": "A", "explanation": "Localization of industry refers to the concentration of an industry in a particular area or region. One of the advantages of this is the development of subsidiary firms. These are firms that provide support services to the main industry, such as suppliers of raw materials, transportation, and maintenance services. This leads to the growth of related industries in the area.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>11", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT", "question": "The additional satisfaction derived from the consumption of one more unit of a good is called", "images": [], "options": {"A": "marginal product", "B": "marginal utility", "C": "marginal revenue", "D": "marginal cost"}, "answer": "B", "explanation": "The additional satisfaction derived from the consumption of one more unit of a good is called marginal utility. In economics, utility refers to the satisfaction or benefit derived from consuming a product or service. Therefore, marginal utility is the change in total satisfaction as a result of consuming one additional unit of a good or service.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>12", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "Use the diagram below to answer this question    The curve labelled X is the", "images": ["Economics/imgs/2003/img1.png"], "options": {"A": "total revenue curve", "B": "total product curve", "C": "marginal product curve", "D": "marginal revenue curve"}, "answer": "B", "explanation": "The labelled X from the diagram is a total product curve.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>13", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION", "question": "When the total product is at its maximum, marginal product is", "images": [], "options": {"A": "increasing", "B": "positive", "C": "negative", "D": "zero"}, "answer": "D", "explanation": "When the total product is at its maximum, the marginal product is zero. Marginal product refers to the additional output resulting from employing an extra unit of input while keeping other inputs constant. When the total product reaches its maximum, it means that adding more inputs does not increase the output, hence the marginal product is zero.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>14", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM", "question": "Marginal cost can be derived from the", "images": [], "options": {"A": "total product", "B": "total revenue", "C": "total cost", "D": "average fixed cost"}, "answer": "C", "explanation": "Marginal cost can be derived from the total cost. Marginal cost refers to the cost of producing one more unit of a good. It can be calculated by taking the change in total cost that comes from producing one more unit of the good.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>15", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "The market supply curve slopes upwards from left to right indicating that", "images": [], "options": {"A": "at a lower price, more is supplied", "B": "two commodities can be supplied at the same time", "C": "at a lower price, less is supplied", "D": "producers pay high taxes"}, "answer": "C", "explanation": "The market supply curve slopes upwards from left to right indicating that at a lower price, less is supplied. This is because suppliers are willing to supply more of a good at a higher price than at a lower price, hence the upward slope of the supply curve.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>16", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "Use the table below to answer this question  OutputTotal Revenue (N)1  2  3  4  540  49  56  61  65  The marginal revenue when output is 4 units is", "images": [], "options": {"A": "5 naira", "B": "8 naira", "C": "56 naira", "D": "61 naira"}, "answer": "A", "explanation": "MR=ΔTRΔQ  at 4 unit,   MR=61-564-3=51  ₦5", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>17", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "The term underpopulation refers to a situation where the population is", "images": [], "options": {"A": "dispersed over the country", "B": "small in relation to available resources", "C": "greater than the available resources", "D": "concentrated in a few areas"}, "answer": "B", "explanation": "Underpopulation is a situation in which the size of the population is small in relation to available resources. It means that there are too few people in an area to use the resources available efficiently. So, the correct option is 2.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>18", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "West African countries experience rapid population growth due to", "images": [], "options": {"A": "existence of birth control clinics", "B": "early marriages", "C": "adequate sex education in schools", "D": "late marriages"}, "answer": "B", "explanation": "Rapid population growth in West African countries is largely due to early marriages. Early marriages often lead to higher fertility rates and hence rapid population growth. So, the correct option is 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>19", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "Which of the following could be used to measure the efficiency of labour?", "images": [], "options": {"A": "Education and training", "B": "Rate of inflation", "C": "Level of unemployment", "D": "Input-Output ratio"}, "answer": "D", "explanation": "The efficiency of labour can be measured by the Input-Output ratio. This ratio compares the amount of input (in this case, labour) used in production to the output produced. A higher ratio indicates greater efficiency. Education and training can improve labour efficiency but are not measures of it. The rate of inflation and level of unemployment are economic indicators but do not directly measure labour efficiency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>20", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "Which of the following is necessary for the survival of small firms in West Africa?", "images": [], "options": {"A": "Access to land for development", "B": "Inadequate collaterals for bank loans", "C": "Government assistance in the form of loans and tax holidays", "D": "High transportation costs"}, "answer": "C", "explanation": "For the survival of small firms in West Africa, government assistance in the form of loans and tax holidays is necessary. This is because small firms often struggle with access to capital and high tax burdens. Access to land for development is important but not necessarily a survival factor. Inadequate collaterals for bank loans and high transportation costs are challenges, not survival factors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>21", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "A normal demand curve slopes", "images": [], "options": {"A": "downwards from left to right", "B": "upwards from left to right", "C": "downwards from right to left", "D": "upwards from the origin"}, "answer": "A", "explanation": "A normal demand curve slopes downwards from left to right. This is because as the price of a good or service increases, the quantity demanded decreases, and vice versa. This is known as the law of demand. The other options do not correctly describe the slope of a normal demand curve.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>22", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If the quantity demanded of a commodity increases from 20 to 30 units when there is an increase in price from 4 naira to 5 naira, the elasticity of demand is", "images": [], "options": {"A": "0", "B": "1", "C": "2", "D": "5"}, "answer": "C", "explanation": "The elasticity of demand is calculated by the formula: % change in quantity demanded / % change in price. Here, the change in quantity demanded is (30-20)/20 = 0.5 or 50% and the change in price is (5-4)/4 = 0.25 or 25%. So, the elasticity of demand is 50%/25% = 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>23", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "Price elasticity of supply measures the responsiveness of quantity supplied to", "images": [], "options": {"A": "changes in suppliers' income", "B": "changes in prices of other commodities", "C": "a change in the price of the commodity", "D": "a change in the demand for the product"}, "answer": "C", "explanation": "Price elasticity of supply measures the responsiveness of quantity supplied to a change in the price of the commodity. It shows how much the quantity supplied of a good responds to a change in the price of that good.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>24", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "The most common type of business in West African countries is", "images": [], "options": {"A": "joint-stock companies", "B": "sole proprietorships", "C": "partnerships", "D": "public enterprises"}, "answer": "B", "explanation": "The most common type of business in West African countries is sole proprietorships. This is because it is easy to set up, requires less capital and is common in the informal sector which is prevalent in West African countries.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>25", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "Which of the following is a type of business organization", "images": [], "options": {"A": "Stock exchange", "B": "Insurance company", "C": "Chain stores", "D": "Co-operative"}, "answer": "D", "explanation": "A type of business organization is a Co-operative. A co-operative is a business organization owned and operated by a group of individuals for their mutual benefit. It is formed on the principle of voluntary association and democratic control. It is not a stock exchange, insurance company or chain stores, which are places or platforms where business transactions occur.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>26", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "One advantage of the sole proprietorship is that", "images": [], "options": {"A": "control and supervision is under one man", "B": "accounts must be publicized", "C": "it is always successful", "D": "funds are easy to obtain"}, "answer": "A", "explanation": "One advantage of the sole proprietorship is that control and supervision is under one man. In a sole proprietorship, the business is owned and managed by one person who has full control over all aspects of the business. This allows for quick decision making and direct supervision. The other options are incorrect because in a sole proprietorship, accounts do not need to be publicized, it is not always successful, and funds may not be easy to obtain as it depends on the financial capacity of the owner.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2003>27", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "The shares which do not carry any fixed rate of dividend are known as", "images": [], "options": {"A": "debentures", "B": "cumulative preference shares", "C": "ordinary shares", "D": "participating preference shares"}, "answer": "C", "explanation": "The shares which do not carry any fixed rate of dividend are known as ordinary shares. Ordinary shares, also known as common shares, are shares of a company that provide the holder with a right to vote at the company's general meetings and to receive a share of the company's profits in the form of dividends. However, these dividends are not fixed and depend on the company's profits. The other options are incorrect because debentures are a type of debt instrument, cumulative preference shares carry a fixed rate of dividend and participating preference shares also carry a fixed rate of dividend but with an additional right to participate in the surplus profits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>28", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "The economic goal of public corporations is to", "images": [], "options": {"A": "maximize profit", "B": "expand assets", "C": "minimize costs", "D": "provide essential services"}, "answer": "D", "explanation": "Public corporations are government-owned entities. They are not primarily driven by profit maximization like private corporations. Instead, their main goal is to provide essential services to the public. These services can be in various sectors such as transportation, utilities, healthcare, etc. Hence, the correct answer is 'provide essential services'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>29", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "One of the factors responsible for low agricultural production in West Africa is", "images": [], "options": {"A": "inadequate labour", "B": "shortage of land", "C": "inadequate implements", "D": "inadequate research"}, "answer": "C", "explanation": "Agricultural production in West Africa is hindered by several factors. However, one of the most significant factors is the lack of adequate implements. This includes machinery, tools, and other equipment necessary for modern farming. Without these implements, farming becomes labor-intensive and less productive. Hence, the correct answer is 'inadequate implements'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>30", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : INTRODUCTION", "question": "Efficient distribution of goods in West Africa will be facilitated by", "images": [], "options": {"A": "poor storage facilities", "B": "adequate transportation system", "C": "high standard of living", "D": "high cost of living"}, "answer": "B", "explanation": "Efficient distribution of goods is largely dependent on a robust and reliable transportation system. This is because goods need to be moved from the point of production to various points of consumption. If the transportation system is inadequate, it will hinder the efficient distribution of goods. Hence, the correct answer is 'adequate transportation system'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>31", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "The demand for money is", "images": [], "options": {"A": "derived demand", "B": "composite demand", "C": "joint demand", "D": "complimentary demand"}, "answer": "A", "explanation": "The demand for money is a derived demand because money is not demanded for its own sake but for what it can purchase. It is a medium of exchange and a store of value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>32", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "Money becomes a very poor store of value in a period of", "images": [], "options": {"A": "deflation", "B": "depression", "C": "recession", "D": "inflation"}, "answer": "D", "explanation": "Money becomes a very poor store of value in a period of inflation because inflation erodes the purchasing power of money. As prices rise, the value of money falls, meaning it can buy less goods and services.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2003>33", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "INFLATION & DEFLATION : INTRODUCTION", "question": "A continuous fall in the general price level is called", "images": [], "options": {"A": "recession", "B": "depression", "C": "deflation", "D": "stagflation"}, "answer": "C", "explanation": "A continuous fall in the general price level is called deflation. Deflation is the opposite of inflation, it is a decrease in the general price level of goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>34", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "Which of the following is a function of the central bank?", "images": [], "options": {"A": "Accepting deposits from the public", "B": "Lending to the commercial banks", "C": "Discounting bills of exchange", "D": "Agent of payment for individuals"}, "answer": "B", "explanation": "The central bank of a country, such as the Federal Reserve in the United States, has several key functions. These include controlling the country's money supply, setting interest rates, managing the country's reserves, issuing currency, and acting as a lender of last resort to commercial banks. Therefore, 'Lending to the commercial banks' is a function of the central bank.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>35", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Cost-push inflation is likely to raise when", "images": [], "options": {"A": "there is an increase in government spending", "B": "there is an increase in direct taxes", "C": "demand for higher wages is granted", "D": "there is a decrease in bank lending"}, "answer": "C", "explanation": "Cost-push inflation occurs when the costs of production increase, causing producers to raise prices to maintain their profit margins. This can be caused by a variety of factors, including increases in the cost of wages, raw materials, or taxes. Therefore, 'demand for higher wages is granted' can cause cost-push inflation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2003>36", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "The most important function of merchant banks is the", "images": [], "options": {"A": "issuing of currency", "B": "provision of short term loans", "C": "provision of medium and long term loans", "D": "provision of short and long term loans"}, "answer": "C", "explanation": "Merchant banks are financial institutions that provide capital to companies in the form of shares rather than loans. They are also involved in international trade and business. Therefore, the most important function of merchant banks is the 'provision of medium and long term loans'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2003>37", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "Precautionary motive related to", "images": [], "options": {"A": "demand for money", "B": "demand for goods", "C": "supply of money", "D": "supply of goods"}, "answer": "A", "explanation": "The precautionary motive refers to the desire to hold cash in order to be able to deal effectively with unexpected events. It is one of the reasons why people demand money. Therefore, the correct answer is 'demand for money'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>38", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "INTERNATIONAL TRADE : INTRODUCTION", "question": "Invisible trade refers to trade in", "images": [], "options": {"A": "services", "B": "goods and services", "C": "tangible goods", "D": "crude oil"}, "answer": "A", "explanation": "Invisible trade refers to the trade of services, such as banking, insurance, tourism, and technology. It does not include the trade of physical goods. Therefore, the correct answer is 'services'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>39", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "When the demand for foreign exchange exceeds its supply, the value of the domestic currency", "images": [], "options": {"A": "appreciates", "B": "depreciates", "C": "inflates", "D": "expands"}, "answer": "B", "explanation": "When the demand for foreign exchange exceeds its supply, it means more people want to buy foreign currency than sell it. This increases the price of foreign currency in terms of the domestic currency, which means the value of the domestic currency depreciates. Therefore, the correct answer is 'depreciates'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2003>40", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Which of the following is part of the capital account of the balance of payments?", "images": [], "options": {"A": "Net investment from abroad", "B": "Import of machinery", "C": "Insurance", "D": "Transportation costs"}, "answer": "A", "explanation": "The capital account in the balance of payments records all international purchases and sales of assets such as money, stocks, bonds, etc. Net investment from abroad falls under this category as it involves the transfer of assets. Import of machinery, insurance, and transportation costs are part of the current account, not the capital account.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2003>41", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "The most common index for measuring development is", "images": [], "options": {"A": "the level of illiteracy", "B": "the per capita income", "C": "nutritional levels", "D": "population growth rate"}, "answer": "B", "explanation": "The most common index for measuring development is the per capita income. It is the measure of the amount of money that each individual gets as their share of the country's wealth. The level of illiteracy, nutritional levels, and population growth rate are also indicators of development but they are not as commonly used as per capita income.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>42", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Governments of West African countries levy taxes to", "images": [], "options": {"A": "prevent prices from falling", "B": "make people richer", "C": "limit the number of banks", "D": "finance government projects"}, "answer": "D", "explanation": "Governments levy taxes primarily to finance government projects. This includes infrastructure development, public services, and other government expenditures. The other options, such as preventing prices from falling, making people richer, or limiting the number of banks, are not the primary reasons for taxation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>43", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Which of the following is a direct tax?", "images": [], "options": {"A": "Import duties", "B": "Purchase tax", "C": "Export duties", "D": "Personal income tax"}, "answer": "D", "explanation": "A direct tax is a tax that the taxpayer pays directly to the government. These taxes cannot be shifted to any other person or group. An individual pays these taxes directly to the government. They are imposed directly by the government. Personal income tax is a direct tax.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>44", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "The tax whose rate increases as the level of income increases is known as", "images": [], "options": {"A": "regressive tax", "B": "proportional tax", "C": "progressive tax", "D": "company tax"}, "answer": "C", "explanation": "A progressive tax is a tax that takes a larger percentage from the income of high-income earners than it does from low-income individuals. The actual tax burden is directly influenced by the earning of a person, the more they earn the more tax they pay. Therefore, the rate of tax increases as the level of income increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>45", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Public expenditure on education and health is known as expenditure on", "images": [], "options": {"A": "general services", "B": "social services", "C": "commercial services", "D": "economic services"}, "answer": "B", "explanation": "Public expenditure on education and health is known as expenditure on social services. Social services are a range of public services provided by the government, private, profit and non-profit organisations. These public services aim to create more effective organizations, build stronger communities, and promote equality and opportunity. Education and health are part of these services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>46", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Budget deficit can be financed by", "images": [], "options": {"A": "reducing the level of taxation", "B": "printing more money", "C": "lending to financial institutions", "D": "employing more workers"}, "answer": "B", "explanation": "A budget deficit occurs when expenses exceed revenue and it is an indicator of financial health. One of the ways to finance a budget deficit is by printing more money. However, this can lead to inflation. Reducing the level of taxation would decrease government revenue, not increase it. Lending to financial institutions and employing more workers do not directly finance a budget deficit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2003>47", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "ECONOMIC INTEGRATION : PROBLEMS OF ECONOMIC INTEGRATION IN WEST AFRICA- ECOWAS", "question": "A major problem facing the Economic Community of West African States (ECOWAS) as an economic integration, is the", "images": [], "options": {"A": "increasing population", "B": "willingness of members to co-operate", "C": "geographical contiguity", "D": "weak trade relations"}, "answer": "D", "explanation": "The major problem facing the Economic Community of West African States (ECOWAS) as an economic integration is weak trade relations. This is because strong trade relations are essential for economic integration to be successful. Increasing population, willingness of members to co-operate, and geographical contiguity are not major problems facing ECOWAS.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2003>48", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "In a socialist economy, the means of production is owned and controlled by the", "images": [], "options": {"A": "state", "B": "rich", "C": "entrepreneur", "D": "traders"}, "answer": "A", "explanation": "In a socialist economy, the means of production are owned and controlled by the state. This is a key characteristic of a socialist economy. The rich, entrepreneurs, and traders do not own or control the means of production in a socialist economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>49", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "NATIONAL INCOME : USES & REASONS FOR MEASURING NATIONAL INCOME", "question": "It is necessary to estimate the national income of a country because it", "images": [], "options": {"A": "indicates the overall performance of the economy", "B": "ensures equitable distribution of wealth", "C": "assists investors in identifying profitable ventures", "D": "enables governments to conserve national resources"}, "answer": "A", "explanation": "National income is the total value of all goods and services produced in a country over a period of time. It is a measure of the economic performance of a country. A high national income indicates a strong economy, while a low national income suggests a weak economy. Therefore, estimating the national income of a country indicates the overall performance of the economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2003>50", "subject": "Economics", "year": "2003", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "The Organization of Petroleum Exporting Countries (OPEC) is an example of a", "images": [], "options": {"A": "perfect competition", "B": "monopsony", "C": "duopoly", "D": "cartel"}, "answer": "D", "explanation": "The Organization of Petroleum Exporting Countries (OPEC) is an example of a cartel. A cartel is a group of independent market participants who collude with each other in order to improve their profits and maintain control over the market. OPEC, for example, coordinates policies among member countries to control oil prices on the global market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>1", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Which of the following is an economic activity?", "images": [], "options": {"A": "attending a town's meeting", "B": "a visit to the stadium", "C": "payment of school fees", "D": "arresting a petty thief"}, "answer": "C", "explanation": "An economic activity is an action that involves the production, distribution, and consumption of goods and services. Payment of school fees is an economic activity because it involves the transfer of money (a medium of exchange in economics) for a service (education).", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2004>2", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "The reward for land as a factor of production is", "images": [], "options": {"A": "interest", "B": "rent", "C": "dividend", "D": "wages"}, "answer": "B", "explanation": "In economics, the reward for land as a factor of production is rent. Land is one of the four main factors of production in economic theory, along with labor, capital, and entrepreneurship. The income earned by these factors of production are wages for labor, interest for capital, profit for entrepreneurship, and rent for land.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2004>3", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "The three broad categories of production are", "images": [], "options": {"A": "direct, secondary and extractive", "B": "primary, tertiary and direct", "C": "primary, secondary and tertiary", "D": "secondary, primary and indirect"}, "answer": "C", "explanation": "The three broad categories of production in economics are primary, secondary, and tertiary. Primary production involves the extraction of raw materials (e.g., mining, agriculture), secondary production involves the transformation of raw or intermediate materials into goods (e.g., manufacturing), and tertiary production involves the supply of services to consumers and businesses (e.g., retail, health care).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>4", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "A carpenter's consumer goods include   I. a kilogram of rice  II. 3 pairs of shoes   III. 4 pairs of socks  iV. 3 screw-drivers", "images": [], "options": {"A": "I and IV only", "B": "I, II, III and IV", "C": "I, II and IV only", "D": "I, II and III only"}, "answer": "D", "explanation": "Consumer goods are products bought for consumption by the average consumer. In the context of the question, a carpenter's consumer goods would include a kilogram of rice, 3 pairs of shoes, and 4 pairs of socks. These are items that the carpenter would consume or use personally. The screw-drivers, on the other hand, would be considered capital goods as they are used in the production of services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>5", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "In a capitalist system, the means of production is owned and controlled by", "images": [], "options": {"A": "the government", "B": "politicians", "C": "private individuals", "D": "the workers"}, "answer": "C", "explanation": "In a capitalist system, the means of production are owned and controlled by private individuals. This is the fundamental characteristic of capitalism, where private property, capital accumulation, wage labor, voluntary exchange, and competitive markets are emphasized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>6", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "Mixed economy refers to a system in which the means of production are controlled by", "images": [], "options": {"A": "private enterprise and the government", "B": "private individuals", "C": "the government only", "D": "the workers and businessmen"}, "answer": "A", "explanation": "A mixed economy is an economic system that combines aspects of both capitalism and socialism. This means that the means of production are controlled by both private enterprise and the government. It is a system where both these sectors co-exist and operate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>7", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "An economic good is described as a good which", "images": [], "options": {"A": "yields utility and commands a price", "B": "is useful and occupies a space", "C": "is in high demand and transferable", "D": "has unlimited supply"}, "answer": "A", "explanation": "An economic good is a good that yields utility and commands a price. This means that it is a good that is useful to consumers and for which they are willing to pay a price. This is the basic definition of an economic good in economics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>8", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "The concept of opportunity cost is important to the firm because it", "images": [], "options": {"A": "determines the prices of the firm's products", "B": "increases the level of output of the firm", "C": "leads to maximum satisfaction of the consumers", "D": "guides firms in allocating scarce resources"}, "answer": "D", "explanation": "Opportunity cost is a fundamental concept in economics that refers to the potential benefit an individual, investor, or business misses out on when choosing one alternative over another. In the context of a firm, opportunity cost is important because it guides firms in allocating scarce resources. It helps firms to make decisions about where to allocate their resources to achieve the maximum possible efficiency and profitability.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>9", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM", "question": "As a firm expands, it enjoys some advantages called", "images": [], "options": {"A": "variable proportions", "B": "diminishing marginal returns", "C": "internal economies of scale", "D": "decreasing returns to scale"}, "answer": "C", "explanation": "As a firm expands, it enjoys some advantages called internal economies of scale. Economies of scale refer to the cost advantage experienced by a firm when it increases its level of output.The advantage arises due to the inverse relationship between per-unit fixed cost and the quantity produced. The efficiency of the firm's operations and the cost per unit of output decrease with increasing scale.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>10", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "Division of labour is limited by", "images": [], "options": {"A": "the size of the market", "B": "the productivity of capital", "C": "cost of production", "D": "the factors of production"}, "answer": "A", "explanation": "The extent to which division of labour can be applied is limited by the size of the market. If the market for a product is small, it may not be economical to divide the production process into many separate tasks because the quantity produced may not be enough to fully utilize the specialized machinery or skills. Therefore, the size of the market is a key factor limiting the division of labour.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>11", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "An entrepreneur is likely to make more profits when", "images": [], "options": {"A": "expenditure is more than revenue", "B": "competitors charge lower prices", "C": "cost per unit output falls", "D": "quantity of output reduces"}, "answer": "C", "explanation": "An entrepreneur is likely to make more profits when the cost per unit output falls. This is because when the cost of producing each unit of a product decreases, the entrepreneur can sell the product at the same price and make more profit, or even lower the price to increase sales volume and still make more profit. This is a basic principle of economics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>12", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "Natural growth rate is", "images": [], "options": {"A": "birth rate less death rate", "B": "death rate less migration", "C": "death rate plus birth rate", "D": "birth rate plus migration"}, "answer": "A", "explanation": "Natural growth rate is birth rate less death rate. This is a demographic measure of population growth. It is calculated by subtracting the death rate from the birth rate. This gives the rate at which the population is increasing or decreasing, without considering migration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>13", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "POPULATION : POPULATION DENSITY, AGEING POPULATION", "question": "A major effect of ageing population is", "images": [], "options": {"A": "reduced labour force", "B": "rise in prices of commodities", "C": "reduced infrastructure", "D": "neglect of agriculture"}, "answer": "A", "explanation": "A major effect of ageing population is reduced labour force. As the population ages, the proportion of people in the working age group decreases. This leads to a decrease in the labour force, which can have significant economic impacts. It can lead to labour shortages and increased costs for businesses, and can also impact the tax base and social services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>14", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "One of the problems associated with the middleman in the distribution of goods is that he", "images": [], "options": {"A": "buys in large quantities", "B": "hoards goods", "C": "grants credit to the retailer", "D": "sells varieties of goods"}, "answer": "B", "explanation": "Middlemen are often criticized for hoarding goods. Hoarding is the practice of accumulating items in an organized manner and in large quantities. In the context of economics, it refers to the accumulation of goods and commodities by a dealer or trader in large quantities for the purpose of selling them at higher prices at an appropriate time. This practice can create artificial scarcity and inflate prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>15", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE RETAILER", "question": "The distribution of goods is said to be completed when it reaches the", "images": [], "options": {"A": "wholesalers", "B": "consumers", "C": "retailers", "D": "manufacturers"}, "answer": "B", "explanation": "The distribution of goods is said to be completed when it reaches the consumers. This is because the ultimate goal of production and distribution is to satisfy the needs and wants of consumers. Wholesalers, retailers, and manufacturers are all part of the distribution chain, but the process is not complete until the goods reach the final consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>16", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "The gap between demand and supply curves below the equilibrium price indicates", "images": [], "options": {"A": "excess demand", "B": "excess supply", "C": "equilibrium quantity", "D": "equilibrium price"}, "answer": "A", "explanation": "The gap indicate excess demand or shortage. It is shown in the diagram below.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>17", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "Demand for inferior good is an example of", "images": [], "options": {"A": "expansion of demand", "B": "contraction of demand", "C": "individual demand", "D": "abnormal demand"}, "answer": "D", "explanation": "Demand for inferior goods is an example of abnormal demand. Inferior goods are goods whose demand decreases when consumer income rises, unlike normal goods, where demand increases along with income. This is considered 'abnormal' because it contradicts the typical law of demand which states that as prices fall, demand usually increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>18", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "When a change in price does not affect the quantity demanded of a commodity, the price elasticity of demand is", "images": [], "options": {"A": "fairly inelastic", "B": "infinitely elastic", "C": "perfectly inelastic", "D": "unitary elastic"}, "answer": "C", "explanation": "Perfectly Inelastic occurs when a change in price does not affect change in quantity demanded of a commodity. It is shown in the diagram below.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>19", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "Use the table below to answer this question  Price (Dollars)Quantity Supplied (Units)5  360  36    The percentage change in supply is", "images": [], "options": {"A": "20%", "B": "30%", "C": "40%", "D": "50%"}, "answer": "C", "explanation": "The percentage change in supply is calculated as the difference in quantity supplied divided by the initial quantity supplied, all multiplied by 100. The difference in quantity supplied is 60 - 36 = 24 units. The initial quantity supplied is 60 units. Therefore, the percentage change in supply is (24/60)*100 = 40%.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>20", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "Use the table below to answer this question  Price (Dollars)Quantity Supplied (Units)5  360  36  The percentage change in price is", "images": [], "options": {"A": "10", "B": "20", "C": "30", "D": "40"}, "answer": "D", "explanation": "The percentage change in price is calculated as the difference in price divided by the initial price, all multiplied by 100. The difference in price is 5 - 3 = 2 dollars. The initial price is 5 dollars. Therefore, the percentage change in price is (2/5)*100 = 40%.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>21", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "Use the table below to answer this question  Price (Dollars)Quantity Supplied (Units)5  360  36  The elasticity of supply is", "images": [], "options": {"A": "infinite", "B": "equal to one", "C": "less than one", "D": "equal to zero"}, "answer": "B", "explanation": "The elasticity of supply is calculated as the percentage change in quantity supplied divided by the percentage change in price. From the calculations above, both the percentage change in quantity supplied and the percentage change in price are 40%. Therefore, the elasticity of supply is 40%/40% = 1.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>22", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : ACCOUNTANTS & ECONOMIST VIEW ON COST", "question": "Use the diagram below to answer this question    The line M in the diagram represents", "images": ["Economics/imgs/2004/img1.png"], "options": {"A": "total cost", "B": "fixed cost", "C": "variable cost", "D": "average cost"}, "answer": "B", "explanation": "The line M in the diagram represent fixed cost. The fixed cost is a cost that do not change with the level of output.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>23", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "MARKET STRUCTURE : FORMS OF MARKET STRUCTURE", "question": "For both the monopolist and the perfectly competitive firm, profit maximizing output occurs at the point where the", "images": [], "options": {"A": "marginal cost curve cuts the marginal revenue curve from below", "B": "marginal revenue curve cuts the marginal output from above", "C": "marginal cost curve intersects the X-axis", "D": "marginal revenue curve intersects the Y-axis"}, "answer": "A", "explanation": "In both monopoly and perfect competition, the profit maximizing output is where the marginal cost (MC) curve intersects the marginal revenue (MR) curve from below. This is because at this point, the cost of producing an additional unit of output (MC) is exactly equal to the revenue gained from selling that additional unit (MR). Producing more would mean the cost of the next unit is greater than the revenue it would bring, while producing less would mean the revenue from the next unit is greater than its cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>24", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "MARKET STRUCTURE : PERFECT MARKET", "question": "The market structure in which the operators are many and none of them can influence the price is", "images": [], "options": {"A": "imperfect market", "B": "perfect market", "C": "oligopolistic market", "D": "stock market"}, "answer": "B", "explanation": "A perfect market, also known as perfect competition, is a market structure where there are many buyers and sellers, none of whom can influence the price. This is because each firm is too small relative to the market to affect the market price. In contrast, in an imperfect market, oligopolistic market, or stock market, individual firms or traders can have an influence on the market price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>25", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "BUSINESS ORGANISATION : PARTNERSHIP", "question": "One main benefit of partnership is", "images": [], "options": {"A": "the possibility of raising funds on the stock exchange", "B": "the possibility of attracting twenty one or more members", "C": "that members can specialize in various functions", "D": "that it enjoys its own separate legal entity"}, "answer": "C", "explanation": "One of the main benefits of a partnership is that members can specialize in various functions. This allows for a division of labor, where each partner can focus on what they do best, leading to increased efficiency and productivity. The other options are incorrect because partnerships cannot raise funds on the stock exchange, they are limited to a certain number of members (usually less than 21), and they do not have their own separate legal entity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2004>26", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES", "question": "Joint ventures are partnerships involving", "images": [], "options": {"A": "the poor and the rich", "B": "employers and workers", "C": "government and private investors", "D": "multinationals and individuals"}, "answer": "C", "explanation": "A joint venture is a business arrangement in which two or more parties agree to pool their resources for the purpose of accomplishing a specific task. This task can be a new project or any other business activity. In a joint venture, each of the participants is responsible for profits, losses, and costs associated with it. Joint ventures can involve any type of business transactions and they often occur between government and private investors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>27", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "The value of money is best determined by", "images": [], "options": {"A": "input-output ratio", "B": "the purchasing power", "C": "the importance people attach to it", "D": "economies of scale"}, "answer": "B", "explanation": "The value of money is best determined by its purchasing power. Purchasing power is the value of a currency expressed in terms of the amount of goods or services that one unit of money can buy. Inflation erodes purchasing power. For example, if the inflation rate is 2%, then a pack of gum that costs $1 in a given year will cost $1.02 the next year. As a result, each unit of currency buys fewer goods and services. This is a reflection of the fact that the purchasing power of money is inversely proportional to the price level in the economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>28", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "Which of the following will be an effect of inflation?", "images": [], "options": {"A": "Wage earners will gain", "B": "Borrowing of money will be restricted", "C": "Money lenders will gain", "D": "Borrowers of money will gain"}, "answer": "D", "explanation": "Inflation is a situation where money will be able to to buy fewer goods than it was able to do so as the value of money comes down. People who have to repay their large debts will benefit from inflation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2004>29", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Government can control inflation by", "images": [], "options": {"A": "printing more money", "B": "reducing the rate of taxes", "C": "reducing the level of expenditure", "D": "establishing more banks"}, "answer": "C", "explanation": "Inflation is a general increase in prices and fall in the purchasing value of money. One of the ways government can control inflation is by reducing the level of expenditure. This is because when government reduces its spending, it decreases the amount of money in circulation, thereby reducing the pressure on prices. Printing more money would actually cause inflation to rise, not fall. Reducing the rate of taxes could stimulate economic activity and potentially lead to inflation. Establishing more banks does not directly control inflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>30", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "FINANCIAL INSTITUTION : FOREIGN EXCHANGE MARKET", "question": "The market consisting of a network of dealers where currencies can be bought and sold is known as", "images": [], "options": {"A": "capital market", "B": "foreign exchange market", "C": "commodity market", "D": "The stock market"}, "answer": "B", "explanation": "The market where currencies can be bought and sold is known as the foreign exchange market. This is a global marketplace for the trading of national currencies. The capital market is where long-term debt or equity-backed securities are bought and sold. The commodity market is a physical or virtual marketplace for buying, selling, and trading raw or primary products. The stock market is where buyers and sellers trade shares of companies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>31", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "Open Market Operation (OMO) means the", "images": [], "options": {"A": "provision of credit facilities by commercial banks", "B": "provision of credit facilities by the mortgage banks", "C": "buying and selling of government securities by the central bank", "D": "procedure for the establishment of commercial banks"}, "answer": "C", "explanation": "Open Market Operation (OMO) refers to the buying and selling of government securities by the central bank. This is a key monetary policy tool used by central banks to control the supply of money and hence manage inflation, interest rates, and the economic cycle. The provision of credit facilities by commercial or mortgage banks is not considered an open market operation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>32", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Which of the following is an advantage of localization of industry?", "images": [], "options": {"A": "development of subsidiary firms", "B": "creation of parallel markets", "C": "development of slums", "D": "attraction of foreign capital"}, "answer": "A", "explanation": "Localization of industry refers to the concentration of a particular industry in a particular area or region. One of the advantages of this is the development of subsidiary firms. These are firms that provide support services to the main industry. For example, in a region where automobile manufacturing is localized, there may be subsidiary firms that provide parts, maintenance services, etc. This leads to the growth of related industries and overall economic development in the region.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>33", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "Which of the following will ensure efficiency in the industrial sector of your country?", "images": [], "options": {"A": "indigenization", "B": "privatisation", "C": "nationalization", "D": "liquidation"}, "answer": "B", "explanation": "Efficiency in the industrial sector can be ensured through privatization. Privatization is the process of transferring ownership of a business, enterprise, agency, public service, or public property from the public sector (a government) to the private sector, either to a business that operates for a profit or to a nonprofit organization. It often improves efficiency because private companies have a profit incentive to cut costs and be more efficient. If they don't, they may lose market share to competitors. Nationalization, on the other hand, can lead to inefficiencies due to lack of competition and motivation for cost reduction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>34", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "The number of people who are qualified to work and who offer themselves for employment are called", "images": [], "options": {"A": "migrant labour", "B": "working population", "C": "labour turnover", "D": "mobility of labour"}, "answer": "B", "explanation": "The number of people who are qualified to work and who offer themselves for employment are called the working population. This term refers to those within the economically active population who are willing and able to work, including both those who are employed and those who are seeking employment. Migrant labour refers to workers who move from one region to another, labour turnover refers to the rate at which workers leave a workforce and are replaced, and mobility of labour refers to the ability of workers to move from one job to another.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2004>35", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "When the general price level persistently falls, the rate of unemployment", "images": [], "options": {"A": "rises", "B": "stagnates", "C": "rapidly reduces", "D": "equals natural growth rate"}, "answer": "A", "explanation": "When the general price level persistently falls, it is referred to as deflation. During deflation, businesses often experience lower profit margins and may resort to cost-cutting measures such as layoffs, leading to a rise in unemployment.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>36", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : ROLES", "question": "Which of the following is not a direct effort to increase agricultural production?", "images": [], "options": {"A": "operation feed the nation", "B": "use of improved seedlings", "C": "increased loans to farmers and co-operative societies", "D": "National Youth Service Corps"}, "answer": "D", "explanation": "The National Youth Service Corps is a program set up by the Nigerian government to involve Nigerian graduates in nation building and the development of the country. It is not a direct effort to increase agricultural production. The other options listed are all direct efforts to increase agricultural production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>37", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "To ensure high employment rates, developing countries should", "images": [], "options": {"A": "build more universities", "B": "protect infant industries", "C": "organize trade fairs", "D": "prevent rural-urban drift"}, "answer": "B", "explanation": "Protecting infant industries can help developing countries ensure high employment rates. Infant industries are new and emerging industries that are not yet capable of competing against established competitors. By protecting these industries, developing countries can help them grow and create jobs. Preventing rural-urban drift, building more universities, and organizing trade fairs may contribute to economic development, but they do not directly ensure high employment rates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>38", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "The act of selling goods in foreign markets at prices below those charged at home markets is called", "images": [], "options": {"A": "exchange", "B": "specialization", "C": "dumping", "D": "exporting"}, "answer": "C", "explanation": "Dumping is a term used in the context of international trade. It's when a country or company exports a product at a price that is lower in the foreign importing market than the price in the exporter's domestic market. The reason they might do this is to increase market share in the foreign market or to offload excess production that isn't selling at home.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>39", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Taxes levied on commodities are", "images": [], "options": {"A": "direct taxes", "B": "indirect taxes", "C": "poll taxes", "D": "investment taxes"}, "answer": "B", "explanation": "Taxes levied on commodities are indirect taxes. Indirect taxes are those paid by consumers when they buy goods and services. These are initially paid to the government by an intermediary, who then adds the amount of tax paid to the value of the goods / services being sold. Examples of indirect taxes include Value Added Tax (VAT), sales tax, duties on imports etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2004>40", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION", "question": "One disadvantage of direct taxes is that", "images": [], "options": {"A": "government's revenue is reduced", "B": "price of essential commodities fall", "C": "people are discouraged from additional work", "D": "firms make more profits"}, "answer": "C", "explanation": "One disadvantage of direct taxes is that they can discourage people from additional work. This is because direct taxes, such as income tax, are levied on the income of individuals or organizations. As the tax rate increases with the increase in income, people may be discouraged from working harder to earn more income as the additional income will be taxed at a higher rate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>41", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "International trade is an application of the principle of", "images": [], "options": {"A": "industrial production", "B": "mass production", "C": "regional co-operation", "D": "comparative cost advantage"}, "answer": "D", "explanation": "International trade is an application of the principle of comparative cost advantage. The principle of comparative cost advantage states that a country should specialize in the production and export of goods and services that it can produce more efficiently (at a lower opportunity cost) than other goods and services, and import goods and services that other countries can produce more efficiently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>42", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INTERNATIONAL TRADE : ECONOMIC INTEGRATION IN AFRICA", "question": "Trade among West African countries is poor because the", "images": [], "options": {"A": "countries are self-sufficient", "B": "communication links are weak", "C": "number of banks is insufficient", "D": "people are not enterprising"}, "answer": "B", "explanation": "Trade among West African countries is poor because the communication links are weak. This means that the infrastructure for trade such as roads, railways, ports, and internet connectivity is not well developed, making it difficult for goods and services to move efficiently across borders.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>43", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "A policy by which governments restrict the amount of foreign currencies bought and sold is known as", "images": [], "options": {"A": "devaluation", "B": "credit creation", "C": "exchange control", "D": "export promotion"}, "answer": "C", "explanation": "A policy by which governments restrict the amount of foreign currencies bought and sold is known as exchange control. Exchange control is a measure taken by a government to regulate the flow of its currency in and out of the country. It is often used to prevent capital flight, stabilize the exchange rate, and control inflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>44", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Which of the following items is under the capital account of a balance of payments?", "images": [], "options": {"A": "repayments of foreign loans", "B": "visible imports", "C": "invisible exports", "D": "cocoa exports"}, "answer": "A", "explanation": "The capital account in a balance of payments records all international purchases and sales of assets such as money, stocks, bonds, etc. Repayments of foreign loans fall under this category as it involves the transfer of assets between countries. Visible imports, invisible exports, and cocoa exports are all part of the current account, not the capital account.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>45", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "A surplus in the balance of payments should be used to", "images": [], "options": {"A": "subsidize multinational companies", "B": "build infrastructure for friendly nations", "C": "make donation to developed countries", "D": "buy investments overseas"}, "answer": "D", "explanation": "A surplus in the balance of payments means that a country has more money coming in from exports than it is spending on imports. This surplus can be used to buy investments overseas, which can provide a return on investment and further strengthen the country's financial position. The other options do not directly contribute to the economic growth or financial stability of the country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>46", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Development planning which take an overall view of the economy is described as", "images": [], "options": {"A": "aggregate economic planning", "B": "disaggregated economic planning", "C": "sectorial economic planning", "D": "system economic planning"}, "answer": "A", "explanation": "Aggregate economic planning refers to the process of setting broad economic goals for an entire economy. This type of planning takes an overall view of the economy, considering all sectors and aspects of economic activity. The other options refer to more specific types of planning that focus on individual sectors or aspects of the economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>47", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "The national income of a country can be estimated by the", "images": [], "options": {"A": "cost-benefit method", "B": "distribution method", "C": "expenditure method", "D": "consumption method"}, "answer": "C", "explanation": "The national income of a country can be estimated by the expenditure method. This method involves adding up all the spending in the economy including consumption, investment, government spending, and net exports. The cost-benefit method is not a method for estimating national income, it is a method for evaluating the social and economic advantages and disadvantages of a project. The distribution method is not a recognized method for estimating national income. The consumption method is not a recognized method for estimating national income, it is a component of the expenditure method.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>48", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "Which of the following is excluded when estimating national income?", "images": [], "options": {"A": "dividends", "B": "wages and salaries", "C": "transfer payments", "D": "profits"}, "answer": "C", "explanation": "When estimating national income, transfer payments are excluded. Transfer payments are payments made by the government to individuals without any goods or services being received in return. They are not included in the calculation of national income because they do not represent production. Dividends, wages and salaries, and profits are all forms of income and are included in the calculation of national income.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2004>49", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "ECONOMIC INTEGRATION : PROBLEMS OF ECONOMIC INTEGRATION IN WEST AFRICA- ECOWAS", "question": "The Economic Community of West African States (ECOWAS) has been slow in achieving its objectives because of", "images": [], "options": {"A": "political instability in member states", "B": "the activities of multinationals", "C": "inadequate personnel at the secretariat", "D": "inadequate international support"}, "answer": "A", "explanation": "The Economic Community of West African States (ECOWAS) has been slow in achieving its objectives because of political instability in member states. Political instability can hinder economic integration and cooperation, which are key objectives of ECOWAS. The activities of multinationals, inadequate personnel at the secretariat, and inadequate international support may affect the operations of ECOWAS, but they are not the primary reasons for its slow progress.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2004>50", "subject": "Economics", "year": "2004", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "A major achievement of the Organization of Petroleum Exporting Countries (OPEC) is that", "images": [], "options": {"A": "crude oil price has increased tremendously", "B": "petroleum products prices have remained low", "C": "producing countries are highly industrialized", "D": "price of crude oil has remained relatively stable"}, "answer": "A", "explanation": "The Organization of Petroleum Exporting Countries (OPEC) is a group of oil-producing countries that came together to regulate the supply and price of oil. One of their major achievements is that they have been able to increase the price of crude oil tremendously. This is done by controlling the supply of oil in the market. When supply is reduced, the price increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>1", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Economic activities are undertaken to solve the problem of", "images": [], "options": {"A": "consumption", "B": "opportunity cost", "C": "Production", "D": "Scarcity"}, "answer": "D", "explanation": "Economic activities such as production, distribution, and consumption are undertaken to solve the problem of scarcity. Scarcity is a fundamental economic problem of having seemingly unlimited human wants and needs in a world with limited resources. Therefore, societies cannot produce enough to fulfill everyone's wants and needs, leading to the need for economic activities to allocate these scarce resources.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2005>2", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "Farming , mining and fishing are", "images": [], "options": {"A": "primary production", "B": "Secondary production", "C": "Tertiary production", "D": "intermediate production"}, "answer": "A", "explanation": "Farming, mining, and fishing are all examples of primary production. Primary production involves the extraction of raw materials from the earth. This includes agriculture (farming), mining, and fishing. Secondary production involves the transformation of raw materials into finished goods, while tertiary production involves the provision of services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2005>3", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT", "question": "A list of consumer's want arranged in order of priority is know as", "images": [], "options": {"A": "A budget", "B": "an opportunity cost", "C": "a scale of preference", "D": "choice"}, "answer": "C", "explanation": "A list of consumer's wants arranged in order of priority is known as a scale of preference. This is a basic economic concept that describes how individuals or societies choose from the limited resources available to them. It involves ranking different options in order of importance to make a choice.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2005>4", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "The 150.00 naira which olu would have used to purchase a textbook was used to buy a T-shirt.", "images": [], "options": {"A": "Olu's real cost is 15.00 naira", "B": "Olu opportuity cost costis the T-shirt he bought", "C": "Olu's opportunity cost is the text book", "D": "Olu's opportunity cost is the T-shirt he bought"}, "answer": "C", "explanation": "Opportunity cost is a key concept in economics, and it refers to the loss of potential gain from other alternatives when one alternative is chosen. In this case, Olu's opportunity cost is the textbook he could have bought with the 150.00 naira but chose to buy a T-shirt instead.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>5", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "The renumeration of the entrepreneur as factor of production is called", "images": [], "options": {"A": "wages", "B": "salary", "C": "interest", "D": "profit"}, "answer": "D", "explanation": "In economics, the remuneration of the entrepreneur as a factor of production is called profit. Profit is the financial gain realized when the amount of revenue gained from a business activity exceeds the expenses, costs, and taxes needed to sustain the activity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2005>6", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "The production factor , whose entire world supply is fixed is", "images": [], "options": {"A": "Land", "B": "skilled labour", "C": "capital goods", "D": "enterpreneurship"}, "answer": "A", "explanation": "The factor of production whose entire world supply is fixed is Land. This is because the total land area of the earth is fixed and cannot be increased or decreased. Skilled labour, capital goods, and entrepreneurship can all be increased or decreased depending on various factors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>7", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "when all factor input are reduced by half , the production possiblity curve will shift", "images": [], "options": {"A": "outward", "B": "inward", "C": "downwards", "D": "upwards"}, "answer": "B", "explanation": "When all factor inputs are reduced by half, the production possibility curve will shift inward. The production possibility curve represents the maximum output possibilities for two goods, given a set of inputs consisting of resources and other factors. When the amount of inputs is reduced, the amount of goods that can be produced also decreases, causing the curve to shift inward.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2005>8", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION", "question": "When a worker changes from one type of job to another, it is called", "images": [], "options": {"A": "geographical mobility of labour", "B": "occupatational mobility of labour", "C": "immobility of labour", "D": "rural-urban"}, "answer": "B", "explanation": "When a worker changes from one type of job to another, it is called occupational mobility of labour. Occupational mobility refers to the ability of workers to switch career fields in order to find gainful employment or meet labor market needs. Geographical mobility of labour refers to the ability of workers to move from one location to another, while immobility of labour refers to the inability of workers to move from one job or location to another.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>9", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "Which of the following determines the size of a country's population ?    I. Birth rate  II. Death rate   III. Migration rate  IV importation   V unemployement", "images": [], "options": {"A": "I, II amd V", "B": "II and IV", "C": "I,  II and III", "D": "I and V"}, "answer": "C", "explanation": "The size of a country's population is determined by the birth rate, death rate, and migration rate. Birth rate refers to the number of live births per 1,000 people per year. Death rate refers to the number of deaths per 1,000 people per year. Migration rate refers to the number of people who move into (immigration) and out of (emigration) a country. Importation and unemployment do not directly determine the size of a country's population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>10", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION", "question": "Age distribution is important because it helps the government to", "images": [], "options": {"A": "Check rural-urban drift", "B": "determines the number of foreigners", "C": "Determines the number of factories", "D": "undertaken effectively planning"}, "answer": "D", "explanation": "Age distribution is important for effective planning by the government. It helps the government to understand the demographic structure of the population, which is crucial for planning in areas such as education, healthcare, and social services. It does not directly help in checking rural-urban drift, determining the number of foreigners, or the number of factories.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>11", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "MARKET STRUCTURE : FORMS OF MARKET STRUCTURE", "question": "A group of firms producing similar commodities for the same market constitute", "images": [], "options": {"A": "cartel", "B": "an industry", "C": "A co-operative", "D": "wholesalers"}, "answer": "B", "explanation": "A group of firms producing similar commodities for the same market constitute an industry. An industry is a group of companies that are related based on their primary business activities. In modern economies, there are dozens of industry classifications. A cartel is a group of independent market participants who collude with each other in order to improve their profits and dominate the market. A co-operative is an organization owned by the members who use its services or by people who work there. Wholesalers are the entities in the supply chain that buy in bulk and sell to resellers rather than to consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>12", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "A factor that has slowed dow the rate of industries deveopment in west Africa is", "images": [], "options": {"A": "inadequate techanology", "B": "inreasing rate of manpower production", "C": "Increased demand for local goods", "D": "Intervention of the goverment in business activities"}, "answer": "A", "explanation": "Inadequate technology can hinder the growth and development of industries.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2005>13", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "To achieve an equilirbium position , the consumer must buy so much of each commodity whose price is equal to its", "images": [], "options": {"A": "marginal utility", "B": "diminishing utility", "C": "total utility", "D": "average utility"}, "answer": "A", "explanation": "In economics, a consumer is said to be in equilibrium when the price of a commodity is equal to its marginal utility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>14", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION", "question": "Price control refers to", "images": [], "options": {"A": "The ways of making more goods available in the market", "B": "a policy of ensuring stable price of ensuring stables price in market", "C": "a general redction i price level", "D": "effective working of the forces of demand an supply"}, "answer": "B", "explanation": "Price control refers to government intervention in the market to control the prices of goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>15", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The desire for goods without the ability to pay is called", "images": [], "options": {"A": "choice", "B": "effective demand", "C": "joint demand", "D": "wants"}, "answer": "D", "explanation": "A want refers to a desire for a good or service, regardless of whether the individual has the ability to pay for it.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2005>16", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Amout of goods offered to market at respective prices and presented i a table is called", "images": [], "options": {"A": "price schedule", "B": "supply schedule", "C": "scale of preference", "D": "demand schedule"}, "answer": "B", "explanation": "A supply schedule is a table that shows the quantity of a good that producers are willing and able to supply at various prices.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2005>17", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "At the equilibriumprices , quantity demnded is", "images": [], "options": {"A": "greater than quality supplied", "B": "equal to quantity supplied", "C": "less than quantity", "D": "equal to excess supply"}, "answer": "B", "explanation": "Equilibrium in economics is the state where supply equals demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>18", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "If the government fixed price of commodiy above the equilibrium price, quantity supplied will be", "images": [], "options": {"A": "less than quatity demanded", "B": "equal to quantity demanded", "C": "greater than quantity demanded", "D": "equal to zero"}, "answer": "C", "explanation": "If the government fixed price of a commodity above the equilibrium price, the quantity supplied will be greater than quantity demanded. It is shown in the diagram below;", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>19", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "One of the factors determining price elasticity of demand for commodity is the", "images": [], "options": {"A": "Availability of close substitutes", "B": "number of producer", "C": "Government policy", "D": "price of other commodity"}, "answer": "A", "explanation": "The price elasticity of demand for a commodity is determined by several factors, one of which is the availability of close substitutes. If a product has many close substitutes, consumers can easily switch to another product when the price of the original product increases, making the demand for the original product more elastic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>20", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "if elasticity of demand for a commodity is less than one demand is", "images": [], "options": {"A": "unitary elasticity", "B": "inelasticity", "C": "infinitely elastic", "D": "zero elastic"}, "answer": "B", "explanation": "Elasticity of demand measures how much the quantity demanded of a good responds to a change in the price of that good. If the elasticity of demand for a commodity is less than one, it means that the quantity demanded is not very responsive to price changes, which is referred to as inelastic demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>21", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "The transfer of ownership of a public eneterprise to individual and firms is called", "images": [], "options": {"A": "Commercialization", "B": "nationalization", "C": "privatization", "D": "restructuring"}, "answer": "C", "explanation": "The transfer of ownership of a public enterprise to individuals and firms is called privatization. This process involves the sale of public assets to private owners, often with the aim of increasing efficiency and productivity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>22", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "One-man businesses are popular in west Africabecause of all the following except the", "images": [], "options": {"A": "ease of entry", "B": "small capital required", "C": "limited entrepreneurial skill needed", "D": "tendency to becomes joint-stock companies"}, "answer": "D", "explanation": "One-man businesses, also known as sole proprietorships, are popular in West Africa due to their ease of entry, small capital requirement, and limited entrepreneurial skill needed. However, they rarely become joint-stock companies. A joint-stock company is a type of business entity where the company's stock is owned jointly by shareholders. This is a more complex business structure that requires more capital, more formalities, and more management skills. Therefore, the tendency to become joint-stock companies is not a reason for the popularity of one-man businesses in West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>23", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER", "question": "Wholesalers are often criticitized because they", "images": [], "options": {"A": "help to break the bulk", "B": "finance producers", "C": "increase price", "D": "provides after-sales services"}, "answer": "C", "explanation": "Wholesalers are often criticized because they increase prices. Wholesalers buy goods in bulk from manufacturers and sell them in smaller quantities to retailers. The price increase is due to the fact that wholesalers add a markup to the price they paid to the manufacturer to cover their operating costs and to make a profit. The other options are actually benefits of wholesalers: they help to break the bulk (making it easier for retailers to buy in quantities they can handle), they finance producers (by buying in bulk and paying upfront), and they provide after-sales services (such as handling returns).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>24", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES", "question": "In which of the following business units are the owners mostly the customers?", "images": [], "options": {"A": "Co-operative", "B": "limited liability companies", "C": "partnerships", "D": "public corporations"}, "answer": "A", "explanation": "In co-operative business units, the owners are mostly the customers. A cooperative is a business or organization owned by and operated for the benefit of those using its services. The members, who use the co-op's services, are also its owners. In contrast, in limited liability companies, partnerships, and public corporations, the owners are not necessarily the customers. They are entities or individuals who have invested capital into the business and own shares or stakes in the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>25", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE RETAILER", "question": "Information about new goods is passed to the buyers through", "images": [], "options": {"A": "advertising", "B": "retail trade", "C": "the manufacturer", "D": "wholesaler trade"}, "answer": "A", "explanation": "Advertising is the primary method through which information about new goods is passed to buyers. It is a marketing communication that employs an openly sponsored, non-personal message to promote or sell a product, service or idea. It is not typically the role of retail trade, the manufacturer, or wholesaler trade to pass information about new goods to buyers, although they may play a part in the process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>26", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "PN equals average revenue or marginal revenue cure of", "images": ["Economics/imgs/2005/l171.png"], "options": {"A": "An imperfect competitive firm", "B": "a monopoly", "C": "a perfectly competitive firm", "D": "a monopolistic competitive firm"}, "answer": "C", "explanation": "The figure PN in the diagram is Average revenue or marginal revenue of a perfect market or perfectly competitive firm.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2005>27", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION", "question": "PN equals average revenue or marginal revenue cure of     The pofit of the producer can be calculated as", "images": ["Economics/imgs/2005/l171.png"], "options": {"A": "total cost less total revenue", "B": "average revenue less average cost", "C": "total revenue less total cost", "D": "marginal revenue less marginal cost"}, "answer": "C", "explanation": "Profit is the total revenue less total cost i.e   Profit = TR = TC", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2005>28", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "MONEY : INTRODUCTION", "question": "The direct exchange of one goods for another without the use of money is known as", "images": [], "options": {"A": "Foreign exhange", "B": "exchange rate", "C": "expenditure", "D": "barter"}, "answer": "D", "explanation": "The direct exchange of one good for another without the use of money is known as barter. Barter is a system of exchange where goods or services are directly exchanged for other goods or services without using a medium of exchange, such as money. It is distinguishable from gift economies in many ways; one of them is that the reciprocal exchange is immediate and not delayed in time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2005>29", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "MONEY : CHARACTERISTICS OF MONEY", "question": "Acceptability , durability, homogenity , and portability are all attributes of good", "images": [], "options": {"A": "markets", "B": "money", "C": "BANK", "D": "government"}, "answer": "B", "explanation": "Acceptability, durability, homogeneity, and portability are all attributes of good money. Money is any item or verifiable record that is generally accepted as payment for goods and services and repayment of debts, such as taxes, in a particular country or socio-economic context. The main functions of money are distinguished as: a medium of exchange, a unit of account, a store of value and sometimes, a standard of deferred payment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2005>30", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "The term demand for money means", "images": [], "options": {"A": "desire to borrow money from people", "B": "desire of a individual to invest all his money projects", "C": "willingness of people to hold money", "D": "willingness of people to keep"}, "answer": "C", "explanation": "The term 'demand for money' in economics refers to the total amount of money that all sectors in the economy would like to hold in liquid form. This is not about borrowing or investing money, but about the willingness to hold money. Therefore, the correct answer is 'willingness of people to hold money'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>31", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "INFLATION & DEFLATION : INTRODUCTION", "question": "A persistent and appreciate rise in the general level of prices is known  as", "images": [], "options": {"A": "depreciation", "B": "inflation", "C": "deflation", "D": "production"}, "answer": "B", "explanation": "A persistent and appreciable rise in the general level of prices is known as inflation. Inflation is a measure of the rate of price increases in an economy over a period of time. It is not depreciation, deflation, or production. Therefore, the correct answer is 'inflation'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>32", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "To a commercial bank , deposits are", "images": [], "options": {"A": "liabilities", "B": "assets", "C": "capital", "D": "production"}, "answer": "A", "explanation": "In the balance sheet of a commercial bank, deposits are considered as liabilities. This is because the bank is obliged to return the money to the depositors on demand or after a certain period. Therefore, the correct answer is 'liability'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>33", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "The lender of last resort in the banking system is he", "images": [], "options": {"A": "industrial bank", "B": "mortgage bank", "C": "commercial bank", "D": "central bank"}, "answer": "D", "explanation": "The Central Bank is known as the lender of last resort in the banking system. This is because it provides financial support to banks or financial institutions facing financial difficulties. The Central Bank can lend money to these institutions to prevent their collapse, which could have a negative impact on the economy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2005>34", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CHEQUES", "question": "Discounting a bill of exchange means the bill is", "images": [], "options": {"A": "cash over the counter", "B": "sold on the stock exchange", "C": "bought for less than its face value", "D": "Sold to the highest"}, "answer": "C", "explanation": "Discounting a bill of exchange means buying it for less than its face value. The difference between the face value of the bill and its purchase price is the 'discount'. This is a common practice in finance where a bill of exchange is sold before its maturity date for a price less than its face value.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2005>35", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "the central bank control credit in the economy through the use of", "images": [], "options": {"A": "legal tender", "B": "travellers cheques", "C": "foreign exchange instrument", "D": "open market operation"}, "answer": "D", "explanation": "The Central Bank controls credit in the economy through the use of open market operations. Open market operations involve the buying and selling of government securities in the open market in order to expand or contract the amount of money in the banking system. By doing so, the Central Bank can influence interest rates and control credit in the economy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2005>36", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION", "question": "Among principles of taxation propounded by Adam smith was that", "images": [], "options": {"A": "a tax should be impossible to evade", "B": "a tax should be convenient to pay", "C": "no tax should be levied on food", "D": "there should be no taxation without representation"}, "answer": "B", "explanation": "Adam Smith, a renowned economist, proposed four principles of taxation, one of which is that taxes should be convenient to pay. This principle states that a tax should be levied at the time and in the manner in which it is most likely to be convenient for the contributor to pay it. None of the other options align with Adam Smith's principles of taxation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>37", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Mr. Bala's income is $800.00 per month while that mr jatau is $1200.00 if messres, Bala and jatau paid $80 and $120.00 repectively as taxes the tax system is", "images": [], "options": {"A": "progressive", "B": "regressive", "C": "proportional", "D": "ad-valorem"}, "answer": "C", "explanation": "The tax system described in the question is proportional. In a proportional tax system, all taxpayers pay the same percentage of their income, regardless of the actual amount of income. In this case, both Mr. Bala and Mr. Jatau are paying 10% of their income as tax ($80/$800 = 10% and $120/$1200 = 10%), which is characteristic of a proportional tax system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>38", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS", "question": "Government revenue from the groundnut industry is from", "images": [], "options": {"A": "licenses", "B": "rent", "C": "royalties", "D": "taxes"}, "answer": "D", "explanation": "Government revenue from industries such as the groundnut industry is typically derived from taxes. These taxes can be levied on the income or profits of the industry, or on the goods and services it produces. Licenses, rent, and royalties can also provide revenue, but these are not the primary sources of government revenue from industries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>39", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "The theory of comparative cost advvantage is associated with", "images": [], "options": {"A": "Alfred marshal", "B": "Adam smith", "C": "David Ricado", "D": "J.B . Say"}, "answer": "C", "explanation": "The theory of comparative cost advantage is associated with David Ricardo. This theory states that a country should specialize in producing and exporting only those goods and services which it can produce more efficiently (at a lower opportunity cost) than other goods and services (which it should import).", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2005>40", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "When the value of a nation's exports is greater than its imports", "images": [], "options": {"A": "a favourable balance balance of trade exists", "B": "an unfavourable balance of payment exists", "C": "The net foreig trade is zero", "D": "inflation occurs"}, "answer": "A", "explanation": "When the value of a nation's exports is greater than its imports, a favourable balance of trade exists. This is because the country is earning more from its exports than it is spending on imports, which is generally seen as a positive economic situation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>41", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "To improve the balance of payment position of west African countries , there must be", "images": [], "options": {"A": "removal of barriers to improtation of goods and services", "B": "increase rate of exportation of goods and services", "C": "increase domestic consumption of foriegn produced goods", "D": "the development of the local market"}, "answer": "B", "explanation": "To improve the balance of payment position of West African countries, there must be an increase in the rate of exportation of goods and services. The balance of payments is a record of all economic transactions between the residents of a country and the rest of the world. It is improved by increasing exports, which brings more foreign currency into the country, or by reducing imports, which sends less currency out of the country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>42", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "The economic community of West African states (ECOWAS) is an examle of", "images": [], "options": {"A": "bilateral trade", "B": "Economic integration", "C": "regional marketin board", "D": "international competition"}, "answer": "B", "explanation": "The Economic Community of West African States (ECOWAS) is an example of economic integration. Economic integration is an arrangement among nations that typically includes the reduction or elimination of trade barriers and the coordination of monetary and fiscal policies. ECOWAS, established in 1975, is a regional group of fifteen West African countries, designed to promote economic integration across the region.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>43", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "One reason for the low agricultural production in west Africa countries is that", "images": [], "options": {"A": "agricultural employs the highest percentage of labour force", "B": "Too much money is invested in agriculture", "C": "farmers lack the finance and technology required", "D": "farm are too large"}, "answer": "C", "explanation": "One reason for the low agricultural production in West African countries is that farmers lack the finance and technology required. Agriculture in many West African countries is often characterized by low productivity due to factors such as lack of access to finance, inadequate technology, poor infrastructure, and lack of modern farming techniques.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>44", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "Mono-product economies are those that", "images": [], "options": {"A": "Produce one main commodity", "B": "produce only raw materials", "C": "depends on export of their raw materials", "D": "specialize in agricultural industries"}, "answer": "A", "explanation": "Mono-product economies are those that produce one main commodity. These economies are heavily dependent on the production and export of a single commodity, which often makes them vulnerable to price fluctuations and economic instability. Examples of such economies include oil in Saudi Arabia and Nigeria, and diamonds in Botswana.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>45", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "MARKET STRUCTURE : MEANING OF MARKET & TYPES", "question": "An essentials charateristics of a market economy is", "images": [], "options": {"A": "goverment control", "B": "producer surplus", "C": "consumer surplus", "D": "Consumer Sovereignty"}, "answer": "D", "explanation": "A market economy is characterized by consumer sovereignty. This means that the production and distribution of goods and services are guided by the aggregate interactions of a community's citizens. In other words, the consumers determine what goods and services are produced based on their demands. Therefore, the correct answer is 'Consumer Sovereignty'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>46", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "In a capitalist  system goods are produced for those who", "images": [], "options": {"A": "want them most but cannot pay for them", "B": "can pay for them but do not want them", "C": "want them and can also pay for them", "D": "are dependent on the labout force"}, "answer": "C", "explanation": "In a capitalist system, goods are produced for those who want them and can also pay for them. This is because capitalism is an economic system where private entities own the factors of production. The four factors are entrepreneurship, capital goods, natural resources, and labor. The owners of these resources compete with one another over consumers, who in turn, pay to utilize them. Therefore, the correct answer is 'want them and can also pay for them'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>47", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "An economy which exibits features of a both private and state enterprises is known as a", "images": [], "options": {"A": "capitalist economy", "B": "mixed economy", "C": "communist economy", "D": "socialist economy"}, "answer": "B", "explanation": "An economy that exhibits features of both private and state enterprises is known as a mixed economy. This is because a mixed economy is a system that combines aspects of both capitalism and socialism. It includes a variety of public and government control, as well as economic planning. Therefore, the correct answer is 'mixed economy'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>48", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "In calculating the national income of a country X, the cost of both raw materials and the finished products were included . This is a case of", "images": [], "options": {"A": "double counting", "B": "price fluntuation", "C": "price differentiation", "D": "price discrimination"}, "answer": "A", "explanation": "The inclusion of both the cost of raw materials and the finished products in the calculation of a country's national income is a case of double counting. Double counting in economics refers to the error of counting the same costs or benefits more than once in the process of economic calculation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2005>49", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Economic development is defined as", "images": [], "options": {"A": "outward shift of the production possibility curve", "B": "availability of more goods and services", "C": "Growth accompanied by qualitative in living standards", "D": "Growth in the national income"}, "answer": "C", "explanation": "Economic development is defined as growth accompanied by qualitative improvement in living standards. It is not just about the availability of more goods and services or growth in the national income, but also about the improvement in the quality of life, which includes factors like health, education, and equality of opportunity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2005>50", "subject": "Economics", "year": "2005", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : OPEC", "question": "Which of the following is not an objective of the organisation of the petroluem exporting countries(OPEC)?", "images": [], "options": {"A": "Stabilization of oil prices", "B": "co-ordinating prices", "C": "Harmonizing oil prices", "D": "stagnation of developed economies"}, "answer": "D", "explanation": "The objectives of the Organization of the Petroleum Exporting Countries (OPEC) include the stabilization, coordination, and harmonization of oil prices. However, causing stagnation of developed economies is not an objective of OPEC. OPEC's mission is to coordinate and unify the petroleum policies of its Member Countries and ensure the stabilization of oil markets in order to secure an efficient, economic and regular supply of petroleum to consumers, a steady income to producers and a fair return on capital for those investing in the petroleum industry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>1", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The study of economics enables individuals to", "images": [], "options": {"A": "change jobs", "B": "evade taxes", "C": "accumulate huge wealth", "D": "make rational decisions"}, "answer": "D", "explanation": "Economics is a social science that studies how individuals, governments, firms, and nations make choices on allocating scarce resources to satisfy their unlimited wants. Therefore, it helps individuals to make rational decisions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2006>2", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Most of the problems of economies arise as a result of", "images": [], "options": {"A": "competing demands for scarce resources", "B": "increase in demand for more goods and services", "C": "the desire for producers to supply more goods and services", "D": "the need to reduce the level of poverty"}, "answer": "A", "explanation": "The fundamental economic problem is the issue of scarcity. Scarcity means that resources are limited and can't meet all our wants and needs. The competing demands for these scarce resources often lead to problems in an economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>3", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH", "question": "Which of the following tools of economic analysis is used when data contains more than one category?", "images": [], "options": {"A": "Bar charts", "B": "Component bar charts", "C": "Graphs", "D": "Symbolic statements"}, "answer": "B", "explanation": "Component bar charts are used to represent and compare different parts of a whole. Each bar in the chart represents a whole, and segments in the bar represent different parts or categories of that whole.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>4", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "The reward of capital as a factor of production is", "images": [], "options": {"A": "rent", "B": "wage", "C": "interest", "D": "commission"}, "answer": "C", "explanation": "The reward for capital as a factor of production is interest. In economics, the four factors of production are land, labor, capital, and entrepreneurship. Each factor receives a different type of payment for its services. Land receives rent, labor receives wages, capital receives interest, and entrepreneurship receives profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2006>5", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Minning is an example of", "images": [], "options": {"A": "tertiary production", "B": "primary production", "C": "secondary production", "D": "advanced production"}, "answer": "B", "explanation": "Mining is an example of primary production. In economics, the three stages of production are primary, secondary, and tertiary. Primary production involves the extraction of raw materials from the earth, such as mining. Secondary production involves the transformation of raw or intermediate materials into goods. Tertiary production involves the supply of services to consumers and businesses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2006>6", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "An owner-manager of a firm can also be called", "images": [], "options": {"A": "a shareholder", "B": "an entrepreneur", "C": "an employer", "D": "a chairman"}, "answer": "B", "explanation": "An owner-manager of a firm can also be called an entrepreneur. An entrepreneur is a person who sets up a business or businesses, taking on financial risks in the hope of profit. They are often the owner and manager of the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2006>7", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "if the fixed cost of a firm is 800 Naira and its variable cost is 2,700 Naira while its total output is 100 units, what is the average cost of the firm?", "images": [], "options": {"A": "25 Naira", "B": "35 Naira", "C": "45 Naira", "D": "50 Naira"}, "answer": "B", "explanation": "Total cost = Fixed cost + variable cost       Average cost = Total cost/Quantity  Fixed cost = ₦800  Variable cost = ₦2,700  Total cost = ₦800 + ₦2700   = ₦3,500  Average cost = ₦3,500/100 = ₦35       Hence, average cost (AC) in the cost per unit of the production is ₦35      The total cost is the sum total of producing a given commodity.   Fixed cost is the cost that does not vary.   Variable cost is the cost of production that varies with changes in the level of production. e.g raw materials, salary.       Diagramatically, the ralation between TC and VC is shown below", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>8", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "Distribution of goods and services is hindered by", "images": [], "options": {"A": "good road network", "B": "efficient storage facilities", "C": "too many middlemen", "D": "adequate market information"}, "answer": "C", "explanation": "The distribution of goods and services can be hindered by too many middlemen. Middlemen are intermediaries between producers and consumers. They buy goods from producers and sell them to consumers. While they can help to distribute goods and services, having too many of them can lead to inefficiencies and increased costs, which can hinder distribution. The other options listed, such as good road network, efficient storage facilities, and adequate market information, are factors that facilitate, not hinder, the distribution of goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>9", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND", "question": "A movement along the same demand curve either upwards or downwards as a result of changes in price implies", "images": [], "options": {"A": "a change in demand", "B": "a change in quantity demanded", "C": "an increase in demand", "D": "a shift in the demand curve to the right"}, "answer": "B", "explanation": "Change in quantity demanded, also called movement along a demand curve is when there is a change in the quantity demanded, the demand curve does not shift. There is a movement along a particular demand curve. The main determinant of a change in the quantity of a commodity demanded is the price of the commodity. The quantity of a commodity demanded changes with price. More is bought at a lower price than at a higher price.   A change in the quantity demanded is of two types.   (1) Increases in the quantity demanded: This occurs if the quantity bought increases as a result a decrease on the price of the commodity.          Decrease in the price of the commodity from ₦20 to ₦40 brought about an increase in quantity from 15 units to 25 units      2. Decrease in demand: This occurs if the quantity of the commodity bought decreases as the price increases.      An increase in the price of the commodity from ₦20 to ₦40 brought about a decrease in the quantity from ₦60 units to ₦30 units.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>10", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "Middlemen in an economy performs the function of", "images": [], "options": {"A": "distribution", "B": "exchange", "C": "hoarding", "D": "protection"}, "answer": "A", "explanation": "Middlemen in an economy perform the function of distribution. They buy goods from producers and sell them to consumers, thereby helping to distribute goods and services throughout the economy. The other options listed, such as exchange, hoarding, and protection, are not primary functions of middlemen.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2006>11", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "One of the factors affecting geographical distribution of population is", "images": [], "options": {"A": "high birth rate", "B": "high death rate", "C": "encouragement of early marriages in rural areas", "D": "climatic conditions of the different part of the country"}, "answer": "D", "explanation": "One of the factors affecting geographical distribution of population is the climatic conditions of the different parts of the country. People tend to live in areas with favorable climatic conditions, such as moderate temperatures and rainfall. Areas with harsh climatic conditions, such as extreme temperatures or heavy rainfall, are likely to have fewer inhabitants. The other options listed, such as high birth rate, high death rate, and encouragement of early marriages in rural areas, are demographic factors that can affect the size of the population, but they do not directly affect its geographical distribution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>12", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "MARKET STRUCTURE : FORMS OF MARKET STRUCTURE", "question": "Standardization of products or services is a feature of", "images": [], "options": {"A": "large films", "B": "retailers", "C": "small firms", "D": "wholesaler"}, "answer": "A", "explanation": "Standardization of products or services is a feature of large firms. This is because large firms have the resources and capacity to produce goods or services on a large scale, which often requires standardization to ensure consistency and efficiency. Standardization refers to the process of making something conform to a standard. In the context of products or services, it means making them identical or consistent in terms of quality, size, shape, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>13", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT", "question": "The amount of satisfaction obtained from the consumption of a commodity at a particular time is called", "images": [], "options": {"A": "marginal utility", "B": "diminishing utility", "C": "total utility", "D": "average utility"}, "answer": "C", "explanation": "The amount of satisfaction obtained from the consumption of a commodity at a particular time is called total utility. Total utility refers to the total satisfaction received from consuming a certain amount of a product or service. For example, if you eat three slices of pizza, your total utility is the sum of the satisfaction you get from each slice.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>14", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "What are inferior goods? These are goods", "images": [], "options": {"A": "that are generally in short supply", "B": "that are no longer in demand", "C": "whose demand falls as income increases", "D": "whose price falls as demand increases"}, "answer": "C", "explanation": "Inferior goods are goods whose demand falls as income increases. This is because as income increases, consumers tend to shift their consumption towards more expensive or higher-quality goods, reducing the demand for inferior goods. Inferior goods are typically goods that are cheaper and of lower quality compared to other goods in the market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>15", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT", "question": "In the analysis of utility theory, the basis of demand is", "images": [], "options": {"A": "marginal utility", "B": "average utility", "C": "fixed utility", "D": "diminishing utility"}, "answer": "A", "explanation": "In the analysis of utility theory, the basis of demand is marginal utility. Marginal utility refers to the additional satisfaction a consumer gets from consuming one more unit of a good or service. It is an important concept in utility theory, which is used to understand consumer behavior and market demand.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>16", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "In the normal situation, when the price of a commodity rises, the", "images": [], "options": {"A": "demand of the commodity will rise", "B": "demand for the commodity will fall", "C": "supply of the commodity will be constant", "D": "supply of the commodity will fall"}, "answer": "B", "explanation": "The law of demand states that, other things being equal, the higher the price of the commodity, the lower the quantity demanded of that commodity and vice versa.   Hence, when price rises under normal market situation, it is expected the demand for the commodity will fall. This is illustrated graphically below:          As price rises from ₦20 to ₦40, the quantity demanded fall from 60 units to 30 units.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>17", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "When the quantity of a commodity supplied increases and the quantity demanded decreases, there will be", "images": [], "options": {"A": "a rise in price", "B": "no change in price", "C": "price fluctuation", "D": "a fall in price"}, "answer": "D", "explanation": "Excess supply occurs when the supply of a commodity exceeds the demand for the commodity. In such situation of excess supply, it is expected that the price of the commodity will fall. This is illustrated below:", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>18", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "The market price of a commodity is normally determined by the", "images": [], "options": {"A": "law of demand", "B": "interaction of the forces of demand and supply", "C": "total number of people in the market", "D": "total quantity of the commodity in the market"}, "answer": "B", "explanation": "The market price of a commodity is normally determined by the interaction of the forces of demand and supply. This is a fundamental concept in economics, where the price of a good or service is set at a point where the quantity demanded by consumers equals the quantity supplied by producers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>19", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION", "question": "The mechanism which allows the price of a commodity to be fixed either above or below the equilibrium is known as", "images": [], "options": {"A": "monopolistic competition", "B": "price discrimination", "C": "perfect competitive market", "D": "price control"}, "answer": "D", "explanation": "The mechanism which allows the price of a commodity to be fixed either above or below the equilibrium is known as price control. Price control is a government measure to set prices for goods or services in a market, instead of allowing them to be determined freely by the forces of supply and demand.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>20", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "A debenture holder is entitled to payments in form of", "images": [], "options": {"A": "allowance", "B": "interest", "C": "salary", "D": "donation"}, "answer": "B", "explanation": "A debenture holder is a creditor to a company. The company pays the debenture holder a fixed rate of interest on the amount of money borrowed. Therefore, a debenture holder is entitled to payments in the form of interest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>21", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "The main difference between a private and a public enterprise is the", "images": [], "options": {"A": "amount of profit realized", "B": "mode of operation", "C": "objective of the business", "D": "ownership structure"}, "answer": "D", "explanation": "The main difference between a private and a public enterprise is the ownership structure. A private enterprise is owned by private individuals or entities, while a public enterprise is owned by the government or state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>22", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "The total amount of money raised by a company through issuance of shares to the public is", "images": [], "options": {"A": "debentures", "B": "nominal capital", "C": "ordinary shares", "D": "paid-up capital"}, "answer": "D", "explanation": "The total amount of money raised by a company through issuance of shares to the public is known as paid-up capital. It is the total amount of a company's capital that is funded by shareholders.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>23", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "Buying and selling is a function  performed mostly by the", "images": [], "options": {"A": "Insurance company", "B": "Stock exchange", "C": "merchant banks", "D": "discount houses"}, "answer": "C", "explanation": "The function of buying and selling is primarily performed by merchant banks. Merchant banks are financial institutions that deal with commercial banking needs of businesses, including underwriting, conducting research, and advising on acquisitions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>24", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "Which of the following is not a reason for establishing public enterprises?", "images": [], "options": {"A": "Discouraging investors", "B": "Opening up neglected parts of the country", "C": "Effective control of natural monopoly", "D": "Rapid economic development"}, "answer": "A", "explanation": "Public enterprises are established for various reasons such as opening up neglected parts of the country, effective control of natural monopoly, and rapid economic development. Discouraging investors is not a reason for establishing public enterprises. In fact, public enterprises often encourage investment by providing infrastructure and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>25", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "For a monopolist, the average revenue (AR) curve is", "images": [], "options": {"A": "above the total cost curve", "B": "the same as the marginal cost curve", "C": "above the marginal revenue curve", "D": "the same as that of perfect competition"}, "answer": "C", "explanation": "For a monopolist, the Average Revenue is the same as the marginal Revenue curve, i.e. the demand curve. This is illustrated below where   D = AR = Mr", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>26", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "MARKET STRUCTURE : PERFECT MARKET", "question": "Advertising expenses would not be necessary under perfect competition because", "images": [], "options": {"A": "consumers would have knowledge about the goods", "B": "cost of production would be at the maximum level", "C": "every firm would enjoy the benefits of large scale production", "D": "incomes of the consumer in the community would be high"}, "answer": "A", "explanation": "In a perfect competition market structure, all participants are assumed to have perfect knowledge. This means consumers are fully aware of the goods available in the market, their prices, and quality. Therefore, there would be no need for advertising expenses as consumers would already have knowledge about the goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>27", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "The equilibrium level of output of a monopolist is determined at a point where", "images": [], "options": {"A": "marginal cost equals average revenue", "B": "marginal cost equals average cost", "C": "marginal cost equals marginal revenue", "D": "marginal revenue equals average cost"}, "answer": "C", "explanation": "In a monopoly, the equilibrium level of output is determined at the point where marginal cost equals marginal revenue. This is because a monopolist will continue to produce as long as the marginal revenue from selling an additional unit of output is greater than the marginal cost of producing that additional unit. When marginal cost equals marginal revenue, the monopolist maximizes its profit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>28", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "MONEY : TYPES OF MONEY", "question": "Which of the following is a legal tender in West Africa?", "images": [], "options": {"A": "Treasury bill", "B": "share", "C": "Credit card", "D": "Currency"}, "answer": "D", "explanation": "Legal tender refers to the medium of payment recognized by a legal system to be valid for meeting a financial obligation. In West Africa, the legal tender is the currency issued by the respective central banks of the countries in the region. Treasury bills, shares, and credit cards are not legal tender, they are financial instruments or payment methods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2006>29", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "MONEY : SUPPLY OF MONEY", "question": "The policy of government to increase the supply of money to meet its own expenditure plans is likely to be", "images": [], "options": {"A": "speculative", "B": "deflationary", "C": "inflationary", "D": "contractionary"}, "answer": "C", "explanation": "When the government increases the supply of money to meet its own expenditure plans, it is likely to be inflationary. This is because an increase in the money supply, if not matched by an increase in the supply of goods and services, can lead to an increase in prices, which is the definition of inflation. Deflationary and contractionary policies involve reducing the money supply, while speculative does not directly relate to government expenditure plans.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>30", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "INFLATION & DEFLATION : INTRODUCTION", "question": "The tendency for prices to rise while the value of money falls is known as", "images": [], "options": {"A": "bills of exchange", "B": "inflation", "C": "depreciation", "D": "deflation"}, "answer": "B", "explanation": "Inflation is the rate at which the general level of prices for goods and services is rising, and subsequently, purchasing power is falling. Central banks attempt to limit inflation, and avoid deflation, in order to keep the economy running smoothly.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2006>31", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "One way to solve the economic problem of inflation in a country is by increasing the", "images": [], "options": {"A": "supply of commodities", "B": "supply of currency", "C": "salaries of workers", "D": "demand for commodities"}, "answer": "A", "explanation": "Inflation is caused by an imbalance between demand and supply in an economy. One way to solve the economic problem of inflation is by increasing the supply of commodities. This will help to balance the demand and supply, and thus, reduce the inflation rate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>32", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "The motive for holding money for investing in securities is referred to as", "images": [], "options": {"A": "transactionary", "B": "speculative", "C": "accumulative", "D": "deflationary"}, "answer": "B", "explanation": "The speculative motive is the desire to hold cash in order to take advantage of market opportunities, such as investing in securities when prices are low. This is one of the three motives for holding money according to Keynesian economics, the other two being the transactionary and precautionary motives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>33", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CHEQUES", "question": "A cheque book is issued to customers of a bank operating a", "images": [], "options": {"A": "saving account", "B": "time deposit account", "C": "current account", "D": "fixed deposit account"}, "answer": "C", "explanation": "A cheque book is typically issued to customers who operate a current account. A current account is a type of deposit account that caters to professionals and businessmen alike. Dealing largely with liquid deposits, this type of bank account encourages limitless withdrawals and deposits.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2006>34", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Amount proposed for payments of wages and salaries in a budget is regarded as part of", "images": [], "options": {"A": "recurrent expenditure", "B": "direct investment", "C": "recurrent revenue", "D": "capital receipts"}, "answer": "A", "explanation": "The amount proposed for payments of wages and salaries in a budget is regarded as part of recurrent expenditure. Recurrent expenditure refers to payments made by governments or organizations for all sorts of running costs. This includes salaries and wages, but also things like electricity bills, fuel for vehicles, and office supplies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>35", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The difference between the Gross National Product (GNP) and the Gross Domestic Product (GDP) is", "images": [], "options": {"A": "total interest payment", "B": "net income generated internally", "C": "total national savings", "D": "net income from abroad"}, "answer": "D", "explanation": "The difference between the Gross National Product (GNP) and the Gross Domestic Product (GDP) is the net income from abroad. GDP is the total value of all goods and services produced within a country's borders, while GNP includes all goods and services produced by its residents, no matter where they are located. Therefore, the difference between the two is the net income from abroad.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>36", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "Which of the following agricultural system is mainly for the cultivation of food crops for family consumption", "images": [], "options": {"A": "Co-operative farming", "B": "Commercial farming", "C": "Subsistence farming", "D": "Plantation farming"}, "answer": "C", "explanation": "Subsistence farming is the type of agriculture that is mainly for the cultivation of food crops for family consumption. It is a self-sufficiency farming system in which the farmers focus on growing enough food to feed themselves and their families. The output is mostly for local requirements with little or no surplus trade.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2006>37", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : ROLES", "question": "Agriculture is important to the economy of West Africa because it is the source of", "images": [], "options": {"A": "power", "B": "equipment supply", "C": "industrial input", "D": "technological progress"}, "answer": "C", "explanation": "Agriculture is important to the economy of West Africa because it is the source of industrial input. Many industries in West Africa depend on agricultural products for their raw materials. For example, the textile industry depends on cotton, the food processing industry depends on various food crops, and the beverage industry depends on crops like cocoa and coffee.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2006>38", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "The economic system in which the state takes the economic decision through detailed planning is", "images": [], "options": {"A": "capitalism", "B": "socialism", "C": "traditional economic system", "D": "mixed economic system"}, "answer": "B", "explanation": "The economic system in which the state takes the economic decision through detailed planning is socialism. In a socialist economy, the means of production are owned and controlled by the state. The government plans and controls all economic activities and there is no competition as the government controls the prices of goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>39", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "A mixed economy combine the character of both", "images": [], "options": {"A": "planned and capitalist economies", "B": "exchange and subsistence economies", "C": "subsistence and planned economies", "D": "capitalist and exchange economies"}, "answer": "A", "explanation": "A mixed economy is an economic system that combines aspects of both capitalism and socialism. It includes both privately-owned and state-owned enterprises or is a mixture of free market and central planning. Therefore, it combines the characteristics of both planned and capitalist economies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>40", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "In a rapid growing economy, a change in technology which is labour saving is likely to cause", "images": [], "options": {"A": "residual unemployment", "B": "structural employment", "C": "disguised unemployment", "D": "frictional unemployment"}, "answer": "B", "explanation": "In a rapidly growing economy, a change in technology which is labour saving is likely to cause structural unemployment. Structural unemployment occurs when there is a long-term shift in the economy that eliminates some jobs while creating others for which the unemployed workers are not qualified. In this case, the introduction of labour-saving technology reduces the demand for certain types of labour and increases demand for others, leading to structural unemployment.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>41", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "Which of the following is a form of tax evasion?", "images": [], "options": {"A": "Wrong declaration of earning", "B": "payment of flat rate tax", "C": "Constant change of employment", "D": "Low capacity utilization"}, "answer": "A", "explanation": "Tax evasion is an illegal practice where a person, organization or corporation intentionally avoids paying their true tax liability. Those caught evading taxes are generally subject to criminal charges and substantial penalties. One form of tax evasion is the wrong declaration of earnings, where an individual or business intentionally underreports their income to reduce their tax liability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>42", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION", "question": "Where the burden of a tax finally rest is called", "images": [], "options": {"A": "tax object", "B": "tax rate", "C": "incidence of taxation", "D": "system of taxation"}, "answer": "C", "explanation": "The term 'incidence of taxation' refers to the final resting place of a tax. It is the individual or group of individuals who actually bear the economic burden of the tax, regardless of who is statutorily assigned to pay the tax. The other options do not correctly define where the burden of a tax finally rests.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>43", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "An increase in the quantity of goods and services produced in a country which raises her national income is known as", "images": [], "options": {"A": "economic development", "B": "economic growth", "C": "domestic investment", "D": "productivity"}, "answer": "B", "explanation": "Economic growth refers to an increase in the quantity of goods and services produced in a country which raises her national income. Economic development, on the other hand, is a broader concept that includes economic growth but also takes into account other aspects like improvement in quality of life, reduction in poverty, etc. Domestic investment and productivity are factors that can contribute to economic growth, but they are not synonymous with it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>44", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "The formular   index of export prices/ index of import prices x 100 is used to measure the", "images": [], "options": {"A": "volume of trade between countries", "B": "direction of international trade", "C": "commodity terms of trade", "D": "volume of imports"}, "answer": "C", "explanation": "The formula given is used to calculate the 'commodity terms of trade'. It is a measure of the amount of import goods an economy can purchase per unit of export goods. It is calculated as the ratio of export prices to import prices. The other options do not correctly describe what this formula is used to measure.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>45", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Use the table below to answer this question    Products Ghana Sierra LeoneCoffee 8 tonnes 2 tonnes Cocoa 7 tonnes 5 tonnes    If specialization should take place, then", "images": [], "options": {"A": "Ghana should produce coffee and cocoa", "B": "Ghana would benefit by producing cocoa only", "C": "Siera Leon should not produce cocoa only", "D": "Sierra Leone should produce cocoa and Ghana coffee"}, "answer": "D", "explanation": "The principle of specialization suggests that countries should produce and export a limited assortment of goods for which they are particularly suited. This is determined by the country's abundance of particular resources. In this case, Ghana produces more coffee and cocoa than Sierra Leone. However, the difference in production is greater in coffee (6 tonnes difference) than in cocoa (2 tonnes difference). Therefore, Ghana should specialize in producing coffee, and Sierra Leone should specialize in producing cocoa.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>46", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "INTERNATIONAL TRADE : INTRODUCTION", "question": "Which of the following is an invisible item?", "images": [], "options": {"A": "banking services", "B": "petroleum products", "C": "Processed rice", "D": "Processed milk"}, "answer": "A", "explanation": "Invisible items in economics refer to the non-physical (non-tangible) items that are traded internationally and included in the balance of payments account. These include services such as banking, insurance, tourism, and transportation. Therefore, banking services are an example of an invisible item.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2006>47", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "In an attempt to correct a deficit balance of payments, a country may decide to increase", "images": [], "options": {"A": "domestic production", "B": "imports", "C": "domestic expenditure", "D": "tax of infant industries"}, "answer": "A", "explanation": "A deficit balance of payments means that the country is spending more on foreign trade (imports) than it is earning from selling goods and services abroad (exports). One way to correct this is to increase domestic production. By doing so, the country can reduce its reliance on imported goods and services, and it can increase its exports if the goods produced are also demanded in foreign markets.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2006>48", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "Which of the following is an objective of economic integration?", "images": [], "options": {"A": "Harmonization of cultural practices", "B": "Free movement of persons, goods and services", "C": "Payment of high tariffs", "D": "Dumping of goods in less developed countries"}, "answer": "B", "explanation": "Economic integration is an arrangement among nations that typically includes the reduction or elimination of trade barriers and the coordination of monetary and fiscal policies. The aim of economic integration is to reduce costs for both consumers and producers, as well as to increase trade between the countries taking part in the agreement. Hence, the free movement of persons, goods, and services is a primary objective of economic integration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>49", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "One of the functions of the International Monetary Fund (IMF) is to", "images": [], "options": {"A": "devaluate the currency of member states", "B": "reduce drastically the size of deficit financing of member states", "C": "give financial assistance to member states that have temporal balance of payment difficulties", "D": "discourage the rapid industrialization process in the less developed nations of the world"}, "answer": "C", "explanation": "The International Monetary Fund (IMF) is an international organization that provides financial assistance and advice to member countries. This assistance is often provided to countries experiencing balance of payments problems. This means that the IMF lends money to countries that have trouble paying for their international transactions. The IMF's primary purpose is to ensure the stability of the international monetary system—the system of exchange rates and international payments that enables countries (and their citizens) to transact with each other.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2006>50", "subject": "Economics", "year": "2006", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : OPEC", "question": "The full meaning of OPEC is", "images": [], "options": {"A": "Oil and Petroleum Exporting Countries", "B": "Organic petroleum Exporting Countries", "C": "Organization of Petrol Exporting Countries", "D": "Organization of Petroleum Exporting Countries"}, "answer": "D", "explanation": "OPEC stands for the Organization of Petroleum Exporting Countries. It is an intergovernmental organization of 13 nations, founded in 1960 in Baghdad by the first five members (Iran, Iraq, Kuwait, Saudi Arabia, and Venezuela), and headquartered since 1965 in Vienna, Austria. The purpose of OPEC is to coordinate and unify petroleum policies among Member Countries, in order to secure fair and stable prices for petroleum producers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2007>1", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The three principal economic units is any system are", "images": [], "options": {"A": "trade, industry and banking", "B": "workers, consumers and share holders", "C": "households, firms and government", "D": "companies, industry and plant"}, "answer": "C", "explanation": "The three principal economic units in any system are households, firms, and government. Households are the consumers of goods and services, firms are the producers of goods and services, and the government is the regulatory body that sets rules and regulations for the functioning of the economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>2", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT", "question": "The satisfaction derived from the use of a commodity is its", "images": [], "options": {"A": "demand", "B": "elasticity", "C": "wealth", "D": "utility"}, "answer": "D", "explanation": "The satisfaction derived from the use of a commodity is its utility. Utility is a term used in economics to describe the total satisfaction received from consuming a good or service. It is a way to quantify the value that an individual gets from consuming goods and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2007>3", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "The reward which accrues to labour for participating in production is", "images": [], "options": {"A": "interest", "B": "wage", "C": "bonus", "D": "profit"}, "answer": "B", "explanation": "The reward which accrues to labour for participating in production is wage. In economics, wages are payments made by a business to its employees for the services they provide. It is a form of compensation given to employees in exchange for their contribution to the organization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2007>4", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "POPULATION : THEORIES OF POPULATION", "question": "The malthusian theory of population does not concern itself with", "images": [], "options": {"A": "growth of foods production in arithmetic progression", "B": "growth of population growth", "C": "positive checks to population growth", "D": "development and growth of manpower"}, "answer": "D", "explanation": "The Malthusian theory of population is primarily concerned with the growth of population and the means to control it. It posits that while population grows in a geometric progression, food production grows in an arithmetic progression, leading to a potential imbalance. It also discusses 'positive checks' to population growth, such as famine, disease, and war, which increase the death rate. However, it does not concern itself with the development and growth of manpower, which is more related to human capital development and economic growth.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2007>5", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "One characteristic of labour is that", "images": [], "options": {"A": "fixed in demand", "B": "fixed in supply", "C": "mobile", "D": "untrainable"}, "answer": "C", "explanation": "Labour is characterized by its mobility. This means that labour, or workers, can move from one job, location, or industry to another in response to changes in economic conditions or personal circumstances. This mobility allows the labour market to adjust to changes in demand and supply for different types of work. The other options are not universally true. Demand and supply for labour are not fixed but vary depending on various factors such as economic conditions, technological changes, and government policies. Also, labour is not untrainable. In fact, training and education are key to improving the skills and productivity of labour.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>6", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "A country where labour is not sufficient to make proper use of the natural resources is said to have an", "images": [], "options": {"A": "active population", "B": "optimum population", "C": "over-population", "D": "under-population"}, "answer": "D", "explanation": "A country is said to be under-populated when the size of the population is too small to fully utilize the country's resources. In such a situation, there is not enough labour to make proper use of the natural resources, leading to under-utilization of the resources and lower levels of economic output and income. The other options do not accurately describe this situation. An active population refers to the part of the population that is of working age and is either employed or actively looking for work. An optimum population is when the population size is just right to fully utilize the country's resources without causing overuse or depletion. Over-population is when the population size is too large relative to the resources, leading to overuse and depletion of resources and lower living standards.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>7", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION", "question": "When population is classified according to professions, it is called", "images": [], "options": {"A": "geographical distribution of population", "B": "age distribution of population", "C": "sex distribution of population", "D": "occupational distribution of population"}, "answer": "D", "explanation": "When population is classified according to professions, it is referred to as occupational distribution of population. This is because the classification is based on the occupation or profession of the individuals in the population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>8", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "What must be added to variable cost to give total cost?", "images": [], "options": {"A": "Average total cost", "B": "Average variable cost", "C": "Fixed cost", "D": "Marginal cost"}, "answer": "C", "explanation": "Total cost is the sum of variable cost and fixed cost. Variable cost changes with the level of output while fixed cost does not change with the level of output. Therefore, to get the total cost, fixed cost must be added to variable cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>9", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "Revenue is the", "images": [], "options": {"A": "total profit made after sales", "B": "amount spent on purchase", "C": "amount of goods produced", "D": "total money realized from sales"}, "answer": "D", "explanation": "Revenue is the total money realized from sales. It is the total income of a business from its selling activities. It is calculated by multiplying the price of goods sold by the number of units sold.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2007>10", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "Given that TR is total revenue, then TRn - TR(n-1) can be used to find the", "images": [], "options": {"A": "marginal revenue", "B": "marginal cost", "C": "average cost", "D": "average revenue"}, "answer": "A", "explanation": "The expression TRn - TR(n-1) is used to find the 'marginal revenue'. Marginal revenue is the additional revenue that a firm receives from selling one more unit of a good or service. It is calculated by taking the change in total revenue (TR) and dividing it by the change in quantity (Q). In this case, TRn represents the total revenue after n units are sold, and TR(n-1) represents the total revenue after (n-1) units are sold. Therefore, the difference between these two values gives the additional revenue obtained from selling the nth unit, which is the marginal revenue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>11", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "The lower the price of a commodity, the greater the quantity demanded. This is based on the assumption that costumer's", "images": [], "options": {"A": "income is diminished", "B": "income remains the same", "C": "utility is diminished", "D": "population is high"}, "answer": "B", "explanation": "The statement 'The lower the price of a commodity, the greater the quantity demanded' is based on the assumption that the consumer's 'income remains the same'. This is a fundamental principle of demand in economics, known as the law of demand, which states that, all else being equal, as the price of a product decreases, the quantity demanded increases. This law assumes that all other factors affecting demand, such as consumer income, tastes and preferences, the price of substitute goods, etc., remain constant (ceteris paribus). If the consumer's income changes, it could affect the quantity demanded even if the price changes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>12", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "The demand for beans in bags is given by the function Q - 36 + 0.4P = 0. Where p is price in Naira and Q is quantity, find Q when p = 20 aira.", "images": [], "options": {"A": "12 bags", "B": "24 bags", "C": "28 bags", "D": "30 bags"}, "answer": "C", "explanation": "The demand function given is Q = 36 + 0.4P. To find Q when P = 20, we substitute P = 20 into the equation to get Q = 36 + 0.4*20 = 36 + 8 = 44. However, none of the options matches this answer. Therefore, none of the options is correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2007>13", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "If the price of goods X rises and the quantity demanded of goods Y increases then the two goods X and Y must be", "images": [], "options": {"A": "inferior goods", "B": "substitutes", "C": "complements", "D": "free goods"}, "answer": "B", "explanation": "If the price of good X rises and the quantity demanded of good Y increases, then the two goods X and Y must be substitutes. This is because substitutes are goods that can be used in place of each other. When the price of one good (X) increases, consumers switch to its substitute (Y), hence the quantity demanded of good Y increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>14", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "Use the following demand schedule to answer question 14.    Price (₦) Quantity Demanded 15 6013 70    The percentage change in quantity demanded is", "images": [], "options": {"A": "12.7%", "B": "15.7%", "C": "16.7%", "D": "19.7%"}, "answer": "C", "explanation": "The percentage change in quantity demanded can be calculated using the formula: ((New Quantity - Old Quantity) / Old Quantity) * 100. From the demand schedule, the old quantity is 60 and the new quantity is 70. Substituting these values into the formula gives: ((70 - 60) / 60) * 100 = 16.7%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>15", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "In a situation where demand is perfectly elastic, imposition of a tax on a commodity to raise its price will result in", "images": [], "options": {"A": "consumer increasing their demand for the product", "B": "consumer's demand for the product remaining unchanged", "C": "consumer's shifting completely to substitute products", "D": "suppliers increasing the supply of the product"}, "answer": "C", "explanation": "If demand for a commodity is perfectly elastic, the seller or producer will bear the whole burden of taxation. This is because any attempts to increase price will make the demand for the commodity fall to zero. The tax burden cannot therefore be passed to the consumer.          In the figure above, the price is represented by KL. Since the tax increases the producer's (Seller's) cost of production, the quantity supplied decreased from OQ to OQ2. However, the price remains at OP since any attempt to increase price will make demand to drop to zero. The producer or seller therefore bears the whole tax burden represented by PKLR. Hence, the answer is consumer's shifting completely to substitute products.       * The consumer has no tendency to increase demand since any price increase will make them abandon the product. (Incorrect)  * Consumer will react to a change in price, hence \"consumer's demand for the product remaining unchanged\" is not the answer.   * Supply will not increase supply since the price constant or else they will make loss.   \"suppliers increasing the supply of the product\" is therefore incorrect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>16", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "Patents are examples of", "images": [], "options": {"A": "natural barriers to entry", "B": "legal barriers to entry", "C": "illegal barriers to entry", "D": "unnatural barriers to entry"}, "answer": "B", "explanation": "Patents are examples of legal barriers to entry. A patent is a legal right granted by a government to an inventor, giving the inventor the exclusive right to manufacture, use, or sell the invention for a certain number of years. This creates a legal barrier to entry because other firms cannot legally produce the patented product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>17", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "Which of the following is a characteristic of monopoly?", "images": [], "options": {"A": "many sellers", "B": "Homogenous commodity", "C": "A single seller", "D": "Perfect knowledge"}, "answer": "C", "explanation": "A monopoly is a market structure characterized by a single seller, selling a unique product in the market. In a monopoly market, the seller faces no competition, as he is the sole seller of goods with no close substitute. Therefore, the correct answer is 'A single seller'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2007>18", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION", "question": "When a firm is nationalized", "images": [], "options": {"A": "formal owners are removed without compensation", "B": "it has the right to draw on state funds for capital investment", "C": "it must break even within a specified period", "D": "workers take control of the firm"}, "answer": "B", "explanation": "Nationalization is the process of transforming private assets into public assets by bringing them under the public ownership of a national government or state. When a firm is nationalized, it has the right to draw on state funds for capital investment. Therefore, the correct answer is 'it has the right to draw on state funds for capital investment'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>19", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "BUSINESS ORGANISATION : PARTNERSHIP", "question": "The practice whereby a business is owned by two or more independent firm is termed", "images": [], "options": {"A": "indigenization", "B": "joint venture", "C": "commercialization", "D": "foreign investment"}, "answer": "B", "explanation": "A joint venture is a business entity created by two or more parties, generally characterized by shared ownership, shared returns and risks, and shared governance. Therefore, the correct answer is 'joint venture'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2007>20", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "The main objective for privatizing a government business is to", "images": [], "options": {"A": "create additional employment", "B": "increase expenditure", "C": "source for new funds", "D": "increase the level of efficiency"}, "answer": "D", "explanation": "The main objective of privatizing a government business is to increase the level of efficiency. Privatization is the process of transferring an enterprise or industry from the public sector to the private sector. The general expectation is that private companies will be more efficient due to the profit motive, which can lead to cost savings and improvements in service quality.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>21", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "The return on investment that is just sufficient to satisfy the owner of a business is called", "images": [], "options": {"A": "economic profit", "B": "business profit", "C": "normal profit", "D": "excess profit"}, "answer": "C", "explanation": "The return on investment that is just sufficient to satisfy the owner of a business is called normal profit. Normal profit is a component of (implicit) costs and not a component of business profit. It represents the opportunity cost of the entrepreneur or the amount of profit that the entrepreneur could have made in the next best alternative venture.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>22", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "Which of the following is a middleman in the chain of distribution?", "images": [], "options": {"A": "An entrepreneur", "B": "A producer", "C": "A banker", "D": "A retailer"}, "answer": "D", "explanation": "A retailer is a middleman in the chain of distribution. The chain of distribution refers to the process of making a product or service available for use or consumption by a consumer or business user. This process involves several intermediaries such as wholesalers, distributors, and retailers before it reaches the end consumer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2007>23", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE RETAILER", "question": "A negative effect of the presence of a large number of middle men in the distributive network is", "images": [], "options": {"A": "greater variety of goods", "B": "greater quantity of goods", "C": "lower price of goods", "D": "higher price of goods"}, "answer": "D", "explanation": "The presence of a large number of middlemen in the distributive network often leads to higher prices of goods. This is because each middleman adds their own markup to the price, which increases the final price paid by the consumer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>24", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "An example of a producer goods is a", "images": [], "options": {"A": "tin of milk", "B": "hammer", "C": "loaf of bread", "D": "shirt"}, "answer": "B", "explanation": "A producer good, also known as a capital good, is a good that is used in the production of goods or services. A hammer is an example of a producer good because it can be used in the production of other goods, such as furniture or houses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2007>25", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : ROLES", "question": "To promote the development of the agriculture sector, government of West African countries should", "images": [], "options": {"A": "encourage rural-urban drift", "B": "discourage foreign investment in agriculture", "C": "support the marketing of farm produce", "D": "reduce tariff on food"}, "answer": "C", "explanation": "To promote the development of the agriculture sector, governments of West African countries should support the marketing of farm produce. This can be done through various means such as providing subsidies, improving infrastructure, and implementing policies that favor local farmers. This will help to increase the demand for locally produced agricultural products, which in turn will stimulate the growth of the agriculture sector.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2007>26", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "MONEY : CHARACTERISTICS OF MONEY", "question": "The most important quality of money is that it must be", "images": [], "options": {"A": "relatively scarce", "B": "generally acceptable", "C": "portable", "D": "durable"}, "answer": "B", "explanation": "The most important quality of money is that it must be generally acceptable. This is because for money to function as a medium of exchange, it must be accepted by all parties involved in a transaction. If money is not generally acceptable, it cannot perform its primary function as a medium of exchange.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2007>27", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "A certain amount of money is needed for everyday expenditure like buying of goods, transportation and others. This is", "images": [], "options": {"A": "transaction demand for money", "B": "precautionary demand for money", "C": "derived demand of money", "D": "speculative demand of money"}, "answer": "A", "explanation": "The need for money for everyday expenditure like buying of goods, transportation and others is referred to as transaction demand for money. This is the demand for money to carry out day-to-day transactions. It is not precautionary, derived or speculative demand for money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>28", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "Long-term loans can be secured from", "images": [], "options": {"A": "commercial banks", "B": "discount houses", "C": "development banks", "D": "acceptance houses"}, "answer": "C", "explanation": "Long-term loans can be secured from development banks. Development banks are financial institutions that provide long-term loans for capital-intensive investments such as infrastructure, construction, and other large-scale projects. Commercial banks, discount houses, and acceptance houses typically provide short-term loans.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>29", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "The value of money is generally measured in relation to the", "images": [], "options": {"A": "interest rate charged on bank loans", "B": "general price level", "C": "size of a country 's gold stock", "D": "volume of imports"}, "answer": "B", "explanation": "The value of money is generally measured in relation to the general price level. This is because the value of money is determined by the purchasing power, which is the quantity of goods and services that can be bought with a unit of money. If the general price level rises (inflation), the value of money falls as you can buy less with the same amount of money. Conversely, if the general price level falls (deflation), the value of money rises as you can buy more with the same amount of money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>30", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "Which of the following is true under rapid inflation? People", "images": [], "options": {"A": "demand less foreign exchange", "B": "set up business", "C": "rush to pay their taxes", "D": "hardly want to lend money"}, "answer": "D", "explanation": "During rapid inflation, people hardly want to lend money. This is because the value of money falls during inflation. If people lend money, the money they get back in the future will have less purchasing power than the money they lent out. Therefore, people are less willing to lend money during periods of high inflation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2007>31", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "Which of the following financial institutions was originally known as a Building Society?", "images": [], "options": {"A": "Development bank", "B": "Insurance company", "C": "Mortgage bank", "D": "Merchant bank"}, "answer": "C", "explanation": "A Mortgage bank was originally known as a Building Society. Building societies were mutual organisations owned by their members (i.e., their customers) that offered banking and related financial services, especially savings and mortgage lending. These institutions were traditionally owned by their members who had a common bond, such as living in the same area or working in the same profession. They were eventually converted into or taken over by banks or other financial institutions and became known as mortgage banks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>32", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "FINANCIAL INSTITUTION : INTRODUCTION", "question": "A non-bank financial intermediary which is regarded as a pool of risks is the", "images": [], "options": {"A": "co-operative society", "B": "stock exchange", "C": "insurance company", "D": "post office"}, "answer": "C", "explanation": "An insurance company is considered a non-bank financial intermediary that is regarded as a pool of risks. This is because insurance companies collect premiums from policyholders and use those funds to pay out claims. The risk is pooled because the losses of the few are paid by the many, with the premiums covering the risk.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>33", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "A foreign exchange market deals in", "images": [], "options": {"A": "treasury bills", "B": "currencies", "C": "government bonds", "D": "commodities"}, "answer": "B", "explanation": "A foreign exchange market deals in currencies. It is a global marketplace for the trading of national currencies against one another. Because of the worldwide reach of trade, commerce, and finance, forex markets tend to be the largest and most liquid asset markets in the world.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>34", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "Which of the following institutions assists the government in managing the national debt?", "images": [], "options": {"A": "Commercial banks", "B": "The central bank", "C": "The capital market", "D": "The world bank"}, "answer": "B", "explanation": "The central bank assists the government in managing the national debt. It does this by implementing monetary policy, which includes controlling inflation, managing the country's foreign exchange and gold reserves, and managing the government's borrowing requirements.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2007>35", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "If tax takes a large proportion of the income of people with lower income, the tax is", "images": [], "options": {"A": "progressive", "B": "proportional", "C": "regressive", "D": "ad-valorem"}, "answer": "C", "explanation": "A regressive tax is a tax that takes a larger percentage of income from low-income earners than from high-income earners. It is in opposition to a progressive tax, which takes a larger percentage from high-income earners. In this case, if tax takes a large proportion of the income of people with lower income, the tax is regressive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>36", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Which of the following is an example of direct tax?", "images": [], "options": {"A": "Import duties", "B": "Income tax", "C": "Export duties", "D": "Purchase tax"}, "answer": "B", "explanation": "A direct tax is a tax an individual or organization pays directly to the entity that imposed it. Examples of direct taxes include income taxes, property taxes, and corporate taxes. In this case, income tax is a direct tax.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>37", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "Monetary control measures are coordinated by", "images": [], "options": {"A": "development banks", "B": "merchant banks", "C": "commercial banks", "D": "the central bank"}, "answer": "D", "explanation": "Monetary control measures, such as interest rates, reserve requirements, and open market operations, are coordinated by the central bank. The central bank uses these tools to implement monetary policy with the aim of controlling inflation, consumption, growth, and liquidity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>38", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "A country whose economy is buoyant is likely to have", "images": [], "options": {"A": "a weak currency", "B": "devaluation from time to time", "C": "a strong currency", "D": "balance of payment problems"}, "answer": "C", "explanation": "A buoyant economy is one that is growing and expanding. This is often associated with a strong currency because as an economy grows, it tends to attract foreign investment. This increases demand for the country's currency, which in turn strengthens its value. Therefore, the correct answer is 'a strong currency'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2007>39", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The net national Product (NNP) is Gross National Product (GNP) less", "images": [], "options": {"A": "domestic product", "B": "foreign product", "C": "depreciation", "D": "investment"}, "answer": "C", "explanation": "Net National Product (NNP) is the total market value of all final goods and services produced by the residents of a country in a given period of time, minus depreciation. Depreciation refers to the decrease in the value of physical capital – that is, the wear and tear of machines, buildings and other physical capital over time. Therefore, the correct answer is 'depreciation'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2007>40", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "NATIONAL INCOME : DIFFERENCE BETWEEN STANDARD OF LIVING & COST OF LIVING", "question": "If the population of a country is low and the Gross National product is high, the per capita income will be", "images": [], "options": {"A": "high", "B": "low", "C": "average", "D": "unitary"}, "answer": "A", "explanation": "Per capita income is calculated by dividing the Gross National Product (GNP) by the population of a country. If the population is low and the GNP is high, the per capita income will be high because the total income is being divided among fewer people. Therefore, the correct answer is 'high'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2007>41", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The population of a country in a certain years was fifty million and the per capita income was $2050. What was the national income?", "images": [], "options": {"A": "$750,000 million", "B": "$100,250 million", "C": "$102,500 million", "D": "$125,050 million"}, "answer": "C", "explanation": "The national income of a country can be calculated by multiplying the per capita income by the population. In this case, $2050 (per capita income) * 50 million (population) = $102,500 million. Therefore, the national income was $102,500 million.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>42", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "One of the advantages of capitalism is that", "images": [], "options": {"A": "consumers are exploited", "B": "private initiative is discouraged", "C": "efficient allocation of resources is assured", "D": "job security is assured"}, "answer": "C", "explanation": "Capitalism is an economic system where private entities own the factors of production. One of the key advantages of capitalism is the efficient allocation of resources. This is because in a capitalist economy, the distribution of resources is determined by the price mechanism (an economic concept that uses the forces of supply and demand to create an equilibrium through price). Therefore, option 3 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>43", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "Which of the following contributes the highest amount of foreign exchange to the economy of West Africa nations?", "images": [], "options": {"A": "Construction, manufacturing and banking", "B": "Shipping, trading and fishing", "C": "Power, telecommunications and sports", "D": "Extraction, farming and tourism"}, "answer": "D", "explanation": "In West African nations, the highest amount of foreign exchange is contributed by extraction (mining), farming (agriculture) and tourism. These sectors are the backbone of most West African economies and they attract a lot of foreign exchange. Therefore, option 4 is correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2007>44", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "International trade depends on the concept of", "images": [], "options": {"A": "marginal cost advantage", "B": "comparative cost disadvantage", "C": "comparative cost advantage", "D": "absolute cost"}, "answer": "C", "explanation": "International trade is based on the concept of comparative cost advantage. This concept states that a country should produce and export goods that it can produce at a lower opportunity cost than other countries, and import goods that other countries can produce at a lower opportunity cost. This allows for efficient use of resources and maximizes global output.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>45", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "INTERNATIONAL TRADE : INTRODUCTION", "question": "One advantage of international trade is that", "images": [], "options": {"A": "countries depend on each other", "B": "it introduces variation in prices", "C": "it increases demand for foreign goods", "D": "it makes variety of goods available"}, "answer": "D", "explanation": "One of the main advantages of international trade is that it makes a variety of goods available to consumers. This is because different countries have different resources and capabilities, allowing them to produce different types of goods. By trading internationally, countries can access a wider range of goods than they could produce domestically.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>46", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "The practice of selling goods overseas and often below the cost of production  is known as", "images": [], "options": {"A": "retailing", "B": "dumping", "C": "internal trade", "D": "advertising"}, "answer": "B", "explanation": "The practice of selling goods overseas, often below the cost of production, is known as dumping. This is often done to gain market share in a foreign market or to offload excess production. It can have negative effects on the domestic industries of the importing country, as they may struggle to compete with the low prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>47", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "A summary of all the receipts and payments of a country in international transaction is called", "images": [], "options": {"A": "terms of trade", "B": "balance of payment", "C": "balance of payment adjustment", "D": "capital account"}, "answer": "B", "explanation": "The Balance of Payments (BOP) is a statement of all transactions made between entities in one country and the rest of the world over a defined period of time, such as a quarter or a year. It involves the country's receipts and payments in international transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>48", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "Which of the following countries export cocoa?", "images": [], "options": {"A": "Liberia and The Gambia", "B": "Ghana and Sierra Leone", "C": "Nigeria and Ghana", "D": "Sierra Leone and Nigeria"}, "answer": "C", "explanation": "Both Nigeria and Ghana are known for their cocoa production and export. Ghana is the second largest cocoa producer in the world, while Nigeria is also one of the largest producers in Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>49", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "PUBLIC FINANCE : INTRODUCTION", "question": "Which of the following are examples of transfer payments?", "images": [], "options": {"A": "Gift and donations", "B": "rent and rate", "C": "Profit and dividends", "D": "Internal and external debts"}, "answer": "A", "explanation": "Transfer payments are payments made without any exchange of goods or services. They are typically made to redistribute income. Examples of transfer payments include gifts and donations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2007>50", "subject": "Economics", "year": "2007", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : ECA, IMF", "question": "ECA means", "images": [], "options": {"A": "Economic Commission for Africa", "B": "Economic Community for Africa", "C": "Exporting Countries of Africa", "D": "Economic Conference on Africa"}, "answer": "A", "explanation": "ECA stands for Economic Commission for Africa. It is one of the five regional commissions under the jurisdiction of the United Nations Economic and Social Council. It was established to encourage economic cooperation among its member states following a recommendation of the United Nations General Assembly.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2008>1", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The main concern for economist is to", "images": [], "options": {"A": "allocate scarce resources to satisfy human wants", "B": "satisfy all human wants", "C": "redistribute income between the rich and the poor", "D": "control the growth of population"}, "answer": "A", "explanation": "The main concern of economists is to allocate scarce resources to satisfy human wants. This is because resources are limited while human wants are unlimited. Therefore, it is the role of economists to study how these scarce resources can be efficiently allocated to meet as many human wants as possible.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2008>2", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Productive resources can also be called", "images": [], "options": {"A": "principle of production", "B": "factors of production", "C": "items of production", "D": "labour and material resources"}, "answer": "B", "explanation": "Productive resources are also known as factors of production. They are the inputs used in the production of goods or services in the attempt to make an economic profit. The factors of production include land, labor, capital and entrepreneurship.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2008>3", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "production covers all the following except when", "images": [], "options": {"A": "utility is created", "B": "a goods is manufactured", "C": "a commodity is consumed", "D": "individual wants are satisfied"}, "answer": "C", "explanation": "Production involves the creation of goods or services, and the satisfaction of individual wants. However, the consumption of a commodity is not part of production.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2008>4", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "Data presented in tables are usually arranged in", "images": [], "options": {"A": "chart and graphs", "B": "rows and columns", "C": "graph and rows", "D": "columns and charts"}, "answer": "B", "explanation": "Data in tables are typically arranged in rows and columns.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>5", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND", "question": "The theory of diminishing marginal utility states that as more units of a commodity are consumed, the", "images": [], "options": {"A": "satisfaction from an extra unit decreases", "B": "satisfaction from an extra units rises", "C": "satisfaction from an extra unit remains constant", "D": "total satisfaction from the goods remain the same."}, "answer": "A", "explanation": "The theory of diminishing marginal utility states that as more utility states that as more units of a commodity is consumed, satisfaction from an extra unit decreases i.e. marginal utility   ⊸   satisfaction from an extra unit can neither rise, remain constant or the same base on the concept of marginal utility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>6", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Which of the following factors does not cause a change in demand", "images": [], "options": {"A": "taste and fashion", "B": "vagaries of weather", "C": "Price of other commodities", "D": "Price of the commodity"}, "answer": "D", "explanation": "The price of the commodity itself does not cause a change in demand. Demand is influenced by factors such as taste and fashion, vagaries of weather, and the price of other commodities. However, the price of the commodity itself is not a determinant of demand, but rather it is the result of the interaction between demand and supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>7", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "If goods P and Q are jointly demanded, an increase in the price of P will likely", "images": [], "options": {"A": "leave the demand for Q constant but reduce the quantity demanded of P", "B": "reduce the quantity demanded of P but increase the price of Q", "C": "Increase the quantity supplied of Q", "D": "decrease the quantity demanded of Q"}, "answer": "A", "explanation": "Goods P and Q are jointly demanded, meaning they are often used together. If the price of P increases, it is likely that the demand for Q will remain constant, but the quantity demanded of P will reduce. This is because the increased price of P makes it less attractive to consumers, reducing the quantity they are willing to buy. However, this does not necessarily affect the demand for Q, which is determined by its own price and other factors.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2008>8", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "The gap between demand and supply curves above the equilibrium price is", "images": [], "options": {"A": "normal demand", "B": "excess supply", "C": "equilibrium quantity", "D": "abnormal demand"}, "answer": "B", "explanation": "Above equilibrium the gap is called excess supply  ⊸ Normal demand is the one that is in consonant with the law of demand   ⊸ Equilibrium quantity is a situation in which quantity demanded equals to quantity supplied   ⊸  Abnormal demand is an exception to the law of demand hence, the answer is \"excess supply\"", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2008>9", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "A major function of the price mechanism is that it determines the", "images": [], "options": {"A": "allocation of resources", "B": "amount of national savings", "C": "population of the country", "D": "number of goods to be taxed"}, "answer": "A", "explanation": "The price mechanism, which is the interaction of buyers and sellers in a market to determine the price of a good or service, plays a major role in the allocation of resources. It helps to decide who gets what and how much they get, based on their willingness and ability to pay. It does not determine the amount of national savings, the population of the country, or the number of goods to be taxed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>10", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Which of the following determinants of supply cannot be predicted easily?", "images": [], "options": {"A": "Price of the commodity", "B": "New techniques of productions", "C": "national emergencies", "D": "Mobility of labour"}, "answer": "C", "explanation": "National emergencies are unpredictable events that can significantly affect the supply of goods and services. Unlike the price of the commodity, new techniques of production, and mobility of labour, which can be predicted or controlled to some extent, national emergencies such as natural disasters, wars, pandemics, etc., are uncertain and can disrupt the supply chain unexpectedly.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2008>11", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If the co-efficient of elasticity demand is 1.5, the demand is", "images": [], "options": {"A": "fair inelastic", "B": "perfectly elastic", "C": "elastic", "D": "inelastic"}, "answer": "C", "explanation": "The coefficient of elasticity of demand measures the responsiveness of the quantity demanded to a change in price. If the coefficient is greater than 1, the demand is considered elastic. This means that the quantity demanded changes more than proportionately to a change in price. In this case, since the coefficient is 1.5, the demand is elastic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>12", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "Small scale enterprises are important in a country because", "images": [], "options": {"A": "they usually produce goods for the dependants", "B": "they provide after sales service only to the rich", "C": "the prices of their products are fixed", "D": "they render personalized services to the consumer"}, "answer": "D", "explanation": "Small scale enterprises are important because they render personalized services to the consumer. They are often closer to their customers, understand their needs better, and are able to tailor their products and services to meet these needs. This is not typically the case with larger enterprises, which often standardize their products and services for efficiency and economies of scale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>13", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "In the long run all factors of production are", "images": [], "options": {"A": "expensive", "B": "variable", "C": "durable", "D": "fixed"}, "answer": "B", "explanation": "In the long run, all factors of production are variable. This means that a firm can adjust all its inputs in response to changes in market conditions. This includes both capital and labor inputs. The firm can change the size of its factory, the amount of equipment it uses, and the number of workers it employs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>14", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH", "question": "The transformation curve slope indicates the", "images": [], "options": {"A": "opportunity cost of producing one commodity for another", "B": "opportunity cost of producing two commodities at a time", "C": "sale of the plant to other investors", "D": "decrease in the cost of production"}, "answer": "A", "explanation": "The slope of the transformation curve (also known as the production possibilities frontier) represents the opportunity cost of producing one commodity for another. This is because the slope of the curve shows the rate at which one good can be substituted for another while still maintaining the same level of production. The steeper the slope, the higher the opportunity cost of producing one good for another.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2008>15", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "Which of the following is regarded as fixed cost?", "images": [], "options": {"A": "Expenditure on raw materials", "B": "Expenditure on fuel", "C": "Expenditure on power", "D": "Rent on land"}, "answer": "D", "explanation": "Fixed costs are costs that do not change with the level of output. They are incurred even if the firm is not producing anything. Rent on land is a typical example of a fixed cost because it has to be paid regardless of whether the firm is producing anything or not. On the other hand, expenditures on raw materials, fuel, and power are variable costs because they change with the level of output.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>16", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "Revenue is the", "images": [], "options": {"A": "cost of goods multiplied by the quantity sold", "B": "price of good multiplied by the quantity sold", "C": "quantity of goods plus purchase price", "D": "quantity supplied less quantity sold"}, "answer": "B", "explanation": "Revenue is the total income generated by the sale of goods or services related to the company's primary operations. It is calculated by multiplying the price of the goods or services by the quantity sold. This is a basic concept in economics and business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2008>17", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "A business outfit is said to be public limited company when it", "images": [], "options": {"A": "is owned by government", "B": "operates as a public corporation", "C": "is run by the public", "D": "sells its shares to members of the public"}, "answer": "D", "explanation": "A public limited company (PLC) is a type of company that is permitted to offer its shares to the public. They can be listed or unlisted on a stock exchange. Therefore, it is correct to say that a business outfit is a public limited company when it sells its shares to members of the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>18", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "The main characteristics of an ordinary share are", "images": [], "options": {"A": "maximum risk, fixed dividends, voting rights", "B": "minimum  risk, fixed dividends, voting rights", "C": "maximum risk, variable dividends, voting rights", "D": "minimum risk, fixed dividend, no voting rights"}, "answer": "C", "explanation": "Ordinary shares, also known as common shares, are shares of a company that provide the holder with voting rights in the company, and the right to a dividend that varies (is not fixed) and is dependent on the profitability of the company. Therefore, they carry the maximum risk among all types of shares because if a company goes bankrupt, ordinary shareholders are the last to receive any remaining funds, after creditors, bondholders, and preferred shareholders.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2008>19", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "The monopolist can determine", "images": [], "options": {"A": "price and output", "B": "price only", "C": "output only", "D": "price or output"}, "answer": "D", "explanation": "The monopolist has control over price or output but not both.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>20", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION", "question": "A market situation with a large number of firms selling closely related but differentiated products is", "images": [], "options": {"A": "monopolistic competition", "B": "perfect competition", "C": "monopoly", "D": "monopsony"}, "answer": "A", "explanation": "Monopolistic competition is a type of market structure where many companies sell products that are similar but not identical. These firms are competing against each other, but each firm's product is slightly different from the others. This allows each firm to have some degree of market power. The firms in a monopolistic competition are price makers, which means they can set their own prices to some extent. This is different from perfect competition, where firms are price takers and have no control over the price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>21", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "Equilibrium under perfect competition requires that", "images": [], "options": {"A": "MC = MR but AR", "B": "MR = MC = AR = AC", "C": "AC = AR", "D": "TR"}, "answer": "B", "explanation": "For a perfect market equilibrium is reached where   MR = MC + AR + AC      The other conditions equations are not related to perfect market   - TR  - AC = AR , MC i.e loss  - MC = MC but AR , AC i.e loss", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2008>22", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "MARKET STRUCTURE : PERFECT MARKET", "question": "The purely competitive firm should close down when its price is less than its", "images": [], "options": {"A": "average variable cost", "B": "total fixed cost", "C": "average total cost", "D": "marginal cost"}, "answer": "A", "explanation": "In a purely competitive market, a firm should close down when its price is less than its average variable cost. The average variable cost is the total variable cost divided by the quantity of output. Variable costs are those costs that change with the level of output, such as raw materials and labor. If the price is less than the average variable cost, the firm is not covering its variable costs and it would be more profitable to shut down and avoid these costs.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2008>23", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : INTRODUCTION", "question": "During a sale by auction, the price at which the goods is finally sold is determined mostly", "images": [], "options": {"A": "competition between buyers and sellers", "B": "competition among buyers", "C": "competition among sellers", "D": "government policy"}, "answer": "B", "explanation": "During a scale by auction, the price at which the goods is finally sold is determined mostly by the competition among buyers. The more buyers are interested in the item, the higher they will bid, and the final price will be determined by the highest bid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>24", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "Which of the following does not affect a country's population?", "images": [], "options": {"A": "Birth rate", "B": "Death rate", "C": "Emigration", "D": "Unemployment"}, "answer": "D", "explanation": "Unemployment does not directly affect a country's population. While it may indirectly influence factors such as emigration or birth rate, it is not a direct determinant of population size. Birth rate, death rate, and emigration, on the other hand, directly affect the population size.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2008>25", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "The trade unions in West Africa have achieved the following for the workers except", "images": [], "options": {"A": "increase wages", "B": "better condition of service", "C": "competitive determination of wage rate", "D": "improved welfare facilities"}, "answer": "C", "explanation": "Trade unions in West Africa have achieved many things for workers, including increased wages, better conditions of service, and improved welfare facilities. However, they have not achieved competitive determination of wage rate. This is because wage rates are typically determined by factors such as the market, the employer's ability to pay, and government policy, not competition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>26", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "The employers' demand curve for labour is represented by the", "images": [], "options": {"A": "marginal product curve of labour", "B": "total product curve of labour", "C": "average product curve of labour", "D": "total cost curve of labour"}, "answer": "A", "explanation": "The employers' demand curve for labour is represented by the marginal product curve of labour. This is because the marginal product of labour refers to the additional output that can be produced by employing one more unit of labour, holding all other inputs constant. Employers will demand more labour as long as the marginal product of labour is greater than the wage rate. Therefore, the marginal product curve of labour represents the employers' demand curve for labour.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>27", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "Agriculture plays a dominant role in our country because", "images": [], "options": {"A": "it is the main source of energy", "B": "it employs more than 50% of the total labour force", "C": "it supplies all industrial inputs", "D": "there are large plantations of cocoa, groundnut and palm oil"}, "answer": "B", "explanation": "Agriculture plays a dominant role in our country because it employs more than 50% of the total labour force. This is because in many developing countries, a large proportion of the population is engaged in agriculture for their livelihood. Therefore, agriculture plays a dominant role in the economy of these countries.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2008>28", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "The main objective of specialization is to", "images": [], "options": {"A": "allocate resources", "B": "limit worker's skill", "C": "increase the use of labour", "D": "increase productivity"}, "answer": "D", "explanation": "The main objective of specialization is to increase productivity. Specialization refers to the method of production where a business, area or economy focuses on the production of a limited scope of products or services to gain greater degrees of productive efficiency within an overall system. By focusing on a limited range of tasks, workers can become more skilled and efficient at them, which can lead to an increase in productivity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2008>29", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Industry can be defined as", "images": [], "options": {"A": "several firms producing different commodities", "B": "group of firms producing similar commodities", "C": "different firms producing equal number of commodities", "D": "many firms producing for export"}, "answer": "B", "explanation": "An industry is a group of firms producing similar commodities. This is because they are in the same line of business and are competing against each other. The other options do not accurately define what an industry is.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2008>30", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "Which of the following is a disadvantage of large scale production?", "images": [], "options": {"A": "Market economics", "B": "Managerial economics", "C": "Impersonal organization", "D": "Division of labour"}, "answer": "C", "explanation": "Impersonal organization is a disadvantage of large scale production. This is because as a firm grows in size, the personal touch between management and workers is lost, which can lead to lower morale and productivity. The other options are not disadvantages of large scale production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>31", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "The national income of a country can be estimated through the", "images": [], "options": {"A": "output approach", "B": "input approach", "C": "empirical approach", "D": "census approach"}, "answer": "A", "explanation": "The national income of a country can be estimated through the output approach. This approach involves adding up the value of all goods and services produced in a country within a specific period of time. The other options do not accurately describe methods of estimating national income.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>32", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Use the table below to answer question 32 and 33  Items $Million Final consumption expenditure 500Gross private investment 150Government purchases 300Depreciation 25Net factor income -10    The gross domestic product (GDP) is equal to", "images": [], "options": {"A": "$825m", "B": "$925m", "C": "$940m", "D": "$950m"}, "answer": "D", "explanation": "GDP is calculated by adding up the final consumption expenditure, gross private investment, and government purchases. From the table, GDP = $500m + $150m + $300m = $950m.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2008>33", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Use the table below to answer question 32 and 33  Items $Million Final consumption expenditure 500Gross private investment 150Government purchases 300Depreciation 25Net factor income -10  The net capital formation is", "images": [], "options": {"A": "$115m", "B": "$125m", "C": "$915m", "D": "$925m"}, "answer": "B", "explanation": "Net Capital Formation is calculated by subtracting depreciation from Gross private investment. From the table, Net Capital Formation = $150m - $25m = $125m.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2008>34", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "MONEY : INTRODUCTION", "question": "A medium of exchange which is generally acceptable is", "images": [], "options": {"A": "barter", "B": "a cheque", "C": "government bond", "D": "money"}, "answer": "D", "explanation": "Money is a medium of exchange that is generally acceptable because it is convenient, easily standardized, and a store of value.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2008>35", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "Since money is demanded for what it can buy, the demand is said to be", "images": [], "options": {"A": "derived", "B": "joint", "C": "composite", "D": "complementary"}, "answer": "A", "explanation": "The demand for money is said to be derived because it is not demanded for its own sake (like a consumer good) but for what it can buy. Money is a medium of exchange and people demand it to facilitate transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>36", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "MONEY : SUPPLY OF MONEY", "question": "The supply of money in the economy includes", "images": [], "options": {"A": "Bank notes only", "B": "bank notes and coins", "C": "bank notes and bank deposits", "D": "bank notes, coins and bank deposits"}, "answer": "D", "explanation": "The supply of money in the economy includes bank notes, coins and bank deposits. Bank notes and coins are physical forms of money, while bank deposits are a form of digital or virtual money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>37", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "The indicator of the value of money is", "images": [], "options": {"A": "the general price level", "B": "the equilibrium price", "C": "consumers' income", "D": "the interest rate"}, "answer": "A", "explanation": "The value of money is indicated by the general price level. If the general price level is high, the value of money is low because each unit of money buys fewer goods and services. Conversely, if the general price level is low, the value of money is high because each unit of money buys more goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>38", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "INFLATION & DEFLATION : INTRODUCTION", "question": "A continuous fall in the general price is called", "images": [], "options": {"A": "recession", "B": "depression", "C": "deflation", "D": "stagflation"}, "answer": "C", "explanation": "Deflation is a decrease in the general price level of goods and services. It occurs when the inflation rate falls below 0%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>39", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "The Central Bank can restrict credit through", "images": [], "options": {"A": "depreciation of assets", "B": "granting overdraft", "C": "direct investment", "D": "open interest rate"}, "answer": "D", "explanation": "The central bank can use various tools to implement monetary policy, including open market operations, discount rate, and reserve requirements. An open market operation (OMO) is an activity by a central bank to give (or take) liquidity in its currency to (or from) a bank or a group of banks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>40", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Creation of money by commercial banks is done by", "images": [], "options": {"A": "increasing the cash ratio", "B": "printing money", "C": "lending to borrowers", "D": "issuing cheque"}, "answer": "C", "explanation": "When a bank makes a loan, for example, it credits the borrower's account with a deposit of the size of the loan. By that action, new commercial bank money is created. As a result, the total amount of money in the economy is increased.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>41", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "PUBLIC FINANCE : INTRODUCTION", "question": "Public finance is basically an analysis of the", "images": [], "options": {"A": "income and expenditure of government", "B": "expenditure patterns of government", "C": "current and capital receipts of government", "D": "current and capital expenditure"}, "answer": "A", "explanation": "Public finance is a field of economics that deals with budgeting the revenues and expenditures of a public sector entity. It is basically an analysis of the income and expenditure of government. It involves understanding the government revenue, government spending, budget process, debt issuance (bonds issuance) for public infrastructure projects.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>42", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION", "question": "A major use of taxation is to", "images": [], "options": {"A": "control population growth rate", "B": "influence people's saving habits", "C": "control money supply", "D": "create bank credits"}, "answer": "C", "explanation": "Taxation is a major tool used by the government to control money supply in the economy. By increasing taxes, the government can reduce the amount of money in circulation, thereby controlling inflation. Conversely, by reducing taxes, the government can increase the amount of money in circulation, thereby stimulating economic activity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>43", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "A tax which is expressed as a given absolute sum of money per unit of a commodity is known as", "images": [], "options": {"A": "a specific tax", "B": "direct tax", "C": "an indirect tax", "D": "a value added tax"}, "answer": "A", "explanation": "A specific tax is a tax that is fixed in amount regardless of the value of the transaction or the characteristics of the buyer or seller. It is expressed as a given absolute sum of money per unit of a commodity. For example, a tax of $1 per gallon of gasoline is a specific tax.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>44", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "All indirect taxes tends to be", "images": [], "options": {"A": "progressive", "B": "regressive", "C": "certain", "D": "equitable"}, "answer": "B", "explanation": "Indirect taxes are typically considered regressive. This is because they are applied uniformly to all consumers regardless of their income level. As a result, lower-income individuals end up paying a larger proportion of their income in indirect taxes than higher-income individuals. This is what makes them regressive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>45", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "PUBLIC FINANCE : FISCAL POLICY", "question": "Which of the following will have a more destabilizing effect on the economy?", "images": [], "options": {"A": "tax on the prices of vehicles", "B": "A tax on petrol", "C": "A decrease in the supply of vehicles", "D": "Moderate increase in wages"}, "answer": "C", "explanation": "A decrease in the supply of vehicles would have a more destabilizing effect on the economy. This is because it would lead to a rise in the price of vehicles due to the law of supply and demand. This could potentially lead to inflation and economic instability. The other options, such as a tax on the prices of vehicles or petrol, would not have as significant an impact as they would only affect a specific sector of the economy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2008>46", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "An important feature of economic development is", "images": [], "options": {"A": "population explosion", "B": "reduction in exports", "C": "high literacy level", "D": "low literacy level"}, "answer": "C", "explanation": "An important feature of economic development is a high literacy level. Literacy is a key factor in a country's economic development. A more literate population has a better understanding of economic policies, can make better decisions for their economic well-being, and is more likely to contribute to the country's economic growth. The other options, such as population explosion or reduction in exports, are not necessarily features of economic development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>47", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Trade among nations is desirable because", "images": [], "options": {"A": "it enables people in a country to know those in other countries", "B": "make it possible for people in a country to enjoy the goods and services produced in other countries", "C": "enables residents in a country to understand the language of resident of other countries", "D": "makes it possible for a country to have the currencies of other countries"}, "answer": "B", "explanation": "Trade among nations is desirable because it allows for the exchange of goods and services. This means that people in one country can enjoy goods and services produced in another country that they may not have access to otherwise. This is the concept of comparative advantage, where countries produce and export goods and services they can produce more efficiently and import those they cannot produce as efficiently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>48", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "INTERNATIONAL TRADE : INTRODUCTION", "question": "Invisible trade refers to trade in", "images": [], "options": {"A": "services", "B": "goods and services", "C": "tangible goods", "D": "crude oil"}, "answer": "A", "explanation": "Invisible trade refers to the trade of services, not physical goods. These can include things like banking, insurance, tourism, and other services. This is in contrast to visible trade, which involves the trade of physical goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2008>49", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "balance of payment surplus implies that the value of the country's", "images": [], "options": {"A": "export exceeds its imports", "B": "import exceeds its export", "C": "exports is equal to its imports", "D": "terms of trade is constant"}, "answer": "A", "explanation": "A balance of payment surplus implies that the value of a country's exports exceeds its imports. This means that the country is earning more from its exports than it is spending on imports, leading to a surplus in its balance of payments. The balance of payments is a record of all economic transactions between the residents of a country and the rest of the world in a particular period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2008>50", "subject": "Economics", "year": "2008", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "The Economic Commission for Africa is an Agency of the", "images": [], "options": {"A": "organization of Africa Unity", "B": "Africa Development Bank", "C": "United Nations Organization", "D": "European Union"}, "answer": "C", "explanation": "The Economic Commission for Africa (ECA) is a regional commission established by the United Nations (UN) to encourage economic cooperation among its member states. It is not an agency of the Organization of Africa Unity, Africa Development Bank, or the European Union.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>1", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The study of economics becomes necessary because of the", "images": [], "options": {"A": "large population size of the world", "B": "scarcely of resources", "C": "opportunity cost of goods and services", "D": "need to satisfy every desire of man"}, "answer": "B", "explanation": "The study of economics becomes necessary because of the scarcity of resources. Economics is the study of how societies, governments, businesses, households, and individuals allocate their scarce resources. The large population size of the world, opportunity cost of goods and services, and the need to satisfy every desire of man are all factors that contribute to the scarcity of resources, but they are not the primary reason why the study of economics is necessary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2009>2", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The concept of opportunity cost is also referred to as", "images": [], "options": {"A": "social cost", "B": "real cost", "C": "fixed cost", "D": "variable cost"}, "answer": "B", "explanation": "The concept of opportunity cost is also referred to as real cost. Opportunity cost is the cost of forgoing the next best alternative when making a decision. It's not referred to as social cost, fixed cost, or variable cost. Social cost is the total cost of producing a good or service, including both the private cost and any externalities. Fixed costs are costs that do not change with the level of output. Variable costs are costs that change with the level of output.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2009>3", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Choice is necessitated by", "images": [], "options": {"A": "demand and supply", "B": "cost of production", "C": "production possibility curve", "D": "scarcity of resources"}, "answer": "D", "explanation": "Choice in economics is necessitated by the scarcity of resources. Scarcity refers to the basic economic problem, the gap between limited resources and theoretically limitless wants. This situation requires people to make decisions about how to allocate resources efficiently, in order to satisfy basic needs and as many additional wants as possible.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2009>4", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "A type of unemployment which occurs due to technological progress is called", "images": [], "options": {"A": "frictional employment", "B": "residual unemployment", "C": "structural unemployment", "D": "mass unemployment"}, "answer": "C", "explanation": "Structural unemployment occurs when a labor market is unable to provide jobs for everyone who wants one because there is a mismatch between the skills of the unemployed workers and the skills needed for the available jobs. Technological progress often leads to structural unemployment. For example, workers who used to work in manual jobs may become unemployed because new technologies can do their jobs more efficiently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>5", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "All the following are features of market economics except", "images": [], "options": {"A": "competition among producers", "B": "demand and supply forces guiding production decisions", "C": "that profit motive is paramount", "D": "public ownership of capital"}, "answer": "D", "explanation": "Market economics, also known as a free market or capitalist economy, is characterized by private ownership of capital. In such an economy, competition among producers, demand and supply forces guiding production decisions, and the profit motive being paramount are all key features. Public ownership of capital, on the other hand, is a feature of a command or planned economy, not a market economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>6", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "The economic system which relies mainly on the price mechanism for the allocation of scarce resources is known as", "images": [], "options": {"A": "capital economic system", "B": "command economic system", "C": "combined economic system", "D": "traditional economic system"}, "answer": "A", "explanation": "The economic system that relies mainly on the price mechanism for the allocation of scarce resources is known as a capitalist economic system. The price mechanism is a system where the forces of supply and demand interact to determine the price of goods and services in a market. In a capitalist economic system, the allocation of resources is determined by the price mechanism, where prices are set by supply and demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>7", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "In a capitalist economy, resources are", "images": [], "options": {"A": "collectively owned", "B": "jointly owned", "C": "privately owned", "D": "communally owned"}, "answer": "C", "explanation": "In a capitalist economy, resources are privately owned. This means that individuals and businesses have the right to own and use property, whether it be land, buildings, or other assets. This private ownership allows individuals and businesses to control the use of the resources they own and to benefit from their use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>8", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "An economic system where the central planning authority determines what goods to produce and in what quantity is known as a", "images": [], "options": {"A": "market economy", "B": "socialist economy", "C": "welfare economy", "D": "traditional economy"}, "answer": "B", "explanation": "An economic system where the central planning authority determines what goods to produce and in what quantity is known as a socialist economy. In a socialist economy, the government or a central authority makes all decisions regarding the production and distribution of goods and services. This includes decisions about what goods and services to produce, how much to produce, and how to distribute these goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>9", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "The main objective of setting up a private business or organization is to", "images": [], "options": {"A": "protect the interest of the owners", "B": "promote exports", "C": "provide infrastructure", "D": "maximize profits"}, "answer": "D", "explanation": "The main objective of setting up a private business or organization is to maximize profits. This is because the primary goal of any business is to increase the wealth of its owners, which is achieved by maximizing profits.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2009>10", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET", "question": "The demand and supply functions of a commodity are given as follows:    Qd = 20 - 2p   Qs = 6p - 12   Where P = price in naira, Qd = Quantity demanded and Qs = Quantity supplied. The equilibrium price is", "images": [], "options": {"A": "2 Naira", "B": "4 Naira", "C": "6 Naira", "D": "20 Naira"}, "answer": "B", "explanation": "The equilibrium price is determined when the quantity demanded (Qd) equals the quantity supplied (Qs). By setting the two equations equal to each other, we get: 20 - 2p = 6p - 12. Solving for p, we get p = 4 Naira. Therefore, the equilibrium price is 4 Naira.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2009>11", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "The type of demand that exists between torchlight and battery is", "images": [], "options": {"A": "competitive demand", "B": "complementary demand", "C": "composite demand", "D": "independent demand"}, "answer": "B", "explanation": "The type of demand that exists between torchlight and battery is complementary demand. This is because the two goods are used together - a torchlight requires a battery to function. Therefore, an increase in demand for torchlights would lead to an increase in demand for batteries, and vice versa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>12", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "When the price of a commodity increases and the quantity demanded also increases, this is a case of", "images": [], "options": {"A": "exceptional demand", "B": "derive demand", "C": "competitive demand", "D": "joint demand"}, "answer": "A", "explanation": "Exceptional demand refers to a situation where the law of demand, which states that price and quantity demanded are inversely related, does not apply. In this case, when the price of a commodity increases, the quantity demanded also increases. This could be due to factors such as the perception of the commodity as a luxury or a status symbol.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>13", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "THEORY OF SUPPLY : TYPES OF SUPPLY", "question": "If a fall in price of one commodity leads to an increase in the supply of another commodity, both commodities have", "images": [], "options": {"A": "composite supply", "B": "joint supply", "C": "competitive supply", "D": "short-run supply"}, "answer": "B", "explanation": "Joint supply refers to a situation where an increase or decrease in the supply of one good leads to an increase or decrease in the supply of another good. These goods are usually produced together. So, if a fall in the price of one commodity leads to an increase in the supply of another commodity, both commodities have joint supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>14", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "At a co-efficient of price elasticity of supply of 0.5, supply is", "images": [], "options": {"A": "perfectly inelastic", "B": "inelastic", "C": "perfectly elastic", "D": "elastic"}, "answer": "B", "explanation": "The coefficient of price elasticity of supply measures the responsiveness of the quantity supplied to a change in the price of a good. If the coefficient is less than 1 (0.5 in this case), supply is considered inelastic. This means that changes in price have a relatively small effect on the quantity supplied.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>15", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "THEORY OF SUPPLY : TYPES OF SUPPLY", "question": "If in the short-run commodity X and commodity Y are supplied jointly, which of the following is correct?", "images": [], "options": {"A": "an increase in demand for X will increase supply of Y", "B": "An increase in demand of X will leave the supply of Y unchanged", "C": "An increase in demand for Y will raise the price of X", "D": "An increase in demand for X will cause less of Y to be produced"}, "answer": "A", "explanation": "In the case of joint supply, an increase in the demand for one commodity (X) will lead to an increase in the supply of the other commodity (Y). This is because both commodities are produced together, so if more of one is produced, more of the other will also be produced. This concept is known as joint supply.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2009>16", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If an increase in earning leads to more of a commodity being demanded, the goods is said to have", "images": [], "options": {"A": "positive income elasticity", "B": "negative income elasticity", "C": "positive cross elasticity", "D": "negative cross elasticity"}, "answer": "A", "explanation": "If an increase in income leads to more of a commodity being demanded, the good is said to have positive income elasticity. Income elasticity of demand measures the responsiveness of the quantity demanded for a good or service to a change in the income of the people demanding the good. It is calculated as the ratio of the % change in quantity demanded to the % change in income.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>17", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "Interaction of supply and demand for labour determines", "images": [], "options": {"A": "production", "B": "income", "C": "wage", "D": "profit"}, "answer": "C", "explanation": "If Demand and supply interact, employers can determine the wage of labour     Where Dl = demand for labour   Ql Quantity of labour   Wl = Wage rate of labour   Dl = Supply of labour", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>18", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET", "question": "Government fixing of prices below the equilibrium point is aimed at protecting the", "images": [], "options": {"A": "sellers", "B": "industries", "C": "distributors", "D": "consumer"}, "answer": "D", "explanation": "Government fixing of prices below the equilibrium point is aimed at protecting the consumer. This is because when prices are set below the equilibrium point, it results in a lower price for consumers. This is often done to ensure that essential goods and services remain affordable for all consumers, particularly those with lower incomes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>19", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "A consumer maximizes his utility in consuming a good 'X' when", "images": [], "options": {"A": "Mux = Px", "B": "Px > Mux", "C": "Price is falling", "D": "Mux > Px"}, "answer": "A", "explanation": "A consumer maximizes his utility in consuming a good 'X' when the marginal utility of consumption (Mux) is equal to the price of the good (Px). This is a fundamental concept in consumer theory, which states that consumers will consume goods until the marginal utility of consumption equals the price. If Mux > Px, the consumer would consume more of the good, and if Px > Mux, the consumer would consume less.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>20", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "The relationship between Marginal Production (MP) and Average production (AP) is such that they are equal when", "images": [], "options": {"A": "Average Product is maximum", "B": "Average Product is minimum", "C": "marginal Product is maximum", "D": "marginal Product is increased"}, "answer": "A", "explanation": "When Average Product is rising, Marginal Product lies above Average Product. When Average Product is declining, Marginal Product lies below Average Product. At the maximum of Average Product, Marginal and Average Product equal each other.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>21", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER", "question": "Who among the following is the intermediary between the producer and the retailer?", "images": [], "options": {"A": "Agent", "B": "Wholesaler", "C": "Consumer", "D": "Distributor"}, "answer": "B", "explanation": "A wholesaler is the intermediary between the producer and the retailer. Wholesalers buy goods in bulk from producers and sell them to retailers. Agents, on the other hand, represent either the producer or the retailer but do not take ownership of the goods. Consumers are the end users of the goods, and distributors distribute the goods but may not necessarily be the intermediary between the producer and the retailer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2009>22", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Which of the following sectors is most capital intensive?", "images": [], "options": {"A": "Insurance", "B": "petroleum", "C": "Commerce", "D": "Tourism"}, "answer": "B", "explanation": "The petroleum sector is the most capital intensive among the options provided. Capital intensity refers to the amount of fixed or real capital present in relation to other factors of production, especially labor. In the petroleum industry, a significant amount of capital is required for exploration, drilling, refining, and distribution activities. The other sectors listed - insurance, commerce, and tourism - are less capital intensive as they require less physical or fixed capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>23", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE", "question": "A society that operates below the production possibility curve is using its productive resources", "images": [], "options": {"A": "optimally", "B": "efficiently", "C": "inefficiently", "D": "maximally"}, "answer": "C", "explanation": "A society that operates below the production possibility curve is not using its resources to their full potential, hence it is operating inefficiently. The production possibility curve represents the maximum output that a society can produce with its available resources and technology. Operating below the curve means that the society is not maximizing its output, hence it is inefficient.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>24", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION", "question": "Labour can be efficient when there is", "images": [], "options": {"A": "adequate tools to work with", "B": "high levels of employment", "C": "Limited vacancies", "D": "government restrictions"}, "answer": "A", "explanation": "Labour can be efficient when there are adequate tools to work with. Efficiency in labour means that the labour is able to produce the maximum output with the given resources. Adequate tools and equipment are necessary for labour to perform their tasks effectively and efficiently. Without the necessary tools, labour cannot perform their tasks to their full potential, hence they would be inefficient.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>25", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "What accounts for the 'U-shape' of the short run average cost (AC) curve?", "images": [], "options": {"A": "The law of variable proportions", "B": "Increasing returns to scale", "C": "Decreasing return to scale", "D": "Changing output during the production period"}, "answer": "A", "explanation": "The law of variable proportions of law of diminishing marginal utility is the main reason for the U-shaperd AC curve.          It implies that cost will continue to reduce but will get to a certain points where it cannot reduce further, hence, it begins to rise.   - Increasing returns to scale are benefits that accrue to a firm   - Decreasing use of inputs relates to fall in input  - Changing output during production period is insignificant.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2009>26", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "MARKET STRUCTURE : PERFECT MARKET", "question": "Which of these is true of a perfect competition?", "images": [], "options": {"A": "P = AR", "B": "P > AR = MR", "C": "P = MR", "D": "P = AR = MR"}, "answer": "D", "explanation": "In a perfect competition, the price (P) equals average revenue (AR) and marginal revenue (MR). This is because in a perfect competition, firms are price takers, meaning they take the market price as given and cannot influence it. Therefore, the price they charge for their product is the same as the average revenue and marginal revenue they receive from selling it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>27", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "One advantage of a sole proprietorship is that", "images": [], "options": {"A": "it can be managed without conflicts", "B": "the sole proprietor raises money from the public", "C": "it makes an increase in the volume of business possible", "D": "there is no limit to the number of people who may bring in capital"}, "answer": "A", "explanation": "A sole proprietorship is a type of business entity that is owned and run by one individual and in which there is no legal distinction between the owner and the business. The advantage of a sole proprietorship is that it can be managed without conflicts because there is only one decision-maker, the owner. This eliminates the potential for disagreements and conflicts that can occur in partnerships or corporations where decisions are made by multiple people or entities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>28", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "MARKET STRUCTURE : FORMS OF MARKET STRUCTURE", "question": "Which of the following is a condition necessary for a perfect markets", "images": [], "options": {"A": "The goods are heterogeneous", "B": "There is preferential treatment", "C": "There is a large number of buyers and sellers", "D": "buyers and sellers are easily influenced"}, "answer": "C", "explanation": "A perfect market, also known as a competitive market, is a theoretical market concept where all market participants are price takers, and there is free entry and exit from the market. One of the conditions necessary for a perfect market is that there is a large number of buyers and sellers. This ensures that no single buyer or seller has the power to influence the price of the product or service, leading to a market equilibrium where supply equals demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>29", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "A market in which a single price obtains for a product is known as", "images": [], "options": {"A": "a product market", "B": "a capital price market", "C": "an imperfect market", "D": "a perfect market"}, "answer": "D", "explanation": "In a perfect market (or perfectly competitive market), the price of a product is uniform across the market due to the presence of many buyers and sellers, all of whom have perfect information and no single participant can influence the price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>30", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "What is the effect of pursuit of higher education on the size labour force?", "images": [], "options": {"A": "It makes labour force to be defective", "B": "It brings higher wage rate", "C": "It increases the size of labour force", "D": "It reduces the size of labour force"}, "answer": "D", "explanation": "The pursuit of higher education often requires individuals to spend more time in school, which reduces the time they have available to work. Therefore, it reduces the size of the labour force. The labour force refers to the total number of people who are either employed or actively looking for work.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>31", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "POPULATION : POPULATION DENSITY, AGEING POPULATION", "question": "The population density of town Y made up of 50 square kilometers land area and 100 million people is", "images": [], "options": {"A": "50,000 people per square kilometre", "B": "0.2 million people per square kilometre", "C": "0.5 million people per square kilometre", "D": "2 million people per square kilometre"}, "answer": "D", "explanation": "Population density   = Total population/Land Area    = 100 million/50sqkm = 2 million/people", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2009>32", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Manufacturing involves the process of", "images": [], "options": {"A": "making goods available", "B": "providing finished products", "C": "changing items to new states", "D": "producing capital goods only"}, "answer": "C", "explanation": "Manufacturing involves the process of changing raw materials into finished goods. This process changes the state of the items from raw materials to new, finished products. Therefore, the correct answer is 'changing items to new states'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2009>33", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Disposable income is total income", "images": [], "options": {"A": "less tax", "B": "divided by tax", "C": "plus tax", "D": "multiplied by tax"}, "answer": "A", "explanation": "Disposable income is the amount of money that households have available for spending and saving after income taxes have been accounted for. Therefore, the correct answer is 'less tax'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>34", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "Use the information below to answer the questions  Depreciation = $40,000  Gross Domestic Product = $100,000  Factor Payments to Foreigners = $20,000  Factor Receipts from Abroad = $25,000    The gross National Product is equal to", "images": [], "options": {"A": "$40,000", "B": "$50,000", "C": "$105,000", "D": "$125,000"}, "answer": "C", "explanation": "GNP = GNP + Net factor income from abroad   Factor receipts - factor payments = Net factor income from abroad.   = $ 25,000 - 20,00  = $  5,000    GNP = GNP + NFIA  =100,000 + $  5,000  =  $ 105,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2009>35", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "Use the information below to answer the questions  Depreciation = $40,000  Gross Domestic Product = $100,000  Factor Payments to Foreigners = $20,000  Factor Receipts from Abroad = $25,000  The national Income is equal to", "images": [], "options": {"A": "$45,000", "B": "$60,000", "C": "$65,000", "D": "$195,000"}, "answer": "C", "explanation": "National income = GNP - Depreciation   = $105,000 - $40,000   = $ 65,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2009>36", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "Use the information below to answer the questions  Depreciation = $40,000  Gross Domestic Product = $100,000  Factor Payments to Foreigners = $20,000  Factor Receipts from Abroad = $25,000  The net domestic product is", "images": [], "options": {"A": "$55,000", "B": "$60,000", "C": "$65,000", "D": "$165,000"}, "answer": "B", "explanation": "Net domestic product = GDP - Depreciation   = GDP - Depreciation = 100,000 - 40,000   = $60,000", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2009>37", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "Which of the following is  specialized in lending money for the purpose of developing real estate?", "images": [], "options": {"A": "Merchant banks", "B": "Mortgage banks", "C": "Discount houses", "D": "Commercial banks"}, "answer": "B", "explanation": "Mortgage banks are specialized in lending money for the purpose of developing real estate. They provide loans specifically for the purchase of real estate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>38", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "The marketing of government security by the Central Bank is termed", "images": [], "options": {"A": "retail banking", "B": "open market operations", "C": "selective credit control", "D": "credit creation"}, "answer": "B", "explanation": "The marketing of government security by the Central Bank is termed open market operations. This is a monetary policy where the central bank buys or sells government bonds to regulate the money supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>39", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "Which of the following serves as a banker's bank?", "images": [], "options": {"A": "Commercial Bank", "B": "The Mortgage Bank", "C": "The Central Bank", "D": "Development Bank"}, "answer": "C", "explanation": "The Central Bank serves as a banker's bank. It is the institution that provides banking services to other banks and governmental institutions. It is responsible for implementing the government's monetary policy, issuing currency, managing the country's foreign exchange and gold reserves, and regulating and supervising the commercial banking system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>40", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "The tax imposed on goods manufactured within a country is", "images": [], "options": {"A": "an excise tax", "B": "a capital gains tax", "C": "profit tax", "D": "a sales tax"}, "answer": "A", "explanation": "An excise tax is a tax imposed on goods manufactured within a country. It is an indirect tax that is included in the price of the product and paid by the consumer. It is levied on specific goods and services like alcohol, tobacco, and fuel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>41", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Government expenditure on the construction of roads and bridges is", "images": [], "options": {"A": "recurrent expenditure", "B": "capital expenditure", "C": "supplementary expenditure", "D": "variable expenditure"}, "answer": "B", "explanation": "Government expenditure on the construction of roads and bridges is a capital expenditure. Capital expenditure refers to the funds used by an organization or government to acquire or upgrade physical assets such as property, industrial buildings, or equipment. In this case, roads and bridges are physical assets that can be used for a long period of time and are not consumed within the fiscal year they were purchased.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>42", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "PUBLIC FINANCE : FISCAL POLICY", "question": "Fiscal policy is associated with", "images": [], "options": {"A": "taxation and government expenditure", "B": "restructuring of the bank", "C": "injection of more money into the economy", "D": "reduction in economic activities"}, "answer": "A", "explanation": "Fiscal policy is a government's policy regarding taxation, government spending, and public debt. It is one of the main methods a government uses to influence the economy. Therefore, the correct answer is 'taxation and government expenditure'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>43", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "The need for development planning arises largely from the fact that", "images": [], "options": {"A": "aggregate savings exceed aggregate consumption", "B": "aggregate consumption equals aggregate savings", "C": "productive resources are scarce relative to the supply for them", "D": "productive resources are scarce relative to the demand for them"}, "answer": "D", "explanation": "The need for development planning arises largely from the fact that productive resources are scarce relative to the demand for them. This is because resources are limited while wants are unlimited, hence the need for planning to allocate these scarce resources efficiently.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2009>44", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "Economic development is reflected in", "images": [], "options": {"A": "Scarcity of capital", "B": "increase in the price level", "C": "decline in agricultural production", "D": "increase in productive capacity"}, "answer": "D", "explanation": "Economic development is reflected in the increase in productive capacity. This means that the economy's ability to produce goods and services has increased, which is a sign of economic development. This can be due to advancements in technology, increase in the quantity and quality of labor, and other factors that increase the productive capacity of an economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>45", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "terms of trade may be defined as the", "images": [], "options": {"A": "trade between one country and another", "B": "relationship between country's receipt from others and payment to others", "C": "rate at which a country's exports exchange for imports", "D": "difference between the value of exports and imports"}, "answer": "C", "explanation": "Terms of trade is an economic concept that refers to the relative price of imports in terms of exports and is defined as the ratio of export prices to import prices. It can be interpreted as the amount of import goods an economy can purchase per unit of export goods. Therefore, it is the rate at which a country's exports exchange for imports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>46", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "The terms of trade is described as unfavorable when", "images": [], "options": {"A": "the price of imports rise relative to those exports", "B": "the price of exports rise relative to those of imports", "C": "the net income from abroad does not change", "D": "the value of exports exceed those of import"}, "answer": "A", "explanation": "The terms of trade are described as unfavorable when the price of imports rises relative to those of exports. This is because it means that a country has to export more goods or services to afford the same amount of imported goods, which can lead to a trade deficit and economic problems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>47", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Expenditure by foreign tourists in a country will be recorded as", "images": [], "options": {"A": "invisible exports", "B": "official transfer", "C": "transfer income", "D": "visible exports"}, "answer": "A", "explanation": "Expenditure by foreign tourists in a country is recorded as invisible exports. Invisible exports are transactions where money is transferred across borders without the physical movement of goods. This includes services such as tourism, where foreign tourists spend money in the country they are visiting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>48", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "One major aim of a cartel is to", "images": [], "options": {"A": "increase production", "B": "regulate output through quota system", "C": "have a joint account", "D": "share profits equally"}, "answer": "B", "explanation": "A cartel is a group of independent market participants who collude with each other in order to improve their profits and establish control over the market. One of the major aims of a cartel is to regulate output through a quota system. By doing so, they can control the supply of the product in the market, which can lead to an increase in the product's price, thereby benefiting the members of the cartel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2009>49", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "The five countries that established the organization of Petroleum Exporting Countries (OPEC) are", "images": [], "options": {"A": "Nigeria, Iraq, Venezuela, Kuwait and Ghana", "B": "Saudi Arabia, Kuwait, Sierra Leon, Iran and Iraq", "C": "Algeria, Kuwait, Venezuela, Iran and The Gambia", "D": "Kuwait, Venezuela, Iran, Iraq and Saudi Arabic"}, "answer": "D", "explanation": "The Organization of Petroleum Exporting Countries (OPEC) was established in Baghdad, Iraq, in 1960 by five countries: Kuwait, Venezuela, Iran, Iraq and Saudi Arabia. These countries were later joined by nine others. The aim of the organization is to coordinate and unify petroleum policies among Member Countries, in order to secure fair and stable prices for petroleum producers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2009>50", "subject": "Economics", "year": "2009", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "The headquaters of the African Development Bank (ADB) was originally located at", "images": [], "options": {"A": "Cotonou", "B": "Harare", "C": "Abidjan", "D": "Lagos"}, "answer": "C", "explanation": "The African Development Bank (ADB) is a multilateral development finance institution. The bank was established in 1964 and originally headquartered in Abidjan, Côte d'Ivoire. However, due to the civil war in Côte d'Ivoire, the bank's headquarters were temporarily relocated to Tunis, Tunisia, in 2003. In 2014, the bank returned its headquarters to Abidjan.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>1", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The following are examples of economic goods except", "images": [], "options": {"A": "bottled water", "B": "air", "C": "household utensils", "D": "shelter"}, "answer": "B", "explanation": "Economic goods are goods and services that are scarce and for which the demand is higher than the supply. They are goods that are not freely available and require some form of payment or effort to acquire. In this context, air is not an economic good because it is freely available and does not require any form of payment or effort to acquire.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>2", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "A tent-making factory offers", "images": [], "options": {"A": "personal services", "B": "indirect services", "C": "social services", "D": "reflex services"}, "answer": "B", "explanation": "A tent-making factory offers indirect services. Indirect services are those services that are not directly consumed but are used in the production of other goods or services. In this case, the tents produced by the factory can be used for various purposes such as camping, events, etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>3", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "In which of the following economic systems do we have mostly private ownership of resources and individual decision making?", "images": [], "options": {"A": "capital system", "B": "Social system", "C": "Mixed system", "D": "Traditional system"}, "answer": "A", "explanation": "In a capital system, also known as a capitalist or free-market system, resources are privately owned and decisions regarding what to produce, how to produce, and for whom to produce are made by individuals based on their own self-interest. This is in contrast to a social system (socialism) where resources are owned by the state, a mixed system where resources are both privately and publicly owned, and a traditional system where economic decisions are based on customs and traditions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>4", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "The sum of items divided by the number of items is the", "images": [], "options": {"A": "frequency", "B": "mean", "C": "Median", "D": "Mode"}, "answer": "B", "explanation": "The mean of a set of numbers is calculated by adding all numbers in the set and then dividing by the count of numbers in the set. Therefore, the sum of items divided by the number of items is the mean.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>5", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "Find the median of the following set of scores: 8,9,6,5 and 10", "images": [], "options": {"A": "9", "B": "8", "C": "6", "D": "5"}, "answer": "B", "explanation": "The median of a set of numbers is the middle number when the numbers are arranged in ascending or descending order. For the set of scores: 5, 6, 8, 9, 10, the median is 8.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>6", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Which of the following causes the demand curve to shift to the right?", "images": [], "options": {"A": "A reduction in the size of population", "B": "An increase in the income of the buyer", "C": "The availability of substitutes", "D": "A decrease in price of the goods"}, "answer": "B", "explanation": "The demand curve shifts to the right when there is an increase in demand. This can be caused by several factors, one of which is an increase in the income of the buyer. When buyers have more income, they are likely to buy more, hence increasing demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>7", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "Goods for which demand rises as income raises are", "images": [], "options": {"A": "complementary goods", "B": "inferior goods", "C": "Normal goods", "D": "Substitute goods"}, "answer": "C", "explanation": "Normal goods are goods for which demand increases when consumer income increases. This is because as income increases, consumers are willing to spend more. Therefore, the demand for normal goods rises as income raises. Complementary goods are goods that are usually consumed together, like bread and butter. Inferior goods are goods for which demand decreases when consumer income increases. Substitute goods are goods that can be used in place of another.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>8", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THE THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "The slope of a supply curve is", "images": [], "options": {"A": "horizontal", "B": "uniform", "C": "positive", "D": "vertical"}, "answer": "C", "explanation": "The supply curve has a positive slope which implies that as the price increases, quantity supplied also increases as shown below.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>9", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "Equilibrium price is the price at which quantity", "images": [], "options": {"A": "demanded is greater than quantity supplied", "B": "supplied is greater than quantity demanded", "C": "demand is equal to quantity supplied", "D": "supplied is equal to quantity produced"}, "answer": "C", "explanation": "Equilibrium price is the price at which the quantity demanded equals the quantity supplied. This is the point where the supply and demand curves intersect. At this price, there is no surplus or shortage of goods. If the price were higher, the quantity supplied would be greater than the quantity demanded, leading to a surplus. If the price were lower, the quantity demanded would be greater than the quantity supplied, leading to a shortage.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>10", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THE THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "A decrease in supply with demand remaining unchanged will cause the equilibrium price for a good to", "images": [], "options": {"A": "be unchanged", "B": "remain elastic", "C": "remain inelastic", "D": "rise"}, "answer": "D", "explanation": "When supply decreases and demand remains unchanged, the equilibrium price will rise. This is because the decrease in supply creates a shortage at the original price, causing the price to rise until the quantity demanded equals the new lower quantity supplied. The terms 'remain elastic' and 'remain inelastic' refer to the price elasticity of demand, which is a measure of how much the quantity demanded of a good responds to a change in the price of that good.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>11", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND", "question": "At the highest level of the total utility, marginal utility is", "images": [], "options": {"A": "negative", "B": "positive and falling", "C": "positive and rising", "D": "Zero"}, "answer": "D", "explanation": "When the total reaches maximum, marginal utility is zero below:", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>12", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND", "question": "The law of diminishing marginal utility states that, the more a commodity is consumed the", "images": [], "options": {"A": "higher the satisfaction derived from an additional unit", "B": "higher the price to be paid", "C": "lower the quantity supplied", "D": "lower the rate of increase in the total utility derived"}, "answer": "D", "explanation": "The law of diminishing marginal utility states that as a person increases consumption of a product while keeping consumption of other products constant, there is a decline in the marginal utility that person derives from consuming each additional unit of that product. In other words, the more of a good a consumer acquires, the less additional (marginal) utility they get from consuming more. Therefore, the rate of increase in total utility derived from the good decreases with each additional unit consumed, which matches option 4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>13", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "Greater inter-dependence among workers in production is associated with", "images": [], "options": {"A": "utility", "B": "manufacturing", "C": "division of labour", "D": "factory workers"}, "answer": "C", "explanation": "Greater inter-dependence among workers in production is associated with division of labour. Division of labour is a production technique where a task is broken down into simple, repetitive tasks that can be performed by individual workers. This leads to greater efficiency in production as workers become specialized in their respective tasks, leading to an increase in productivity and output. This matches option 3.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>14", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "If TC, FC and VC represent total cost, fixed cost and variable cost respectively, which of the following is correct?", "images": [], "options": {"A": "TC = FC - VC", "B": "FC = FC + VC", "C": "TC > FC + VC", "D": "TC = FC + VC"}, "answer": "D", "explanation": "In economics, the total cost (TC) of production is the sum of fixed cost (FC) and variable cost (VC). Fixed costs are costs that do not change with the level of output, such as rent or salaries. Variable costs are costs that change with the level of output, such as raw materials or energy costs. Therefore, the correct equation is TC = FC + VC, which matches option 4.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>15", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "The reward to land as a factor of production is", "images": [], "options": {"A": "profit", "B": "rent", "C": "interest", "D": "wage"}, "answer": "B", "explanation": "The reward for land as a factor of production is rent. This is the payment made to the owner of the land for the use of the land. It is a form of income derived from ownership, not from labor or investment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>16", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "A firm is said to  be a public joint stock company when it", "images": [], "options": {"A": "is owned by the government", "B": "sells is shares to members of the public", "C": "operates as a government corporation", "D": "is not legally recognized as a firm"}, "answer": "B", "explanation": "A firm is said to be a public joint stock company when it sells its shares to members of the public. This means that the company's stock can be bought and sold by investors on public exchanges. The company is owned by its shareholders, who profit from increases in the stock's price and from dividends.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>17", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "All the following are sources of finance to a joint stock company except", "images": [], "options": {"A": "debentures", "B": "cooperative loans", "C": "shares", "D": "bank loans"}, "answer": "B", "explanation": "Cooperative loans are not a source of finance for a joint stock company. A cooperative is a type of business organization that is owned and run by its members, who share the profits or benefits. It is different from a joint stock company, which is owned by shareholders who buy and sell shares on public exchanges.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>18", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "The public sector of an economy includes", "images": [], "options": {"A": "cooperative societies", "B": "nationalized industries", "C": "joint stock companies", "D": "pressure groups"}, "answer": "B", "explanation": "The public sector of an economy includes all government-owned or government-controlled entities. Nationalized industries, which are industries taken over by the government, are part of the public sector. Cooperative societies, joint stock companies, and pressure groups are not inherently part of the public sector as they can be privately owned or controlled.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>19", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "One advantage of the Sole Proprietorship over other forms of business organizations is that it can", "images": [], "options": {"A": "make very high profits", "B": "employ many workers", "C": "keep its affairs private", "D": "produce on a very large scale"}, "answer": "C", "explanation": "One advantage of the Sole Proprietorship over other forms of business organizations is that it can keep its affairs private. This is because a sole proprietorship is owned and run by one individual, who has total control over the business and its operations, including its information. The other options do not necessarily apply to sole proprietorships. For example, they may not make very high profits, employ many workers, or produce on a very large scale, depending on the nature and size of the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>20", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM", "question": "Which of the following is obtainable in a perfect market?", "images": [], "options": {"A": "P = MR > AR", "B": "MP = MC > P", "C": "MR", "D": "P = MR = MC"}, "answer": "D", "explanation": "For a perfect market, profit is maximized in the short run when   P = MR = MC.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>21", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER", "question": "The wholesaler performs the following functions except", "images": [], "options": {"A": "breaking the bulk", "B": "offering credit facilities to consumers", "C": "financing manufacturers", "D": "buying in bulk from manufacturers"}, "answer": "B", "explanation": "Wholesalers typically do not offer credit facilities to consumers. Their role is to buy goods in bulk from manufacturers and sell them in smaller quantities to retailers, who then sell to consumers. Offering credit facilities to consumers is usually the role of retailers or financial institutions. The other functions listed - breaking the bulk, financing manufacturers, and buying in bulk from manufacturers - are typical roles of wholesalers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>22", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION", "question": "Age Group 19830 - 15 30% 16 - 40 27% 41 - 60 25% 61 and above 18%     The table above shows the age distribution of country A in 1983. Using the data in the table, calculate the percentage of working population in 1983", "images": [], "options": {"A": "48%", "B": "52%", "C": "57%", "D": "70%"}, "answer": "B", "explanation": "The working population is usually considered to be those between the ages of 16 and 60. From the table, this is 27% (16 - 40 age group) + 25% (41 - 60 age group) = 52%. Therefore, the percentage of the working population in 1983 is 52%.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>23", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "A country whose population size is too small relative to its resources is", "images": [], "options": {"A": "over populated", "B": "optimally populated", "C": "under populated", "D": "producing the optimum output"}, "answer": "C", "explanation": "A country is considered under-populated when the size of the population is too small relative to its resources. This means that the country has more resources than it can use effectively. Therefore, the correct answer is 'under populated'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>24", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "An efficient weapon used in resolving disputes between employers and employers is", "images": [], "options": {"A": "co-operation", "B": "collective bargaining", "C": "display placards", "D": "legal action"}, "answer": "B", "explanation": "Collective bargaining is a process of negotiation between employers and a group of employees aimed at agreements to regulate working conditions. The interests of the employees are commonly presented by representatives of a trade union to which the employees belong. Therefore, the correct answer is 'collective bargaining'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>25", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following does not explain why a school principal earns more salary than a school messenger?", "images": [], "options": {"A": "Length of training", "B": "Demand and supply", "C": "Cost of training", "D": "The messenger is a non-teaching staff"}, "answer": "D", "explanation": "The salary of a school principal is higher than that of a school messenger due to factors such as the length of training, demand and supply, and cost of training. These factors contribute to the value of the principal's skills and expertise, which are reflected in their salary. The fact that the messenger is a non-teaching staff does not directly influence the salary difference. Therefore, option 4 is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>26", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : ROLES", "question": "The role of the government in promoting agricultural development includes the following except", "images": [], "options": {"A": "paying the wages of all farmers", "B": "establishing and funding research", "C": "formulation of policies", "D": "provision of rural infrastructure"}, "answer": "A", "explanation": "The government plays a significant role in promoting agricultural development. However, paying the wages of all farmers is not one of these roles. The government's role includes establishing and funding research, formulating policies, and providing rural infrastructure. Therefore, option 1 is the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>27", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "The following are advantages of large scale agriculture except", "images": [], "options": {"A": "use of simple implements", "B": "use of sophisticated implements", "C": "increase in employment", "D": "integration of crop and animal farming?"}, "answer": "A", "explanation": "Large scale agriculture is characterized by the use of sophisticated implements, increase in employment, and integration of crop and animal farming. The use of simple implements is more associated with small scale or subsistence farming. Therefore, option 1 is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>28", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "The following are all factors determining the location of industry except", "images": [], "options": {"A": "minimum wages rate", "B": "availability of labour", "C": "nearness to raw materials", "D": "proximity to market"}, "answer": "A", "explanation": "The minimum wage rate is not a factor that determines the location of an industry. Factors that determine the location of an industry include availability of raw materials, labor, infrastructure, proximity to market, etc. The minimum wage rate is a factor that affects the cost of labor but it does not directly determine the location of an industry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>29", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Which of the following is not a concept in National Income accounting?", "images": [], "options": {"A": "Domestic National Product (DNP)", "B": "Gross National Product (GNP)", "C": "Gross Domestic Product (GDP)", "D": "Net Domestic Product (GDP)"}, "answer": "A", "explanation": "Domestic National Product (DNP) is not a concept in National Income accounting. The concepts in National Income accounting include Gross National Product (GNP), Gross Domestic Product (GDP), and Net Domestic Product (NDP). DNP is not recognized as a standard measure in economics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>30", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "Which of the following equation is appropriate for determining the Net Domestic Product (NDP)", "images": [], "options": {"A": "NDP = GNP - depreciation", "B": "NDP - GDP + Net Income from abroad", "C": "NDP = GDP - depreciation", "D": "NDP = GDP x Net Income from abroad"}, "answer": "C", "explanation": "The correct equation for determining the Net Domestic Product (NDP) is NDP = GDP - depreciation. Gross Domestic Product (GDP) is the total value of all goods and services produced within a country in a given period. Depreciation is the decrease in the value of physical capital - that is, the amount of value that is 'used up' or consumed in the process of producing the GDP. Therefore, to get the Net Domestic Product (NDP), which is the value of the GDP after accounting for depreciation, we subtract the depreciation from the GDP.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>31", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "NATIONAL INCOME : PROBLEMS OF NATIONAL INCOME", "question": "Which of the following over estimate the value of national income?", "images": [], "options": {"A": "Incomplete statistical data", "B": "Wrong timing of computation", "C": "Changes of prices of goods within the year", "D": "Double counting"}, "answer": "D", "explanation": "Double counting overestimates the value of national income. This happens when the same good or service is counted more than once in the calculation of the Gross Domestic Product (GDP). For example, if a farmer sells wheat to a baker and the baker sells bread to a customer, counting both the sale of wheat and the sale of bread would be double counting, as the value of the wheat is already included in the value of the bread.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>32", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "MONEY : SUPPLY OF MONEY", "question": "The total stock of money available for us in an economy is", "images": [], "options": {"A": "a function of money", "B": "a characteristic of money", "C": "the demand for money", "D": "the supply of money"}, "answer": "D", "explanation": "The total stock of money available for use in an economy is the supply of money. The supply of money is determined by the central bank of a country and includes currency (coins and paper money) in circulation and demand deposits held by commercial banks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>33", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "Which of the following is not a reason for holding money?", "images": [], "options": {"A": "Ostentation", "B": "Speculation", "C": "Transactions", "D": "Precautionary"}, "answer": "A", "explanation": "Ostentation is not a reason for holding money. The three main motives for holding money, according to Keynes, are the transactions motive (people need cash for everyday items), the precautionary motive (people hold cash for unexpected expenses) and the speculative motive (people hold cash to profit from changes in interest rates). Ostentation, or display of wealth, is not a recognized economic motive for holding money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>34", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "The best way of combating demand - pull inflation is to", "images": [], "options": {"A": "increase income taxes", "B": "reduce income taxes", "C": "increase import duties", "D": "increase salaries and wages"}, "answer": "A", "explanation": "Demand-pull inflation is caused by an increase in demand for goods and services that outpaces supply. It can be combated by reducing the amount of money available for purchasing goods and services. One way to do this is by increasing income taxes, which reduces the amount of disposable income people have, thereby reducing their ability to buy goods and services. This can help to bring demand back in line with supply and reduce inflation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>35", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "In which of the following ways has inflation adversely affected your country's economy?", "images": [], "options": {"A": "Increase in money supply", "B": "A fall in real income", "C": "Appreciation in the value of money", "D": "Increase employment"}, "answer": "B", "explanation": "Inflation is a general increase in prices and fall in the purchasing value of money. When inflation occurs, the real income, which is the income of an individual after taking into consideration the effects of inflation on purchasing power, falls. This is because as prices rise, the same amount of money buys fewer goods and services. This is why a fall in real income is one of the ways inflation can adversely affect an economy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>36", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "MONEY : TYPES OF MONEY", "question": "Which of the following is a legal tender?", "images": [], "options": {"A": "bank notes", "B": "Bank overdrafts", "C": "Bills of exchange", "D": "Money order"}, "answer": "A", "explanation": "Legal tender is the recognized medium of exchange for goods and services in a country, which by law must be accepted if offered in payment of a debt. In most countries, this includes coins and banknotes. Bank overdrafts, bills of exchange, and money orders are not legal tender. They are financial instruments that can be used to transfer money, but they are not in themselves a medium of exchange.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>37", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "The central Bank controls money supply through all the following except", "images": [], "options": {"A": "lending to the public", "B": "bank rate", "C": "legal reserve requirements", "D": "open market operation"}, "answer": "A", "explanation": "The central bank does not control money supply by lending to the public. The central bank controls money supply through methods such as changing the bank rate, altering legal reserve requirements, and conducting open market operations. The bank rate is the interest rate at which a nation's central bank lends money to domestic banks. Legal reserve requirements refer to the minimum amount of funds that a bank must hold in reserve against deposit liabilities. Open market operations involve the buying and selling of government securities in the open market in order to expand or contract the amount of money in the banking system.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>38", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "One of the functions of the Central bank is", "images": [], "options": {"A": "production of goods", "B": "issuing of currency", "C": "presenting budgets", "D": "printing of cheque books"}, "answer": "B", "explanation": "One of the main functions of the Central bank is the issuing of currency. The central bank has the exclusive right to issue banknotes and coins in a country. This function is not related to the production of goods, presenting budgets, or printing of cheque books.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2010>39", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "The functions of the Central Bank as a lender of last resort means that when all other sources fail", "images": [], "options": {"A": "the consumer can always borrow money from the Central bank", "B": "the government can ask the Central bank to print more money", "C": "commercial banks can raise loans from the Central Bank", "D": "Commercial bank can deposit money with the Central Bank"}, "answer": "C", "explanation": "The function of the Central Bank as a lender of last resort means that when all other sources fail, commercial banks can raise loans from the Central Bank. This is to prevent a financial crisis in the economy. It does not mean that consumers can always borrow money from the Central bank or that the government can ask the Central bank to print more money. It also does not mean that commercial banks can deposit money with the Central Bank.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>40", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "One disadvantage of direct taxes is that they", "images": [], "options": {"A": "allocate scarce resources", "B": "are not rigid", "C": "can be progressive", "D": "can be evaded"}, "answer": "D", "explanation": "Direct taxes can be evaded because they are imposed on individuals or entities, who may not fully declare their income or wealth, hence avoiding or reducing the tax they should pay. This is a disadvantage of direct taxes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>41", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "Excise duty is levied on", "images": [], "options": {"A": "the total population", "B": "local products", "C": "luxury goods", "D": "the working population"}, "answer": "C", "explanation": "Excise duty is a type of tax that is levied on specific goods and services, often considered as luxury goods. These are goods that are not essential but are highly desired. This makes them a good source of revenue for the government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>42", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "A component of the national debt of a country is", "images": [], "options": {"A": "taxation", "B": "bank saving", "C": "the budget", "D": "treasury bills"}, "answer": "D", "explanation": "The national debt of a country is made up of the amount of money that the government has borrowed. One way that governments can borrow money is by issuing treasury bills. These are short-term debt securities issued by a government to finance their debt.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>43", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "When the demand for a good is fairly inelastic, the burden of an indirect tax falls", "images": [], "options": {"A": "more on the consumer of the goods", "B": "more on the sellers of the goods", "C": "on sellers and consumers equally", "D": "completely on the capital"}, "answer": "A", "explanation": "When the demand for a good is fairly inelastic, consumers are less responsive to changes in price. Therefore, if an indirect tax is imposed, the price of the good will increase, but consumers will continue to buy it because their demand is inelastic. As a result, the burden of the tax falls more on the consumer of the goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>44", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Dumping means the selling of a goods in a foreign market at a price that is", "images": [], "options": {"A": "below the home market price", "B": "above the home market price", "C": "equal to the home market price", "D": "able to clear the home market"}, "answer": "A", "explanation": "Dumping is a term used in the context of international trade. It's when a country or company exports a product at a price that is lower in the foreign importing market than the price in the exporter's domestic market. Hence, the correct answer is 'below the home market price'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>45", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Which of the following group of accounts make up the balance of payments?", "images": [], "options": {"A": "The current account; multiplied account and capital account", "B": "Monetary movement account; company account and international account", "C": "Cash account; double entry account and current account", "D": "Capital account; current account and monetary movement account"}, "answer": "D", "explanation": "The balance of payments is a statement of all transactions made between entities in one country and the rest of the world over a defined period of time. It consists of the current account (which includes goods and services imports and exports, and other transfers), the capital account (which includes capital transfers and acquisition/disposal of non-produced, non-financial assets), and the financial account (which records investment flows). However, the term 'monetary movement account' is not a standard term in balance of payments accounting, but it could be interpreted as referring to the financial account. Therefore, the closest correct answer is 'Capital account; current account and monetary movement account'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>46", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "A country's balance of payments is in deficit when", "images": [], "options": {"A": "a country's payments for imports of invisible goods are greater than her receipts from exports of invisible goods", "B": "the total receipts from her export of visible and invisible goods are greater than her payments for visible and invisible imports", "C": "It can record a surplus on current account of her balance of payments accounts", "D": "the total payments for visible and invisible imports are greater than the total receipts from her exports of visible and invisible goods"}, "answer": "D", "explanation": "A country's balance of payments is in deficit when the total payments for visible and invisible imports are greater than the total receipts from her exports of visible and invisible goods. The balance of payments is a record of all economic transactions between the residents of a country and the rest of the world. It includes the trade of goods (visible) and services (invisible), as well as financial transfers. When the value of what is imported (both goods and services) exceeds the value of what is exported, the balance of payments is said to be in deficit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2010>47", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "In order to stabilize oil price in the world market, there is the need for OPEC members to", "images": [], "options": {"A": "always have budget deficit", "B": "encourage competition among themselves", "C": "adhere to production quotas", "D": "fix the price of non-oil products"}, "answer": "C", "explanation": "In order to stabilize oil price in the world market, there is the need for OPEC (Organization of the Petroleum Exporting Countries) members to adhere to production quotas. OPEC is a group of oil-producing countries that work together to coordinate their petroleum policies and provide member states with technical and economic aid. By adhering to production quotas, OPEC members can control the supply of oil in the market, which in turn can help stabilize prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>48", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "ECONOMIC INTEGRATION : PROBLEMS OF ECONOMIC INTEGRATION IN WEST AFRICA- ECOWAS", "question": "Which of the following is not a member of the Economic Community of West African States (ECOWAS)?", "images": [], "options": {"A": "Cape verde", "B": "Mauritania", "C": "Cameroun", "D": "Niger"}, "answer": "C", "explanation": "The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. Among the options given, Cameroun is not a member of ECOWAS. It is part of the Central African region.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>49", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "Which of the following is not a type of international economic integration?", "images": [], "options": {"A": "Customs market", "B": "Common market", "C": "Economic union", "D": "Free trade area"}, "answer": "A", "explanation": "A customs market is not a type of international economic integration. The other options, common market, economic union, and free trade area, are all forms of international economic integration. A customs market is not a recognized term in economics. International economic integration refers to the unification of economic policies between different states through the partial or full abolition of tariff and non-tariff restrictions on trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2010>50", "subject": "Economics", "year": "2010", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "Which of the following is not an international economic organization?", "images": [], "options": {"A": "Economic Commission for Africa (ECA)", "B": "Africa Development Bank (ADB)", "C": "World Health Organization (WHO)", "D": "International Monetary Fund (IMF)"}, "answer": "C", "explanation": "The World Health Organization (WHO) is not an international economic organization. It is a specialized agency of the United Nations responsible for international public health. The other options, Economic Commission for Africa (ECA), Africa Development Bank (ADB), and International Monetary Fund (IMF), are all international economic organizations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>1", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Human wants are", "images": [], "options": {"A": "limited", "B": "scarce", "C": "unlimited", "D": "in grades"}, "answer": "C", "explanation": "Human wants are unlimited. This is a basic concept in economics. It refers to the idea that there is an infinite amount of human needs and wants. As soon as one want is satisfied, another one appears. This is in contrast to the limited resources available to satisfy these wants, creating the basic economic problem of scarcity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2011>2", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS", "question": "The difference between the money cost and the real cost of any items is that", "images": [], "options": {"A": "real cost is the alternative forgone while the money cost is the actual amount paid for buying the item", "B": "the real cost is the opportunity cost while the money cost is the marginal cost", "C": "money cost is the opportunity cost, while the real cost is the actual cost in monetary terms", "D": "money cost is always greater than real cost"}, "answer": "A", "explanation": "The real cost of an item refers to the opportunity cost, which is the value of the next best alternative that is forgone when a decision is made. It's not just the monetary cost, but also includes factors like time, resources, etc. that are given up. On the other hand, the money cost is the actual amount paid for buying the item. Therefore, option 1 is correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>3", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE", "question": "The Production Possibility Curve (PPC) indicates that as more of one good is produced", "images": [], "options": {"A": "less of the other goods is produced", "B": "the same quantity of the other goods is produced", "C": "more of the other goods is produced", "D": "none of the other goods is produced"}, "answer": "A", "explanation": "The Production Possibility Curve (PPC) is a graphical representation of the possible combinations of two goods that can be produced with constant resources and technology. The curve shows that as more of one good is produced, less of the other good can be produced due to the scarcity of resources. This is known as the law of increasing opportunity cost. Therefore, option 1 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>4", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH", "question": "An arrangement of data in rows and columns is referred to as a", "images": [], "options": {"A": "graph", "B": "bar chart", "C": "pie chart", "D": "table"}, "answer": "D", "explanation": "An arrangement of data in rows and columns is referred to as a table. It is a structured set of data. A table allows for easy comparison and analysis of data. Therefore, option 4 is correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2011>5", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "A normal demand curve slopes", "images": [], "options": {"A": "downwards from left to right", "B": "upwards from right to left", "C": "downward from right to left", "D": "upward from left to right"}, "answer": "A", "explanation": "A normal demand curve slopes downwards from left to right. This is because as the price of a good or service increases, the quantity demanded decreases, and vice versa. This is known as the law of demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>6", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "The co-efficient of income elasticity of demand for inferior goods is", "images": [], "options": {"A": "Positive", "B": "equal to one", "C": "less than one", "D": "negative"}, "answer": "D", "explanation": "The coefficient of income elasticity of demand for inferior goods is negative. Inferior goods are those goods for which demand decreases when consumer income rises, unlike normal goods, for which demand increases as consumer income rises. Therefore, the income elasticity of demand for inferior goods is negative.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>7", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If 20% rise in the price of Whisky leads to a 30% increase in quantity demanded of Schnapps, the cross elasticity of demand is", "images": [], "options": {"A": "3.0", "B": "2.5", "C": "2.3", "D": "1.5"}, "answer": "D", "explanation": "Cross elasticity of Demand = %Δ in Quantity Demanded ÷ % Δ in price    = 30/20    = 1.5", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>8", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Palm oil and palm kernel have", "images": [], "options": {"A": "competitive supply", "B": "excess supply", "C": "joint supply", "D": "composite supply"}, "answer": "C", "explanation": "Palm oil and palm kernel are examples of joint supply. This is because they are derived from the same source, which is the oil palm tree. In economics, joint supply refers to a situation where an increase or decrease in the supply of one good leads to an increase or decrease in the supply of another good.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>9", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "A supply curve which is vertical has an elastic co-efficient of", "images": [], "options": {"A": "0", "B": "0.5", "C": "1.5", "D": "2"}, "answer": "A", "explanation": "A vertical supply curve is perfectly inelastic, meaning that the quantity supplied does not change regardless of changes in price. The elasticity coefficient of a perfectly inelastic supply curve is 0. Elasticity measures the responsiveness of quantity supplied to a change in price.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>10", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "If the current price of an apple is twice that of last year, it implies that the value of money is", "images": [], "options": {"A": "stable", "B": "falling", "C": "rising", "D": "getting stronger"}, "answer": "B", "explanation": "If the current price of an apple is twice that of last year, it implies that the value of money is falling. This is because it now takes more money to purchase the same quantity of goods, indicating that the purchasing power of money has decreased. In economics, this is often a sign of inflation, which is a general increase in prices and fall in the purchasing value of money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>11", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "Price fixed above the equilibrium is to", "images": [], "options": {"A": "protect agriculture producers", "B": "discourage agricultural producers", "C": "lower the prices of agricultural produce", "D": "favour consumers"}, "answer": "A", "explanation": "The price is fixed above the equilibrium so as to help protect the producers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>12", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "A consumer purchasing a commodity X will maximize his satisfaction if", "images": [], "options": {"A": "Px = MUx", "B": "Px ≥ MUx", "C": "Px > MUx", "D": "Px"}, "answer": "A", "explanation": "The consumer maximizes his satisfaction when the price of the commodity (Px) is equal to the marginal utility of the commodity (MUx). This is known as the law of equi-marginal utility, which states that consumers allocate their income so that the last dollar spent on each product purchased yields the same amount of extra (marginal) utility.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>13", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND", "question": "When total utility is constant, it means marginal utility is", "images": [], "options": {"A": "increasing", "B": "zero", "C": "decreasing", "D": "one"}, "answer": "B", "explanation": "When total utility is constant, it means that the additional satisfaction (marginal utility) a consumer gets from consuming an additional unit of a good is zero. This is because the total utility, which is the total satisfaction received from consuming a certain quantity of a good, is not changing as more of the good is consumed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>14", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "A rational consumer is one who", "images": [], "options": {"A": "spends his income to maximize satisfaction", "B": "is not influenced by advertisement", "C": "behaves in a particular way all the time", "D": "knows the prices of all goods and buys the cheapest"}, "answer": "A", "explanation": "A rational consumer is one who spends his income to maximize satisfaction. This is based on the assumption of rational behavior, which suggests that individuals make decisions that provide the greatest benefit or satisfaction given the choices available. This is also known as utility maximization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>15", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following is not true about land?", "images": [], "options": {"A": "The supply is fixed", "B": "Land is mobile", "C": "It is subject to diminishing returns", "D": "Land is heterogenous"}, "answer": "B", "explanation": "Land is not mobile. This means that it cannot be moved from one place to another. The other options are true about land: its supply is indeed fixed, it is subject to diminishing returns, and it is heterogeneous, meaning it varies in quality and characteristics.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2011>16", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "The type of production that involves the tapping and harvesting of natural resources is", "images": [], "options": {"A": "primary production", "B": "secondary production", "C": "tertiary production", "D": "industrial production"}, "answer": "A", "explanation": "Primary production involves the tapping and harvesting of natural resources. This includes activities like farming, fishing, and mining. Secondary production involves the processing of these raw materials into finished goods, while tertiary production refers to the provision of services. Industrial production could involve any of these stages, depending on the industry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2011>17", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "Which of the following does not change in the short run?", "images": [], "options": {"A": "variable cost", "B": "Marginal cost", "C": "Total cost", "D": "Fixed cost"}, "answer": "D", "explanation": "In the short run, fixed costs do not change. These are costs that a business incurs regardless of the level of output, such as rent or salaries for permanent staff. Variable costs, marginal costs, and total costs can all change in the short run, depending on the level of production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>18", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "The resources used in production are called?", "images": [], "options": {"A": "variable inputs", "B": "factors of production", "C": "capital of production", "D": "fixed inputs"}, "answer": "B", "explanation": "The resources used in production are referred to as 'factors of production'. These include land, labor, capital, and entrepreneurship. Variable inputs and fixed inputs are types of factors of production, but they are not the general term for all resources used in production. Capital of production is not a recognized term in economics.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2011>19", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION", "question": "A firm will shut down in the long run if its earning is", "images": [], "options": {"A": "less than normal profit", "B": "greater than normal profit", "C": "equal to super normal profit", "D": "less than super normal profit"}, "answer": "A", "explanation": "A firm will shut down in the long run if its earning is less than normal profit. Normal profit is the minimum level of profit needed for a company to remain competitive in the market. If a firm's earnings fall below this level, it may not be able to cover its costs, and thus would choose to shut down in the long run.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>20", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "MARKET STRUCTURE : PERFECT MARKET", "question": "A market structure where profit is maximized when marginal revenue, marginal cost and price are equal is known as", "images": [], "options": {"A": "perfect competition", "B": "monopoly", "C": "oligopoly", "D": "imperfect competition"}, "answer": "A", "explanation": "A market structure where profit is maximized when marginal revenue, marginal cost and price are equal is known as perfect competition. In a perfectly competitive market, firms are price takers and cannot influence the market price. They maximize their profit by producing up to the point where marginal cost equals marginal revenue, which is also equal to the market price.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>21", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "In which of the following markets does a firm have power to make super normal profits both in the short run and long run?", "images": [], "options": {"A": "Monopoly", "B": "Duopoly", "C": "Oligopoly", "D": "Monopsony"}, "answer": "A", "explanation": "In a monopoly market, a single firm controls the entire market. It is the only supplier of a particular commodity and hence, has the power to influence price. This gives the firm the ability to make super normal profits both in the short run and long run because there are high barriers to entry and no close substitutes exist.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>22", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "If there are no barriers to entering a market, it means that", "images": [], "options": {"A": "anyone can become a buyer or seller", "B": "unwanted goods can always enter the market", "C": "the market becomes a dumping ground", "D": "the goods are not inspected"}, "answer": "A", "explanation": "In economics, barriers to entry are obstacles that make it difficult for new firms to enter a market. If there are no barriers to entering a market, it means that anyone can become a buyer or seller. The other options do not accurately describe a market with no barriers to entry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2011>23", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "A firm's main aim is to", "images": [], "options": {"A": "survive in business", "B": "maximize profits", "C": "increase it market share", "D": "satisfy the ambitions of its managers"}, "answer": "B", "explanation": "The main aim of a firm is to maximize profits. This is the fundamental assumption in economics. While other goals like survival, increasing market share, and satisfying the ambitions of its managers may be important, they are secondary to the primary goal of profit maximization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>24", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "One good reason for the elimination of middlemen is that they", "images": [], "options": {"A": "cause increase in price", "B": "help in price stability", "C": "grade and blend goods", "D": "are too many"}, "answer": "A", "explanation": "Middlemen are intermediaries between producers and consumers in the supply chain. They buy products from producers and sell them to consumers. In the process, they add their own margin to the cost of the products, which increases the final price that consumers have to pay. Therefore, eliminating middlemen can help to reduce the price of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>25", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "The increase in population growth in big cities is referred to as", "images": [], "options": {"A": "settlement", "B": "migration", "C": "industrialization", "D": "urbanization"}, "answer": "D", "explanation": "The term for the increase in population growth in big cities is 'urbanization'. Urbanization refers to the population shift from rural areas to urban areas, and the ways in which society adapts to this change. It is not to be confused with 'settlement', 'migration', or 'industrialization'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>26", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "Frictional unemployment can be reduced by", "images": [], "options": {"A": "encouraging the use of retraining schemes", "B": "removing barriers to labour mobility", "C": "restricting the introduction of new technology", "D": "lowering the level of wages paid to young people"}, "answer": "B", "explanation": "Frictional unemployment is the short-term unemployment that occurs when people are in between jobs, have quit their job to find a better one, or are looking for their first job. It can be reduced by removing barriers to labour mobility. This means making it easier for workers to move from one job to another, or from one location to another, in search of work. This can involve things like improving transportation infrastructure, reducing legal restrictions on job changes, and providing better information about job opportunities.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>27", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "If the labour force of a country is 2.5 million and 2 million are employed, what is the unemployment rate?", "images": [], "options": {"A": "0.2%", "B": "20%", "C": "200%", "D": "250%"}, "answer": "B", "explanation": "The unemployment rate is calculated by dividing the number of unemployed individuals by the total labor force and multiplying by 100. In this case, the number of unemployed individuals is 2.5 million (total labor force) - 2 million (employed) = 0.5 million. Therefore, the unemployment rate is (0.5 million / 2.5 million) * 100 = 20%.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>28", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION", "question": "The grouping of population according to the economic activities people engage in is", "images": [], "options": {"A": "age distribution", "B": "sex distribution", "C": "geographical distribution", "D": "occupation distribution"}, "answer": "D", "explanation": "The grouping of population according to the economic activities people engage in is referred to as occupation distribution. This involves categorizing people based on their jobs or professions, such as farming, teaching, engineering, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>29", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "Natural growth rate of population can be defined as the", "images": [], "options": {"A": "difference between birth rate and death rate", "B": "number of births in a year", "C": "increase in the population growth in a year", "D": "difference between the total population and the death rate"}, "answer": "A", "explanation": "The natural growth rate of a population is defined as the difference between the birth rate and the death rate. This is because the natural increase or decrease in a population is determined by the number of births and deaths.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>30", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "Which of the following is NOT a consequence of increased unemployment?", "images": [], "options": {"A": "A fall in tax revenue for the government", "B": "A reduction in trade union's influence", "C": "A fall in the death rate", "D": "An increase in the labour force"}, "answer": "C", "explanation": "Increased unemployment does not lead to a fall in the death rate. Unemployment is an economic condition where individuals seeking jobs remain un-hired. It can lead to a fall in tax revenue for the government because fewer people are earning income and therefore paying less in taxes. It can also lead to a reduction in trade union's influence as fewer workers are available to join and support unions. An increase in the labour force is also not a direct consequence of increased unemployment, as the labour force includes both employed and unemployed individuals. However, a fall in the death rate is not a direct or indirect consequence of increased unemployment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>31", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "The following are features of subsistence agriculture except", "images": [], "options": {"A": "little capital", "B": "processing of raw materials", "C": "small allotments of land", "D": "use of crude implements"}, "answer": "B", "explanation": "Processing of raw materials is not a feature of subsistence agriculture. Subsistence agriculture is a type of farming in which the farmers focus on growing enough food to feed themselves and their families. The output is mostly for local requirements with little or no surplus trade. The typical subsistence farm has a range of crops and animals needed by the family to feed and clothe themselves during the year. Therefore, it involves little capital, small allotments of land, and use of crude implements. However, processing of raw materials is typically associated with industrial or commercial agriculture, not subsistence agriculture.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2011>32", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Which of the following is NOT true of small companies? They", "images": [], "options": {"A": "cannot benefit from economics of scale", "B": "are a good source of new jobs", "C": "can satisfy demand in specialist markets", "D": "have a good record of technical innovations"}, "answer": "A", "explanation": "The statement that small companies cannot benefit from economies of scale is not true. Economies of scale refer to the cost advantage experienced by a firm when it increases its level of output.The advantage arises due to the inverse relationship between per-unit fixed cost and the quantity produced. The efficiency of large scale production can be enjoyed by small companies through methods like mass production, specialization, and networking. Small companies can also be a good source of new jobs, satisfy demand in specialist markets, and have a good record of technical innovations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>33", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "The effect of privatization of the industrial sector of a country is that it", "images": [], "options": {"A": "ensures efficiency", "B": "discourages efficiency", "C": "leads to decrease in output", "D": "leads to liquidation"}, "answer": "A", "explanation": "Privatization of the industrial sector often leads to increased efficiency. This is because private companies are driven by profit motives and therefore have an incentive to minimize costs and maximize output. This often leads to more efficient practices than in the public sector, where the absence of a profit motive can sometimes lead to inefficiencies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>34", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "The production strategy used in an over-populated country is", "images": [], "options": {"A": "import substitution", "B": "capital intensive", "C": "labour intensive", "D": "first come first employed"}, "answer": "C", "explanation": "In an over-populated country, the production strategy used is often labour intensive. This is because labour is abundant and therefore relatively cheap. Using a labour intensive strategy can help to reduce unemployment and make use of the available workforce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>35", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "National income is used to measure", "images": [], "options": {"A": "a country's population size", "B": "a country's economic growth", "C": "the human level of development", "D": "the flow of imports to a country"}, "answer": "B", "explanation": "National income is used to measure a country's economic growth. It represents the total value of all goods and services produced over a specific time period within a country's borders. It is a comprehensive measure of a nation's overall economic activity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2011>36", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "A tax is regressive if the", "images": [], "options": {"A": "rate of tax is constant at all income levels", "B": "rate of tax decrease as income increases", "C": "rate of tax increases as income increases", "D": "tax is direct rather than indirect"}, "answer": "B", "explanation": "A regressive tax is one which takes from the poor than the rich. Hence, the higher your income the lesser will be your tax.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>37", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "When a country's net income from abroad is added to its total output, the result is", "images": [], "options": {"A": "gross domestic product", "B": "net national product", "C": "gross national product", "D": "net domestic product"}, "answer": "C", "explanation": "Gross National Product (GNP) is the total value of all final goods and services produced within a nation in a particular year, plus income earned by its citizens (including income of those located abroad), minus income of non-residents located in that country. Therefore, when a country's net income from abroad is added to its total output, the result is Gross National Product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>38", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "NATIONAL INCOME : USES & REASONS FOR MEASURING NATIONAL INCOME", "question": "A fall in national output will necessitate", "images": [], "options": {"A": "a rise in expenditure on imports", "B": "a rise in the level of savings", "C": "an increase in consumption expenditure", "D": "a rise in the standard of living"}, "answer": "A", "explanation": "If there is a decline in national output (i.e goods and services produced within the country) this will necessitate an increase in spending on imported goods.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>39", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "The demand for money to take advantage of change in bond prices is the", "images": [], "options": {"A": "unforeseen motive", "B": "transaction motive", "C": "speculative motive", "D": "precautionary motive"}, "answer": "C", "explanation": "The speculative motive for holding money refers to holding money to make speculative investments. These investments are made in the hope of making profit from changes in prices, such as buying assets when their prices are low and selling them when their prices are high. Therefore, the demand for money to take advantage of change in both prices is the speculative motive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>40", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Cost push inflation is caused by a", "images": [], "options": {"A": "rise in the cost of production", "B": "decrease in the transportation cost", "C": "rise in demand for goods", "D": "decrease in the cost of production"}, "answer": "A", "explanation": "Cost push inflation is a type of inflation caused by substantial increases in the cost of important goods or services where no suitable alternative is available. A common example is when the cost of raw materials increases. This increase in the cost of production would then be passed on to consumers in the form of higher prices, hence causing inflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>41", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Deposit held in a commercial bank are part of", "images": [], "options": {"A": "money supply", "B": "transfer payments", "C": "ordinary shares", "D": "treasury bills"}, "answer": "A", "explanation": "Money supply is the total amount of monetary assets available in an economy at a specific time. It includes demand deposits (deposits that customers can withdraw at any time, such as money in a checking account) held in commercial banks. Therefore, deposits held in a commercial bank are part of the money supply.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2011>42", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "One profitable form of business undertaken by the commercial banks is", "images": [], "options": {"A": "the issuing of cheques", "B": "the payment of standing order", "C": "lending money to borrowers", "D": "accepting cheques from customers"}, "answer": "C", "explanation": "Commercial banks make profit by lending money to borrowers at a higher interest rate than they pay to depositors. The difference between the interest rate that the bank charges borrowers and the interest rate that it pays to depositors is called the net interest margin, which is a key source of profit for banks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>43", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "When governments want to discourage consumption, they tax goods whose demand is", "images": [], "options": {"A": "price inelastic", "B": "abnormal in nature", "C": "price elastic", "D": "normal in nature"}, "answer": "A", "explanation": "When governments want to discourage consumption, they tax goods whose demand is price inelastic. Price inelastic demand refers to a situation where the demand for a good does not change significantly when the price changes. Therefore, even if the government imposes a tax on such goods, consumers will continue to buy them, albeit at a higher price. This discourages consumption as consumers have to pay more for the same goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>44", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "A rise in government expenditure can lead to", "images": [], "options": {"A": "higher inflation", "B": "higher unemployment", "C": "lower profits for industries", "D": "lower importation of raw materials by industries"}, "answer": "A", "explanation": "A rise in government expenditure can lead to higher inflation. This is because when the government spends more, it injects more money into the economy. If this increase in money supply is not matched by an increase in the production of goods and services, it can lead to inflation, which is a general rise in prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>45", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Tariff is used to protect domestic industries by making foreign goods relatively", "images": [], "options": {"A": "cheaper in the domestic market", "B": "more expensive in the domestic market", "C": "more expensive in the international market", "D": "cheaper in the international market"}, "answer": "B", "explanation": "Tariffs are used to protect domestic industries by making foreign goods relatively more expensive in the domestic market. A tariff is a tax imposed on imported goods. When a tariff is imposed, the price of the imported good increases, making it more expensive compared to the domestically produced goods. This encourages consumers to buy domestic goods, thereby protecting the domestic industries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>46", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INTRODUCTION", "question": "The process of increasing the real per capita income and effecting changes in various sectors of the economy is known as", "images": [], "options": {"A": "economic acceleration", "B": "economic development", "C": "economic integration", "D": "economic growth"}, "answer": "B", "explanation": "Economic development is a process that involves the improvement of the economic wealth of a country or region for the well-being of its inhabitants. It involves increasing the real per capita income and effecting changes in various sectors of the economy. Economic acceleration, economic integration, and economic growth are all aspects of economic development, but they do not encompass the full meaning of the term.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>47", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Development plans in West Africa tend to deviate from their targets mainly due to", "images": [], "options": {"A": "political instability", "B": "lack of manpower", "C": "high population growth rate", "D": "low level of education"}, "answer": "A", "explanation": "Political instability is a major factor that causes development plans in West Africa to deviate from their targets. This is because political instability often leads to policy inconsistency, insecurity, and a lack of continuity in government programs. While lack of manpower, high population growth rate, and low level of education can also affect development plans, they are not the main reasons for deviation from targets in the context of West Africa.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2011>48", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "The balance of trade is", "images": [], "options": {"A": "an annual statement showing transaction within a country", "B": "the relationship between a country's visible exports and imports", "C": "the relationship between a country's receipt from visible and invisible trade", "D": "an account that shows a country's payment to other countries"}, "answer": "B", "explanation": "The balance of trade is the difference between a country's exports and its imports. If a country exports more than it imports, it has a trade surplus. If it imports more than it exports, it has a trade deficit. Therefore, the balance of trade is the relationship between a country's visible exports and imports. The other options do not accurately define the balance of trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>49", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "As one of the instruments of commercial policy, quota is", "images": [], "options": {"A": "a qualitative restriction on imports", "B": "a normal restriction on imports", "C": "a quantitative restriction on imports", "D": "an outright prohibition of imports"}, "answer": "C", "explanation": "A quota is a type of trade restriction that sets a physical limit on the quantity of a good that can be imported during a specific period. It is a quantitative restriction on imports, not a qualitative, normal, or outright prohibition of imports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2011>50", "subject": "Economics", "year": "2011", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "The full meaning of the IMF is", "images": [], "options": {"A": "International Military Force", "B": "International Monetary Fund", "C": "International Mortgage Fund", "D": "International Monetary Financing"}, "answer": "B", "explanation": "IMF stands for International Monetary Fund. It is an international organization that aims to promote global economic growth and financial stability, to encourage international trade, and to reduce poverty around the world.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2012>1", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "Which of the following problems arises where there are more than one technically possible methods of production?", "images": [], "options": {"A": "Where to produce", "B": "For whom to produce", "C": "How to produce", "D": "What to produce"}, "answer": "C", "explanation": "The problem of 'how to produce' arises when there are more than one technically possible methods of production. It involves deciding on the most cost-effective method of production considering the available resources and technology.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>2", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Visible balance is also known as", "images": [], "options": {"A": "term of trade", "B": "balance of payments", "C": "balance of trade", "D": "capital balance"}, "answer": "C", "explanation": "Visible balance is also known as the balance of trade. The balance of trade is the difference between a country's exports and its imports. It is the largest component of a country's balance of payments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>3", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND", "question": "A shift in the demand-curve indicates", "images": [], "options": {"A": "exceptional demand", "B": "change in demand", "C": "change in quantity demanded", "D": "elasticity of demand"}, "answer": "B", "explanation": "A change in demand is caused by other factors affecting demand except price and can be illustrated as follow:", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>4", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "If a 6% decrease in price result in more than 6% decrease in quantity supplied, supply can be regarded as", "images": [], "options": {"A": "elastic", "B": "unitary elastic", "C": "perfectly inelastic", "D": "perfectly elastic"}, "answer": "A", "explanation": "If a 6% decrease in price results in more than a 6% decrease in quantity supplied, supply can be regarded as elastic. Elasticity measures the responsiveness of quantity supplied to a change in price. If the percentage change in quantity supplied is greater than the percentage change in price, the supply is considered elastic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>5", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "A condition for cosumer utility maximization is", "images": [], "options": {"A": "equality of the ratio of marginal utilities and ratio of prices", "B": "equality of the ratio average utilities and the ratio of prices", "C": "equality of the marginal utility to total utility ratio for both commodities", "D": "total utility and marginal utility must be zero"}, "answer": "A", "explanation": "A condition for consumer utility maximization is the equality of the ratio of marginal utilities and the ratio of prices. This is known as the law of equi-marginal utility, which states that consumers will allocate their resources in a way that maximizes their total utility. In other words, the last dollar spent on each product consumed must yield the same amount of extra (marginal) utility, or satisfaction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>6", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "Which of the following BEST describes the mode? The", "images": [], "options": {"A": "observation with the highest frequency", "B": "average of two middle numbers", "C": "items that occupies the middle position", "D": "different of two extreme values"}, "answer": "A", "explanation": "The mode in statistics is the value that appears most frequently in a data set. A set may have one mode, more than one mode, or no mode at all. Hence, the mode is the observation with the highest frequency.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2012>7", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "Where a commodity takes an insignificant proportion of the consumer's income, demand for it will be", "images": [], "options": {"A": "unitary elastic", "B": "price inelastic", "C": "fairy elastic", "D": "income inelastic"}, "answer": "B", "explanation": "When a commodity takes an insignificant proportion of the consumer's income, the demand for it is usually price inelastic. Price elasticity of demand measures the responsiveness of the quantity demanded of a good to a change in its price. If the price changes and the demand remains relatively unchanged, the demand is said to be inelastic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>8", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "A demand schedule shows the quantities of goods that are", "images": [], "options": {"A": "bought at given prices at a time", "B": "supplied at given price at a time", "C": "produced at given prices at a time", "D": "reserved for future consumption"}, "answer": "A", "explanation": "A demand schedule, in economics, is a table of the quantity demanded of a good at different price levels. Thus, it shows the quantities of goods that are bought at given prices at a time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2012>9", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "The demand curve for commodity is downward sloping because the consumer will pay", "images": [], "options": {"A": "less as the marginal utility falls", "B": "more as the marginal utility falls", "C": "less as the total utility falls", "D": "more as the average utility falls"}, "answer": "A", "explanation": "The law of diminishing marginal utility explains why the demand curve is downward sloping. As a consumer consumes more units of a commodity, the marginal utility derived from each additional unit decreases. Therefore, the consumer is willing to pay less for each additional unit of the commodity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>10", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "A decrease in the demand for a product X resulted in a decrease in the demand for another product Y. The demand for X and Y is", "images": [], "options": {"A": "derived", "B": "composite", "C": "joint", "D": "competitive"}, "answer": "C", "explanation": "The demand for products X and Y is joint. This is because a decrease in the demand for product X led to a decrease in the demand for product Y. This suggests that the two products are complements, i.e., they are used together. Therefore, a decrease in the demand for one leads to a decrease in the demand for the other.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>11", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "Any price below the equilibrium price will lead to", "images": [], "options": {"A": "increase in supply", "B": "excess demand", "C": "equality of demand and supply", "D": "decrease in demand"}, "answer": "B", "explanation": "The point below the equilibrium price implies excess demand or shortage as illustrated below.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>12", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "The allocation of goods and services in a free market economy is performed by", "images": [], "options": {"A": "the price system", "B": "the banking system", "C": "the central planning body", "D": "government budgets"}, "answer": "A", "explanation": "In a free market economy, the allocation of goods and services is performed by the price system. Prices act as signals to producers and consumers, guiding them in their decisions about what and how much to produce or consume. The price system ensures that resources are allocated to their most efficient uses, based on the preferences and willingness to pay of consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>13", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Given that Qd = 20 - 1/2P. What is the Qd when P is $12?", "images": [], "options": {"A": "6 units", "B": "10 units", "C": "12 units", "D": "14 units"}, "answer": "D", "explanation": "Qd = 20 - 1/2P    = 20 - 1/2(12)    = 20 - 6    = 14 units.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>14", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT", "question": "If a particular consumer derives total utility of 22 utils having consumed 4 units of a given product, his average utility will be", "images": [], "options": {"A": "88 utils", "B": "18 utils", "C": "5.5 utils", "D": "3.5 utils"}, "answer": "C", "explanation": "Average utility is calculated by dividing the total utility by the number of units consumed. In this case, the total utility is 22 utils and the number of units consumed is 4. Therefore, the average utility is 22/4 = 5.5 utils. Hence, the correct option is '5.5 utils'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>15", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND", "question": "The law of diminishing marginal utility applies to a", "images": [], "options": {"A": "firm which maximizes satisfaction", "B": "consumer who maximizes satisfaction", "C": "producer who maximizes marginal products", "D": "consumer who maximizes total utility"}, "answer": "B", "explanation": "The law of diminishing marginal utility states that as a person increases consumption of a product while keeping consumption of other products constant, there is a decline in the marginal utility that person derives from consuming each additional unit of that product. This law is typically applied to consumers, not firms or producers. Therefore, the correct option is 'consumer who maximizes satisfaction'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>16", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION", "question": "Why is the law of diminishing returns a short run phenomenon?", "images": [], "options": {"A": "All inputs are fixed", "B": "All inputs are variable", "C": "Some outputs are variable", "D": "Some inputs are variable"}, "answer": "D", "explanation": "The law of diminishing returns is a short run phenomenon because in the short run, some inputs are fixed while others are variable. This means that as more of the variable input (like labor) is added to the fixed input (like capital or land), the additional output (returns) will eventually start to decrease. This is because the fixed input can only support a certain amount of the variable input before it becomes less effective.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>17", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "Which of the following is capable of increasing the population of a country?", "images": [], "options": {"A": "Decrease in death rate", "B": "increase in death rate", "C": "poor medical facilities", "D": "Decrease in birth rate"}, "answer": "A", "explanation": "A decrease in death rate can increase the population of a country. This is because when fewer people die, the population naturally increases. This is assuming that the birth rate remains constant or increases. If the birth rate decreases at a faster rate than the death rate, the population could still decrease.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>18", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "In the firm's production process, marginal cost", "images": [], "options": {"A": "falls continuously throughout", "B": "falls and later rises", "C": "remains unchanged throughout", "D": "rises and later falls"}, "answer": "B", "explanation": "In the firm's production process, the marginal cost falls initially due to economies of scale and then rises due to the law of diminishing returns. Economies of scale refer to the cost advantages that a business obtains due to expansion. As the quantity of production increases, the cost per unit of production decreases, leading to a fall in the marginal cost. However, after a certain point, as production continues to increase, the additional cost of producing one more unit starts to rise due to the law of diminishing returns.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>19", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION", "question": "If a firms price is less than average cost but more than average variable cost, the firm is covering", "images": [], "options": {"A": "all of its fixed cost and variable cost", "B": "all of its fixed cost and part of variable cost", "C": "all of its variable cost and part of fixed cost", "D": "part of its fixed cost and part of its variable cost"}, "answer": "C", "explanation": "If a firm's price is less than average cost but more than average variable cost, it means that the firm is covering all of its variable costs and part of its fixed costs. Variable costs are costs that change with the level of output, such as raw materials, while fixed costs are costs that do not change with the level of output, such as rent or salaries. In this case, the firm's price is enough to cover all the variable costs and some, but not all, of the fixed costs.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>20", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "An arrangement in which the debts of a company can only be paid from its own assets implies", "images": [], "options": {"A": "unlimited liability", "B": "transferred liability", "C": "limited liability", "D": "capital liability"}, "answer": "C", "explanation": "An arrangement in which the debts of a company can only be paid from its own assets implies limited liability. Limited liability is a type of liability where a company's financial liability is limited to a fixed sum, usually the value of a person's investment in a company or partnership. If a company with limited liability is sued, then the claimants are suing the company, not its owners or investors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>21", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "One reason why small scale business are very common in West Africa is that", "images": [], "options": {"A": "they can easily float shares", "B": "their management boards are easily formed", "C": "their initial capital is easily to raise", "D": "their dividend payments are very regular"}, "answer": "C", "explanation": "One reason why small scale businesses are very common in West Africa is that their initial capital is easy to raise. Small scale businesses often require less capital to start up compared to larger businesses. This makes it easier for individuals or small groups to raise the necessary funds to start the business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>22", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "A public limited company could finance its operation through", "images": [], "options": {"A": "government taxes", "B": "equity shares", "C": "dividend payment", "D": "import liability"}, "answer": "B", "explanation": "A public limited company can finance its operations through equity shares. Equity shares represent ownership in a company and constitute a claim on part of the company's assets and earnings. There are two main types of stock: common and preferred. The government taxes, dividend payment, and import liability are not ways a company can finance its operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>23", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "The factor of production which takes the initiative in combining resources for production is known as", "images": [], "options": {"A": "capital", "B": "land", "C": "entrepreneur", "D": "labour"}, "answer": "C", "explanation": "The factor of production which takes the initiative in combining resources for production is known as the entrepreneur. An entrepreneur is an individual who creates a new business, bearing most of the risks and enjoying most of the rewards. The entrepreneur is commonly seen as an innovator, a source of new ideas, goods, services, and business/or procedures.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2012>24", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "The type of monopoly that develops as a result of granting patent right is known as", "images": [], "options": {"A": "natural monopoly", "B": "state monopoly", "C": "legal monopoly", "D": "discriminating monopoly"}, "answer": "C", "explanation": "The type of monopoly that develops as a result of granting patent right is known as a legal monopoly. A legal monopoly, also known as a statutory monopoly, is a company that is protected by law from competitors. In other words, a legal monopoly is a company that is allowed by the government to provide a particular service or product exclusively.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>25", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "MARKET STRUCTURE : FORMS OF MARKET STRUCTURE", "question": "Which of the following markets determines its own price or output?", "images": [], "options": {"A": "Perfect market", "B": "Common market", "C": "Monopoly market", "D": "Commodity market"}, "answer": "C", "explanation": "A monopoly market determines its own price or output. In a monopoly, a single firm controls the entire market. It is the sole seller of goods and services with no close substitutes, hence it has the power to set prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>26", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE RETAILER", "question": "Which of the following is a function of a retailer?", "images": [], "options": {"A": "Banking services", "B": "Hoarding services", "C": "Storage services", "D": "Sales services"}, "answer": "D", "explanation": "Sales services is a function of a retailer. Retailers are intermediaries in the distribution channel that buy products from wholesalers or directly from manufacturers and sell them to end consumers. They provide services such as sales, customer support, and after-sales service.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2012>27", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION", "question": "The difference between the number of immigrants and emigrant is", "images": [], "options": {"A": "natural growth rate", "B": "natural increase", "C": "net migration", "D": "census"}, "answer": "C", "explanation": "The difference between the number of immigrants and emigrants is net migration. Net migration is the difference between the number of people who enter a country (immigrants) and the number of people who leave it (emigrants). If the number of immigrants is higher than the number of emigrants, the net migration is positive, and vice versa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>28", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "All the following are features of optimum population except", "images": [], "options": {"A": "full employment of available resources", "B": "unlimited amount of unexploited resources", "C": "maximum per capita production and income", "D": "high standard of living"}, "answer": "B", "explanation": "Optimum population refers to the size of a population that produces the maximum output per capita. It is characterized by full employment of available resources, maximum per capita production and income, and a high standard of living. However, it does not imply an unlimited amount of unexploited resources. In fact, in an optimum population, resources are fully utilized to achieve maximum productivity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>29", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "The financial institution that specializes in risk spreading is called", "images": [], "options": {"A": "an investment bank", "B": "a development bank", "C": "an insurance bank", "D": "the stock exchange"}, "answer": "C", "explanation": "An insurance bank is a financial institution that specializes in risk spreading. This is done through the process of insurance, where the risk of a loss is spread over a number of people. This is different from an investment bank, a development bank, or the stock exchange, which have different roles in the financial system.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>30", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "The following are means of reducing the population of a country except encouraging", "images": [], "options": {"A": "emigration", "B": "family planning", "C": "early marriage", "D": "sex education"}, "answer": "C", "explanation": "Early marriage is not a means of reducing the population of a country. In fact, it can lead to a higher population growth rate as it increases the number of childbearing years. On the other hand, emigration, family planning, and sex education are all strategies that can help to reduce population growth.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>31", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "Which of the following features best describes peasant agriculture in West Africa? it", "images": [], "options": {"A": "Specializes in the production of one crop", "B": "involves the use of small farm holdings", "C": "is a capital-intensive system of farming", "D": "is mostly associated with tree crops"}, "answer": "B", "explanation": "Peasant agriculture in West Africa is characterized by the use of small farm holdings. This is because most of the farmers are subsistence farmers who cultivate small plots of land mainly for their family consumption and sell the little surplus. The other options are not entirely correct because peasant agriculture does not specialize in one crop, it is not a capital-intensive system of farming, and it is not mostly associated with tree crops.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>32", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "One of the problems facing industrial development in West Africa countries is", "images": [], "options": {"A": "inadequate large market", "B": "inadequate infrastructure", "C": "inadequate supply of labour", "D": "unavailable of natural resources"}, "answer": "B", "explanation": "One of the major problems facing industrial development in West Africa is inadequate infrastructure. Infrastructure includes things like roads, electricity, water supply, etc. Without these, industries cannot function effectively. The other options are not entirely correct because there is a large market in West Africa, there is not an inadequate supply of labour, and there are plenty of natural resources.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>33", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "In a situation where the finished product of an industry is fragile, bulky and perishable, such an industry should be located close to its", "images": [], "options": {"A": "raw materials", "B": "market", "C": "labour supply", "D": "power supply"}, "answer": "B", "explanation": "If the finished product of an industry is fragile, bulky and perishable, it is best for such an industry to be located close to its market. This is to reduce the cost and risk of transportation and to ensure that the products reach the consumers in good condition. The other options are not entirely correct because the location of raw materials, labour supply, and power supply do not directly affect the condition of the finished product.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>34", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "If Y = Income, C = Consumption, I = Investment, X = Export and M = Import, then national income is", "images": [], "options": {"A": "Y = C - I + (x+m)", "B": "Y = C + I + (x+m)", "C": "Y = C + I + (x-m)", "D": "Y = C + I + (m+x)"}, "answer": "C", "explanation": "National income is calculated as the sum of Consumption, Investment, and the difference between Export and Import. This is represented as Y = C + I + (X - M). Therefore, the correct option is 'Y = C + I + (X - M)'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>35", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The national income is the", "images": [], "options": {"A": "Gross Domestic Product at market prices", "B": "Gross National product at factor cost", "C": "Net National Product at factor cost", "D": "Net national product at market prices"}, "answer": "C", "explanation": "National income is the total net output of an economy, i.e., it is the total income of a nation. In economic terms, it is referred to as the Net National Product at factor cost. This is because it is the total product net of depreciation (Net National Product) and it is valued at the cost of the factors of production (factor cost).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>36", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "When depreciation is deducted from Gross National Product, the result is", "images": [], "options": {"A": "total national income", "B": "gross domestic product", "C": "net national product", "D": "net domestic product"}, "answer": "C", "explanation": "When depreciation (the decrease in the value of physical capital over time due to wear and tear) is deducted from Gross National Product (the total value of all final goods and services produced by the residents of a country within a specific time period), the result is Net National Product. This is because Net National Product accounts for the depreciation of the nation's stock of capital goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>37", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "MONEY : INTRODUCTION", "question": "Mr. Okpoti has meat and wants maize, while Mr. Adama has maize and wants meat. A transaction was made possible because of", "images": [], "options": {"A": "joint demand", "B": "scale of preference", "C": "double coincidence of wants", "D": "opportunity cost"}, "answer": "C", "explanation": "The transaction was made possible because of the 'double coincidence of wants'. This is an economic term that refers to the situation where the supplier of good A wants good B and the supplier of good B wants good A. In this case, Mr. Okpoti has meat and wants maize, while Mr. Adama has maize and wants meat. This is a perfect example of a double coincidence of wants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>38", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "MONEY : TYPES OF MONEY", "question": "Which of the following is not a form of money?", "images": [], "options": {"A": "Coins", "B": "Bank notes", "C": "Bank balance", "D": "Bank deposit"}, "answer": "C", "explanation": "Bank balance is not a form of money as it does not give a picture of money in real terms unlike bank deposit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2012>39", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "A price index as a statistic, measures", "images": [], "options": {"A": "how the value of money change over time", "B": "the volume of currency in the economy", "C": "the exchange rate of a country's currency", "D": "the composition of goods and services"}, "answer": "A", "explanation": "A price index measures how the value of money changes over time. It does this by tracking the price of a basket of goods and services over time. If the price of these goods and services increases, then the value of money has decreased (because each unit of money buys less). Conversely, if the price of these goods and services decreases, then the value of money has increased (because each unit of money buys more).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>40", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "The difference between birth rate and death rate is known as", "images": [], "options": {"A": "demographic transition", "B": "natural growth rate", "C": "migration rate", "D": "fertility rate"}, "answer": "B", "explanation": "The difference between birth rate and death rate is known as the natural growth rate. This is a measure of the rate at which a population is increasing (or decreasing) in a given year due to a surplus (or deficit) of births over deaths, expressed as a percentage of the base population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>41", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "In open market operations, what the Central bank sells or buys are", "images": [], "options": {"A": "shares", "B": "debentures", "C": "securities", "D": "equities"}, "answer": "C", "explanation": "In open market operations, the Central bank sells or buys securities. Open market operations (OMO) refers to a central bank buying or selling short-term treasuries and other securities in the open market in order to influence the money supply, thus influencing short term interest rates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>42", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "The following are reasons for the failure of agricultural policies in West Africa except", "images": [], "options": {"A": "vague policy statements", "B": "negation of policies", "C": "creation of agro-service stations", "D": "provision of obsolete implements"}, "answer": "C", "explanation": "The creation of agro-service stations is not a reason for the failure of agricultural policies in West Africa. Instead, it is a strategy to improve agricultural productivity by providing farmers with necessary services and resources. The other options, such as vague policy statements, negation of policies, and provision of obsolete implements, can contribute to the failure of agricultural policies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>43", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "A situation in which the estimated government revenue is less than the proposed expenditure for a given year can be described as", "images": [], "options": {"A": "surplus budgeting", "B": "supplementary budgeting", "C": "balanced budgeting", "D": "deficit budgeting"}, "answer": "D", "explanation": "A situation where the estimated government revenue is less than the proposed expenditure for a given year is described as deficit budgeting. This is because the government is planning to spend more than it expects to earn, resulting in a budget deficit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>44", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "An excise tax imposed on goods", "images": [], "options": {"A": "smuggled into the country", "B": "manufactured locally", "C": "imported into the country", "D": "seized by custom officials"}, "answer": "B", "explanation": "An excise tax is a tax charged on goods produced within the country, not on goods imported or smuggled into the country. Therefore, an excise tax is imposed on goods manufactured locally.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>45", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "Which of the following will not retard economic development in West Africa?", "images": [], "options": {"A": "Dependence on imports", "B": "Population control", "C": "High level of illiteracy", "D": "Low level of savings"}, "answer": "B", "explanation": "Population control will not retard economic development in West Africa. In fact, it can promote economic development by ensuring that resources are not overstretched by a rapidly growing population. The other options, such as dependence on imports, high level of illiteracy, and low level of savings, can all hinder economic development.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>46", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "When there is improvement in a country's term of trade, it means that the country's", "images": [], "options": {"A": "export are cheaper relative to imports", "B": "imports are cheaper relative to exports", "C": "volume of imports has declined", "D": "volume of exports has declined"}, "answer": "B", "explanation": "Improvement in a country's terms of trade means that the country's imports are cheaper relative to its exports. This is because the terms of trade is the ratio of an index of a country's export prices to an index of its import prices. If the terms of trade is improving, it means that for every unit of exports sold, a country can buy more units of imported goods, which means imports are cheaper relative to exports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>47", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Which of the following is true about import substitution? It", "images": [], "options": {"A": "helps in increasing exportation", "B": "is meant to reduce exportation", "C": "enables a country to curtail importation", "D": "enables a country to improve on importation"}, "answer": "C", "explanation": "Substitution in economics refers to the act of replacing a product with another. In the context of international trade, it often refers to import substitution, which is a trade and economic policy that advocates replacing foreign imports with domestic production. Therefore, substitution enables a country to curtail importation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>48", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Balance of payments problem can be corrected through", "images": [], "options": {"A": "increasing foreign reserves", "B": "increasing domestic borrowing", "C": "import promotion strategies", "D": "export promotion strategies"}, "answer": "D", "explanation": "Balance of payments problem can be corrected through export promotion strategies. The balance of payments is a record of all transactions made between entities in one country and the rest of the world. If a country is importing more than it is exporting, it can lead to a deficit in the balance of payments. To correct this, the country can implement export promotion strategies to increase its exports, thereby balancing out the payments.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2012>49", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "One of the reasons why government may erect a trade barrier is to", "images": [], "options": {"A": "control foreign currencies", "B": "protect infant industries", "C": "promote importation", "D": "diversify the economy"}, "answer": "B", "explanation": "Trade barriers are often erected to protect infant industries that are not yet mature enough to compete with established industries in other countries. This protection allows these industries to develop and grow until they can compete on equal terms. This concept is known as 'infant industry argument'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2012>50", "subject": "Economics", "year": "2012", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "Cyclical unemployment is one associated with", "images": [], "options": {"A": "inadequate information", "B": "trade fluctuations", "C": "structural changes", "D": "seasonal changes"}, "answer": "B", "explanation": "Cyclical unemployment is a type of unemployment that occurs when there is not enough aggregate demand in the economy to provide jobs for everyone who wants to work. It is associated with the business cycle, where periods of high demand and employment are followed by periods of low demand and unemployment. Hence, it is associated with trade fluctuations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>1", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The action of government to forgo road construction in order to provide more health facilities denotes", "images": [], "options": {"A": "sound of economic decision", "B": "opportunity cost", "C": "practicable government policy", "D": "scale of preference"}, "answer": "B", "explanation": "The action of government to forgo road construction in order to provide more health facilities denotes the concept of opportunity cost. Opportunity cost is an economic term that refers to the cost of forgoing the next best alternative when making a decision. In this case, the opportunity cost of providing more health facilities is the forgone road construction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>2", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "MARKET STRUCTURE : MEANING OF MARKET & TYPES", "question": "In Economics, a market is defined as any", "images": [], "options": {"A": "agreement made for consumers to buy all they need", "B": "agreement to sell commodities at low prices", "C": "arrangement made for producers to sell all their goods", "D": "arrangement whereby the buyers and sellers are in contact"}, "answer": "D", "explanation": "In economics, a market is defined as a setup where buyers and sellers interact to trade goods, services, or contracts or instruments. Therefore, the correct answer is 'arrangement hereby the buyers and sellers are in contact'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2013>3", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "Which of the following is not a function of an insurance company?", "images": [], "options": {"A": "Pooling resources together against risk", "B": "Mobilization of funds through premiums collected", "C": "Encouragement of investment by security of capital", "D": "Collection of deposits from the public for investment"}, "answer": "D", "explanation": "Insurance companies do not collect deposits from the public for investment. Their primary function is to provide financial protection or reimbursement against losses to an individual or entity. They pool resources together against risk, mobilize funds through premiums collected, and encourage investment by security of capital. Therefore, the correct answer is 'Collection of deposits from the public for investment'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>4", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "A debenture holder receives", "images": [], "options": {"A": "commission", "B": "profits", "C": "fixed interest", "D": "quasi-rent"}, "answer": "C", "explanation": "A debenture holder is a type of creditor who owns a debenture issued by the company. Debentures are a type of debt instrument that is not secured by physical assets or collateral. They are backed by the general creditworthiness and reputation of the issuer. The debenture holder receives a fixed interest as a return on the investment. Therefore, the correct answer is 'fixed interest'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>5", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "All economics system must decide what to produce because", "images": [], "options": {"A": "resources are not available", "B": "consumer wants maximum satisfaction", "C": "resources are limited in supply", "D": "producers want maximum profit"}, "answer": "C", "explanation": "All economic systems must decide what to produce because resources are limited in supply. This is based on the fundamental economic problem of scarcity, which states that there are limited resources to satisfy unlimited wants and needs. Therefore, choices must be made about how to allocate and use these resources most efficiently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>6", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INTERNATIONAL TRADE : INTRODUCTION", "question": "Trade between two countries is known as", "images": [], "options": {"A": "bilateral trade", "B": "unilateral trade", "C": "multilateral trade", "D": "internal trade"}, "answer": "A", "explanation": "Trade between two countries is known as bilateral trade. Bilateral trade is the exchange of goods between two nations promoting trade and investment. The two countries will reduce or eliminate tariffs, import quotas, export restraints, and other trade barriers to encourage trade and investment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2013>7", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "In the balance of payments of a country, tourism is classified under", "images": [], "options": {"A": "capital account", "B": "invisible trade", "C": "merchandise trade", "D": "official reserves"}, "answer": "B", "explanation": "In the balance of payments of a country, tourism is classified under invisible trade. Invisible trade in an economic model refers to the trading of services and other non-physical items. This includes services such as consulting and banking, as well as intellectual property such as the transfer of patents, copyrights, and trademarks. Tourism falls under this category as it involves the provision of services, not goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>8", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "General rise in the price level induced by increased price of inputs referred to as", "images": [], "options": {"A": "run-away inflation", "B": "cost-push inflation", "C": "demand-pull inflation", "D": "imported inflation"}, "answer": "B", "explanation": "Cost-push inflation is a type of inflation caused by substantial increases in the cost of important goods or services where no suitable alternative is available. A common type of cost-push inflation is 'wage-push inflation', where labor costs increase, and businesses compensate by raising prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>9", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "Which of the following is a function of merchant banks?", "images": [], "options": {"A": "Acting as banker's bank", "B": "Lending to the commercial banks as a last resort", "C": "Controlling inflation in the economy", "D": "Underwriting and issuing of shares"}, "answer": "D", "explanation": "Merchant banks are involved in international trade and long-term loans for companies. They also underwrite and issue shares, which is a process by which a company raises capital. Underwriting involves the bank guaranteeing to sell the shares at a certain price, and if it can't sell the shares, it will buy them itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>10", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "Demand is elastic when percentage change in", "images": [], "options": {"A": "quantity demanded is greater than percentage change in price", "B": "price is greater than percentage change in quantity demanded", "C": "price is equal to one", "D": "quantity demanded is zero"}, "answer": "A", "explanation": "Demand is said to be elastic when the percentage change in quantity demanded is greater than the percentage change in price. This means that consumers are highly responsive to changes in the price of this good.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>11", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "A budget is balanced when expected total revenue is", "images": [], "options": {"A": "greater than expected expenditure", "B": "less than total expenditure", "C": "equal to expected expenditure", "D": "greater than total expenditure"}, "answer": "C", "explanation": "A budget is considered balanced when the total expected revenue is equal to the total expected expenditure. This means that the income (revenue) is enough to cover all the costs (expenditure) without any deficit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>12", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES", "question": "A co-operative society is a", "images": [], "options": {"A": "finance", "B": "self-help business organization", "C": "public corporation", "D": "non-democratic business organization"}, "answer": "B", "explanation": "A co-operative society is a self-help business organization. It is formed by individuals who pool their resources together to achieve a common economic goal. The members are both the owners and the customers of the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2013>13", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "The value of money is affected by", "images": [], "options": {"A": "speculative motive", "B": "price level", "C": "precautionary motive", "D": "intervention of development banks"}, "answer": "B", "explanation": "The value of money is affected by the price level. This is because when the general price level rises, the purchasing power of money falls, and vice versa. This is known as the inverse relationship between the value of money and the price level.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>14", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "Which of the following is a function of money?", "images": [], "options": {"A": "Medium of communication", "B": "Measure of securities", "C": "store of wealth", "D": "discounting bills of exchange"}, "answer": "C", "explanation": "Money serves as a store of wealth. This means that individuals can save their wealth in the form of money. It is a way of transferring purchasing power from the present to the future. It is not a medium of communication, a measure of securities, or used for discounting bills of exchange.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2013>15", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Which of the following is an asset of commercial bank?", "images": [], "options": {"A": "Reserve funds", "B": "Shareholder's capital", "C": "Customers' deposits", "D": "Treasury bills"}, "answer": "A", "explanation": "Reserve funds are an asset of a commercial bank. These are funds that are set aside by the bank as a form of financial protection. Shareholder's capital, customers' deposits, and treasury bills are not considered assets of a commercial bank.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>16", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "An increase in the supply of a commodity X automatically results in an increase in the supply of another commodity Y. This is a case of", "images": [], "options": {"A": "elastic supply", "B": "joint supply", "C": "exceptional supply", "D": "competitive supply"}, "answer": "B", "explanation": "This is a case of joint supply. Joint supply is a term used in economics to describe a situation where an increase in the supply of one good leads to an increase in the supply of another good. This typically occurs when the goods are produced together. Elastic supply, exceptional supply, and competitive supply do not describe this situation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>17", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "Why would an individual increase his level of consumption during inflationary periods?", "images": [], "options": {"A": "The real value of any amount saved falls over time", "B": "interest rate are generally low", "C": "There are varieties of goods to buy", "D": "Wages and salaries stagnates during inflation"}, "answer": "A", "explanation": "During inflationary periods, the value of money decreases. This means that the purchasing power of any amount of money saved would decrease over time. Therefore, it is more beneficial for an individual to increase his level of consumption during inflationary periods rather than saving the money. This is because the goods and services that the money can buy at present may be more than what it can buy in the future due to the decrease in the value of money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>18", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "The type of monopoly that develops as a result of un-even distribution of resources is called", "images": [], "options": {"A": "legal monopoly", "B": "natural monopoly", "C": "state monopoly", "D": "international monopoly"}, "answer": "B", "explanation": "A natural monopoly occurs when a single firm can supply a good or service to an entire market at a lower cost than could two or more firms. This typically happens in industries where capital costs predominate, creating economies of scale that are large in relation to the size of the market, and hence high barriers to entry; examples include public utilities such as water services and electricity. Uneven distribution of resources can lead to a natural monopoly, as the firm that has access to the resources can produce at a lower cost than other firms.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>19", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "BUSINESS ORGANISATION : PARTNERSHIP", "question": "A major disadvantages of partnership form of business is that", "images": [], "options": {"A": "every partner has to be consulted during decision making", "B": "partners could be too friendly with their customers", "C": "affair can be kept private", "D": "partners could take long holidays"}, "answer": "A", "explanation": "In a partnership form of business, every partner has a say in the decision-making process. This can be a major disadvantage as it can lead to disagreements and delays in decision making. It can also lead to inefficiencies if every partner has to be consulted for every decision, as opposed to a sole proprietorship where decisions can be made quickly by the owner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>20", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Goods which have to be paid for are known as", "images": [], "options": {"A": "physical goods", "B": "economic goods", "C": "free goods", "D": "intangible goods"}, "answer": "B", "explanation": "Economic goods are goods and services that are scarce and for which the demand is higher than the supply. They are known as economic goods because they are capable of being economically useful. These goods are not available for free and have to be paid for.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2013>21", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Goods are said to be in competitive demand when they are", "images": [], "options": {"A": "substitutes", "B": "complementary", "C": "jointly demanded", "D": "identical"}, "answer": "A", "explanation": "Goods are said to be in competition demand when they are substitutes. This means that the goods can be used in place of one another. If the price of one good increases, the demand for its substitute will increase.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2013>22", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "In the long run, factors of production are considered to be", "images": [], "options": {"A": "an maximum", "B": "fixed", "C": "variable", "D": "increasing"}, "answer": "C", "explanation": "In the long run, all factors of production are considered to be variable. This is because, in the long run, companies are able to adjust all their inputs and costs, in contrast to the short run where at least one input is fixed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>23", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Which of the following will shift the demand curve for cocoa to the right?", "images": [], "options": {"A": "An increase in consumers' income", "B": "A rise in the price of cocoa", "C": "A tax on cocoa producers", "D": "A fall in the quantity demanded of cocoa"}, "answer": "A", "explanation": "The demand curve for a product can shift due to several factors, one of which is a change in consumers' income. If consumers' income increases, they have more purchasing power and are likely to buy more of the product, thus shifting the demand curve to the right. The other options do not cause a shift in the demand curve. A rise in the price of cocoa or a tax on cocoa producers would cause a movement along the demand curve, not a shift. A fall in the quantity demanded of cocoa is a result of a shift in the demand curve, not a cause.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>24", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "An agricultural production process which uses more machinery relative to labour is referred to as", "images": [], "options": {"A": "large scale farming", "B": "capital intensive farming", "C": "commercial farming", "D": "land intensive farming"}, "answer": "B", "explanation": "In economics, the term 'capital intensive' refers to a production process that uses a higher proportion of capital (machinery, equipment etc.) relative to labour. Therefore, an agricultural production process which uses more machinery relative to labour is referred to as capital intensive farming. Large scale farming refers to farming on a large piece of land, commercial farming refers to farming for commercial purposes, and land intensive farming refers to farming that requires a lot of land.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>25", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Which of the following will enhance productivity in an economy?", "images": [], "options": {"A": "The use of obsolete capital", "B": "Technological change", "C": "Expansion of land under cultivation", "D": "An increase in the labour force"}, "answer": "B", "explanation": "Productivity in an economy can be enhanced through several ways, one of which is technological change. Technological change can lead to more efficient production processes, thus increasing productivity. The use of obsolete capital would likely decrease productivity as outdated equipment is typically less efficient. Expansion of land under cultivation or an increase in the labour force could potentially increase productivity, but not necessarily, as it depends on other factors such as the quality of the land or the skills of the labour force.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>26", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "Post harvest losses in West Africa countries can be reduced if", "images": [], "options": {"A": "the land tenure system could be reformed", "B": "more irrigation schemes could be provided", "C": "better storage facilities could be provided", "D": "erosion is controlled"}, "answer": "C", "explanation": "Post-harvest losses refer to the decrease in quantity and quality of agricultural produce after harvest. These losses can be significantly reduced by providing better storage facilities. This is because most post-harvest losses occur due to improper storage, leading to spoilage and damage of the produce. Therefore, better storage facilities would ensure that the produce is stored under optimal conditions, thus reducing losses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>27", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Which of the following best explains what to produce?", "images": [], "options": {"A": "How much goods are to be produced", "B": "The combination of resources to be use", "C": "Which goods and services to be produced", "D": "How many wants are to be satisfied"}, "answer": "C", "explanation": "'What to produce?' is a fundamental question in economics that deals with the decision of which goods and services should be produced in the economy. This decision is based on the needs and wants of the society, availability of resources, and the technology available. Therefore, the option 'Which goods and services to be produced' best explains 'what to produce?'", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2013>28", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "The demand for money is described as a", "images": [], "options": {"A": "competitive demand", "B": "joint demand", "C": "derive demand", "D": "composite demand"}, "answer": "C", "explanation": "The demand for money is a derived demand because money is demanded for the purpose of purchasing other items and not for idle cash.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2013>29", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "Which of the following is the main outcome of a trade union's conference with the wage rate. Wages are", "images": [], "options": {"A": "lowered but more employment opportunities are created", "B": "lowered but employment level remains unchanged", "C": "increase and employment levels are unchanged", "D": "increased but employment levels are reduced"}, "answer": "D", "explanation": "Trade unions negotiate for better wages and working conditions for their members. When wages are increased, it may lead to a reduction in employment levels because employers may not be able to afford to pay the increased wages to the same number of employees. Therefore, they may have to reduce their workforce.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>30", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "The introduction of tariffs and quotas", "images": [], "options": {"A": "reduce the price of imports", "B": "increase the demand for locally made goods", "C": "discourage domestic industries from becoming more efficient", "D": "reduce the prices of locally made goods"}, "answer": "B", "explanation": "Tariffs and quotas are trade barriers that are used to protect domestic industries from foreign competition. By making imported goods more expensive, they increase the demand for locally made goods because they become relatively cheaper.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>31", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "A government that wants to get more revenue will increase the tax on commodities with a", "images": [], "options": {"A": "high price elasticity of demand", "B": "low price elasticity of demand", "C": "high income elasticity of demand", "D": "low income elasticity of demand"}, "answer": "B", "explanation": "The price elasticity of demand measures how responsive the quantity demanded of a good is to a change in its price. Goods with a low price elasticity of demand are inelastic, meaning that changes in price have little effect on the quantity demanded. Therefore, a government can increase the tax on these goods to increase revenue without significantly affecting their demand.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>32", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Which of the following is involved in the money market?", "images": [], "options": {"A": "Building society", "B": "Developing banks", "C": "Commercial banks", "D": "Stock exchange"}, "answer": "C", "explanation": "The money market is a sector of the financial market in which financial instruments with high liquidity and short maturities are traded. The money market is used by participants as a means for borrowing and lending in the short term, with maturities that usually range from overnight to just under a year. Among the list, Commercial banks are involved in the money market as they offer services such as savings accounts, certificates of deposit, and money market accounts, which fall under the category of short-term lending or borrowing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>33", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Demand pull inflation can aptly be described as", "images": [], "options": {"A": "inflation induced by rising costs of production", "B": "reduction in government expenditure", "C": "persistent rise in price due to increase in expenditure", "D": "massive importation of goods from a country with hyperinflation"}, "answer": "C", "explanation": "Demand-pull inflation is asserted to arise when demand in an economy outpaces supply. It involves inflation rising as real gross domestic product rises and unemployment falls, as the economy moves along the Phillips curve. This is commonly described as 'too much money chasing too few goods'. More accurately, it should be described as involving 'too much money spent chasing too few goods', since not all expenditures of money are absorbed by the market to result in inflation. Thus, the third option 'persistent rise in price due to increase in expenditure' is the correct answer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>34", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "FINANCIAL INSTITUTION : INTRODUCTION", "question": "In order to develop the banking habit of rural dwellers, the traditional money lenders should be", "images": [], "options": {"A": "prescribed", "B": "legalized", "C": "subsidized", "D": "heavily taxed"}, "answer": "B", "explanation": "Legalizing traditional money lenders can help in developing the banking habit of rural dwellers. Traditional money lenders are often the only source of credit in many rural areas. By legalizing them, it can help to regulate their activities and ensure they are providing fair and reasonable terms to borrowers. This can also encourage rural dwellers to use these services more, thereby developing their banking habits. Therefore, the option 'legalized' is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>35", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "All rates of interest in a country are influenced by the", "images": [], "options": {"A": "bank rate", "B": "population growth rate", "C": "wage rate", "D": "mortgage rate"}, "answer": "A", "explanation": "The bank rate, also known as the discount rate, is the interest rate charged by a nation's central bank to commercial banks for short-term loans. Changes in the bank rate influence other interest rates in the economy, including those for mortgages, car loans, and personal loans. Therefore, all rates of interest in a country are influenced by the bank rate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>36", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "Exchange control is a weapon used in regulating", "images": [], "options": {"A": "barter trade", "B": "stock exchange", "C": "foreign trade", "D": "internal trade"}, "answer": "C", "explanation": "Exchange control is a measure used by governments to regulate the inflow and outflow of foreign currency and goods. It is a tool used in the regulation of foreign trade, not barter trade, stock exchange, or internal trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>37", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "When the marginal product is negative, the total product will be", "images": [], "options": {"A": "constant", "B": "at a maximum", "C": "increasing", "D": "decreasing"}, "answer": "D", "explanation": "At the point where marginal product is declining, the total product is declining.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>38", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Physical productivity is affected by all the underlisted factors except the", "images": [], "options": {"A": "state of technology", "B": "quantity of inputs", "C": "quality of inputs", "D": "price of output"}, "answer": "D", "explanation": "Physical productivity refers to the quantity of output produced by a certain amount of input. It is affected by the state of technology, the quantity of inputs, and the quality of inputs. However, it is not directly affected by the price of output, which is a market-determined factor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>39", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : MARGINAL RATE OF SUBSTITUTION - MRS", "question": "If a commodity has a high marginal utility, its market price will be", "images": [], "options": {"A": "stable", "B": "high", "C": "zero", "D": "constant"}, "answer": "B", "explanation": "Marginal utility refers to the additional satisfaction a consumer gets from having one more unit of a good or service. If a commodity has a high marginal utility, it means that consumers derive a lot of satisfaction from consuming it. Therefore, they would be willing to pay a high price for it. Hence, the market price of a commodity with high marginal utility will be high.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>40", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "Price fluctuation is a feature of", "images": [], "options": {"A": "common market", "B": "imperfect market", "C": "supermarkets", "D": "market failure"}, "answer": "B", "explanation": "Price fluctuation is a feature of an imperfect market. An imperfect market refers to any economic market that does not meet the rigorous standards of a hypothetical perfectly (or \"purely\") competitive market. Price fluctuation occurs in an imperfect market because sellers have the power to set prices and can change them based on supply and demand conditions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>41", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "Which of the following statements is not a feature of a monopoly?", "images": [], "options": {"A": "Seller is allowed to fix his own price", "B": "Buyers and seller are price takers", "C": "New entrances are restricted", "D": "There is only one seller of the commodity"}, "answer": "B", "explanation": "In a monopoly, the seller is the price maker, not the price taker. A monopoly is a market structure characterized by a single seller, selling a unique product in the market. In a monopoly market, the seller faces no competition, as he is the sole seller of goods with no close substitute. Therefore, the statement 'Buyers and seller are price takers' is not a feature of a monopoly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>42", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP", "question": "The following are advantages of sole proprietorship except", "images": [], "options": {"A": "quick and easy decision making", "B": "keeping its business affairs private", "C": "assurance of raising huge capital for expansion", "D": "high level of commitment"}, "answer": "C", "explanation": "Sole proprietorship is a type of business entity that is owned and run by one individual and in which there is no legal distinction between the owner and the business. The owner receives all profits and has unlimited personal liability for all losses. One of the disadvantages of sole proprietorship is the difficulty in raising capital. The financial resources of a single individual are often insufficient for business expansion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>43", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Which of the following controls a limited liability company?", "images": [], "options": {"A": "The general manager", "B": "The managing director", "C": "Tax payers", "D": "the board of directors"}, "answer": "D", "explanation": "A limited liability company is a corporate structure in the United States whereby the owners are not personally liable for the company's debts or liabilities. It is controlled by the board of directors. The board of directors is a group of individuals that are elected as, or elected to act as, representatives of the stockholders to establish corporate management related policies and to make decisions on major company issues.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>44", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Given that Qd = 80 - 2p where Qd is quantity demanded and P is the price, what quantity would be demanded when the price (P) is $3?", "images": [], "options": {"A": "86 units", "B": "80 units", "C": "76 units", "D": "74 units"}, "answer": "D", "explanation": "Qd = 80 - 2p    since p = ₦3    Qd = 80 - 2(3)    = 80 - 6    = 72 units.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>45", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "Which of the following can be used to calculate the price elasticity of demand?", "images": [], "options": {"A": "percentage change in quantity demanded/percentage change in price", "B": "percentage change in price/percentage change in the quantity demanded", "C": "percentage change in the quantity demanded/percentage change in income", "D": "percentage change in income/percentage change in the quantity demanded"}, "answer": "A", "explanation": "The price elasticity of demand is calculated as the percentage change in quantity demanded divided by the percentage change in price. This measures how responsive the quantity demanded of a good is to a change in its price.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>46", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "The main advantage of large scale production is that", "images": [], "options": {"A": "unit cost of production falls", "B": "decision making is quick", "C": "worker-management relationship is improved", "D": "the quality of the product increase"}, "answer": "A", "explanation": "The main advantage of large scale production is that the unit cost of production falls. This is due to economies of scale, which is the cost advantage that arises with increased output of a product. Economies of scale occur when increasing production allows greater efficiency of production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>47", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "Which of the following items is not included in measuring national income by the income approach?", "images": [], "options": {"A": "Profit of companies", "B": "Rents on property", "C": "students grants and scholarships", "D": "wages and salaries of public servants"}, "answer": "C", "explanation": "Students grants and scholarships are not included in measuring national income by the income approach. The income approach to measuring the Gross Domestic Product (GDP) sums up the incomes earned by households and firms in the economy. This includes wages, rents, and profits, but not student grants and scholarships as they are not considered earned income.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2013>48", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "Gold, diamond, iron ore and limestone are collectively referred to as", "images": [], "options": {"A": "human resources", "B": "mineral resources", "C": "artificial resources", "D": "forest resources"}, "answer": "B", "explanation": "Gold, diamond, iron ore and limestone are all examples of mineral resources. Mineral resources are naturally occurring substances that are solid and inorganic representable by a chemical formula, usually abiogenic and have an ordered atomic structure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2013>49", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE", "question": "Points outside a production possibility curve indicate", "images": [], "options": {"A": "unattainable production levels", "B": "attainable production levels", "C": "inefficient, but attainable production levels", "D": "optimum production levels"}, "answer": "A", "explanation": "Points outside a production possibility curve indicate unattainable production levels. The production possibility curve (PPC) is a graphical representation of the possible combinations of two goods/services that can be produced within the given resources and technology/a graphical representation of alternative production possibilities facing an economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2013>50", "subject": "Economics", "year": "2013", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "The International Bank for Reconstruction and Development (IBRD) is imported to developing nations because it", "images": [], "options": {"A": "gives aid for defence", "B": "offers loans for public projects", "C": "offers aids to finance private projects", "D": "Lives loans for legal proceedings"}, "answer": "B", "explanation": "The International Bank for Reconstruction and Development (IBRD) offers loans for public projects. The IBRD is a global development cooperative owned by 189 member countries. As the largest development bank in the world, it supports the World Bank Group's mission by providing loans, guarantees, risk management products, and advisory services to middle-income and creditworthy low-income countries, as well as by coordinating responses to regional and global challenges.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>1", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Human wants are unlimited because", "images": [], "options": {"A": "production is inadequate", "B": "resources have alternative uses", "C": "new wants always arise", "D": "resources are limited"}, "answer": "C", "explanation": "Human wants are considered unlimited because new wants always arise. This is a fundamental concept in economics. As soon as one want is satisfied, another one comes up. This is different from needs, which are basic necessities like food, clothing, and shelter. Wants include things like a new car, a bigger house, etc. which are not necessary for survival but are desired for comfort or pleasure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2014>2", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "A basic economic problem of any society is", "images": [], "options": {"A": "high level of illiteracy", "B": "irregular power supply", "C": "population growth", "D": "resource allocation"}, "answer": "D", "explanation": "The basic economic problem of any society is resource allocation. This is because resources are limited but human wants are unlimited. Therefore, it becomes necessary to decide how to distribute these resources efficiently to satisfy as many wants as possible. This is known as the problem of resource allocation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>3", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "In a central planned economy, what to produce is", "images": [], "options": {"A": "determined by the forces of demand and supply", "B": "driven by profit motive", "C": "determined by consumers", "D": "the responsibility of state's bureaucrat"}, "answer": "D", "explanation": "In a centrally planned economy, what to produce is the responsibility of the state's bureaucrat. This is because in such an economy, all the decisions related to production, investment, and prices are made by the government or a central authority. The forces of demand and supply, profit motive, or consumers do not determine what to produce in a centrally planned economy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>4", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "Which of the following is related to resource allocation in an economy?", "images": [], "options": {"A": "How to produce", "B": "What to produce", "C": "For whom to produce", "D": "Efficient use of inputs"}, "answer": "D", "explanation": "Resource allocation in an economy refers to the distribution of resources among producers and the allocation of goods and services among consumers. This process involves the efficient use of inputs. The other options, 'how to produce', 'what to produce', and 'for whom to produce' are related to the basic economic problems, not specifically to resource allocation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>5", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "Which of the following is not a feature of socialism?", "images": [], "options": {"A": "Collective ownership of productive resources", "B": "Freedom of enterprise", "C": "Production is not based on the profit motive", "D": "Maximization of public welfare"}, "answer": "B", "explanation": "Socialism is characterized by collective ownership of productive resources, production not based on the profit motive, and maximization of public welfare. However, it does not support the freedom of enterprise. In a socialist economy, the government controls and regulates all means of production and there is little or no room for private enterprises.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>6", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT", "question": "Household make economic decision because they want to", "images": [], "options": {"A": "make more profit", "B": "increase their salaries and wages", "C": "increase their purchase", "D": "maximize their satisfaction"}, "answer": "D", "explanation": "Households make economic decisions to maximize their satisfaction. This concept is known as utility maximization. Households aim to get the most satisfaction from their limited resources. The other options, 'make more profit', 'increase their salaries and wages', and 'increase their purchase' are not the primary reasons why households make economic decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>7", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "State owned enterprises are more common in", "images": [], "options": {"A": "central planned economics", "B": "mixed economics", "C": "capitalist economics", "D": "developed economics"}, "answer": "A", "explanation": "State-owned enterprises are more common in centrally planned economies. In these economies, the government owns and controls all major means of production and distribution. This is in contrast to capitalist economies where private individuals or businesses own capital goods, or mixed economies which combine elements of both.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>8", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "A normal supply curve has a positive slope which indicates that", "images": [], "options": {"A": "sellers are willing to sell more at a lower price", "B": "seller are indifference to prices", "C": "sellers are willing to sell more at a higher price", "D": "there is always a fixed supply"}, "answer": "C", "explanation": "A normal supply curve slopes upward from right to left indicating that more is sold at a higher price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>9", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "To control inflation, the central bank of a country may adopt", "images": [], "options": {"A": "an expansionary monetary policy", "B": "a restrictive monetary policy", "C": "an increase wage policy", "D": "a deficit financial policy"}, "answer": "B", "explanation": "To control inflation, the central bank of a country may adopt a restrictive monetary policy. This policy involves increasing interest rates, reducing the money supply, and other measures to decrease overall demand in the economy. This is because inflation is often caused by an excess of demand over supply.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>10", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Disposable income is the income earned", "images": [], "options": {"A": "by the nationals of a country resident within the country", "B": "from productive activities of national of a country both at home and abroad", "C": "when personal income tax is deducted from personal income", "D": "when the gross income of an individual is added to personal income tax"}, "answer": "C", "explanation": "Disposable income is the income earned when personal income tax is deducted from personal income. It is the amount of money that households have available for spending and saving after income taxes have been accounted for. It is also known as disposable personal income (DPI).", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>11", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "Livestock production in West Africa is hindered mainly by", "images": [], "options": {"A": "inadequate demand", "B": "use of traditional implement", "C": "land tenure system", "D": "pest and disease"}, "answer": "D", "explanation": "Livestock production in West Africa is primarily hindered by pests and diseases. These can significantly reduce the productivity of livestock, leading to lower yields and economic losses. The other options do not directly affect livestock production as much as pests and diseases do.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>12", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "The components of a three-sector economy are", "images": [], "options": {"A": "banks, schools and hospital", "B": "workers, producers and marketers", "C": "households, firms and the government", "D": "primary, secondary and tertiary"}, "answer": "C", "explanation": "In economics, a three-sector economy is divided into households, firms, and the government. Households are the consumers, firms are the producers, and the government is the regulatory body. The other options do not accurately represent the components of a three-sector economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>13", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "A declining population is one in which the population is", "images": [], "options": {"A": "experiencing a high rate of emigration", "B": "made up of a large number of old people", "C": "not producing enough goods", "D": "not contributing enough to the national income"}, "answer": "B", "explanation": "A declining population is one where the number of old people is larger than the number of young people. This can lead to a decrease in the workforce and a potential decrease in economic productivity. The other options do not accurately describe a declining population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>14", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS", "question": "Which of the following agencies help to stabilize farmers' income?", "images": [], "options": {"A": "Local government authorities", "B": "Trade unions", "C": "Marketing boards", "D": "Co-operative organization"}, "answer": "C", "explanation": "Marketing boards help to stabilize farmers' income by setting prices and controlling the supply of agricultural products. They ensure that farmers get a fair price for their produce and protect them from price fluctuations in the open market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>15", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "Other things being equal, an increase in supply will lead to", "images": [], "options": {"A": "a fall in price and an increase in quantity bought and sold", "B": "an increase in price and increase in quantity bought and sold", "C": "a fall in price and a fall in quantity bought and sold", "D": "an increase in quantity supplied and demanded only"}, "answer": "A", "explanation": "According to the law of supply and demand, if supply increases while demand remains the same, the price will fall. This is because there is more of the product available, so buyers can be more selective and pay less. The increased supply also means that more of the product can be bought and sold.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>16", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Examples of joint stock banks are", "images": [], "options": {"A": "commercial banks", "B": "co-operative credit societies", "C": "central banks", "D": "development bank"}, "answer": "A", "explanation": "Commercial banks are examples of joint stock banks. A joint stock bank is a type of corporation that is owned by shareholders and operates for profit. Commercial banks accept deposits, make loans, and provide other financial services for profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2014>17", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "Which of the following is not a characteristic of a developing country? High", "images": [], "options": {"A": "real per capital income", "B": "level of primary production", "C": "population growth rate", "D": "level of illiteracy"}, "answer": "A", "explanation": "A developing country is characterized by a low level of real per capita income, high level of primary production, high population growth rate, and high level of illiteracy. Therefore, high real per capita income is not a characteristic of a developing country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>18", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "Goods consumed out of habit have", "images": [], "options": {"A": "elastic demand", "B": "perfectly elastic demand", "C": "inelastic demand", "D": "unitary elastic demand"}, "answer": "C", "explanation": "Goods consumed out of habit have inelastic demand. This is because the quantity demanded of these goods does not change significantly with changes in price. People continue to consume these goods out of habit, regardless of price changes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>19", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Which of the following items is not a recurrent expenditure?", "images": [], "options": {"A": "Building of schools and colleges", "B": "Maintenance of school buildings", "C": "Payment of teachers' salaries", "D": "Purchase of stationery for examinations"}, "answer": "A", "explanation": "Recurrent expenditure refers to the regular and ongoing costs of running an organization or system, such as salaries, maintenance, and stationery. Building of schools and colleges is a capital expenditure, not a recurrent expenditure, as it is a one-time investment in physical assets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>20", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If the coefficient of price elasticity of demands 0.1, demand is", "images": [], "options": {"A": "elastic", "B": "inelastic", "C": "zero elastic", "D": "unitary elastic"}, "answer": "B", "explanation": "The coefficient of price elasticity of demand measures how much the quantity demanded responds to a change in price. If the coefficient is less than 1, demand is considered inelastic. This means that the quantity demanded does not respond strongly to changes in price. In this case, the coefficient is 0.1, which is less than 1, so the demand is inelastic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>21", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION", "question": "The profit of a producer is the difference between", "images": [], "options": {"A": "total cost and marginal cost", "B": "total revenue and total cost", "C": "average cost and total cost", "D": "price and total cost"}, "answer": "B", "explanation": "The profit of a producer is calculated as the difference between the total revenue and the total cost. Total revenue is the total income from selling a certain quantity of goods or service, while total cost is the total expense incurred in producing a certain quantity of goods or service. Therefore, the difference between these two gives the profit or loss made by the producer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>22", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : MARGINAL RATE OF SUBSTITUTION - MRS", "question": "The rate of increase in utility is", "images": [], "options": {"A": "average utility", "B": "increasing utility", "C": "total utility", "D": "marginal utility"}, "answer": "D", "explanation": "The rate of increase in utility is referred to as marginal utility. Marginal utility is the additional satisfaction a consumer gains from consuming one more unit of a good or service. It is an important concept in economics because it is used to determine how much of an item a consumer will buy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>23", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "The supply of tea is linearly presented as P = 0.2Q, where P is the price and Q is the quantity. What is P when Q = 25?", "images": [], "options": {"A": "₦0.08", "B": "₦5.00", "C": "₦25.02", "D": "₦125"}, "answer": "B", "explanation": "The supply of tea is given by the equation P = 0.2Q. To find the price (P) when the quantity (Q) is 25, we substitute Q = 25 into the equation. This gives P = 0.2 * 25 = 5. Therefore, the correct answer is ₦5.00.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>24", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM", "question": "Increase in supply due to changes in plant size will take place only in the", "images": [], "options": {"A": "normal time", "B": "long run", "C": "market period", "D": "short run"}, "answer": "B", "explanation": "In economics, changes in plant size, which involve changes in the scale of production, can only occur in the long run. This is because in the short run, at least one factor of production is fixed (e.g., plant size), while in the long run, all factors of production are variable. Therefore, the correct answer is 'long run'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>25", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "The long run average cost curve is made up of several short-run", "images": [], "options": {"A": "marginal and average cost curves", "B": "average cost curves", "C": "average variable cost curves", "D": "average variable and total cost curves"}, "answer": "B", "explanation": "The long run average cost curve is derived from the short run average cost curves. It is the 'envelope' of the short run average cost curves, and is therefore made up of several short-run average cost curves. Therefore, the correct answer is 'average cost curves'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>26", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "X2345F2521    From the table,the mean of the distribution is?", "images": [], "options": {"A": "2.2", "B": "2.5", "C": "3.2", "D": "4.5"}, "answer": "C", "explanation": "The mean of a distribution is calculated by multiplying each value by its frequency, summing these products, and then dividing by the total number of values. In this case, the mean is calculated as follows: ((2*2) + (3*5) + (4*2) + (5*1)) / (2+5+2+1) = 3.2. Therefore, the correct answer is 3.2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>27", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "X2345F2521  What is the median of the distribution?", "images": [], "options": {"A": "5", "B": "4", "C": "3", "D": "2"}, "answer": "C", "explanation": "The median of a distribution is the middle value when the values are arranged in ascending order. In this case, the values are already in ascending order and the frequencies are given. The total number of values is 10 (2+5+2+1). The median is the average of the 5th and 6th values, which are both 3. Therefore, the correct answer is 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>28", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES", "question": "Co-operative society formed to market the output of their members are called", "images": [], "options": {"A": "Consumers' co-operation societies", "B": "Wholesale co-operative societies", "C": "Credit and thrift co-operative societies", "D": "Producers' co-operative societies"}, "answer": "D", "explanation": "A co-operative society formed to market the output of their members is called a Producers' co-operative society. These societies are formed by producers who wish to obtain maximum profits by eliminating middlemen. The producers are the members of the society and they participate in the decision-making process. Therefore, the correct answer is Producers' co-operative societies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2014>29", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "Money will serve as a standard of deferred payment if it is", "images": [], "options": {"A": "homogenous", "B": "durable", "C": "easily recognized", "D": "stable in value"}, "answer": "D", "explanation": "Money will serve as a standard of deferred payment if it is stable in value. This is because for money to be a standard of deferred payment, it must be able to maintain its value over time. This means that the value of money should not fluctuate or change rapidly. If the value of money is not stable, it will not be a reliable standard for deferred payments, as the amount of money required to settle a debt could change significantly over time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>30", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THEORY OF SUPPLY : DISTINCTION BETWEEN CHANGE IN QUANTITY SUPPLIED AND CHANGE IN SUPPLY", "question": "Due to an increase in price, a seller increase the quantity offered for sale from 400 units to 450 units. What is the percentage change in quantity supplied", "images": [], "options": {"A": "1%", "B": "7.5%", "C": "12.5%", "D": "20%"}, "answer": "C", "explanation": "The percentage change in quantity supplied can be calculated using the formula: (New Quantity - Old Quantity) / Old Quantity * 100%. In this case, the old quantity is 400 units and the new quantity is 450 units. Therefore, the percentage change in quantity supplied is (450 - 400) / 400 * 100% = 12.5%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>31", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Which of the following will increase the nominal value of national income?", "images": [], "options": {"A": "High rate of inflation", "B": "Increase in the value of money", "C": "Increase in import", "D": "High rate of substances production"}, "answer": "A", "explanation": "A high rate of inflation will increase the nominal value of national income. The nominal value of national income is the total value of all goods and services produced in a country at current prices. When there is inflation, the prices of goods and services increase, which in turn increases the nominal value of national income. However, it's important to note that this does not necessarily mean that the real value or purchasing power of the national income has increased, as the cost of goods and services has also increased.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>32", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "Cyclical unemployment is one associated with", "images": [], "options": {"A": "inadequate information", "B": "trade fluctuations", "C": "structural changes", "D": "seasonal changes"}, "answer": "B", "explanation": "Cyclical unemployment is a type of unemployment that occurs when there is not enough aggregate demand in the economy to provide jobs for everyone who wants to work. It is associated with the business cycle, where periods of high unemployment coincide with economic recessions or depressions, hence the term 'trade fluctuations' is the most appropriate among the options.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>33", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "INFLATION & DEFLATION : INTRODUCTION", "question": "Which of the following best defines inflation?", "images": [], "options": {"A": "Cyclical increase in prices", "B": "Periodic increase in prices", "C": "Persistent increase in prices", "D": "Occasional increase in prices"}, "answer": "C", "explanation": "Inflation is defined as a sustained increase in the general level of prices for goods and services. It is measured as an annual percentage increase. As inflation rises, every dollar you own buys a smaller percentage of a good or service. Therefore, 'Persistent increase in prices' is the correct definition of inflation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2014>34", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "MARKET STRUCTURE : MEANING OF MARKET & TYPES", "question": "Perfect knowledge of events in a perfect market will be made possible by the existence of", "images": [], "options": {"A": "many buyer and sellers", "B": "homogenous products", "C": "means of communication", "D": "large number of traders"}, "answer": "C", "explanation": "In a perfect market, perfect knowledge is assumed to exist which means that all consumers and producers have perfect and instantaneous knowledge of all market prices, their own utility, and own cost functions. This is made possible by the existence of 'means of communication'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>35", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THE THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "An increase in the price of a commodity from N10 to N15 leads to an increase in the quantity supplied from 10 units to 15 units. The price elasticity of supply is", "images": [], "options": {"A": "0", "B": "0.5", "C": "1", "D": "5"}, "answer": "C", "explanation": "Priceelasticityofsupply=%Δ in quantity supplied%Δ in price   %Δinquantitysupplied=15-1010x100    = 50    %ΔinP=15-1010x100  =510x100=50   Price elasticity of supply = 50/50 = 1 (unitary)", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>36", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Economic development may be hindered if there is", "images": [], "options": {"A": "a high pool of skilled labour", "B": "a high rate of economic growth", "C": "political stability", "D": "rapid population growth"}, "answer": "D", "explanation": "Rapid population growth can hinder economic development because it can lead to overpopulation, which can strain resources and infrastructure, leading to lower standards of living and slower economic growth. The other options, such as a high pool of skilled labour, a high rate of economic growth, and political stability, are generally beneficial for economic development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>37", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "Which of the following types of unemployment results from changes in the pattern of aggregate demand?", "images": [], "options": {"A": "Technological unemployment", "B": "Structural unemployment", "C": "Frictional unemployment", "D": "Seasonal unemployment"}, "answer": "B", "explanation": "Structural unemployment occurs when there is a change in the pattern of aggregate demand. This type of unemployment occurs when the skills of workers do not match the jobs available, often due to technological changes or shifts in the economy. The other types of unemployment listed do not result from changes in aggregate demand. Technological unemployment is caused by the replacement of workers by machines or technology. Frictional unemployment is temporary unemployment that occurs when people are between jobs or are looking for their first jobs. Seasonal unemployment occurs when people are out of work due to the season, such as construction workers in the winter or farm workers in the off-growing season.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>38", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL TRADE : INTRODUCTION", "question": "Which of the following is not a reason countries import goods?", "images": [], "options": {"A": "Differences in natural endowments", "B": "The law of absolute advantage", "C": "Differences in taste", "D": "The love for other nations"}, "answer": "D", "explanation": "Countries import goods for various reasons such as differences in natural endowments, the law of absolute advantage, and differences in taste. However, 'the love for other nations' is not a valid economic reason for importing goods. It does not directly contribute to the economic benefit or strategic advantage of a country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2014>39", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "Provision of short terms loans to solve balance payments problem is done by the", "images": [], "options": {"A": "International Finance Corporation", "B": "International Monetary Fund", "C": "International Bank for Reconstruction and Development", "D": "Africa Development Bank"}, "answer": "B", "explanation": "The International Monetary Fund (IMF) is an international organization that provides short-term loans to member countries to help them maintain balance of payments stability. The International Finance Corporation, International Bank for Reconstruction and Development, and Africa Development Bank do not primarily focus on short-term loans for balance of payments problems.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>40", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "West African countries are experiencing worsening terms of trade because", "images": [], "options": {"A": "they are primary producers", "B": "their currencies are overvalued", "C": "they import less machines", "D": "they are tertiary producers"}, "answer": "A", "explanation": "West African countries are experiencing worsening terms of trade primarily because they are primary producers. Primary producers are countries that mainly export raw materials and agricultural products, which often have lower prices and are more susceptible to price fluctuations on the international market. This leads to a worsening of the terms of trade, which is the ratio of export prices to import prices. The other options do not directly lead to worsening terms of trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>41", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT", "question": "Which of the following statements is correct?", "images": [], "options": {"A": "As total utility increases, the marginal utility also increases", "B": "The marginal utility is always zero whenever the total utility reaches the maximum", "C": "The total utility is at maximum whenever marginal utility is at its maximum.", "D": "There is no relationship between total utility and the marginal utility"}, "answer": "B", "explanation": "The marginal utility is always zero whenever the total utility reaches the maximum", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>42", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "A change in the quantity demanded of a given commodity is determined by the", "images": [], "options": {"A": "size of the population", "B": "income of the consumer", "C": "price of the commodity", "D": "taste and fashion"}, "answer": "C", "explanation": "A change in the quantity demanded of a given commodity is determined by the price of the commodity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>43", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "The likely implication of the devaluation of a country's currency is that", "images": [], "options": {"A": "exports of such a country become cheaper", "B": "importation of goods into such a country becomes cheaper", "C": "the value of such a country's currency rises", "D": "foreign goods attracted into the country"}, "answer": "A", "explanation": "Devaluation of a country's currency makes its goods and services cheaper for foreign buyers, thereby making exports cheaper. This is because when a currency is devalued, more units of the currency are needed to purchase goods, so the goods become cheaper for those buying with foreign currency.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>44", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL TRADE : INTRODUCTION", "question": "International trade is desirable because it", "images": [], "options": {"A": "may lead to overproduction", "B": "bring about over-dependence of countries on one another", "C": "provides foreign market for local goods", "D": "brings about unhealthy competition and rivalries"}, "answer": "C", "explanation": "International trade is desirable because it provides foreign markets for local goods. This allows countries to sell their goods and services to other countries, which can lead to increased production and economic growth. It also allows countries to access goods and services that may not be available domestically.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>45", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "A financial institute established for the purpose of providing specialized services like acceptable of bills of exchange and equipment leasing is known as", "images": [], "options": {"A": "Merchant Bank", "B": "Development Bank", "C": "Central Bank", "D": "Insurance company"}, "answer": "A", "explanation": "A Merchant Bank is a financial institution that provides specialized services such as acceptance of bills of exchange and equipment leasing. They are also involved in international finance, business loans for companies, and underwriting. A bill of exchange is a binding agreement by one party to pay a fixed amount of cash to another party on a specified date or on demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>46", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "Which of the following functions of money is mostly affected during inflation?", "images": [], "options": {"A": "Medium of exchange", "B": "Unit of Account", "C": "Store of value", "D": "Standard of deferred payment"}, "answer": "C", "explanation": "Inflation erodes the purchasing power of money, which means that the same amount of money can buy fewer goods and services. This primarily affects money's function as a 'store of value'. A store of value is the function of an asset that can be saved, retrieved and exchanged at a later time, and be predictably useful when retrieved. During inflation, money doesn't hold its value over time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>47", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "Precautionary motive for holding money is to", "images": [], "options": {"A": "Meet daily and regular transactions", "B": "take advantage of changes in prices of goods and services", "C": "cover unforeseen events", "D": "Cover expenses on house rent"}, "answer": "C", "explanation": "The precautionary motive for holding money refers to holding money to cover unforeseen events. This is a key concept in Keynesian economic theory, which states that people hold money for three reasons: transactions, precautionary and speculative. The precautionary motive is about holding money to be able to cope with unexpected expenses or opportunities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>48", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION", "question": "Which of the following measures will not encourage Industrialization in West Africa?", "images": [], "options": {"A": "Taking over of all forms of industries by the government", "B": "Provision of social infrastructure", "C": "Giving tax incentives, especially to infant industries", "D": "Using tariffs to discourage the use of imported items"}, "answer": "A", "explanation": "Taking over all forms of industries by the government will not encourage industrialization. This is because it can lead to inefficiencies and lack of competition, which can stifle innovation and growth. Industrialization is often driven by private sector competition, innovation, and investment. Government's role is to provide the enabling environment such as infrastructure, stable economic policies, and regulatory frameworks.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2014>49", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "The concentration of many firms of a particular industry in a particular area is known as", "images": [], "options": {"A": "location of industry", "B": "amalgamation", "C": "localization of industry", "D": "nationalization of industry"}, "answer": "C", "explanation": "The concentration of many firms of a particular industry in a particular area is known as localization of industry. This happens when firms of a similar industry gather in a specific area due to benefits such as shared resources, skilled labor, and reduced transportation costs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2014>50", "subject": "Economics", "year": "2014", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "Which of the following is not an effect of the discovery of mineral resources in an area?", "images": [], "options": {"A": "Increase in wealth", "B": "Overcrowding", "C": "Increase in crime rate", "D": "Under population"}, "answer": "D", "explanation": "The discovery of mineral resources in an area often leads to an increase in population due to the influx of people seeking employment and business opportunities. Therefore, underpopulation is not an effect of the discovery of mineral resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>1", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Economics is regarded as a science because it", "images": [], "options": {"A": "studies law that governs human behaviour", "B": "uses scientific method to explain human behaviour", "C": "make use of controlled experiments to explain human behaviour", "D": "makes use of machines to study human behaviour"}, "answer": "B", "explanation": "Economics is regarded as a science because it uses scientific methods to explain human behavior. These methods include observation, formulation of hypotheses, testing, and drawing conclusions. Controlled experiments and machines are not typically used in economics.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2015>2", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following cannot be described as land?", "images": [], "options": {"A": "Forest", "B": "Diamond", "C": "Roads", "D": "Crude oil"}, "answer": "C", "explanation": "Land, in economics, refers to all naturally occurring resources whose supply is inherently fixed. Examples are any geographical areas like forests, fields, and bodies of water, and resources like minerals, fossil fuels, etc. Roads, however, are man-made and thus cannot be described as land.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2015>3", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "An outward shift of the production possibility curve shows that", "images": [], "options": {"A": "production is shifting to the right", "B": "resources are under utilized", "C": "economic growth has taken place", "D": "factors of production are moving outward"}, "answer": "C", "explanation": "In economics, the production possibility curve (PPC) is a graphical representation showing the maximum combination of goods and services that can be produced in an economy at a given level of technology and resources at full employment. An outward shift of the PPC indicates that there has been an increase in resources or improvement in technology, which leads to economic growth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>4", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "The following constitute the criteria for identifying an economic system except", "images": [], "options": {"A": "ownership of resources", "B": "scarcity of resources", "C": "method of decision making", "D": "motivation for production"}, "answer": "B", "explanation": "An economic system is identified by the way a society organizes its resources to satisfy the needs and wants of its citizens. The criteria for identifying an economic system include the ownership of resources, the method of decision making, and the motivation for production. However, scarcity of resources is not a criterion for identifying an economic system, but rather a fundamental economic problem that all systems must address.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>5", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "A disadvantage of the mean as a measure of central tendency is that it", "images": [], "options": {"A": "is affected by extreme values", "B": "can only be used for continuous data", "C": "cannot be used to measure the qualities of a population", "D": "cannot be determined in group data"}, "answer": "A", "explanation": "The mean is a measure of central tendency that calculates the average of a set of values. However, it is sensitive to extreme values (outliers). This means that if there is a value in the data set that is significantly higher or lower than the rest, it can skew the mean and give a misleading representation of the data. Therefore, the disadvantage of the mean as a measure of central tendency is that it is affected by extreme values.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>6", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "Which of the following is not an effect of many middlemen in the chain of distribution?", "images": [], "options": {"A": "Shortage of commodities", "B": "Low retail prices", "C": "Hoarding of goods", "D": "High retail prices"}, "answer": "B", "explanation": "Middlemen in the chain of distribution are intermediaries between producers and consumers. They buy goods from producers and sell them to consumers. The presence of many middlemen can lead to hoarding of goods, shortage of commodities, and high retail prices as each middleman adds their markup. However, it does not lead to low retail prices. Therefore, the statement that is not an effect of many middlemen in the chain of distribution is 'Low retail prices'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>7", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "If the price of floor rises, then bread's", "images": [], "options": {"A": "demand curve will shift to the left while supply curve will be to the right", "B": "supply curve will shift to the left", "C": "supply curve will shift to the right", "D": "demand curve will shift to the right while supply curve remains unchanged"}, "answer": "B", "explanation": "The price of flour is a cost of production for bread. If the price of flour rises, it becomes more expensive to produce bread. This would decrease the quantity of bread that suppliers are willing and able to produce at each price, causing the supply curve to shift to the left. Therefore, if the price of flour rises, then bread's supply curve will shift to the left.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>8", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "Which of the following is not a reason for abnormal demand?", "images": [], "options": {"A": "Price of the commodity", "B": "Goods of ostentation", "C": "Giffen goods", "D": "rare commodity"}, "answer": "A", "explanation": "Abnormal demand is a situation where demand does not correspond to the price of the goods or services. It is not affected by the price of the commodity. Instead, it is influenced by factors such as goods of ostentation, Giffen goods, and rare commodities. Therefore, the price of the commodity is not a reason for abnormal demand.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>9", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THE THEORY OF SUPPLY : DISTINCTION BETWEEN CHANGE IN QUANTITY SUPPLIED AND CHANGE IN SUPPLY", "question": "Increase in production subsidies will shift", "images": [], "options": {"A": "the demand curve to the left", "B": "the supply curve to the right", "C": "both the supply and demand curves to the left", "D": "the supply curve to the left and demand curve to the right"}, "answer": "B", "explanation": "Production subsidies are financial aid provided by the government to industries or businesses to support their operations and reduce the cost of production. When production subsidies increase, the cost of production decreases, leading to an increase in supply. This shifts the supply curve to the right.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>10", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THE THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "The market supply curve slopes upwards from left to right indicating that", "images": [], "options": {"A": "producers pay high taxes", "B": "two commodities can be supplied at the same time", "C": "at a lower price, less is supplied", "D": "at a lower price, more is supplied and demanded"}, "answer": "C", "explanation": "The market supply curve slopes upwards from left to right, indicating the law of supply. The law of supply states that as the price of a good or service increases, the quantity supplied also increases, and vice versa. Therefore, at a lower price, less is supplied.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>11", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "Government revenue will increase if taxes are levied on goods with", "images": [], "options": {"A": "perfectly elastic demand", "B": "fairly elastic demand", "C": "perfectly inelastic demand", "D": "unitary elastic demand"}, "answer": "C", "explanation": "Government revenue will increase if taxes are levied on goods with perfectly inelastic demand. This is because the demand for these goods does not change with price. Therefore, even if the government imposes a tax, the quantity demanded will remain the same, leading to an increase in government revenue.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>12", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If a given change in price brings about a proportionately larger change in quantity demanded, then", "images": [], "options": {"A": "demand is relatively price elastic", "B": "demand is relatively price inelastic", "C": "price elasticity of demand is unitary", "D": "price elasticity of demand is constant"}, "answer": "A", "explanation": "If a given change in price brings about a proportionately larger change in quantity demanded, then demand is relatively price elastic. This is because the elasticity of demand measures the responsiveness of quantity demanded to a change in price. If the change in quantity demanded is larger than the change in price, the demand is said to be elastic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>13", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : GIFFEN GOODS", "question": "If the price of a commodity Z falls and a consumer buys less of it, then commodity Z is a", "images": [], "options": {"A": "necessity", "B": "good of ostentation", "C": "Giffen good", "D": "normal good"}, "answer": "C", "explanation": "If the price of a commodity Z falls and a consumer buys less of it, then commodity Z is a Giffen good. A Giffen good is a type of inferior good where the demand decreases as the price decreases, which is contrary to the law of demand. This is due to the income effect, which is stronger than the substitution effect for these types of goods.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>14", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT", "question": "In order to calculate total utility (TU) from given levels of marginal utility (MU), one has to", "images": [], "options": {"A": "subtract MU and TU", "B": "add MU from the various levels", "C": "multiply MU by the initial TU", "D": "divide current MU by previous MU"}, "answer": "B", "explanation": "Total utility is the aggregate sum of satisfaction or benefit that an individual gains from consuming a given amount of goods or services in an economy. It is calculated by summing up the marginal utility (MU) at various levels. Marginal utility is the additional satisfaction a consumer gains from consuming one more unit of a good or service. Therefore, to calculate total utility from given levels of marginal utility, one has to add MU from the various levels.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>15", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET", "question": "Which of the following will not affect the market price of a commodity?", "images": [], "options": {"A": "Increase in demand", "B": "Changes in taste", "C": "intersection of demand and supply", "D": "Increase in supply"}, "answer": "C", "explanation": "The market price of a commodity is determined by the interaction of supply and demand. Changes in demand, changes in supply, and changes in taste can all affect the market price. However, the intersection of demand and supply is not a factor that affects the market price, but rather it is the point at which the market price is determined. Therefore, the intersection of demand and supply will not affect the market price of a commodity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>16", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION", "question": "All the following are methods of determining prices except", "images": [], "options": {"A": "maximum pricing", "B": "rationing", "C": "minimum pricing", "D": "auctioning"}, "answer": "B", "explanation": "Methods of determining prices include maximum pricing, minimum pricing, and auctioning. Maximum pricing is a price ceiling above which a price cannot legally go. Minimum pricing is a price floor below which a price cannot legally fall. Auctioning is a process where potential buyers place competitive bids on assets and services. However, rationing is not a method of determining prices. Rationing is a system of allocating scarce goods and services using criteria other than price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>17", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION", "question": "The law of diminishing returns relates to", "images": [], "options": {"A": "total utility", "B": "average utility", "C": "total product", "D": "marginal product"}, "answer": "D", "explanation": "The law of diminishing returns, also known as the law of variable proportions, states that if one factor of production is increased while other factors are held constant, the overall returns will relatively decrease after a certain point. This law is most often applied to production processes, referring to the point at which the marginal increase in output for an additional unit of input starts to become less. Therefore, it relates to the 'marginal product'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>18", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCTION FUNCTIONS AND LAWS OF RETURNS", "question": "By adding all the marginal products at each level of employment of the variable input, we obtain a value equal to", "images": [], "options": {"A": "average product", "B": "total product", "C": "average variable cost", "D": "total cost"}, "answer": "B", "explanation": "The total product is the total output a production unit can produce, using different combinations of factors of production. When we add up all the marginal products at each level of employment of the variable input, we get the total product. Marginal product is the change in output resulting from employing one more unit of a particular input (for example, the change in output when a firm's labor increases from five to six units). Therefore, the sum of all marginal products gives us the total product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>19", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "Total cost is obtained by", "images": [], "options": {"A": "adding up the marginal cost at each level", "B": "dividing the total cost by output at each level", "C": "adding up the average variable cost at each level", "D": "adding up the total variable cost at each level"}, "answer": "A", "explanation": "The sum of all marginal cost at each level of output gives total cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>20", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "Which of the following cost is not U-shaped? The", "images": [], "options": {"A": "Marginal cost curve", "B": "Average fixed cost curve", "C": "Average total cost curve", "D": "Average variable cost curve"}, "answer": "B", "explanation": "AFC = Average fixed cost   This is not U-shaped.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>21", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Which of the following business, organizations is likely to experience disagreements between management and shareholders?", "images": [], "options": {"A": "Co-operative society", "B": "Sole trader", "C": "partnership", "D": "Joint-stock company"}, "answer": "D", "explanation": "A joint-stock company is likely to experience disagreements between management and shareholders. This is because in a joint-stock company, the shareholders are the owners of the company but the management is responsible for running the company. The management may take decisions that the shareholders do not agree with, leading to disagreements. The other options like co-operative society, sole trader, and partnership do not have this kind of separation between ownership and management.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>22", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "Which of the following is not a method of controlling monopoly?", "images": [], "options": {"A": "Preventing mergers", "B": "Indigenization", "C": "Privatization", "D": "Imposing high profit tax"}, "answer": "C", "explanation": "Privatization is not a method of controlling monopoly. Privatization is the process of transferring ownership of a business, enterprise, agency, public service, or public property from the public sector (a government) to the private sector, either to a business that operates for a profit or to a nonprofit organization. It does not necessarily prevent or control monopolies. The other options like preventing mergers, indigenization, and imposing high profit tax are methods that can be used to control monopolies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>23", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Which of the following features distinguishes a public limited company from a private limited company?", "images": [], "options": {"A": "Perpetual existence", "B": "Limited liability", "C": "legal entity", "D": "sale of shares to the public"}, "answer": "D", "explanation": "The feature that distinguishes a public limited company from a private limited company is the sale of shares to the public. A public limited company can sell its shares to the general public and can be listed on a stock exchange, while a private limited company cannot. The other features like perpetual existence, limited liability, and legal entity are common to both public and private limited companies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>24", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Inflation may occur if there is", "images": [], "options": {"A": "excess supply over demand", "B": "increase in productivity", "C": "excess demand with limited supply", "D": "increase government spending in a depressed economy"}, "answer": "C", "explanation": "Inflation occurs when the demand for goods and services exceeds their supply. This is often due to an increase in production costs or an increase in demand without a corresponding increase in supply. This situation is described in option 3, 'excess demand with limited supply'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>25", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "Frictional unemployment occurs when", "images": [], "options": {"A": "there is a change in the technique of production", "B": "job seekers lack information where jobs exist", "C": "bad weather prevent work from progressing", "D": "job seekers have disabilities"}, "answer": "B", "explanation": "Frictional unemployment refers to the period of time when a worker is searching for, or transitioning from one job to another. It is often caused by lack of information about where jobs exist, as stated in option 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>26", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "Which of the following will increase the demand for labour?", "images": [], "options": {"A": "increase wage rate", "B": "Labour's demand for output", "C": "low wage rate", "D": "Low marginal productivity of labour"}, "answer": "B", "explanation": "The demand for labour increases when there is an increase in the demand for the output that the labour produces. This is because as demand for a product or service increases, companies need more workers to meet this demand. Therefore, 'Labour's demand for output' in option 2 is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>27", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "One reason for low agricultural productivity in most West African Countries is that", "images": [], "options": {"A": "farmers are not capable of cultivating cash crops", "B": "it does not provide income to farmers with large families", "C": "farmers find it difficult getting help from financial institutions", "D": "it is not the only source of raw materials for agro-based industries"}, "answer": "C", "explanation": "The main reason for low agricultural productivity in most West African countries is the difficulty farmers face in accessing financial support from institutions. This is because agriculture is often seen as a risky venture due to factors such as unpredictable weather conditions, pests and diseases, and market price fluctuations. As a result, financial institutions are often reluctant to lend to farmers, which in turn limits their ability to invest in inputs and technologies that could increase their productivity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>28", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "The movement of labour from one grade to an entirely different grades is an example of", "images": [], "options": {"A": "industrial labour mobility", "B": "horizontal occupational mobility", "C": "vertical occupational mobility", "D": "geographical mobility"}, "answer": "C", "explanation": "The movement of labour from one grade to an entirely different grade is an example of vertical occupational mobility. Vertical occupational mobility refers to the movement of an employee from one job level to another within the same field. This could be either upward (promotion) or downward (demotion). In contrast, horizontal occupational mobility refers to the movement of an employee from one job to another within the same job level.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>29", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "Ten bags of wheat bought for $50 by a flour miller were sold for $65. What is the value added Tax payable by the flour miller if the tax rate is 5%", "images": [], "options": {"A": "$7.50", "B": "$3.25", "C": "$2.25", "D": "$0.75"}, "answer": "D", "explanation": "Profit = selling price - cost price  = 65 - 50  Profit = $15      Tax = 5%    5100x15=$0.75", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>30", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "Which of the following is not a strong basis for trade union's demand for higher wages? The", "images": [], "options": {"A": "company is making higher profit", "B": "productivity of the workers has increased", "C": "members of the union have high qualifications", "D": "commodity produced by the workers is very essential"}, "answer": "C", "explanation": "Trade unions demand higher wages based on factors such as the company's profitability, increased worker productivity, and the essential nature of the commodity produced by the workers. However, the high qualifications of union members are not a strong basis for demanding higher wages. This is because wages are typically determined by the value of the work done, not the qualifications of the workers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>31", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The difference between the gross domestic product (GDP) and gross national product (GNP) is", "images": [], "options": {"A": "depreciation", "B": "transfer payment", "C": "net income from abroad", "D": "direct taxes"}, "answer": "C", "explanation": "The difference between Gross Domestic Product (GDP) and Gross National Product (GNP) is the net income from abroad. GDP measures the value of all goods and services produced within a country's borders, while GNP measures the value of all goods and services produced by a country's residents, regardless of where they live. Therefore, the net income from abroad (income earned by domestic residents from overseas investments minus income earned within the domestic economy by overseas residents) is added to GDP to get GNP.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>32", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Location of firms of an industry is not influenced by", "images": [], "options": {"A": "availability of raw materials", "B": "existence of other firms", "C": "nearness to the source of money supply", "D": "government policy"}, "answer": "C", "explanation": "The location of firms in an industry is influenced by factors such as the availability of raw materials, the existence of other firms, and government policy. However, the nearness to the source of money supply does not directly influence the location of firms. While access to capital is important for businesses, it is not tied to a physical location in the same way as raw materials or other firms might be.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>33", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "In national income accounting, the term net is used to indicate that a value", "images": [], "options": {"A": "includes income of foreigners", "B": "exclude income of citizens", "C": "include depreciation", "D": "excludes depreciation"}, "answer": "C", "explanation": "In national income accounting, the term 'net' is used to indicate that a value includes depreciation. Depreciation refers to the decrease in the value of physical properties or assets with time and use. So, when we talk about net income or net value, we are considering the income or value after accounting for depreciation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>34", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "MONEY : TYPES OF MONEY", "question": "Which of the following best describe token money?", "images": [], "options": {"A": "Money in the vault of commercial banks", "B": "Currency and coins in circulation", "C": "Money with face value higher than its material content", "D": "Coins and notes made of poor quality materials"}, "answer": "C", "explanation": "Token money is best described as money with face value higher than its material content. This means that the value of the material (like paper or metal) used to make the money is less than the value that the money represents. For example, a $10 bill does not cost $10 to produce, but it is accepted as being worth $10.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>35", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "An industry is best described as", "images": [], "options": {"A": "firm that sells a set of closely related commodities", "B": "a factory that produces different lines of products", "C": "a group of firms that sells a closely related set of products", "D": "industrial concern that is into production and selling of goods"}, "answer": "C", "explanation": "An industry is best described as a group of firms that sells a closely related set of products. For example, the automobile industry includes all companies that manufacture cars, trucks, and other vehicles. These companies are producing similar products and are therefore part of the same industry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>36", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "In developing countries, a larger percentage of the labour force is employed in the", "images": [], "options": {"A": "trade sector", "B": "tertiary sector", "C": "primary sector", "D": "secondary sector"}, "answer": "C", "explanation": "In developing countries, a larger percentage of the labour force is employed in the primary sector. The primary sector of the economy includes any industry involved in the extraction and collection of natural resources; such as farming, forestry, mining and fishing. In developing countries, a larger percentage of the population is involved in these activities, hence the larger labour force in the primary sector.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>37", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "The main item on a stock exchange market is", "images": [], "options": {"A": "treasury bills", "B": "traveller's cheques", "C": "foreign currencies", "D": "new shares"}, "answer": "D", "explanation": "The main item on a stock exchange market is new shares. A stock exchange, securities exchange, or bourse is a facility where stockbrokers and traders can buy and sell securities, such as shares of stock and bonds and other financial instruments. New shares are the primary items traded on these markets.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>38", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "The proportion of commercial banks' total assets kept in the form of highly liquid assets is known as", "images": [], "options": {"A": "demand deposit", "B": "fixed deposit", "C": "cash ratio", "D": "moral suasion"}, "answer": "C", "explanation": "The proportion of commercial banks' total assets kept in the form of highly liquid assets is known as cash ratio. The cash ratio is the ratio of a company's total cash and cash equivalents to its current liabilities. The metric calculates a company's ability to repay its short-term debt; this information is useful to creditors when deciding how much debt, if any, they would be willing to extend to the asking party.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>39", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "EXPECTED REVENUEITEMS AMOUNT($M)Rates and Royalties 75.00Company Income Tax 150.00Customs and excise duties 300.20Personal Income Tax 80.00Fess and fines 60.80Value added tax 100.00    What is the total revenue from indirect taxes?", "images": [], "options": {"A": "$686.00m", "B": "$400.20m", "C": "$135.80m", "D": "$100.00m"}, "answer": "B", "explanation": "Indirect taxes    Customs & excise duties ( 300.20) + Value Added tax  (100)   = $400.20m", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>40", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "EXPECTED REVENUEITEMS AMOUNT($M)Rates and Royalties 75.00Company Income Tax 150.00Customs and excise duties 300.20Personal Income Tax 80.00Fess and fines 60.80Value added tax 100.00  What is the total revenue from non-tax sources?", "images": [], "options": {"A": "$400.20m", "B": "$375.20m", "C": "$135.80m", "D": "$75.00m"}, "answer": "C", "explanation": "Non-tax sources    Fees and Fines ∔ Rents and Royalties    = 60.80 ∔75   = 135.80.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>41", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Which of the following is not an objective of economic planning?", "images": [], "options": {"A": "Need to direct economic development of the country towards the desired direction", "B": "Desire to ensure a sustained structural development of the country", "C": "Desire to widen the gap between developing countries and the developed worlds", "D": "Management of scarce resources in the face of unlimited wants of the citizens"}, "answer": "C", "explanation": "Economic planning is a resource allocation mechanism that is contrasted with the market mechanism. As a coordinating mechanism for socialist economics, economic planning substitutes factor markets with a direct allocation of resources within a single or interconnected group of socially owned organizations. The objective of economic planning is not to widen the gap between developing countries and the developed worlds. Therefore, option 3 is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>42", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "In order to control inflation, the government should", "images": [], "options": {"A": "reduce the cost of borrowing", "B": "buy securities in the open market", "C": "adopt restrictive monetary policy", "D": "discourage savings"}, "answer": "C", "explanation": "Inflation is a general increase in prices and fall in the purchasing value of money. To control inflation, the government should adopt a restrictive monetary policy. This policy reduces the amount of money circulating in the economy, which helps to control inflation. The reduction in money supply is achieved by increasing interest rates, increasing reserve requirements for banks, or selling securities in the open market to pull money out of circulation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>43", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "When the demand for foreign exchange exceeds its supply, the value of the domestic currency", "images": [], "options": {"A": "appreciates", "B": "depreciates", "C": "remains unchanged", "D": "expands"}, "answer": "B", "explanation": "When the demand for foreign exchange exceeds its supply, the value of the domestic currency depreciates. This is because the high demand for foreign currency implies that more of the domestic currency is being offered or used to get the foreign currency. As a result, the value of the domestic currency falls or depreciates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>44", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "The export of West Africa countries are mainly composed of", "images": [], "options": {"A": "services", "B": "raw materials", "C": "manufactured goods", "D": "consumer goods"}, "answer": "B", "explanation": "The exports of West African countries are mainly composed of raw materials. These countries are rich in natural resources like oil, gold, diamonds, cocoa, coffee, timber etc. These raw materials are exported to other countries where they are processed into finished goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2015>45", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "A conscious effort of government to achieve a specific set of goal is", "images": [], "options": {"A": "economic planning", "B": "economic development", "C": "economic growth", "D": "economic target"}, "answer": "A", "explanation": "Economic planning is a term used to describe the long term plans of government to co-ordinate and develop the economy with efficient use of resources. Economic planning is often associated with the idea of a central planning economy. In this context, the state makes all the decisions about what to produce, how to produce, and who will receive the final goods. Therefore, a conscious effort of government to achieve a specific set of goal is economic planning.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>46", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "A country has favourable terms of trade when the prices of her", "images": [], "options": {"A": "export rise relative to the price of imports", "B": "exports fall relative to the price of import", "C": "imports rise faster than the price of exports", "D": "import and exports move in the same direction"}, "answer": "A", "explanation": "Terms of trade (TOT) refer to the relative price of imports in terms of exports and is defined as the ratio of export prices to import prices. It can be interpreted as the amount of import goods an economy can purchase per unit of export goods. Therefore, a country has favourable terms of trade when the prices of her export rise relative to the price of imports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>47", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "The abolition of all forms of trade barriers among member countries while maintaining common external tariffs against non-members is a feature of a", "images": [], "options": {"A": "free trade", "B": "customs union", "C": "common market", "D": "economic union"}, "answer": "B", "explanation": "A customs union is a type of trade bloc which is composed of a free trade area with a common external tariff. The participant countries set up common external trade policy, but in some cases they use different import quotas. Common competition policy is also helpful to avoid competition deficiency. Therefore, the abolition of all forms of trade barriers among member countries while maintaining common external tariffs against non-members is a feature of a customs union.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>48", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "In order to correct adverse balance of payment, government should", "images": [], "options": {"A": "reduce tariffs", "B": "increase subsidies on exports", "C": "increase tax on local industries", "D": "reduce personal income tax"}, "answer": "B", "explanation": "Adverse balance of payment can be corrected by increasing exports. One way to increase exports is by increasing subsidies on exports. This makes the products cheaper in the international market, thereby increasing demand and subsequently exports.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2015>49", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "Which of the following is a benefit to a member country of the world bank?", "images": [], "options": {"A": "Easy access to long term loans", "B": "Management of foreign exchange", "C": "mediating in labour dispute", "D": "Financial balance of payment deficit"}, "answer": "A", "explanation": "The World Bank provides financial and technical assistance to developing countries for development programs (e.g., bridges, roads, schools, etc.) that are expected to improve the economic prospects and quality of life for people in those countries. One of the benefits to a member country of the World Bank is easy access to long term loans.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2015>50", "subject": "Economics", "year": "2015", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "Which of the following is an objective of OPEC? TO", "images": [], "options": {"A": "prevent fluctuation in prices of all commodities", "B": "protect the economic interest of all countries", "C": "control the level of output of oil", "D": "discover oil in all countries"}, "answer": "C", "explanation": "The Organization of the Petroleum Exporting Countries (OPEC) is a permanent, intergovernmental Organization, created at the Baghdad Conference on September 10–14, 1960, by Iran, Iraq, Kuwait, Saudi Arabia and Venezuela. The main objective of OPEC is to coordinate and unify petroleum policies among Member Countries, in order to secure fair and stable prices for petroleum producers; an efficient, economic and regular supply of petroleum to consuming nations; and a fair return on capital to those investing in the industry. Therefore, controlling the level of output of oil is one of the objectives of OPEC.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>1", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Human wants are insatiable because wants are", "images": [], "options": {"A": "limited while means are scarce", "B": "unlimited and means are also unlimited", "C": "limited and means are also limited", "D": "unlimited while means are scarce"}, "answer": "D", "explanation": "Human wants are considered insatiable because they are unlimited while the means to satisfy them are scarce. This is a fundamental concept in economics, which states that resources are limited, but human wants are unlimited. Therefore, we always have more wants than we have resources to satisfy them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2016>2", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT", "question": "Scale of preference is important for the following reasons except in", "images": [], "options": {"A": "satisfying wants", "B": "making rational choice", "C": "making optimum allocation of resources", "D": "using scarce resources efficiently"}, "answer": "A", "explanation": "The scale of preference is a basic economic concept that refers to the listing of wants or needs by an individual in order of importance. It is used to make rational choices and optimum allocation of resources, and to use scarce resources efficiently. However, it does not directly contribute to the satisfaction of wants. The satisfaction of wants is dependent on the availability of resources and not the scale of preference.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>3", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "In a socialist economy, prices of commodities are determined by", "images": [], "options": {"A": "forces of demand and supply", "B": "producers of the commodities", "C": "the central planning authority", "D": "consumers who are sovereign"}, "answer": "C", "explanation": "In a socialist economy, the prices of commodities are determined by the central planning authority. This is because in a socialist economy, the government or a central authority owns and controls the means of production and distribution of goods and services. Therefore, they determine the prices of commodities, not the forces of demand and supply or the producers or consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>4", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following cannot be classified as land in economics?", "images": [], "options": {"A": "Bauxite deposit in the ground", "B": "A lake used for irrigation", "C": "A bulldozer for clearing farm land", "D": "Grazing field for cattle"}, "answer": "C", "explanation": "In economics, land refers to all naturally occurring resources whose supply is inherently fixed. Examples include geographical locations, mineral deposits, and even particular aspects of the environment. A bulldozer for clearing farm land is not a naturally occurring resource, it is a man-made capital good, hence it cannot be classified as land.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>5", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "A country's budget allocation to various sectors of the economy is shown in the pie chart below...    Use it to answer this question    If the budget of the country was $7,200, how much is allocated to Education?", "images": ["Economics/imgs/2016/pix1.png"], "options": {"A": "$2,400.00", "B": "$2,000.00", "C": "$1,200.00", "D": "$1,000.00"}, "answer": "A", "explanation": "AllocationtoEducation=120360×7200   = $2400", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2016>6", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "A country's budget allocation to various sectors of the economy is shown in the pie chart below...    Use it to answer this question  What is the ratio of expenditure on health to Agriculture?", "images": ["Economics/imgs/2016/pix1.png"], "options": {"A": "2 : 3", "B": "3 : 4", "C": "4 : 3", "D": "5 : 4"}, "answer": "B", "explanation": "Ratio of expenditure on health to Agriculture  =Expenditure on healthExpenditure on Agriculture  Expenditureonhealth=60360×7200=1200  ExpenditureonAgriculture=80360×7200=1600  The ratio of expenditure on health to Agric = 3 : 4  Note: when writing the ratio, numerator come before denominator.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2016>7", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "The demand curve for a necessity is usually", "images": [], "options": {"A": "vertical", "B": "backward bending", "C": "horizontal", "D": "negatively sloped"}, "answer": "D", "explanation": "A necessity good, like food or shelter, will still be demanded even if its price increases, but the demand will decrease significantly. This inverse relationship between price and quantity demanded is what defines a negatively sloped demand curve.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>8", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "What effect will an increase in price have on the total revenue of a firm whose product has inelastic demand? Total revenue will", "images": [], "options": {"A": "increase", "B": "fall", "C": "fluctuate", "D": "remain unchanged"}, "answer": "A", "explanation": "If the demand for a product is inelastic, it means that the quantity demanded does not respond strongly to changes in the price. Therefore, if the price increases, the total revenue of the firm will increase because the decrease in quantity demanded will not be enough to offset the increase in price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>9", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "If the quantity of men's hat demanded per week is represented by the function Qd = 20 - 1/3 P, where P is price, how many hats are demanded when the price is $9.00?", "images": [], "options": {"A": "11", "B": "17", "C": "23", "D": "47"}, "answer": "B", "explanation": "The quantity demanded can be calculated by substituting the price into the demand function. So, Qd = 20 - 1/3 * 9 = 17. Therefore, 17 hats are demanded when the price is $9.00.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2016>10", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "The demand for torch and batteries is a example of", "images": [], "options": {"A": "competitive demand", "B": "composite demand", "C": "complementary demand", "D": "derived demand"}, "answer": "C", "explanation": "The demand for torch and batteries is an example of complementary demand. Complementary goods are goods that are used together. In this case, torches and batteries are used together, hence they are complementary goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>11", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "Price elasticity of supply measures how responsive", "images": [], "options": {"A": "consumers are to a change in price", "B": "sellers are to a change in buyers' income", "C": "sellers are to a change in price", "D": "buyers are to a change in income"}, "answer": "C", "explanation": "Price elasticity of supply measures how responsive sellers are to a change in price. It is a measure of the relationship between a change in the quantity supplied of a particular good and a change in its price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>12", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "The tendency of workers to value their leisure hours more than hours of work as wage rate increases gives rise to", "images": [], "options": {"A": "positively sloping supply curve", "B": "perfectly elastic supply curve", "C": "backward bending supply curve", "D": "perfectly inelastic supply curve"}, "answer": "C", "explanation": "The backward bending supply curve is a graphical representation of the labor-leisure tradeoff for high-income individuals. It shows that as wages increase, the substitution effect causes individuals to supply more labor (i.e., work more hours), but at some point, the income effect dominates, causing individuals to supply less labor (i.e., work fewer hours). This is because they value leisure time more than additional income.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2016>13", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "The supply of rice in tons is given by the function: Qs - 80 - 0.7P = 0. Where Qs = Quantity supplied , P = price in Naira (₦). Find Qs, when P = ₦40.", "images": [], "options": {"A": "108tons", "B": "52tons", "C": "-52tons", "D": "-108tons"}, "answer": "A", "explanation": "The supply function given is Qs = 80 + 0.7P. If we substitute P = 40 into the equation, we get Qs = 80 + 0.7*40 = 108 tons. Therefore, when the price is ₦40, the quantity supplied is 108 tons.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2016>14", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "How does producers' expectation of a price fall affect the supply curve of a product? There will be", "images": [], "options": {"A": "a movement along the curve", "B": "a leftward shift", "C": "no shift of the supply curve", "D": "a shift to the right"}, "answer": "B", "explanation": "If producers expect the price of a product to fall in the future, they will be more inclined to sell their product now rather than later. This will increase the current supply of the product, causing a leftward shift in the supply curve. A leftward shift in the supply curve indicates an increase in supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>15", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND", "question": "One relationship between  marginal utility  and  total utility  is that when total utility is", "images": [], "options": {"A": "rising, marginal utility is rising", "B": "falling, marginal utility is negative", "C": "maximum, marginal utility is maximum", "D": "falling, marginal utility is rising"}, "answer": "B", "explanation": "Marginal utility refers to the additional satisfaction a consumer gets from consuming one more unit of a good or service. Total utility is the total satisfaction received from consuming a certain quantity of a good or service. When total utility is falling, it means the consumer is getting less satisfaction from consuming the goods or services, hence the marginal utility is negative because the additional satisfaction from consuming one more unit is decreasing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>16", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "A shift in the supply curve to the right while demand curve remains the same will cause equilibrium price", "images": [], "options": {"A": "and quantity to fall", "B": "and quantity to rise", "C": "to rise and quantity to fall", "D": "to fall and quantity to rise"}, "answer": "D", "explanation": "A shift in the supply curve to the right indicates an increase in supply while the demand curve remains the same. This increase in supply, with demand remaining constant, will cause the equilibrium price to fall due to the excess supply and the equilibrium quantity to rise as more quantity is available at lower prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>17", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION", "question": "A price floor results in", "images": [], "options": {"A": "excess demand", "B": "excess supply", "C": "parallel market", "D": "hoarding of goods"}, "answer": "B", "explanation": "A price floor is a minimum price buyers are required to pay for a good or service. When the price floor is above the equilibrium price, it results in excess supply because the price is above the market-clearing level, leading to suppliers being unable to sell all they want at the market price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>18", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "An entrepreneur is encouraged to adopt division of labour in production because it", "images": [], "options": {"A": "provides more employment opportunities", "B": "leads to increased output and lower cost of production", "C": "brings about equal cost and employment opportunities", "D": "leads to increased cost of production and lower output"}, "answer": "B", "explanation": "Division of labour refers to the breaking down of the production process into different stages enabling workers to focus on specific tasks. If workers specialize in certain aspects of production, output can increase and costs can decrease because workers do not lose time switching tasks. Therefore, it leads to increased output and lower cost of production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>19", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "The long run is a period when", "images": [], "options": {"A": "only he variable factors can be altered", "B": "all factors become variable", "C": "the firm will cease to exist", "D": "only the fixed factors can be altered"}, "answer": "B", "explanation": "In the long run, all factors of production become variable. This means that a firm can adjust all its inputs, such as labour and capital, in response to changes in market conditions. This is different from the short run, where at least one factor of production is fixed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2016>20", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION", "question": "The necessary condition for a firm to be in equilibrium is that marginal revenue is", "images": [], "options": {"A": "greater than marginal cost", "B": "equal to marginal cost", "C": "less than average revenue", "D": "equal to average cost"}, "answer": "B", "explanation": "For a firm to be in equilibrium, its marginal revenue (the additional income from selling one more unit of a good) must be equal to its marginal cost (the cost of producing one more unit of a good). This is because at this point, the firm maximizes its profit. If marginal revenue was greater than marginal cost, the firm could increase profit by producing more. If marginal cost was greater than marginal revenue, the firm could increase profit by producing less.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>21", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM", "question": "At which stage of production should a firm shut down? When", "images": [], "options": {"A": "AVC = ATC", "B": "AVC", "C": "AVC > Price", "D": "AVC = MC"}, "answer": "C", "explanation": "A firm should shut down when Average Variable Cost (AVC) is greater than the price. This is because, at this point, the firm is not able to cover its variable costs of production, which includes costs that vary with the level of output like raw materials, energy costs, and wages. If the price is less than AVC, it means the firm is making a loss on each unit of output produced and it would be better off shutting down.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2016>22", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "Charging different prices for the same commodity is a feature of a", "images": [], "options": {"A": "perfect competition", "B": "commodity market", "C": "monopolistic competition", "D": "monopoly market"}, "answer": "D", "explanation": "Charging different prices for the same commodity is a feature of a monopoly market. This is known as price discrimination. In a monopoly market, the seller has the power to control the price of the product because there are no close substitutes available in the market. Therefore, the seller can charge different prices to different consumers based on their willingness to pay.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>23", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "BUSINESS ORGANISATION : PARTNERSHIP", "question": "In a partnership, the conduct of members is guided by", "images": [], "options": {"A": "a memorandum of understanding", "B": "the article of partnership", "C": "an article of association", "D": "a partnership constitution"}, "answer": "B", "explanation": "In a partnership, the conduct of members is guided by the article of partnership. The article of partnership is a voluntary contract between two or among more than two persons to place their capital, labor, and skills, and corporation in business, with the understanding that there will be a sharing of the profits and losses between/among partners. It outlines the rights, responsibilities, and obligations of the partners.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2016>24", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION", "question": "Indigenization policy is a measure aimed at", "images": [], "options": {"A": "privatizing the existing business owned by the state", "B": "commercializing state-owned businesses", "C": "reducing foreign economic domination", "D": "making the indigenes managing directors of businesses"}, "answer": "C", "explanation": "Indigenization policy is a measure aimed at reducing foreign economic domination. This policy is often implemented by governments to ensure that the control of the economy is in the hands of the indigenous people. It is a way of promoting local entrepreneurship and reducing reliance on foreign investment and businesses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>25", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS", "question": "Which of the following measures will hinder efficient distribution of goods in West Africa?", "images": [], "options": {"A": "Improving road networks", "B": "Provision of adequate storage facilities", "C": "Instituting price control", "D": "Formation of producer's co-operative societies"}, "answer": "C", "explanation": "Instituting price control will hinder efficient distribution of goods in West Africa. Price control is a measure where the government sets the maximum or minimum prices for certain goods or services. While it may be intended to protect consumers, it can lead to shortages or surpluses, and disrupt the balance between supply and demand. This can hinder the efficient distribution of goods as producers may be discouraged from producing or distributing goods if they cannot set prices that would cover their costs and allow them to make a profit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2016>26", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "The type of unemployment that occurs as a result of physical or mental disability of labour is known as", "images": [], "options": {"A": "frictional unemployment", "B": "structural unemployment", "C": "cyclical unemployment", "D": "residual unemployment"}, "answer": "D", "explanation": "The type of unemployment that occurs as a result of physical or mental disability of labour is known as residual unemployment. This type of unemployment occurs when workers are left unemployed due to personal characteristics that prevent them from obtaining employment. These characteristics can include physical or mental disabilities that limit their ability to perform certain jobs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>27", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "One feature of a growing population is", "images": [], "options": {"A": "increase in the number of young people", "B": "increase in the number of old people", "C": "decrease in the dependent population", "D": "decrease in the life expectancy"}, "answer": "A", "explanation": "A growing population is characterized by an increase in the number of young people. This is because a growing population implies a high birth rate, which results in a larger number of young people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>28", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "Efficiency of labour in a country is determined by the following factors except the", "images": [], "options": {"A": "social attitude to work", "B": "education and training", "C": "working conditions of workers", "D": "total population"}, "answer": "D", "explanation": "The efficiency of labour in a country is determined by factors such as the social attitude to work, education and training, and working conditions of workers. However, the total population of a country does not directly determine the efficiency of its labour. While a larger population can mean a larger workforce, it does not necessarily mean a more efficient workforce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>29", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "Which of the following will encourage capital intensive farming?", "images": [], "options": {"A": "Encouraging communal system of land ownership", "B": "Adopting policies that will encourage rural-urban migration", "C": "Provision of subsidies on equipment", "D": "Restrictive lending policies by banks"}, "answer": "C", "explanation": "Capital intensive farming is a type of farming that uses a large amount of capital (money, machinery, etc.) in relation to labour. Provision of subsidies on equipment would encourage capital intensive farming because it would make it cheaper for farmers to purchase and use machinery and other equipment, thereby reducing their reliance on labour.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2016>30", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Which of the following best explains why more foreign investments are not attracted to West Africa?", "images": [], "options": {"A": "Small population size", "B": "Small sizes of market places", "C": "Instability in political and industrial policies", "D": "Lack of manpower needed to work in industries"}, "answer": "C", "explanation": "Foreign investments are often attracted to regions with stable political and industrial policies. This is because stability in these areas provides a predictable environment for business operations and growth. Instability in political and industrial policies can lead to unpredictable changes in business regulations, tax laws, and other factors that can affect the profitability and feasibility of business operations. Therefore, instability in political and industrial policies can deter foreign investments.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2016>31", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "Location of firms in rural areas may", "images": [], "options": {"A": "enable the firms to enjoy existing infrastructural facilities", "B": "make finance readily available", "C": "enhance even or balanced development", "D": "make such firms enjoy external economics of scale"}, "answer": "C", "explanation": "The location of firms in rural areas can contribute to balanced or even development. This is because the establishment of firms in these areas can lead to the creation of jobs and the stimulation of economic activity, which can help to reduce regional disparities in economic development. This can lead to a more balanced distribution of economic activity and wealth across a country or region.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>32", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "In national income accounting, double counting occurs when", "images": [], "options": {"A": "Intermediate goods are counted twice", "B": "Intermediate goods are counted with the final goods", "C": "Final goods are counted more than once", "D": "DIfferent people count the products"}, "answer": "B", "explanation": "In international income accounting, double counting occurs when the value of intermediate goods - goods used in the production of other goods - is counted along with the value of the final goods. This results in an overestimation of the total value of goods produced. Therefore, to avoid double counting, only the value of final goods - goods that are ready for use by the end consumer - should be counted.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2016>33", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The difference between GDP and GNP is", "images": [], "options": {"A": "consumption of fixed capital", "B": "indirect business tax", "C": "net factor income from abroad", "D": "public transfer payments"}, "answer": "C", "explanation": "The difference between GDP (Gross Domestic Product) and GNP (Gross National Product) is the net factor income from abroad. GDP measures the value of goods and services produced within a country's borders, while GNP measures the value of goods and services produced by a country's residents, no matter where they live. The net factor income from abroad includes income from foreign investments by residents minus income earned within the domestic economy by overseas residents.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2016>34", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "Which of the following items is not included in the measurement of the national income using the income approach?", "images": [], "options": {"A": "Wages and salaries", "B": "Government purchases", "C": "Interest", "D": "Dividend"}, "answer": "B", "explanation": "The income approach to measuring national income includes wages and salaries, interest, and dividends. It does not include government purchases. The income approach calculates national income by adding up all incomes received by producers of goods and services, including wages, interest, and dividends.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>35", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "MONEY : INTRODUCTION", "question": "A bank note is said to be a legal tender because it is", "images": [], "options": {"A": "printed by government", "B": "a store of value", "C": "signed by the head of state", "D": "backed by law"}, "answer": "D", "explanation": "A bank note is said to be a legal tender because it is backed by law. This means that it is recognized by the law as a medium of exchange for goods and services and must be accepted if offered in payment of a debt. The fact that it is printed by the government or signed by the head of state does not make it a legal tender. Its status as a legal tender comes from the law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2016>36", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "During inflation, interest rate will", "images": [], "options": {"A": "rise", "B": "fluctuate", "C": "remain constant", "D": "fall"}, "answer": "A", "explanation": "During inflation, the general price level in an economy increases. To control this, central banks often increase the interest rate. This is because higher interest rates mean higher borrowing costs, which reduces the amount of money in circulation, thereby controlling inflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>37", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Cost push inflation is likely to arise when", "images": [], "options": {"A": "there is an increase in bank lending", "B": "there is an increase in subsidies", "C": "there is an increase in the cost of production or input.", "D": "there is an increase in the cost of living"}, "answer": "C", "explanation": "Cost push inflation occurs when the cost of production or inputs increases. This could be due to an increase in the cost of raw materials, wages, etc. When the cost of production increases, producers pass on this cost to consumers in the form of higher prices, leading to inflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>38", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Which of the following financial institutions cannot be found on the capital market of a country?", "images": [], "options": {"A": "Commercial Bank", "B": "Mortgage Bank", "C": "Stock Exchange", "D": "Agricultural Bank"}, "answer": "A", "explanation": "Commercial banks are part of the money market, not the capital market. The capital market is where long-term securities such as stocks and bonds are traded, while the money market is where short-term securities are traded. Commercial banks provide short-term loans and accept deposits, which are activities associated with the money market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>39", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "The stock market is a market for", "images": [], "options": {"A": "new and second hand shares", "B": "debentures", "C": "goods and services", "D": "short-term securities"}, "answer": "A", "explanation": "The stock market is a market where securities, bonds, and other financial instruments are bought and sold. It includes both new and second-hand shares. Therefore, the correct answer is 'new and second hand shares'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>40", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Indirect taxes are generally", "images": [], "options": {"A": "progressive", "B": "regressive", "C": "equitable", "D": "proportionate"}, "answer": "B", "explanation": "Indirect taxes are generally regressive. This means that they take a larger percentage of income from low-income earners than from high-income earners. This is because the tax is applied uniformly to all consumers regardless of their income level.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>41", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "PUBLIC FINANCE : FISCAL POLICY", "question": "Fiscal policy that can control inflation will include the use of", "images": [], "options": {"A": "balanced budgeting", "B": "tax holidays", "C": "budget deficit", "D": "budget surplus"}, "answer": "D", "explanation": "Fiscal policy that can control inflation will include the use of a budget surplus. A budget surplus occurs when income exceeds expenditure. This can help control inflation by reducing the amount of money in circulation. When the government runs a surplus, it can use the extra money to pay off public debt, which reduces the amount of money in the economy and helps control inflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>42", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Which of the following is a cause of under-development in West Africa?", "images": [], "options": {"A": "Availability of manpower", "B": "Increasing population", "C": "High rate of capital formation", "D": "Large size of market places"}, "answer": "B", "explanation": "Under-development in West Africa is largely due to the increasing population. This is because the resources available are not sufficient to cater for the growing population, leading to a strain on the resources and hence under-development. The other options such as availability of manpower, high rate of capital formation, and large size of market places are generally considered as factors that can contribute to development rather than under-development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>43", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Which of the following is not a major problem of development planning?", "images": [], "options": {"A": "Shortage of skilled manpower", "B": "Inadequate data for planning", "C": "Political Instability", "D": "Poor identification of projects"}, "answer": "D", "explanation": "Poor identification of projects is not a major problem of development planning. The major problems of development planning are usually related to the shortage of skilled manpower, inadequate data for planning, and political instability. These factors can hinder the effective implementation of development plans. Poor identification of projects can be a result of these problems but is not a major problem in itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>44", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "The principle of comparative cost advantage was propounded by", "images": [], "options": {"A": "David Ricardo", "B": "Alfred Marshal", "C": "J. S. Mill", "D": "Adam Smith"}, "answer": "A", "explanation": "The principle of comparative cost advantage was propounded by David Ricardo. This principle states that a country should specialize in the production of goods and services that it can produce at a lower opportunity cost compared to other countries. This allows for efficient use of resources and promotes trade between countries. The other economists listed, Alfred Marshal, J. S. Mill, and Adam Smith, have made significant contributions to economics but they did not propound the principle of comparative cost advantage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>45", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "The rate at which a country's exports is exchanged for her imports is", "images": [], "options": {"A": "trade balance", "B": "balance of payments", "C": "terms of trade", "D": "balance on current account"}, "answer": "C", "explanation": "The rate at which a country's exports is exchanged for her imports is known as the 'terms of trade'. The terms of trade are defined as the ratio of an index of a country's export prices to an index of its import prices. If the terms of trade increase, this means that for each unit of exports sold, a country can buy more units of imported goods. So, it is beneficial for a country if its terms of trade increase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>46", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Balance of payments surplus implies that receipts for exports are", "images": [], "options": {"A": "at par with payments for imports", "B": "greater than payments for imports", "C": "less than payments for imports", "D": "proportional to payments for imports"}, "answer": "B", "explanation": "A balance of payments surplus implies that the receipts for exports are greater than payments for imports. The balance of payments is a record of all economic transactions between the residents of a country and the rest of the world in a particular period. It represents a summation of country's current demand and supply of the claims on foreign currencies and of foreign claims on its currency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>47", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "When the international value of a country's currency rises, other things being equal, the country's", "images": [], "options": {"A": "net exports tend to increase", "B": "imports tend to decrease", "C": "net exports tend to decrease", "D": "export tend to be stable"}, "answer": "C", "explanation": "When the international value of a country's currency rises, other things being equal, the country's net exports tend to decrease. This is because a rise in the value of a country's currency makes its goods more expensive for foreign buyers, which can lead to a decrease in exports. At the same time, it makes foreign goods cheaper for domestic consumers, which can lead to an increase in imports. The net effect is a decrease in net exports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>48", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "One of the physical measures that can be used to reduce the volume of imports is the", "images": [], "options": {"A": "reduction of personal income tax", "B": "removal of import duties", "C": "use of foreign exchange control", "D": "liberalization of credit for importers"}, "answer": "C", "explanation": "Foreign exchange control is a measure that can be used to reduce the volume of imports. This is because it involves the regulation of the purchase and sale of foreign currencies by the government. By controlling the availability of foreign currency, a government can limit the ability of individuals and companies to purchase foreign goods, thereby reducing imports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>49", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "When a number of countries agree to remove all trade barriers among themselves and at the same time charge a common tariff against non-member countries, it is known as", "images": [], "options": {"A": "free trade area", "B": "common market", "C": "custom union", "D": "economic community"}, "answer": "C", "explanation": "A customs union is a type of trade bloc which is composed of a free trade area with a common external tariff. The participant countries set up common external trade policy, but in some cases they use different import quotas. Common competition policy is also helpful to avoid competition deficiency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2016>50", "subject": "Economics", "year": "2016", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "Which of the following international organizations is concerned with the stabilization of the balance of payments?  The", "images": [], "options": {"A": "International Monetary Fund (IMF)", "B": "World Bank (IBRD)", "C": "United Nations Organization (UNO)", "D": "Economic Commission for Africa (ECA)"}, "answer": "A", "explanation": "The International Monetary Fund (IMF) is an international organization that aims to promote global economic growth and financial stability, to encourage international trade, and to reduce poverty around the world. One of its core functions is to provide loans to member countries experiencing balance of payments problems, which helps to stabilize the global economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>1", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Economics is regarded as a science because", "images": [], "options": {"A": "its issues can be easily verified by reference to facts", "B": "it adopts scientific method in making its analysis", "C": "its issues are relevant for national development", "D": "its subject matter studies human behaviour"}, "answer": "B", "explanation": "Economics is considered a science because it uses scientific methods to analyze its issues. This involves formulating hypotheses, testing them empirically, and refining theories based on the results. The scientific method is a systematic and logical approach to discovering how things in the universe work.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2017>2", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT", "question": "The opportunity cost of a worker going to the university is", "images": [], "options": {"A": "tuition, fees and books", "B": "boarding and lodging", "C": "the wages given up to attend university", "D": "transportation and entertainment"}, "answer": "C", "explanation": "The opportunity cost of a worker going to the university is the wages given up to attend university. Opportunity cost is an economic concept that refers to the loss of potential gain from other alternatives when one alternative is chosen. In this case, if a worker decides to go to university, they give up the wages they could have earned during that time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>3", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Which of the following items is not an example of circulating capital?", "images": [], "options": {"A": "Raw material", "B": "Money", "C": "Fuel", "D": "Machinery"}, "answer": "D", "explanation": "Circulating capital refers to the portion of capital which is used in the production process and gets transformed into goods. It includes raw materials, fuel, and money used in the production process. Machinery, on the other hand, is a part of fixed capital as it is not transformed into goods but helps in the production process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>4", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "In a market economy, the problem of what goods to produce is solved primarily by", "images": [], "options": {"A": "directives of the government", "B": "the pattern of consumer's spending", "C": "producers of consumer goods", "D": "people producing what they want"}, "answer": "B", "explanation": "In a market economy, the problem of what goods to produce is primarily solved by the pattern of consumer's spending. This is because a market economy is driven by supply and demand. Producers will produce goods that consumers want and are willing to buy. Therefore, the spending patterns of consumers will dictate what goods are produced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>5", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "If the weights of five puppies in kilograms are 3.5, 3.0, 4.2, 5.0 and 4.3, then the mean weight of the puppies is", "images": [], "options": {"A": "3.5 kg", "B": "4.0 kg", "C": "4.2 kg", "D": "5.0 kg"}, "answer": "B", "explanation": "The mean weight of the puppies can be calculated by adding up all the weights and dividing by the number of puppies. So, (3.5 + 3.0 + 4.2 + 5.0 + 4.3) / 5 = 20 / 5 = 4.0 kg. Therefore, the mean weight of the puppies is 4.0 kg.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2017>6", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If the coefficient of cross elasticity of demand for goods and Y and Z is positive, the two goods are", "images": [], "options": {"A": "complements", "B": "substitutes", "C": "luxuries", "D": "inferior"}, "answer": "B", "explanation": "The coefficient of cross elasticity of demand measures the responsiveness of the quantity demanded of one good to a change in the price of another good. If the coefficient is positive, it means that as the price of one good increases, the demand for the other good also increases. This is characteristic of substitute goods. Therefore, if the coefficient of cross elasticity of demand for goods Y and Z is positive, the two goods are substitutes.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2017>7", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "The difference between demand and wants is in", "images": [], "options": {"A": "desire for commodity", "B": "significance of the commodity", "C": "ability to pay the commodity", "D": "economic value of the commodity"}, "answer": "C", "explanation": "The difference between demand and wants lies in the ability to pay for the commodity. Demand refers to the desire for a product or service that is backed by the ability and willingness to pay for it. On the other hand, wants refer to the desire for a product or service, regardless of the ability to pay.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>8", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "A demand curve parallel  to the Y-axis indicates", "images": [], "options": {"A": "fairly elastic demand", "B": "perfectly elastic demand", "C": "perfectly inelastic demand", "D": "fairly inelastic demand"}, "answer": "C", "explanation": "A demand curve parallel to the Y-axis indicates perfectly inelastic demand. Perfectly inelastic demand refers to a situation where the quantity demanded does not change regardless of changes in price. This means that the demand is completely unresponsive to price changes, hence the vertical (parallel to Y-axis) demand curve.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2017>9", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "Which of the following is an example of derived demand?", "images": [], "options": {"A": "Textbook", "B": "Labour", "C": "Staple food", "D": "Mobile phone"}, "answer": "B", "explanation": "Derived demand refers to the demand for a good or service that results from the demand for a different, or related, good or service. In this case, labour is an example of derived demand because the demand for labour comes from the demand for goods and services that labour is used to produce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>10", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "A rightward shift in the supply curve of a commodity is brought about by an increase in", "images": [], "options": {"A": "the level of technology", "B": "the price of the commodity", "C": "the cost of production", "D": "taxation"}, "answer": "A", "explanation": "A rightward shift in the supply curve of a commodity is brought about by an increase in the level of technology. This is because an improvement in technology can lead to more efficient production processes, which can increase the quantity of the commodity that suppliers are able to produce at each price level. This increase in supply is represented by a rightward shift in the supply curve.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2017>11", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Effective supply is the total amount of a commodity", "images": [], "options": {"A": "from a single producer", "B": "in the warehouses of producers", "C": "offered for sale at a market price", "D": "produce for the market"}, "answer": "C", "explanation": "Effective supply is the total amount of a commodity offered for sale at a market price. It is the quantity of a good or service that producers are willing and able to sell at the current market price. It does not refer to the total amount from a single producer, in the warehouses of producers, or produced for the market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>12", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "Price elasticity of supply can be influenced by the following factors except", "images": [], "options": {"A": "time period", "B": "cost of production", "C": "size of consumer's income", "D": "nature of the product"}, "answer": "C", "explanation": "Price elasticity of supply can be influenced by factors such as the time period, cost of production, and nature of the product. However, the size of consumer's income does not directly influence the price elasticity of supply. The size of consumer's income is more likely to affect the demand for a product rather than the supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>13", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Increase in the supply of a product can be caused by", "images": [], "options": {"A": "change in taste and fashion of consumers", "B": "increase in the incomes of consumers", "C": "a fall in the cost of production", "D": "increase in the price of a product"}, "answer": "C", "explanation": "An increase in the supply of a product can be caused by a fall in the cost of production. When the cost of producing a good or service decreases, producers are able to produce more of it. This is because the lower cost increases the profitability of each unit produced, incentivizing producers to increase their output.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>14", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "A rational consumer will purchase a commodity whose price is", "images": [], "options": {"A": "greater than his marginal utility", "B": "less than his marginal utility", "C": "equal to his marginal utility", "D": "equal to his total utility"}, "answer": "C", "explanation": "A rational consumer will purchase a commodity whose price is equal to his marginal utility. This is based on the principle of marginal utility, which states that consumers will continue to consume a good or service until the marginal utility (the satisfaction gained from consuming an additional unit) equals the price. If the price is higher than the marginal utility, the consumer will not buy the product because the cost outweighs the benefit. If the price is lower than the marginal utility, the consumer will buy more of the product because the benefit outweighs the cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>15", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION", "question": "Parallel markets are usually the result of", "images": [], "options": {"A": "excess supply", "B": "the activities of rich individuals", "C": "price legislation", "D": "inadequate information"}, "answer": "C", "explanation": "Parallel markets are usually the result of price legislation. A parallel market, also known as a black market, often arises when government-imposed price controls create a discrepancy between the official price of a good or service and its market value. When the official price is set below the market value, it can lead to a shortage, prompting sellers to offer the good or service at a higher price in the parallel market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>16", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "Another term for equilibrium price is", "images": [], "options": {"A": "price floor", "B": "demand price", "C": "market clearing price", "D": "satisfactory price"}, "answer": "C", "explanation": "The equilibrium price is also known as the 'market clearing price'. This is the price at which the quantity of goods producers wish to supply equals the quantity consumers wish to purchase. It is the price at which the supply and demand curves intersect. The other options do not accurately describe the equilibrium price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>17", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "When a firm is enjoying internal economies of scale, its", "images": [], "options": {"A": "total cost of production is increasing as output increases", "B": "average fixed cost is rising continuously", "C": "average cost of production decreases as output increases", "D": "average revenue and marginal revenue are decreasing"}, "answer": "C", "explanation": "A firm enjoys internal economics of scale when the  average cost of production decreases as output increases. This means that the overall production cost decreases as output increases.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2017>18", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "The specialisation of labour enhances production because people", "images": [], "options": {"A": "can concentrate on all goods they can produce better", "B": "can efficiently produce their own needs", "C": "can save time and produce more", "D": "become experts in all areas of production"}, "answer": "C", "explanation": "The specialisation of labour enhances production because people can save time and produce more. This is because when workers specialise in a particular task or job, they become more efficient and productive at it, leading to increased output. The other options do not accurately describe the benefits of labour specialisation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>19", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "Which of the following can be added to a firm's profit to obtain total revenue?", "images": [], "options": {"A": "Total variable cost", "B": "Total fixed cost", "C": "Marginal cost", "D": "Total cost"}, "answer": "D", "explanation": "Total revenue obtained by a firm can be calculated by adding total cost to the profits because profit represents the difference between total revenue and total cost i.e. profit = TR - TC", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>20", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "The amount of money that a firm receives from the sale of its output is called", "images": [], "options": {"A": "Total variable cost", "B": "Total revenue", "C": "Marginal cost", "D": "Total cost"}, "answer": "B", "explanation": "Total revenue is the amount of money a firm receives from the sale of outputs and it is calculated as TR = Price  x Quantity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>21", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "Which of the following is true of the monopolist?", "images": [], "options": {"A": "His average revenue curve is horizontal", "B": "He determines both price and output", "C": "He demand and marginal revenue curves are the same", "D": "He determines either price or output"}, "answer": "D", "explanation": "A monopolist has the power to influence the market, but it cannot simultaneously control both the price and the quantity it produces. It can choose either to set the price and let the market demand determine the quantity sold, or it can choose the quantity to produce and let the market demand determine the price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>22", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Equity shares form the bulk of the capital of a", "images": [], "options": {"A": "private company", "B": "public company", "C": "statutory company", "D": "limited partnership"}, "answer": "B", "explanation": "Equity shares form the bulk of the capital of a public company. Equity shares represent the ownership of a company and constitute the right to claim a part of the company's profits or residual value. Public companies raise capital primarily through the issuance of equity shares to the general public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>23", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "If a state-owned firm is sold through the stock market, the organisation becomes a", "images": [], "options": {"A": "partnership", "B": "private company", "C": "public limited company", "D": "public corporation"}, "answer": "C", "explanation": "When a state-owned firm is sold through the stock market, it becomes a public limited company. This process is known as privatization. A public limited company is a company that has offered shares to the general public and has limited liability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>24", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "The total number of people of working age who are willing and prepared to work at a given wage rate is the", "images": [], "options": {"A": "labour force", "B": "supply of labour", "C": "demand for labour", "D": "occupational demand for labour"}, "answer": "B", "explanation": "The total number of people of working age who are willing and prepared to work at a given wage rate is the supply of labour. The supply of labour is determined by those who are employed, as well as those who are currently unemployed but are willing and able to work.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>25", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "A civil engineer who accepts to teach elementary science in a primary school because he cannot get a paid engineering job is an example of", "images": [], "options": {"A": "structural unemployment", "B": "disguised unemployment", "C": "residual unemployment", "D": "frictional unemployment"}, "answer": "B", "explanation": "The scenario described in the question is an example of disguised unemployment. Disguised unemployment occurs when more people are doing work than actually required. In this case, the civil engineer is overqualified for the job he is doing, hence his skills are not being fully utilized. This is different from structural unemployment (which occurs due to a mismatch between the skills of the unemployed and the skills required for the job), residual unemployment (which is the unemployment that always exists in an economy), and frictional unemployment (which is temporary unemployment as workers move between jobs).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>26", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "Which of the following is an implication of a large population?", "images": [], "options": {"A": "Decrease in crime rate", "B": "Increase in food supply", "C": "Decrease in standard of living", "D": "Decrease in cost of living"}, "answer": "C", "explanation": "A large population often leads to a decrease in the standard of living. This is because resources are finite, and when they are divided among a larger number of people, each person's share is smaller. This can lead to lower levels of access to food, clean water, healthcare, education, and other necessities, thereby reducing the standard of living. The other options are incorrect as a large population does not necessarily lead to a decrease in crime rate, an increase in food supply, or a decrease in cost of living.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>27", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "The system of agriculture which involves the cultivation of crops and rearing of animals for family consumption only is termed", "images": [], "options": {"A": "peasant farming", "B": "plantation agriculture", "C": "commercial farming", "D": "subsistence farming"}, "answer": "D", "explanation": "The system of agriculture which involves the cultivation of crops and rearing of animals for family consumption only is termed subsistence farming. In subsistence farming, farmers focus on growing enough food to feed themselves and their families. The output is mostly for local requirements with little or no surplus trade. The other options, peasant farming, plantation agriculture, and commercial farming, involve selling the produce or products to others.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2017>28", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "An industry whose product loses considerable weight after processing must be sited close to", "images": [], "options": {"A": "the source of finance", "B": "a ready market", "C": "a power station", "D": "the source of raw material"}, "answer": "D", "explanation": "An industry whose product loses considerable weight after processing must be sited close to the source of raw material. This is because the cost of transporting the raw materials to the processing site would be less than the cost of transporting the processed goods to the market. This is a concept in industrial location theory.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>29", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "Which of the following is a threat to the existence of middlemen?", "images": [], "options": {"A": "Consumer's cooperative societies", "B": "Producers' cooperative societies", "C": "Sale agents", "D": "Large scale producers"}, "answer": "A", "explanation": "Consumer's cooperative societies are a threat to the existence of middlemen. This is because these societies are formed by consumers who come together to buy goods directly from the producers, thereby eliminating the need for middlemen. Middlemen are individuals or businesses that act as intermediaries between producers and consumers in a supply chain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>30", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "In an industrial area, the location of industries is particularly influenced by", "images": [], "options": {"A": "extent of the division of labour", "B": "external economies", "C": "internal economies", "D": "nearness to financial institution"}, "answer": "B", "explanation": "In an industrial area, the location of industries is particularly influenced by external economies. External economies refer to the benefits that a firm or an industry gains due to its location near other firms or industries. These benefits could be in the form of shared infrastructure, access to a large pool of skilled labor, or the ability to share knowledge and innovation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>31", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Which of the following is a transfer income?", "images": [], "options": {"A": "Dividends", "B": "Rent", "C": "Pensions", "D": "Interest"}, "answer": "C", "explanation": "Transfer income refers to the income that is not earned from any productive activity but is received by virtue of personal claims. Pensions are a type of transfer income because they are received by individuals after retirement, not as a result of any current productive activity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>32", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "The value-added method used in measuring national income is to", "images": [], "options": {"A": "measure output at factor cost", "B": "avoid multiple counting of output", "C": "deduct depreciation of capital assets", "D": "add net factor income from abroad"}, "answer": "B", "explanation": "The value-added method is used in measuring national income to avoid multiple counting of output. This method involves adding up the value added at each stage of production. Value added is the increase in value that a firm contributes to a product or service. It is calculated as the difference between the total sales of the firm and the total amount the firm paid for inputs.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2017>33", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "Which of the following is most likely to be of benefit to a debtor?", "images": [], "options": {"A": "Inflation", "B": "Deflation", "C": "Revaluation", "D": "Monetization"}, "answer": "A", "explanation": "Inflation is most likely to be of benefit to a debtor. This is because during inflation, the real value of money falls. Therefore, the real value of the amount to be repaid by the debtor decreases. In other words, the debtor repays less in terms of goods and services than was borrowed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>34", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The formula Y = C + I + G + (X - M) will be appreciated for measuring national income using the", "images": [], "options": {"A": "income approach", "B": "expenditure approach", "C": "output approach", "D": "factor approach"}, "answer": "B", "explanation": "The formula Y = C + I + G + (X - M) is used to calculate the Gross Domestic Product (GDP) of a country using the expenditure approach. In this formula, Y is the total output or GDP, C is consumption expenditure, I is investment expenditure, G is government expenditure, X is exports, and M is imports. The expenditure approach sums up all the money spent on final goods and services produced within a country in a specific period.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2017>35", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "A measure of the value of money in an economy is the", "images": [], "options": {"A": "size of workers' income", "B": "generate price level", "C": "total level of savings", "D": "total amount of loans granted by the banks"}, "answer": "B", "explanation": "The value of money in an economy is measured by the general price level. The general price level refers to the average of the prices for goods and services in the economy. It is a measure of inflation and deflation. When the general price level rises, each unit of currency buys fewer goods and services; this is inflation. When the general price level falls, each unit of currency buys more goods and services; this is deflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>36", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "MONEY : CHARACTERISTICS OF MONEY", "question": "One characteristic of money is that it should be", "images": [], "options": {"A": "a standard for deferred payment", "B": "stable in value", "C": "a store of value", "D": "acceptable by the central bank"}, "answer": "B", "explanation": "For money to effectively serve its functions, it needs to have a relatively stable value to facilitate consistent pricing, savings, and transactions. Stability in value ensures that money retains its purchasing power over time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2017>37", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC", "question": "A financial institution that specializes in giving loans using real assets as collateral security is a", "images": [], "options": {"A": "development bank", "B": "insurance company", "C": "central bank", "D": "mortgage bank"}, "answer": "D", "explanation": "A mortgage bank is a financial institution that specializes in originating and/or servicing mortgage loans. In the US, it is a licensed banking entity that makes mortgage loans directly to consumers. The difference between a mortgage banker and a mortgage broker is that the mortgage banker funds loans with its own capital. Generally, a mortgage bank originates a loan and places it on a pre-established warehouse line of credit until the loan can be sold to an investor, which are typically large institutions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>38", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "The function that distinguishes commercial banks from the central bank is that the former", "images": [], "options": {"A": "is a leader of last resort", "B": "accepts deposits from the public", "C": "services the public debt", "D": "regulates foreign exchange"}, "answer": "B", "explanation": "Commercial banks are distinguished from central banks in many ways, one of which is that they accept deposits from the public. Central banks are primarily responsible for currency stability, controlling inflation, and economic policy. Commercial banks, on the other hand, are profit-based institutions that accept deposits from the public and use those funds to offer loans. They make money by charging interest on these loans, which are given to businesses, individuals, and other organizations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>39", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Direct taxes include", "images": [], "options": {"A": "excise duty", "B": "ad valorem tax", "C": "specific tax", "D": "capital gains tax"}, "answer": "D", "explanation": "Direct taxes are those taxes that are levied on the income or wealth of a person or organization. One example of a direct tax is the capital gains tax, which is a tax on the profit realized on the sale of a non-inventory asset. The most common capital gains are realized from the sale of stocks, bonds, precious metals, real estate, and property. Not all countries implement a capital gains tax and most have different rates of taxation for individuals and corporations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2017>40", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "PUBLIC FINANCE : FISCAL POLICY", "question": "The control of aggregate demand through changes in government spending and tax rates is referred to as", "images": [], "options": {"A": "monetary policy", "B": "government policy", "C": "income policy", "D": "fiscal policy"}, "answer": "D", "explanation": "Fiscal policy refers to the use of government spending and tax policies to influence macroeconomic conditions, including aggregate demand, employment, inflation and economic growth. It is different from monetary policy, which is conducted by central banks and is concerned with money supply and interest rates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>41", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "Which of the following is not a feature of economic under development?", "images": [], "options": {"A": "Monocultural economy", "B": "High productivity", "C": "Low life expectancy", "D": "Income inequality"}, "answer": "B", "explanation": "High productivity is not a feature of economic underdevelopment. In fact, it is the opposite. Economic underdevelopment is characterized by low productivity, among other things such as low life expectancy, income inequality, and monocultural economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>42", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "One way of speeding up the economic development of a country is by encouraging", "images": [], "options": {"A": "the consumption of consumer goods", "B": "early marriages", "C": "the importation of more consumer goods", "D": "savings and investment"}, "answer": "D", "explanation": "Encouraging savings and investment is one way of speeding up the economic development of a country. Savings provide the funds for investment, and investment in turn leads to economic growth and development. The other options do not directly contribute to economic development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>43", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Dumping in international trade occurs when a foreign firm sells", "images": [], "options": {"A": "above its cost of production at home and abroad", "B": "below is cost of production at home and abroad", "C": "more goods to a country than the country has need of", "D": "below is cost of production in a foreign market"}, "answer": "D", "explanation": "Dumping in international trade refers to a situation where a foreign firm sells its goods in a foreign market below its cost of production. This is usually done to gain a competitive advantage over domestic firms in the foreign market.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2017>44", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "Infant industries can be described as", "images": [], "options": {"A": "newly established industries", "B": "industries enjoying tax holidays", "C": "industries producing baby products", "D": "newly commercialised industries"}, "answer": "A", "explanation": "Infant industries refer to newly established industries that are in their early stages of development. These industries often require protection from competition to grow and develop.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>45", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Modern international trade is based on the principle of", "images": [], "options": {"A": "absolute cost advantage", "B": "comparative cost advantage", "C": "terms of trade", "D": "balance of trade"}, "answer": "B", "explanation": "Modern international trade is based on the principle of comparative cost advantage. This principle states that a country should specialize in the production of goods and services that it can produce at a lower opportunity cost compared to other countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2017>46", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Which of the following items is recorded in a country's current account section of the balance of payments?", "images": [], "options": {"A": "Investment income", "B": "Foreign direct investment", "C": "Long-term capital flows", "D": "Long-term loans"}, "answer": "A", "explanation": "The current account in a country's balance of payments records transactions related to import and export of goods, services, and investment incomes. Investment income is recorded in the current account because it is a return on investments like interest, dividends, and profits from foreign investments. It does not include foreign direct investment, long-term capital flows, or long-term loans, which are recorded in the financial account.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2017>47", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "ECONOMIC INTEGRATION : PROBLEMS OF ECONOMIC INTEGRATION IN WEST AFRICA- ECOWAS", "question": "One problem facing the economic integration of countries in West Africa is the", "images": [], "options": {"A": "presence of large and developed markets", "B": "uneven development among West African countries", "C": "existence of different central banks in the countries", "D": "failure of labour to move freely in the region"}, "answer": "B", "explanation": "The uneven development among West African countries is a significant problem facing the economic integration of these countries. This is because the disparities in economic development and industrialization can lead to imbalances in benefits from integration, with more developed countries potentially benefiting more than less developed ones. The other options do not accurately represent the problems facing economic integration in West Africa.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2017>48", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF", "question": "One objective of the organisation of Petroleum Exporting Countries (OPEC) is to", "images": [], "options": {"A": "harmonise and stabilize oil prices", "B": "ensure excess supply of oil to consuming countries", "C": "subsidise oil prices in member countries", "D": "assist member countries to exploit oil resources"}, "answer": "A", "explanation": "The Organisation of Petroleum Exporting Countries (OPEC) was established with the objective of coordinating and unifying petroleum policies among member countries to secure fair and stable prices for petroleum producers. This involves harmonizing and stabilizing oil prices, which is done by controlling oil production levels. The other options do not accurately represent the objectives of OPEC.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2017>49", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "Which of the following resources is renewable?", "images": [], "options": {"A": "Coal", "B": "Iron ore", "C": "Rice", "D": "Limestone"}, "answer": "C", "explanation": "Renewable resources are those that can be replenished naturally over time. Rice is a renewable resource because it can be grown again and again on the same piece of land. Coal, iron ore, and limestone are non-renewable resources because they take millions of years to form and once depleted, they cannot be replenished.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2017>50", "subject": "Economics", "year": "2017", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "The negative effects of mining in West Africa does not include", "images": [], "options": {"A": "reafforestation in rural communities", "B": "land degradation", "C": "destruction of farmlands", "D": "pollution of water bodies"}, "answer": "A", "explanation": "Reafforestation in rural communities is not a negative effect of mining. It is actually a positive effect as it involves the process of replanting an area with trees in an effort to reduce the environmental impact of deforestation. Land degradation, destruction of farmlands, and pollution of water bodies are all negative effects of mining.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>1", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Economics problems arise in all societies because", "images": [], "options": {"A": "resources are mismanaged by leaders", "B": "there is no proper planning", "C": "resource are not in adequate supply", "D": "the services of economists are not employed"}, "answer": "C", "explanation": "Economic problems arise in all societies because resources are not in adequate supply. This is the fundamental problem of economics, also known as the problem of scarcity. It means that the resources available to satisfy our needs and wants are limited, but our needs and wants are unlimited. This creates a situation where choices have to be made about how to use these limited resources. The other options are not the fundamental reasons for economic problems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>2", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE", "question": "Which of the following is not emphasized in a product possibility curve?", "images": [], "options": {"A": "Scarcity of resources", "B": "Economic development", "C": "Inefficiency in the use of resources", "D": "Unemployment of labour"}, "answer": "B", "explanation": "A production possibility curve (PPC) is a graphical representation of the alternative combinations of the amounts of two goods or services that an economy can produce by transferring resources from one good or service to the other. This curve helps to illustrate concepts such as scarcity of resources, opportunity cost, and trade-offs. However, it does not directly emphasize economic development. Economic development involves improvements in a variety of indicators such as literacy rates, life expectancy, and poverty rates. A PPC is more about production efficiency and trade-offs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>3", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "The organization of productive factors is the responsibility of the", "images": [], "options": {"A": "management", "B": "entrepreneur", "C": "production", "D": "labour union"}, "answer": "B", "explanation": "The organization of productive factors, also known as factors of production, is the responsibility of the entrepreneur. An entrepreneur is a person who combines the other factors of production - land, labor, and capital - in order to produce a good or service. They are the ones who take the initiative and risk to start a business with the hope of making a profit. The other options - management, production, and labor union - are part of the factors of production but they do not organize them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>4", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "Producers operating in a free market economy are more efficient as a result of", "images": [], "options": {"A": "the existence of competition", "B": "the very few number of participants", "C": "the commitment of the shareholders", "D": "government regulation of their activities"}, "answer": "A", "explanation": "In a free market economy, producers are more efficient as a result of the existence of competition. Competition forces producers to improve their products and processes to maintain or increase their market share. Producers who fail to do so may lose their market share to more efficient competitors. The other options - the very few number of participants, the commitment of the shareholders, and government regulation of their activities - do not necessarily lead to efficiency in a free market economy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>5", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "In a pie chart, the population of a city is represented  by 45. If the country has a population of 10 million people, then the city's population is?", "images": [], "options": {"A": "0.0045 million", "B": "4.5 million", "C": "1.25 million", "D": "16 million"}, "answer": "C", "explanation": "The city's population is calculated as:    45360×10,000,000=1.25million", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>6", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "A downward sloping demand curve means that", "images": [], "options": {"A": "total revenue declines as price is lowered", "B": "demand falls as output increases", "C": "demand falls as output falls", "D": "price must be lowered to sell more"}, "answer": "D", "explanation": "A downward sloping demand curve represents the law of demand, which states that as the price of a good or service increases, consumer demand for the good or service will decrease, and vice versa. Therefore, to sell more of a good or service, the price must be lowered. Hence, option 4 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>7", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "If the price of commodity X rises and consumers shift to commodity Y, then commodities X and Y are", "images": [], "options": {"A": "substitutes", "B": "complements", "C": "inferior goods", "D": "bought together"}, "answer": "A", "explanation": "If the price of commodity X rises and consumers shift to commodity Y, then commodities X and Y are substitutes. Substitutes are goods that can be used in place of each other. When the price of a good rises, consumers will shift to a substitute good. Hence, option 1 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>8", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Goods whose demand vary directly with money income are called", "images": [], "options": {"A": "inferior goods", "B": "complementary goods", "C": "substitute goods", "D": "normal goods"}, "answer": "D", "explanation": "Normal goods are goods whose demand increases when consumer income increases, hence, they vary directly with money income. This is in contrast to inferior goods, whose demand decreases as consumer income increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>9", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "An exceptional demand curve can result from", "images": [], "options": {"A": "increase in price of raw materials", "B": "increase in the size of the population", "C": "expectation of future price increase", "D": "change in taste of consumer"}, "answer": "C", "explanation": "An exceptional demand curve, which slopes upward instead of the typical downward slope, can result from the expectation of future price increases. This is because consumers may buy more of a good if they expect its price to increase in the future, leading to an increase in demand even as prices rise.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>10", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Palm oil and palm kernel are in", "images": [], "options": {"A": "joint supply", "B": "competitive demand", "C": "competitive supply", "D": "complementary demand"}, "answer": "A", "explanation": "Palm oil and palm kernel are in joint supply. This means that they are produced from the same process or resource. In this case, both are products of the oil palm tree.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>11", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Which of the following is true about the supply of land? It", "images": [], "options": {"A": "is higher in urban  than rural areas", "B": "varies with time", "C": "rises with demand", "D": "is fixed"}, "answer": "D", "explanation": "The supply of land is fixed. This is because land is a natural resource and its quantity cannot be increased or decreased by human activities. It is not affected by demand, time or location.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>12", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "The backward bending supply curve of labour indicates", "images": [], "options": {"A": "an abnormal supply situation", "B": "the law of supply", "C": "that labour supply and wage rate are directly related", "D": "that the elasticity of supply is uniform"}, "answer": "A", "explanation": "A backward bending supply curve of labour suggests that beyond a certain wage level, individuals may choose to work fewer hours as wage increases. Backward bending supply curve of labour indicate an abnormal supply curve situation because this goes against the typical supply curve behavior where higher prices lead to higher quantities supplied. Therefore, the backward bending supply curve represents a situation where the income effect outweighs the substitution effect.   It is indicate in the diagram below", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>13", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "A supply curve parallel to the X-axis indicates", "images": [], "options": {"A": "fairly elastic supply", "B": "infinitely elastic supply", "C": "fairly inelastic supply", "D": "perfectly inelastic supply"}, "answer": "B", "explanation": "Infinitely elastic supply curve is parallel to the x-axis i.e at a fixed price, there is change in quantity supplied. It is indicated in the diagram below.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>14", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "If the marginal utility of commodity is equal to its price, then", "images": [], "options": {"A": "the consumer is in equilibrium", "B": "more of the commodity can be consumed", "C": "total utility is also equal to its price", "D": "the market is not in equilibrium"}, "answer": "A", "explanation": "When the marginal utility of a commodity is equal to its price, the consumer is in equilibrium. This is based on the principle of equi-marginal utility which states that a consumer will distribute his income in such a way that the utility derived from the last unit of money spent on each commodity is the same. If the marginal utility of a commodity is equal to its price, it means the consumer is getting the maximum possible satisfaction from his expenditure on the commodity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>15", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET", "question": "A price floor is usually fixed", "images": [], "options": {"A": "at the equilibrium and causes no shortage", "B": "above the equilibrium and causes shortage", "C": "below the equilibrium and causes surpluses", "D": "above the equilibrium and causes surpluses"}, "answer": "D", "explanation": "Price floor or minimum price legislation is when the price is fixed above the equilibrium price by the government. When the price is fixed above the equilibrium price, there will be excess supply over demand which will lead to surplus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>16", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "A market is in equilibrium when", "images": [], "options": {"A": "there is no government intervention", "B": "the demand is the same as the supply", "C": "buyers and sellers are free to sell more goods", "D": "there is no free entry and exit"}, "answer": "B", "explanation": "A market is in equilibrium when the quantity demanded by consumers is equal to the quantity supplied by producers. This is the point where the supply and demand curves intersect. At this point, there is no tendency for the price to change, as everyone (buyers and sellers) is satisfied with the current market conditions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>17", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "A firm's average cost decreases in the long-run because of", "images": [], "options": {"A": "increasing returns to scale", "B": "diminishing average returns", "C": "decreasing marginal returns", "D": "decreasing average fixed cost"}, "answer": "A", "explanation": "In the long run, all factors of production are variable. Therefore, a firm can adjust all its inputs to achieve the most cost-effective way of producing goods. This leads to increasing returns to scale, which means that as the scale of production increases, the average cost of production decreases. This is because the firm can take advantage of economies of scale, such as bulk buying of inputs, spreading administrative costs over a larger output, and using more efficient capital machinery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>18", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "\"The larger a firm,the lower its cost of production\". This statement explains the", "images": [], "options": {"A": "law of diminishing returns", "B": "concept of economics of scale", "C": "law of comparative cost of advantage", "D": "theory of division of labour"}, "answer": "B", "explanation": "The statement 'The larger a firm, the lower its cost of production' explains the concept of economies of scale. Economies of scale refer to the cost advantage that a business obtains due to expansion. As the scale of output increases, factors such as production efficiencies, technological innovations, and managerial specialization lead to a decrease in the average cost of production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>19", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "Quantity Total cost0 201 252 283 304 385 556 927 135    The total fixed cost is", "images": [], "options": {"A": "$7.00", "B": "$30.00", "C": "$20.00", "D": "$135.00"}, "answer": "C", "explanation": "Total cost represents the complete expenses incurred by a business to produce goods or services. It is composed of total fixed cost and total variable cost. The TFC are expenses that remain constant regardless of the production level, while the TVC fluctuate with the amount of goods produced. Therefore, if the total cost at 0, the total cost is 20.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>20", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "Quantity Total cost0 201 252 283 304 385 556 927 135  At output level 5, the total variable cost is", "images": [], "options": {"A": "$5.00", "B": "$20.00", "C": "$55.00", "D": "$35.00"}, "answer": "D", "explanation": "TVC = TC - FC  Note that fixed cost is equal to $20 since total cost remain the same at all level of output.  TVC = 55 - 20   = $35", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>21", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION", "question": "In the long-run, a firm must shut down if its average revenue is", "images": [], "options": {"A": "greater than average cost", "B": "less than average variable cost", "C": "equal to the minimum average revenue is", "D": "equal to the average cost"}, "answer": "B", "explanation": "In the long run, a firm must shut down if its average revenue is less than average variable cost. This is because if the firm's revenue is not enough to cover its variable costs, it is operating at a loss. In the long run, it is not sustainable for a firm to continue operating if it cannot cover its variable costs. Average revenue is the total revenue divided by the quantity of the product sold, while average variable cost is the total variable cost divided by the quantity of the product produced.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>22", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Public limited liability companies are democratic in nature because", "images": [], "options": {"A": "government appointees are members of the board", "B": "they are run by elected public officers", "C": "electoral principles are adopted in the day-to-day management", "D": "shareholders elect the board of directors"}, "answer": "D", "explanation": "Public limited liability companies are democratic in nature because shareholders elect the board of directors. The board of directors is responsible for the overall management of the company, and they are elected by the shareholders, who are the owners of the company. This democratic process ensures that the interests of the shareholders are represented in the management of the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>23", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "In the event of bankruptcy, owners of joint-stock companies lose", "images": [], "options": {"A": "their private properties", "B": "both company and private assets", "C": "only the capital invested", "D": "only their dividends"}, "answer": "C", "explanation": "In the event of bankruptcy, owners of joint-stock companies lose only the capital invested. This is because a joint-stock company is a type of corporation or partnership involving individuals who own shares of stock in the company. These shareholders are only liable for the company's debts up to the amount of their investment, and their personal assets are protected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>24", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER", "question": "Wholesalers play an important role in the distribution of goods and services because they", "images": [], "options": {"A": "are located very close to consumers", "B": "finance both producers and retailers", "C": "pass information on from retailers to consumers", "D": "sell in small units to consumers"}, "answer": "B", "explanation": "Wholesalers play an important role in the distribution of goods and services because they finance both producers and retailers. Wholesalers buy large quantities of goods from producers and sell them to retailers. They provide credit facilities to both producers (by buying their products) and retailers (by selling goods to them on credit).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>25", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "If workers at the school canteen cannot sell during the holidays, this is example of", "images": [], "options": {"A": "structural unemployment", "B": "frictional unemployment", "C": "seasonal unemployment", "D": "residual unemployment"}, "answer": "C", "explanation": "If workers at the school canteen cannot sell during the holidays, this is an example of seasonal unemployment. Seasonal unemployment occurs when people are unemployed at certain times of the year, because they work in industries where they are not needed all year round.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>26", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "POPULATION : THEORIES OF POPULATION", "question": "Positive check as envisaged by Thomas Malthus can be prevented if", "images": [], "options": {"A": "death rate is reduced", "B": "marriage is abolished", "C": "more hospitals are built", "D": "moral restraint is adopted"}, "answer": "D", "explanation": "Thomas Malthus, an English economist, proposed that population growth would outpace the growth of food supply, leading to famine and death - a concept he referred to as 'positive checks'. However, he suggested that this could be prevented through 'moral restraint', which includes delayed marriage and abstinence. Therefore, the correct answer is 'moral restraint is adopted'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>27", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "Which of the following factors is not a reason for farmers' unstable incomes?", "images": [], "options": {"A": "dependence on too many crops", "B": "poor storage facilities", "C": "adverse weather conditions", "D": "recession in the world economy"}, "answer": "A", "explanation": "Farmers' unstable incomes are typically due to factors such as poor storage facilities, adverse weather conditions, and economic recessions, which can affect crop prices and yields. However, dependence on too many crops is not a reason for unstable incomes. In fact, diversifying crop production can help farmers manage risk and stabilize their incomes. Therefore, the correct answer is 'dependence on too many crops'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>28", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Local firms can help in reducing unemployment in a country when", "images": [], "options": {"A": "land acquisition becomes centralized", "B": "imports of substitutes are reduced", "C": "waste in the firm is eliminated", "D": "subsidies to firms are decreased"}, "answer": "B", "explanation": "Local firms can help reduce unemployment by creating jobs. One way to encourage this is by reducing imports of substitutes, which can increase demand for locally produced goods and services, leading to higher production and more employment opportunities. Therefore, the correct answer is 'imports of substitutes are reduced'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>29", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "An industry is described as a group of firms", "images": [], "options": {"A": "that provides jobs for many people", "B": "which uses advance technology in production", "C": "which produces similar products", "D": "that provides jobs for few people"}, "answer": "C", "explanation": "An industry is a group of firms that produce similar products or services. This is because they are in the same line of business and compete with each other for market share. The other options do not accurately define what an industry is.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2018>30", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The largest component of national income in developing countries consist of", "images": [], "options": {"A": "profit", "B": "profit and rent", "C": "rent", "D": "wages and salaries"}, "answer": "D", "explanation": "In developing countries, the largest component of national income usually consists of wages and salaries. This is because a large portion of the population in these countries is employed in wage-earning jobs. The other components like profit, rent, and a combination of profit and rent, while they contribute to the national income, they do not form the largest component.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>31", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "A baker bought flour and other ingredients for S250.00, spent S52.00 on distribution, sold the bread for S320.00. The value added by the baker", "images": [], "options": {"A": "S302.00", "B": "S52.00", "C": "S18.00", "D": "S622.00"}, "answer": "C", "explanation": "The value added by the baker is the difference between the cost of the raw materials and the price at which the final product is sold. In this case, the baker bought the ingredients for $250 and spent $52 on distribution, making the total cost $302. The bread was sold for $320. Therefore, the value added by the baker is $320 - $302 = $18.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>32", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "In a country with large population of full-time house wives, national income", "images": [], "options": {"A": "will be composed of goods produced by women", "B": "figures will be grossly over-stated", "C": "statistics will be difficult to calculate", "D": "figures will be grossly under-estimated"}, "answer": "D", "explanation": "National income is the total value of all goods and services produced in a country within a specific period. If a country has a large population of full-time housewives, their contribution to the economy in terms of unpaid work (like housekeeping, child-rearing, etc.) is not accounted for in the national income. Therefore, the national income figures will be grossly under-estimated.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>33", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Demand-pull inflation is likely to be caused by", "images": [], "options": {"A": "an increase in the cost of factor inputs", "B": "increase in the income tax rate", "C": "increase in bank lending rate", "D": "increasingly large budget deficit"}, "answer": "D", "explanation": "Demand-pull inflation occurs when demand for goods and services exceeds their supply. It can be caused by any factor that increases demand, including an increasingly large budget deficit. A budget deficit can lead to demand-pull inflation because the government might finance its deficit by creating new money, which increases the money supply and can lead to increased demand for goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>34", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "Holding money to take care of contingencies is", "images": [], "options": {"A": "a speculative motive", "B": "a transactions motive", "C": "a precautionary motive", "D": "an expansionary motive"}, "answer": "C", "explanation": "Holding money to take care of contingencies is a precautionary motive. The precautionary motive for holding money refers to holding money to meet unforeseen expenses and emergencies. This is one of the three motives for holding money according to Keynes, the other two being the transactions motive (holding money for everyday transactions) and the speculative motive (holding money to take advantage of future changes in interest rates or prices).", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2018>35", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT", "question": "If a housewife has meat and wants tomatoes, she must find someone who has tomatoes to give and wants meat. This concept is described as", "images": [], "options": {"A": "scale of preference", "B": "opportunity cost", "C": "complementary demand", "D": "double coincidence of wants"}, "answer": "D", "explanation": "The concept described in the question is known as 'double coincidence of wants'. This is a key element of a barter system where two parties each have something that the other wants. In this case, the housewife has meat and wants tomatoes, so she needs to find someone who has tomatoes and wants meat. This is a direct exchange of goods or services without the use of a medium of exchange, like money.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2018>36", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "FINANCIAL INSTITUTION : STOCK EXCHANGE", "question": "The stock exchange is an example of the", "images": [], "options": {"A": "labour market", "B": "money market", "C": "commodity market", "D": "capital market"}, "answer": "D", "explanation": "The stock exchange is an example of the 'capital market'. A capital market is a financial market in which long-term debt or equity-backed securities are bought and sold. The stock exchange is a key institution in this market, where shares of public companies are traded.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>37", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "What happens when the central bank increases the bank rate in an economy?", "images": [], "options": {"A": "borrowing is discouraged", "B": "customers increase their borrowing", "C": "banks can increase their lending", "D": "money supply increases"}, "answer": "A", "explanation": "When the central bank increases the bank rate, 'borrowing is discouraged'. The bank rate is the interest rate at which a nation's central bank lends money to domestic banks. When this rate increases, the cost of borrowing for banks also increases. This, in turn, leads to an increase in the interest rates for customers, making loans more expensive and thus discouraging borrowing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>38", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION", "question": "Income is re-distributed when the rich are progressively taxed and", "images": [], "options": {"A": "more private schools are established", "B": "subsidy is provided on petroleum products", "C": "more public goods are provided", "D": "farmers are given guaranteed prices"}, "answer": "C", "explanation": "Income is re-distributed when the rich are progressively taxed and more public goods are provided. This is because progressive taxation takes more from the rich than the poor, and public goods are available to all citizens regardless of their income level. This helps to reduce income inequality.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>39", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "In order to increase revenue, government should tax commodities for which demand is", "images": [], "options": {"A": "perfectly price inelastic", "B": "price inelastic", "C": "price elastic", "D": "unitary elastic"}, "answer": "B", "explanation": "In order to increase revenue, government should tax commodities for which demand is price inelastic. Price inelastic demand refers to a situation where the quantity demanded of a good does not change significantly with changes in price. Therefore, even if the government imposes a tax that increases the price, the quantity demanded will not decrease significantly, leading to increased revenue.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>40", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Which of the following activities will not lead to economic growth", "images": [], "options": {"A": "Massive importation of capital goods", "B": "Intensive capital formation", "C": "Use of modern technology", "D": "Massive importation of consumer goods"}, "answer": "D", "explanation": "Massive importation of consumer goods will not lead to economic growth. This is because it does not contribute to the production capacity of the economy. Instead, it can lead to a trade deficit and reduce domestic production as imported goods compete with locally produced goods. On the other hand, importation of capital goods, capital formation, and use of modern technology all contribute to increasing the production capacity of the economy, leading to economic growth.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>41", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "The poorer the country, the larger the percentage of labour force engaged in", "images": [], "options": {"A": "agriculture", "B": "mining", "C": "trading", "D": "manufacturing"}, "answer": "A", "explanation": "In poorer countries, a larger percentage of the labour force is typically engaged in agriculture. This is because agriculture is often the most accessible form of work, requiring little to no formal education or training. It is also often the case that poorer countries have less industrialization, meaning there are fewer opportunities for work in sectors like manufacturing or mining.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2018>42", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "Which of the following measures can be adopted to stabilize the external value of the local currency", "images": [], "options": {"A": "reduce the volume of exports", "B": "increase the demand for imports", "C": "increase domestic money supply", "D": "reduce the demand for imports"}, "answer": "D", "explanation": "To stabilize the external value of the local currency, one of the measures that can be adopted is to reduce the demand for imports. This is because when a country imports goods, it pays for those goods in the currency of the exporting country. This increases the demand for the foreign currency, which can lead to a depreciation of the local currency. By reducing the demand for imports, the demand for foreign currency is also reduced, which can help to stabilize the value of the local currency.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>43", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Which of the following is not a measure for reducing balance of payment deficits", "images": [], "options": {"A": "Export", "B": "Reducing tariffs", "C": "Adding value to export goods", "D": "Increasing local production"}, "answer": "B", "explanation": "Reducing tariffs is not a measure for reducing balance of payment deficits. Tariffs are taxes on imports. Reducing them would likely increase imports, which would worsen a balance of payments deficit. Measures to reduce a balance of payments deficit typically involve increasing exports or decreasing imports, such as by adding value to export goods or increasing local production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>44", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Nation engage in external trade because of difference in", "images": [], "options": {"A": "comparative cost", "B": "absolute cost", "C": "fixed cost", "D": "variable cost"}, "answer": "A", "explanation": "Nations engage in external trade because of differences in comparative cost. The concept of comparative cost, also known as comparative advantage, refers to a country's ability to produce a particular good or service at a lower opportunity cost than its trading partners. This is the fundamental reason for international trade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>45", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "One advantage of international trade is that", "images": [], "options": {"A": "prices of goods become stable", "B": "countries become self-sufficient", "C": "goods consumed are produced at a very high cost", "D": "it makes possible the consumption of a variety of goods"}, "answer": "D", "explanation": "One advantage of international trade is that it makes possible the consumption of a variety of goods. International trade allows countries to expand their markets for both goods and services that otherwise may not have been available domestically. As a result, consumers have access to a wider variety of goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2018>46", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "Which of the following forms of economic integration is a member nation free to impose duty against non-members", "images": [], "options": {"A": "Customs union", "B": "Free trade area", "C": "Common market", "D": "Economic community"}, "answer": "B", "explanation": "In a Free Trade Area, member nations are free to impose duty against non-members. A Free Trade Area is a region where a group of countries has signed a free trade agreement, and they abolish tariffs and import quotas between each other, but they do not have a common external tariff against non-members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>47", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "The International Bank for Reconstruction and Development(IBRD) performs the following Except", "images": [], "options": {"A": "granting long-term loans", "B": "assisting with technical expertise", "C": "reducing tariff among members", "D": "developing human resource"}, "answer": "A", "explanation": "The International Bank for Reconstruction and Development (IBRD) is part of the World Bank Group. Its primary function is to provide loans to middle-income and creditworthy low-income countries for sustainable development projects that can reduce poverty and create shared prosperity. Therefore, the correct answer is 'granting long-term loans'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2018>48", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "An electrical engineer who is teaching physics in a secondary school is said to be", "images": [], "options": {"A": "under-employed", "B": "unemployed", "C": "fully employed", "D": "technologically unemployed"}, "answer": "A", "explanation": "Underemployment refers to a situation where a person is working below their skills or full capacity. In this case, an electrical engineer teaching physics in a secondary school is not fully utilizing his/her skills and is therefore underemployed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2018>49", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "One benefit a country can derive from the extraction of crude oil is increase in", "images": [], "options": {"A": "population", "B": "employment", "C": "money supply", "D": "demand for imports"}, "answer": "B", "explanation": "The extraction of crude oil can lead to an increase in employment. This is because the oil industry requires a large workforce to operate, from extraction to refining to distribution. Therefore, the extraction of crude oil can create jobs and reduce unemployment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2018>50", "subject": "Economics", "year": "2018", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "Which of the following cannot be classified as a natural resource?", "images": [], "options": {"A": "Iron rod", "B": "Wild life", "C": "Solar energy", "D": "Gold"}, "answer": "A", "explanation": "A natural resource is a material or substance that occurs in nature and can be used for economic gain. They are often resources that come from the Earth and are necessary for humans to survive on this planet. Iron rod is not a natural resource because it is a man-made product. It is made from iron ore, which is a natural resource, but the rod itself is not naturally occurring.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2019>1", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "The fundamental economic problem in every society is", "images": [], "options": {"A": "the large number of the unemployed.", "B": "inadequate supply of money.", "C": "corruption and mismanagement", "D": "limited supply of productive resources"}, "answer": "D", "explanation": "The fundamental economic problem in every society is the limited supply of productive resources. This is also known as the problem of scarcity. It arises because human wants for goods and services exceed the quantity of goods and services that can be produced using all available resources. The other options listed are issues that can exacerbate the economic problem, but they are not the fundamental problem.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2019>2", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "A point X inside a production possibility curve indicates that", "images": [], "options": {"A": "resources are fully utilized.", "B": "the country is poor.", "C": "some resources are idle.", "D": "resources are not available."}, "answer": "C", "explanation": "The point inside the production possibility curve indicate that resource is idle or unemployed. This is shown in the diagram below;    point X indicate unemployment, resources are not fully employed or utilized or idle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>3", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "The major employer of labour in developing countries is the", "images": [], "options": {"A": "tertiary sector.", "B": "secondary sector.", "C": "primary sector.", "D": "industrial sector."}, "answer": "C", "explanation": "In developing countries, the primary sector is often the major employer of labour. The primary sector of the economy includes any industry involved in the extraction and collection of natural resources, such as farming, forestry, fishing and mining. In many developing countries, a large portion of the population is involved in these activities. The other sectors listed, such as the secondary (manufacturing) and tertiary (services) sectors, tend to be more dominant in developed economies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>4", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "The desire for profit is a major feature of", "images": [], "options": {"A": "traditional economy.", "B": "mixed economy.", "C": "market economy.", "D": "command economy."}, "answer": "C", "explanation": "The desire for profit is a major feature of a market economy. In a market economy, individuals and businesses are motivated to make decisions based on the potential to make a profit. This is not the primary feature of a traditional, mixed, or command economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>5", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "The wages of a group of workers in dollars are stated below:  40, 30, 70, 20, 60, 10, 10, 80, 30 and 10.   What is the mean wage?", "images": [], "options": {"A": "$35", "B": "$36", "C": "$37", "D": "$38"}, "answer": "B", "explanation": "Meanwage=∑xn=40+30+70+20+60+10+10+80+30+1010  =36010=$36", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2019>6", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If the coefficient of price elasticity of demand of a product is zero, then its demand curve will be", "images": [], "options": {"A": "parallel to the quantity axis.", "B": "parallel to the price axis.", "C": "negatively sloped.", "D": "positively sloped."}, "answer": "B", "explanation": "Perfectly Inelastic Demand: When the price elasticity of demand is zero, the demand curve is vertical. This implies that the quantity demanded remains constant regardless of any changes in price.  Demand Curve Parallel to Price Axis: A vertical demand curve is parallel to the price axis, reflecting that price changes do not affect the quantity demanded.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>7", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "If the demand function is Qd = -0.5p + 20, calculate the quantity demanded when price is $15.00.", "images": [], "options": {"A": "-$27.50", "B": "-$12.50", "C": "$12.50", "D": "$27.50"}, "answer": "C", "explanation": "The demand function Qd = -0.5p + 20 is used to calculate the quantity demanded at a given price. If the price is $15.00, we substitute p = 15 into the equation to get Qd = -0.5*15 + 20 = 12.5. So, the quantity demanded when the price is $15.00 is 12.5.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>8", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "If less of a good is bought as one's income increases, such a good is", "images": [], "options": {"A": "a normal good.", "B": "a luxury.", "C": "a necessity.", "D": "an inferior good."}, "answer": "D", "explanation": "In economics, if less of a good is bought as one's income increases, such a good is referred to as an 'inferior good'. An inferior good is a type of good whose demand decreases when consumer income rises, unlike normal goods, for which the opposite is observed. Normal goods are those for which consumers' demand increases when their income increases. This is primarily due to the fact that cheaper goods are replaced by more expensive substitutes when income increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>9", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "The demand for coffee and tea is", "images": [], "options": {"A": "joint.", "B": "competitive.", "C": "composite.", "D": "derived."}, "answer": "B", "explanation": "The demand for coffee and tea is 'competitive'. In economics, competitive demand refers to the demand for goods that are in competition with each other. This means that they are substitutes for each other. If the price of coffee rises, people may switch to tea, hence they are in competition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>10", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "What effect will an increase in the supply of fish have on the meat market?", "images": [], "options": {"A": "A fall in equilibrium price and quantity.", "B": "An increase in equilibrium price and quantity.", "C": "An increase in equilibrium price and a fall in quantity.", "D": "Increase in equilibrium quantity and decrease in equilibrium price"}, "answer": "D", "explanation": "From the diagram above, the supply shift from S1 S1 to S2 S2 indicating an increase in supply while the demand remains constant. Therefore, the effect is that, there is a decrease in equilibrium price from p1 to p2 and an increase in equilibrium quantity from q1 to q2 as shown from the diagram above.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>11", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Which of the following factors is not a condition for a change in supply of a commodity?", "images": [], "options": {"A": "Improved technology", "B": "Cost of production", "C": "The price of the commodity", "D": "Government tax policies"}, "answer": "C", "explanation": "The price of the commodity is not a condition for a change in supply of a commodity. In economics, a change in supply refers to a shift in the entire supply curve, which is caused by shifting the quantity supplied at every price. It is caused by a change in the production cost, technological progress, taxes and subsidies, price of related goods, and number of suppliers. However, the price of the commodity itself does not cause the supply curve to shift; it only results in a movement along the curve.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>12", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "Supply of agricultural products is likely to be elastic in the", "images": [], "options": {"A": "intermediate period", "B": "long-run", "C": "market period", "D": "short-run"}, "answer": "B", "explanation": "The supply of agricultural products is likely to be elastic in the long-run. Elasticity of supply refers to the degree of responsiveness of quantity supplied to the changes in the price of the commodity. In the long-run, all factors of production are variable and farmers can adjust their production processes in response to price changes, making the supply more elastic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>13", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Two commodities X and Y are in joint supply when", "images": [], "options": {"A": "X is a by-product of Y.", "B": "X and Y are produced by the same firm.", "C": "increase in quantity of X leads to decrease in Y.", "D": "X and Y cannot be produced in the same process."}, "answer": "A", "explanation": "Two commodities X and Y are in joint supply when X is a by-product of Y. Joint supply refers to a situation where an increase in the production of one good leads to an increase in the supply of another good. This typically occurs when one good is a by-product of the production process for another good.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>14", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND", "question": "Table I  Units of quantity consumedTotal UtilityMarginal Utility0  1  2  3  4  5-  10  15  17  18  18-  10  5  2  1  0  Table I above illustrates the law of", "images": [], "options": {"A": "diminishing returns.", "B": "diminishing marginal productivity.", "C": "diminishing marginal utility.", "D": "variable proportion."}, "answer": "C", "explanation": "Table I above illustrates the law of diminishing marginal utility. The law of diminishing marginal utility states that as a person increases consumption of a product while keeping consumption of other products constant, there is a decline in the marginal utility that person derives from consuming each additional unit of that product. In the table, as the units of quantity consumed increase, the marginal utility decreases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>15", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET", "question": "When the price of a good is above the equilibrium, there will be", "images": [], "options": {"A": "a shortage.", "B": "a surplus.", "C": "unemployment.", "D": "inflation."}, "answer": "B", "explanation": "From the diagram, when price is fixed above the equilibrium, there will be excess of supply over demand i.e surplus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>16", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION", "question": "What happens when a minimum price is imposed in a market?", "images": [], "options": {"A": "Shortage occurs", "B": "Surplus occurs", "C": "The market maintains its equilibrium", "D": "Many firms will close down"}, "answer": "B", "explanation": "The minimum price or price floor is when price is fixed above the equilibrium price. Surplus occurs when a minimum price is imposed in a market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>17", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCTION FUNCTIONS AND LAWS OF RETURNS", "question": "When an increase in inputs leads to a more than proportionate increase in output, there is", "images": [], "options": {"A": "decreasing returns to scale.", "B": "increase in marginal product.", "C": "increasing returns to scale.", "D": "constant returns to scale."}, "answer": "C", "explanation": "Increasing returns to scale occur when the output increases by a larger proportion than the increase in inputs during the production process. This means that if the quantity of inputs is doubled, the output more than doubles. This is often due to the fact that larger firms are able to take advantage of economies of scale.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>18", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "The short-run in production is the time period when", "images": [], "options": {"A": "techniques of production can easily be changed.", "B": "all factors of production are variable.", "C": "at least a factor is fixed while others are variable.", "D": "variable factors cannot be changed."}, "answer": "C", "explanation": "In the short run, at least one factor of production is fixed while others are variable. This is because there is not enough time to adjust all resources, as some resources (like buildings and machinery) are fixed in nature and cannot be adjusted quickly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>19", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM", "question": "Table II shows the short-run cost of a firm.  Quantity  (kg)Fixed Cost  ($)Variable Cost  ($)Total Cost  ($)Marginal Cost  ($)Average Cost  ($)1  2  3750  750  750200  560  900950  1310  P-  360  Q950  655  550  Calculate the value of Q.", "images": [], "options": {"A": "$350", "B": "$340", "C": "$360", "D": "$370"}, "answer": "B", "explanation": "To find Q, we need to get the value of P  P ⇒ TC = FC + VC  ⇒ 750 + 900  TC = 1650  ∴ P = $1,650    Q⇒MC=ΔTCΔQ=P-13103-2  =1650 - 13101  Q = $340", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>20", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS", "question": "A cost of production that is positively related to output is the", "images": [], "options": {"A": "total fixed cost.", "B": "average fixed cost.", "C": "variable cost.", "D": "social cost."}, "answer": "C", "explanation": "Variable costs are dependent on production output or sales. The variable cost of production is a constant amount per unit produced. As the volume of production and output increases, variable costs will also increase.    Examples of variable costs include the cost of raw materials, wages for production workers, and electricity consumption directly related to production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>21", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "MARKET STRUCTURE : PERFECT MARKET", "question": "In perfect competition, the average revenue curve of a firm is", "images": [], "options": {"A": "below the marginal revenue curve.", "B": "downward sloping.", "C": "the marginal revenue curve.", "D": "convex to the origin."}, "answer": "C", "explanation": "In perfect competition, the Average revenue curve of a firm is the marginal revenue curve. This is because the firm can sell any quantity of its product at the prevailing market price. It is illustrated in the diagram below:", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>22", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "Which of the following means of funding a business is very reliable and cheap?", "images": [], "options": {"A": "Bank loans", "B": "Loans from friends", "C": "Plough back profits", "D": "Debentures"}, "answer": "C", "explanation": "Plough back profits is the most reliable and cheap means of funding a business. This is because it involves reinvesting the net profits of the business back into the business. It is reliable because it does not depend on external factors or entities, and it is cheap because it does not involve any interest payments or additional costs that are associated with loans or debentures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>23", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Government in most cases influences location of firms to", "images": [], "options": {"A": "discourage private investors.", "B": "ensure equitable distribution.", "C": "reduce cost of production.", "D": "make the firms enjoy economies of scale."}, "answer": "B", "explanation": "Government in most cases influences the location of firms to ensure equitable distribution. This is done to promote balanced economic development across different regions, prevent regional disparities, and ensure that resources and opportunities are not concentrated in a particular area.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>24", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "Middlemen are made up of", "images": [], "options": {"A": "manufacturers, wholesalers and consumers.", "B": "manufacturers, wholesalers and retailers.", "C": "wholesalers, retailers and hawkers.", "D": "wholesalers, retailers and consumers."}, "answer": "C", "explanation": "Middlemen are made up of wholesalers, retailers, and hawkers. These are the intermediaries who buy products from manufacturers and sell them to the end consumers. They play a crucial role in the distribution of goods and services in the market.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2019>25", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "POPULATION : THEORIES OF POPULATION", "question": "The Malthusian theory of population was proved wrong because", "images": [], "options": {"A": "the practice of subsistence farming was encouraged.", "B": "developing countries adopted birth control method.", "C": "new lands and new methods of production were discovered.", "D": "Malthus' view was seen as an exaggeration."}, "answer": "C", "explanation": "The Malthusian theory of population posits that population growth would outpace the growth of food supply leading to overpopulation and resources scarcity. However, this theory was proved wrong because new lands and new methods of production were discovered, which increased the food supply and other resources. This development disproved Malthus' prediction of inevitable starvation due to population growth.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>26", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Human development can be improved if", "images": [], "options": {"A": "banks give more loans to businessmen.", "B": "large family sizes are encouraged.", "C": "general education and training is encouraged.", "D": "it is handled by the private sector only."}, "answer": "C", "explanation": "Human development is a broad concept that involves the health, education, and income indices of a person or society. It can be improved if general education and training is encouraged. Education and training equip individuals with the knowledge and skills needed to improve their quality of life and contribute to the development of their society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>27", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "The use of interest rates to control money supply is a", "images": [], "options": {"A": "control policy.", "B": "monetary policy.", "C": "developmental policy.", "D": "fiscal policy."}, "answer": "B", "explanation": "The use of interest rates to control money supply is a monetary policy. Monetary policy refers to the actions undertaken by a nation's central bank to control money supply and achieve goals that promote sustainable economic growth. This can be done through various mechanisms, including manipulating interest rates. Lowering interest rates encourages borrowing and spending, which increases money supply, while raising interest rates does the opposite.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>28", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "Agricultural productivity may be increased if", "images": [], "options": {"A": "educational institutions are established in rural areas.", "B": "commercial banks are established in rural areas.", "C": "more infrastructural facilities are provided in rural areas.", "D": "labour intensive method of agriculture is encouraged."}, "answer": "C", "explanation": "Agricultural productivity can be increased by providing more infrastructural facilities in rural areas. Infrastructure such as irrigation systems, roads, storage facilities, and electricity can enhance agricultural activities by improving access to markets, enabling the use of modern farming equipment, and reducing post-harvest losses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>29", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "A country is described as industrialized if", "images": [], "options": {"A": "the contributions of industries to national income is high.", "B": "traditional and modern sectors coexist.", "C": "the country adopts import promotion strategy.", "D": "primary industries dominate the economy."}, "answer": "A", "explanation": "A country is described as industrialized if the contributions of industries to national income is high. This is because industrialization is characterized by a shift from an economy dominated by agricultural output to an economy dominated by manufacturing and services. In an industrialized country, industries contribute significantly to the Gross Domestic Product (GDP).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>30", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "Which of the following is a major advantage of establishing a tomato-processing factory in a country?", "images": [], "options": {"A": "Local consumption will decrease", "B": "More unskilled labour will be employed", "C": "Foreign exchange will be conserved", "D": "It will attract more tourists"}, "answer": "C", "explanation": "A major advantage of establishing a tomato-processing factory in a country is that it will conserve foreign exchange. This is because the country will reduce the importation of processed tomato products, thereby saving foreign exchange. Additionally, the processed tomato products can be exported to earn foreign exchange.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>31", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The total value of goods and services produced within the borders of a country is", "images": [], "options": {"A": "net national product.", "B": "net domestic product.", "C": "gross domestic product.", "D": "gross national product"}, "answer": "C", "explanation": "The total value of goods and services produced within the borders of a country is referred to as Gross Domestic Product (GDP). GDP is a measure of economic activity within a country. It's the market value of all goods and services produced in a year within a country's borders.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>32", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Which of the following items is not considered as a transfer payment?", "images": [], "options": {"A": "Pension pay", "B": "Government subsidy", "C": "Students' grant", "D": "Doctor's salary"}, "answer": "D", "explanation": "Transfer payments are payments made by the government to individuals without any goods or services being received in return. These include pensions, government subsidies, and student grants. A doctor's salary, however, is not a transfer payment because it is a payment for services rendered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>33", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "NATIONAL INCOME : PROBLEMS OF NATIONAL INCOME", "question": "Which of the following factors will not underestimate the national income?", "images": [], "options": {"A": "Rapid decrease in prices", "B": "Increased subsistence production", "C": "Practice of specialization of labour", "D": "Increase in value of services not paid for"}, "answer": "C", "explanation": "National income can be underestimated due to factors such as rapid decrease in prices, increased subsistence production, and increase in value of services not paid for. However, the practice of specialization of labour does not lead to underestimation of national income. Instead, it can lead to increased productivity and potentially higher national income.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>34", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "Which of the following is true of the value of money? It", "images": [], "options": {"A": "is positively related to the price level.", "B": "depends on the value people attach to it.", "C": "is determined by the government.", "D": "is inversely related to the price level."}, "answer": "D", "explanation": "The value of money is inversely related to the price level. This is because as the price level increases, the purchasing power or the value of money decreases. This is a basic principle in economics known as the price level effect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>35", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "The motive for holding money to meet unforeseen events is termed", "images": [], "options": {"A": "precautionary demand.", "B": "transactions demand.", "C": "liquidity demand.", "D": "speculative demand."}, "answer": "A", "explanation": "The motive for holding money to meet unforeseen events is termed as precautionary demand. This is one of the three motives for holding money according to Keynes, the other two being transactions demand and speculative demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>36", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "An increase in the prices of factor inputs may result in", "images": [], "options": {"A": "demand-pull inflation.", "B": "stagflation.", "C": "open inflation.", "D": "cost-push inflation."}, "answer": "D", "explanation": "An increase in the prices of factor inputs may result in cost-push inflation. Cost-push inflation is a type of inflation caused by substantial increases in the cost of important goods or services where no suitable alternative is available. A situation that has been often cited of this was the oil crisis of the 1970s, which some economists see as a major cause of the inflation experienced in the Western world in that decade. It is argued that this inflation resulted from increases in the cost of petroleum imposed by the member states of OPEC.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>37", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Insurance companies are similar to commercial banks in that they", "images": [], "options": {"A": "compensate their customers for losses.", "B": "acts as lender of last resort.", "C": "help in maintaining monetary stability in a nation.", "D": "help in mobilizing savings for investment."}, "answer": "D", "explanation": "Insurance companies and commercial banks both play a role in mobilizing savings for investment. Insurance companies collect premiums from policyholders, which they then invest in various financial instruments. Similarly, commercial banks accept deposits from customers, which they then lend out to businesses and individuals for investment purposes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>38", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "What happens when the central bank increases the bank rate?", "images": [], "options": {"A": "Amount of borrowing increases", "B": "Amount of borrowing decreases", "C": "Supply of money increases", "D": "Commercial banks are not affected"}, "answer": "B", "explanation": "When the central bank increases the bank rate, it makes borrowing more expensive. This discourages commercial banks from borrowing from the central bank, which in turn reduces the amount of money they have available to lend to customers. As a result, the amount of borrowing decreases.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>39", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION", "question": "Citizens are protected from government's arbitrariness in taxation by the canon of", "images": [], "options": {"A": "elasticity.", "B": "flexibility.", "C": "economy.", "D": "certainty."}, "answer": "D", "explanation": "The canon of certainty in taxation protects citizens from the government's arbitrariness. This principle states that tax rules should be clear and certain, not arbitrary. Taxpayers should know in advance what they will be taxed, when they will be taxed, and how much they will be taxed. This allows them to plan their activities and finances accordingly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>40", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "In a period of unemployment and falling priced, government should adopt a", "images": [], "options": {"A": "zero-based budget.", "B": "budget deficit.", "C": "balanced budget.", "D": "surplus budget."}, "answer": "B", "explanation": "During a period of unemployment and falling prices, the government should adopt a budget deficit to stimulate the economy by creating demand and jobs. A budget deficit, by increasing government spending or reducing taxes, is a tool that can be used to stimulate economic activity and help address unemployment and deflation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>41", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "In most developing countries, a large percentage of the labour force is engaged in", "images": [], "options": {"A": "trading.", "B": "mining", "C": "agriculture.", "D": "manufacturing"}, "answer": "C", "explanation": "In most developing countries, a large percentage of the labour force is engaged in agriculture, as it is often the mainstay of the economy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2019>42", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "In most underdeveloped countries, development plans do not achieve their objectives due to", "images": [], "options": {"A": "poor coordination between local and national governments.", "B": "exportation of more primary products.", "C": "lack of educational institutions in those countries.", "D": "urban-rural migration of citizens."}, "answer": "A", "explanation": "In most underdeveloped countries, development plans do not achieve their objectives due to poor coordination between local and national governments, leading to inefficiencies and misallocation of resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>43", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Balance of trade involves exchange of", "images": [], "options": {"A": "goods only.", "B": "services only.", "C": "goods and services.", "D": "goods and capital."}, "answer": "C", "explanation": "Balance of trade involves the exchange of both goods and services. It is the difference between the value of a country's imports and exports for a set period. It does not include capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>44", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "An improvement in a country's terms of trade means that the", "images": [], "options": {"A": "nation can export more services.", "B": "nation's receipts on export is equal to payments on imports.", "C": "value of her imports is lower than her exports.", "D": "visible exports is less than visible imports."}, "answer": "C", "explanation": "An improvement in a country's terms of trade means that the value of her exports is higher than her imports. This means that the country is earning more from its exports than it is spending on imports, which is beneficial for its economy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>45", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "Devaluation of currency may not correct a balance of payments deficit if the demand for export is", "images": [], "options": {"A": "perfectly inelastic.", "B": "perfectly elastic.", "C": "fairly elastic.", "D": "unitary elastic."}, "answer": "A", "explanation": "Devaluation of currency may not correct a balance of payments deficit if the demand for export is perfectly inelastic. This is because when demand is perfectly inelastic, the quantity demanded does not change as the price changes. Therefore, even if the currency is devalued to make exports cheaper, it will not increase the quantity of exports if the demand is perfectly inelastic.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>46", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "One measure for financing a country's balance of payments deficit is through", "images": [], "options": {"A": "export diversification.", "B": "import substitution.", "C": "short-term borrowing from IMF.", "D": "internal borrowing from commercial banks."}, "answer": "C", "explanation": "A country's balance of payments deficit can be financed through short-term borrowing from the International Monetary Fund (IMF). The IMF provides financial assistance to countries that have a balance of payments need, enabling them to rebuild their international reserves, stabilize their currencies, continue paying for imports, and restore conditions for strong economic growth, while undertaking policies to address underlying problems. Import substitution and export diversification are strategies to improve a country's balance of payments, but they are not measures for financing a deficit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2019>47", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "ECONOMIC INTEGRATION : PROBLEMS OF ECONOMIC INTEGRATION IN WEST AFRICA- ECOWAS", "question": "The major achievement of the Economic Community of West African States (ECOWAS) is that it has", "images": [], "options": {"A": "made capital more mobile.", "B": "made possible the use of common currency.", "C": "increased members allegiance to former colonial masters.", "D": "widened the market for goods produced."}, "answer": "D", "explanation": "The major achievement of the Economic Community of West African States (ECOWAS) is that it has widened the market for goods produced. ECOWAS, a regional group of fifteen West African countries, was founded to promote economic integration across the region. A wider market allows for increased trade, economic growth, and development. While ECOWAS has made strides towards a common currency, it has not yet been fully implemented.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>48", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : UNCTAD", "question": "Which of the following institutions is concerned with expanding developing countries' commodity trade?", "images": [], "options": {"A": "World Trade Organization (WTO)", "B": "United Nations Conference on Trade and Development (UNCTAD)", "C": "Economic Commission for Africa (ECA)", "D": "African Development Bank (AfDB)"}, "answer": "B", "explanation": "The United Nations Conference on Trade and Development (UNCTAD) is the institution concerned with expanding developing countries' commodity trade. UNCTAD is a permanent intergovernmental body established by the United Nations General Assembly in 1964, and its work is to maximize the trade, investment and development opportunities of developing countries and assist them in their efforts to integrate into the world economy on an equitable basis. The other institutions listed have different primary focuses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>49", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "Exploitation of forest resources becomes a major problem when", "images": [], "options": {"A": "communities fight over ownership.", "B": "they are not renewed.", "C": "they are neglected.", "D": "the supply is fixed in the long-run."}, "answer": "B", "explanation": "Exploitation of forest resources becomes a major problem when they are not renewed. This is because forests are a renewable resource, meaning they can replenish over time if managed sustainably. If they are not renewed, it leads to deforestation which can have severe environmental impacts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2019>50", "subject": "Economics", "year": "2019", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "Natural resources that are renewable are found in the", "images": [], "options": {"A": "mining sector.", "B": "traditional sector.", "C": "agricultural sector.", "D": "secondary sector."}, "answer": "C", "explanation": "Natural resources that are renewable are found in the agricultural sector. This is because the agricultural sector involves the cultivation of plants and the rearing of animals, both of which are renewable resources. Renewable resources are those that can be replenished naturally over time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2020>1", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "Which of the following is central to the definition of Economics?", "images": [], "options": {"A": "Resources", "B": "Wants", "C": "Scarcity", "D": "Capital"}, "answer": "C", "explanation": "Scarcity is central to the definition of Economics. Economics is the study of how individuals, businesses, governments, and societies make choices to cope with scarcity. Scarcity refers to the basic economic problem, the gap between limited resources and theoretically limitless wants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2020>2", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "When the production possibility curve shifts outwards, the economy experiences", "images": [], "options": {"A": "growth", "B": "over-population", "C": "ineffiecient use of resources", "D": "under-population"}, "answer": "A", "explanation": "The production possibility curve (PPC) represents the maximum combination of goods and services that can be produced by an economy with the available resources and technology. An outward shift of the PPC represents economic growth, as it means that the economy can now produce more of both goods and services than before. This could be due to an increase in resources or an improvement in technology.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>3", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "Land as a factor of production is made useful through the", "images": [], "options": {"A": "application of human effort", "B": "acts of nature", "C": "application of fertilzer", "D": "use of machines"}, "answer": "A", "explanation": "Land as a factor of production becomes useful through the application of human effort. This includes activities such as farming, mining, and construction. While acts of nature, application of fertilizer, and use of machines can enhance the productivity of land, it is the application of human effort that primarily makes land useful as a factor of production.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2020>4", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "In a free market economy, resources are allocated through the", "images": [], "options": {"A": "government department", "B": "price mechanism", "C": "trade union", "D": "state planning committee"}, "answer": "B", "explanation": "In a free market economy, resources are allocated through the price mechanism. The price mechanism is the system in a free market economy where decisions about what to produce, how to produce, and for whom to produce are made based on the prices of goods and services. Prices are determined by the forces of supply and demand. If demand for a product increases, its price will rise, which will incentivize producers to produce more of that product. Conversely, if demand for a product decreases, its price will fall, which will discourage producers from producing that product.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>5", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH", "question": "Use Figure 1 below to answer questions below          The diagram in Figure 1 above depicts a", "images": ["Economics/imgs/2020/ssceecon2020objq5.png"], "options": {"A": "simple bar chart", "B": "complex bar chart", "C": "component bar chart", "D": "multiple bar chart"}, "answer": "C", "explanation": "A component bar chart is used when the data involved are of two variables each component is represented by a section proportional in size to its representation in total of each bar", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>6", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Figure 2 below shows change in demand for commodity X which is a normal good.Use it to answer thne questions that follows          Which of the following caused the change in demand from D1D1 to D2D2?", "images": ["Economics/imgs/2020/ssceecon2020objq6.png"], "options": {"A": "Fall in the income of consumers", "B": "Rise in the price of a substitute", "C": "Rise in the price of a complement", "D": "Fall in the supply of commodity X"}, "answer": "B", "explanation": "A change in the demand from D0 D0 to D2 D2 is caused by the rise in the price of substitue i.e if the price of milo increases, consumers will buy more of Bournvita which will make the demand for Bournvita to increase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>7", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "PUBLIC FINANCE : SUBSIDY", "question": "Use Figure 3 below to answer the question that follows.        The curves Do Do and So So are the initial demand and supply curves respectively.What happens when government provides subsidy to producers?", "images": ["Economics/imgs/2020/ssceecon2020objq7.png"], "options": {"A": "The supply curve will shift from SoSo to S2 S2", "B": "The supply curve will shift from SoSo to S1S1", "C": "The demand curve will shift from DoDo to D1D1", "D": "The supply curve will shift from S1S1 to SoSo"}, "answer": "A", "explanation": "When the government feels that the market price for the producers is too low, it decides to pay them subsidy.Subsidy shifts the supply curve downward to the right. From the diagram above, the supply will curve will shift from S0 S0 to S2 S2", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>8", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE", "question": "In Figure 4 above,YZ represents", "images": ["Economics/imgs/2020/ssceecon2020objq8.png"], "options": {"A": "excess demand", "B": "excess supply", "C": "equilibrium quantity", "D": "equilibrium price"}, "answer": "B", "explanation": "From the diagram above, YZ represent excess supply since it is above the equilibruim price", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>9", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "Goods are described as inferior if their demand", "images": [], "options": {"A": "decreases as price falls.", "B": "increases as income rises.", "C": "decreases as income increases.", "D": "increases as price increases."}, "answer": "C", "explanation": "Inferior goods are those goods for which demand decreases when consumer income increases. This is because as income increases, consumers shift to more expensive or higher quality substitutes. Therefore, the correct answer is 'decreases as income increases.'", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2020>10", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "A consumer is in equilibrium when", "images": [], "options": {"A": "his market supply is equal to his market demand.", "B": "he maximizes his satisfaction from spending his income", "C": "the market is also in equilibrium.", "D": "he has consumed all he wants"}, "answer": "B", "explanation": "A consumer is said to be in equilibrium when he maximizes his satisfaction given his income and the market prices. This is based on the concept of utility maximization, which states that consumers aim to get the most satisfaction (utility) possible from their spending, given their budget constraints. Therefore, the correct answer is 'he maximizes his satisfaction from spending his income.'", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>11", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Goods that are abundant in supply usually have low", "images": [], "options": {"A": "total utility.", "B": "marginal utility.", "C": "average utility.", "D": "time utility."}, "answer": "B", "explanation": "Marginal utility refers to the additional satisfaction a consumer gains from consuming one more unit of a good or service. If a good is abundant in supply, it means that the additional satisfaction gained from consuming one more unit of the good (marginal utility) is likely to be low because the consumer has already consumed a lot of it. Therefore, the correct answer is 'marginal utility.'", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>12", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF SUPPLY : DISTINCTION BETWEEN CHANGE IN QUANTITY SUPPLIED AND CHANGE IN SUPPLY", "question": "An increase in supply means that", "images": [], "options": {"A": "more is sold at different prices.", "B": "more is sold at same price", "C": "there is leftward shift of the supply curve.", "D": "there is a movement along the supply curve."}, "answer": "A", "explanation": "An increase in supply means that producers are willing and able to sell more of a good or service at each price. This is often due to factors such as improvements in technology, an increase in the number of producers, or a decrease in the cost of production. Therefore, 'more is sold at different prices' is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>13", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF SUPPLY : TYPES OF SUPPLY", "question": "If an increase in the price of crude oil led to an increase in the prices of kerosene and  grease,then kerosene and grease are in", "images": [], "options": {"A": "joint supply.", "B": "competitive supply.", "C": "market supply.", "D": "composite supply."}, "answer": "A", "explanation": "When an increase in the price of one good (in this case, crude oil) leads to an increase in the supply of other goods (in this case, kerosene and grease), those goods are said to be in joint supply. This is because they are produced together or are by-products of the same production process. Therefore, 'joint supply' is the correct answer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>14", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "A seller increased the quantity he offered for sales from 200 units to 250 units when price of his product increased by 12.5%.What is the price elasticity of supply of his product?", "images": [], "options": {"A": "2.00", "B": "1.50", "C": "1.00", "D": "0.50"}, "answer": "A", "explanation": "e  = % ∆ in Qs/% ∆ in price    % ∆ in Qs = 250 - 200/200 x 100                = 50/200 x 100  = 25%    Since the % ∆ in p =12.5     Therefore, ep = 25/12.5   = 2", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>15", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF SUPPLY : TYPES OF SUPPLY", "question": "If an increase in the supply of beef increased the supply of hides,then beef and hides are in", "images": [], "options": {"A": "competitive supply.", "B": "joint supply.", "C": "composite supply.", "D": "joint demand."}, "answer": "B", "explanation": "Beef and hides are in joint supply. This is because an increase in the supply of beef leads to an increase in the supply of hides. Joint supply refers to a situation where an increase in the production of one good leads to an increase in the supply of another good. In this case, when more beef is produced, more hides are also produced as a by-product.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>16", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "If a beef market is in equilibrium at $4.00 per kg,an increase in price to $6.00 per kg may cause", "images": [], "options": {"A": "surplus in the market.", "B": "shortage in the market.", "C": "black market to come into operation.", "D": "rationing to be introduced."}, "answer": "A", "explanation": "If a beef market is in equilibrium at $4.00 per kg, an increase in price to $6.00 per kg may cause a surplus in the market. This is because at a higher price, quantity supplied will exceed quantity demanded. This situation is known as a surplus. In other words, producers are willing to supply more at the higher price, but consumers are not willing to buy as much, leading to an excess supply or surplus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>17", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM", "question": "A large firm may experience diseconomies of scale if there is", "images": [], "options": {"A": "difficulty in coordinating  decisions.", "B": "division of labour in production.", "C": "employment of more specialists.", "D": "decrease in the cost of production."}, "answer": "A", "explanation": "A large firm may experience diseconomies of scale if there is difficulty in coordinating decisions. Diseconomies of scale occur when a firm's long-run average costs start to rise as output increases. This can happen in large firms due to problems with communication and coordination. As firms grow larger, it can become more difficult to manage and coordinate the firm's operations, leading to inefficiencies and higher costs.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>18", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCTION FUNCTIONS AND LAWS OF RETURNS", "question": "Increasing returns to scale suggests that", "images": [], "options": {"A": "a firm can make profit by reducing output.", "B": "a firm can make more profit by increasing output", "C": "as the producer reduces the quantity of raw materials used,the marginal product will double.", "D": "as the producer increases the quantity of raw materials used,the marginal product will fall."}, "answer": "B", "explanation": "Increasing returns to scale refers to a situation where a firm can increase its output more than proportionately by increasing all its inputs. This means that if a firm doubles its inputs, its output will more than double, leading to more profit. Therefore, the correct answer is 'a firm can make more profit by increasing output'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>19", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "One feature of the average fixed cost is that it", "images": [], "options": {"A": "falls continuously but is never equal to zero.", "B": "is U-shaped and intersects the Y-axis.", "C": "rises and falls faster than the marginal cost.", "D": "is always higher than the average variable cost."}, "answer": "A", "explanation": "Average Fixed Cost (AFC) is the fixed cost of production divided by the quantity of output produced. As output increases, AFC decreases because the same fixed cost is spread over more units of output. However, it never reaches zero because fixed costs are costs that do not change with the level of output. Therefore, the correct answer is 'falls continuously but is never equal to zero.'", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>20", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "If the average fixed cost (AFC) of producing 5 bags of rice is $20.00,the average fixed cost of producing 10 bags will be", "images": [], "options": {"A": "$2.00", "B": "$4.00", "C": "$10.00", "D": "$20.00"}, "answer": "C", "explanation": "Average Fixed Cost (AFC) is calculated by dividing the total fixed cost by the quantity of output. If the AFC of producing 5 bags of rice is $20.00, then the total fixed cost is $100.00 ($20.00 * 5). If the firm produces 10 bags of rice, the AFC will be $10.00 ($100.00 / 10). Therefore, the correct answer is '$10.00'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2020>21", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "Table 1 below shows the total revenue schedule of a firm. Use the information to answer the question                                                                         Table 1  Output(Units)            5060708090Total revenue(TR) $  85102119136153    What is the units price of the firm's output?", "images": [], "options": {"A": "$10.00", "B": "$2.70", "C": "$2.00", "D": "$1.70"}, "answer": "D", "explanation": "The unit price of the firm's output is calculated by dividing the total revenue by the number of units. For example, at 50 units, the total revenue is $85. So, the unit price is $85/50 = $1.70.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>22", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "Table 1 below shows the total revenue schedule of a firm. Use the information to answer the question                                                                         Table 1  Output(Units)            5060708090Total revenue(TR) $  85102119136153  What is the firm's marginal revenue?", "images": [], "options": {"A": "$153.00", "B": "$17.00", "C": "$1.70", "D": "$0.80"}, "answer": "C", "explanation": "Marginal revenue =  ∆ in total revenue/∆ in output                                   =  102 - 85/ 60 - 50                                        =      17 /10                                                                                     = 1.7", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>23", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES~~BUSINESS ORGANISATION : SOLE PROPRIETOSHIP~~BUSINESS ORGANISATION : PARTNERSHIP~~BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "Organization and entreprenuership are vested in different persons in a", "images": [], "options": {"A": "cooperative society", "B": "sole proprietorship", "C": "partnership", "D": "public company"}, "answer": "D", "explanation": "In a public company, organization and entrepreneurship are vested in different persons. The entrepreneurs (shareholders) provide the capital and bear the risk, while the organization (management) runs the business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2020>24", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "The public sector in a mixed economy is  not  always efficient because of", "images": [], "options": {"A": "bureacratic practices", "B": "the desire to make huge profit", "C": "annual planning of activities", "D": "the activities of shareholders"}, "answer": "A", "explanation": "The public sector in a mixed economy is not always efficient due to bureaucratic practices. Bureaucracy often involves a lot of red tape, slow decision-making processes, and inefficiencies due to the lack of competition and profit motive. The other options do not accurately describe the reasons for inefficiency in the public sector.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>25", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER", "question": "Which functions of the wholesaler enables him to stabilize prices?", "images": [], "options": {"A": "warehousing goods", "B": "advertising the goods", "C": "granting credit to retailers", "D": "transporting goods"}, "answer": "A", "explanation": "The function of the wholesaler that enables him to stabilize prices is warehousing goods. By warehousing goods, wholesalers can control the supply of goods in the market, releasing them when there is high demand and storing them when there is low demand, thereby stabilizing prices. The other options do not directly contribute to price stabilization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>26", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "In the long run, as individual receives higher wages, it causes", "images": [], "options": {"A": "demand for food to decrease", "B": "demand for leisure to decrease", "C": "supply of normal goods to decrease", "D": "supply of labour to decrease"}, "answer": "D", "explanation": "In the long run, as an individual receives higher wages, it causes the supply of labour to decrease. This is because as wages increase, individuals may choose to work fewer hours, effectively reducing the supply of labour. The other options do not accurately describe the effects of higher wages in the long run.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>27", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "Population growth rate can be calculated as", "images": [], "options": {"A": "birth rate- death rate-emigrants-immigrants", "B": "birth rate-death rate+migration rate-immigration rate", "C": "birth rate- death rate", "D": "birth rate- death rate + immigrants - emigrants"}, "answer": "D", "explanation": "Population growth rate is calculated as the birth rate minus the death rate plus the net migration (immigrants - emigrants). This is because the population increases with births and immigrants (people moving into the area) and decreases with deaths and emigrants (people moving out of the area).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>28", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "Labour productivity is defined as", "images": [], "options": {"A": "output per man hour", "B": "average output", "C": "the maximum number of hours worked", "D": "total output of labour"}, "answer": "A", "explanation": "Labour productivity is defined as output per man hour. It is a measure of the efficiency of a worker or group of workers performing a task. It is calculated by dividing the total output by the total number of man-hours. It is not the average output, the maximum number of hours worked, or the total output of labour.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>29", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "Which of the following problems has the least effect on agricultural productivity in West Africa?", "images": [], "options": {"A": "Incidence of pests and diseases", "B": "Unfavourable weather conditions", "C": "Urban-rural migration", "D": "Illiteracy"}, "answer": "C", "explanation": "Urban-rural migration has the least effect on agricultural productivity in West Africa. This is because the other options, such as the incidence of pests and diseases, unfavourable weather conditions, and illiteracy, have a more direct and significant impact on agricultural productivity. Urban-rural migration can even potentially increase agricultural productivity if the migrants bring new skills and knowledge to the rural areas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>30", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "The location of iron and steel industry at a place is due to", "images": [], "options": {"A": "easy access to raw material", "B": "access to cheap labour", "C": "government policy", "D": "good infrastructure"}, "answer": "A", "explanation": "The location of iron and steel industry at a place is primarily due to easy access to raw materials. Iron and steel industry is a heavy industry that requires large quantities of heavy and bulky raw materials such as iron ore, coal, and limestone. The cost of transporting these materials can be high, so industries often choose to locate near the source of raw materials to reduce transportation costs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>31", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Import substitution as a strategy of industrialization is the", "images": [], "options": {"A": "replacement of locally produced goods with imported ones", "B": "development of local firms to produce local goods that are imported", "C": "establishement of firms to process imported raw materials", "D": "act of using local inputs to produce goods for export"}, "answer": "B", "explanation": "Import substitution as a strategy of industrialization is the development of local firms to produce goods that are imported. The idea behind this strategy is to reduce dependency on foreign goods and promote the growth of domestic industries. This strategy was widely used by developing countries in the mid-20th century to promote their industrial sectors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>32", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "Which of the following are intermediate products?", "images": [], "options": {"A": "cement and steel", "B": "furniture and shirt", "C": "handkerchief and shoe", "D": "table and door"}, "answer": "A", "explanation": "Intermediate products are those products that are used as inputs in the production of other goods. They are not final goods and are used in the production process of other goods. Cement and steel are examples of intermediate products as they are used in the construction industry to produce buildings and other structures. Furniture, shirts, handkerchiefs, shoes, tables, and doors are all final goods, not intermediate products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>33", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "How is NNP at factor cost derived from GNP at market prices?", "images": [], "options": {"A": "GNP - Depreciation + Indirect taxes + Subsidies", "B": "GNP - Depreciation - Indirect taxes + Subsidies", "C": "GNP + Depreciation + indirect taxes - Subsidies", "D": "GNP + Depreciation - Indirect taxes + SUbsidies"}, "answer": "B", "explanation": "Net National Product (NNP) at factor cost is derived from Gross National Product (GNP) at market prices by subtracting depreciation and indirect taxes, and adding subsidies. This is because depreciation is the wear and tear of capital goods which should be deducted from GNP. Indirect taxes increase the market price hence should be subtracted, while subsidies reduce the factor cost hence should be added.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>34", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "NATIONAL INCOME : PROBLEMS OF NATIONAL INCOME", "question": "Which of the following factors may lead to under-estimation of national income figures?", "images": [], "options": {"A": "availability of skilled statisticians", "B": "high volume of exports", "C": "emigrations of skilled workers to foreign countries", "D": "subsistence production"}, "answer": "D", "explanation": "Subsistence production may lead to under-estimation of national income figures. This is because subsistence production refers to the production of goods for personal consumption and not for sale in the market. As such, these goods are often not counted in the calculation of national income, leading to an underestimation of the true economic activity in a country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>35", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Inflation may occur if", "images": [], "options": {"A": "rate of productivity is higher than wage rate", "B": "prices fluctuate during a particular season of the year", "C": "wage increase is granted without increase in productivity", "D": "the government embarks on restrictive monetary policies"}, "answer": "C", "explanation": "Inflation may occur if wage increase is granted without an increase in productivity. This is because when wages are increased without a corresponding increase in productivity, it means that the cost of production has increased. If the cost of production increases, producers may pass on this cost to consumers in the form of higher prices, leading to inflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>36", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "Money would cease to be good store of value when", "images": [], "options": {"A": "prices of goods and services are fallng slowly", "B": "there is high level of unemployment", "C": "prices of goods and services are rising rapidly", "D": "prices of goods and services are rising slowly"}, "answer": "C", "explanation": "Money would cease to be a good store of value when prices of goods and services are rising rapidly. This is because inflation erodes the purchasing power of money. When prices rise rapidly, the value of money falls as it can buy fewer goods and services. This makes it a poor store of value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>37", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Governments in West Africa can curtail inflation by", "images": [], "options": {"A": "purchasing securities in the open market", "B": "selling securities in the open market", "C": "encouraging importation of goods from all countries", "D": "encouraging banks to lead for consumption"}, "answer": "B", "explanation": "Governments in West Africa can curtail inflation by selling securities in the open market. This is a monetary policy tool known as open market operations. When the government sells securities, it reduces the amount of money in circulation, which helps to reduce inflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>38", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "The central bank can reduce the ability of commercial banks to give out loans by", "images": [], "options": {"A": "raising the bank rate", "B": "reducing special deposit", "C": "reducing the liquidity ratio", "D": "issuing more currency"}, "answer": "A", "explanation": "The central bank can reduce the ability of commercial banks to give out loans by raising the bank rate. The bank rate is the interest rate at which the central bank lends money to commercial banks. When this rate is increased, it becomes more expensive for commercial banks to borrow money from the central bank, which reduces their ability to give out loans.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>39", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "Tools of monetary policy do not inculde", "images": [], "options": {"A": "open market operations", "B": "reserve requirement", "C": "bank rate", "D": "tax and public expenditure"}, "answer": "D", "explanation": "Monetary policy is the macroeconomic policy laid down by the central bank. It involves management of money supply and interest rate and is the demand side economic policy used by the government of a country to achieve macroeconomic objectives like inflation, consumption, growth and liquidity. The tools of monetary policy include open market operations, reserve requirement, and bank rate. Tax and public expenditure are tools of fiscal policy, not monetary policy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>40", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "PUBLIC FINANCE : FISCAL POLICY", "question": "During inflation, the appropriate fiscal measure to adopt is to", "images": [], "options": {"A": "increase indirect taxes", "B": "increase direct taxes", "C": "reduce personal income tax", "D": "increase government expenditure"}, "answer": "B", "explanation": "During inflation, the appropriate fiscal measure to adopt is to increase direct taxes. Inflation is a general increase in prices and fall in the purchasing value of money. By increasing direct taxes, the disposable income of individuals decreases which in turn reduces their purchasing power. This can help to control inflation as it reduces demand for goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>41", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION", "question": "Mr. X and Mrs. Y pay $500.00 and $1,400.00 as taxes on their earnings of $5,000.00 and $7,000.00 respectively. The system of taxation employed is", "images": [], "options": {"A": "specific tax", "B": "proportional tax", "C": "regressive tax", "D": "progressive tax"}, "answer": "C", "explanation": "The system of taxation employed is regressive tax. A regressive tax is a tax applied uniformly, taking a larger percentage of income from low-income earners than from high-income earners. It is in opposition to a progressive tax, which takes a larger percentage from high-income earners. In this case, Mr. X pays 10% of his earnings as tax while Mrs. Y pays 20% of her earnings as tax. Therefore, the tax is regressive as it takes a larger percentage from the lower income earner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>42", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Expenditure on food takes a large proportion of incomes of people in", "images": [], "options": {"A": "Industrialized countries", "B": "advanced countries", "C": "developing countries", "D": "capitalist countries"}, "answer": "C", "explanation": "Expenditure on food takes a large proportion of incomes of people in developing countries. This is because in developing countries, a significant portion of income is spent on basic needs such as food, clothing, and shelter. In contrast, in industrialized or advanced countries, a smaller proportion of income is spent on food as income levels are generally higher and basic needs are more easily met.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>43", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "A country should embark on development planning to ensure that", "images": [], "options": {"A": "it becomes popular among the comity of nations", "B": "it also do what others are doing", "C": "its scare productive resources are efficiently utilized", "D": "the nation is able to contribute its own quota to international organizations"}, "answer": "C", "explanation": "A country should embark on development planning to ensure that its scarce productive resources are efficiently utilized. Development planning is a strategic plan for economic development that aims to improve the economic and social well-being of a community. It involves the allocation of limited resources, such as labor, capital, and natural resources, in a way that maximizes the production of goods and services. This helps to ensure that resources are not wasted, but are used in the most efficient way possible.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>44", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "A country is allowed to import just 50,000 tonnes of rice annually.  This describes", "images": [], "options": {"A": "devaluation", "B": "tariff", "C": "embargo", "D": "quota"}, "answer": "D", "explanation": "A country is allowed to import just 50,000 tonnes of rice annually. This describes a quota. A quota is a type of trade restriction that sets a physical limit on the quantity of a good that can be imported during a specific period. It is used to protect domestic producers from competition by limiting the amount of foreign goods that can enter the country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>45", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Dumping is selling goods in a foreign market at a price", "images": [], "options": {"A": "below what is sold at the home market", "B": "above what is sold at the home market", "C": "equal to what is sold at the home market", "D": "equal to the cost of producing the goods"}, "answer": "A", "explanation": "Dumping is a term used in the context of international trade. It's when a country or company exports a product at a price that is lower in the foreign importing market than the price in the exporter's domestic market. Hence, the correct answer is 'below what is sold at the home market'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>46", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "INTERNATIONAL TRADE : ECONOMIC INTEGRATION IN AFRICA", "question": "The principle of comparative advantage encourages a country to", "images": [], "options": {"A": "produce only consumer goods", "B": "engage in trade if its can produce a commodity at a lower cost", "C": "specialize in the production of all goods", "D": "try as much as possible to be self - sufficient"}, "answer": "B", "explanation": "The principle of comparative advantage suggests that a country should engage in trade if it can produce a commodity at a lower opportunity cost than other countries. It doesn't mean that the country should produce only consumer goods or all goods, or try to be self-sufficient. Rather, it should specialize in producing and exporting only those goods and services which it can produce more efficiently.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>47", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "In order to discourage the importation of manufactured goods, a country should adopt", "images": [], "options": {"A": "import promotion strategy", "B": "export led strategy", "C": "liberal foreign exchange", "D": "import substitution strategy"}, "answer": "D", "explanation": "To discourage the importation of manufactured goods, a country should adopt an 'import substitution strategy'. This strategy encourages domestic industries to produce goods that the country would otherwise import. This reduces dependency on foreign goods and strengthens the domestic manufacturing sector.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2020>48", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "A free trade area is one in which", "images": [], "options": {"A": "each member operates its own barriers against non-members", "B": "factors of production are mobile", "C": "members adopts a common external tariff against non-members", "D": "members adopt common fiscal and economic policies"}, "answer": "A", "explanation": "A free trade area is a region where a group of countries has signed a free trade agreement, and they do not impose tariffs, quotas or other trade barriers on each other. However, each country in the free trade area maintains its own trade policies, including tariffs and other trade barriers, with countries outside the free trade area. Therefore, the correct answer is 'each member operates its own barriers against non-members'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2020>49", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "The foremost objective of the International Bank of Reconstruction and Development (IBRD) is to", "images": [], "options": {"A": "help promote private and public investments", "B": "assist members achieve balance of payments stability", "C": "grants long term loan for infrastructure", "D": "maintain stabilty of foreign exchange"}, "answer": "A", "explanation": "The International Bank for Reconstruction and Development (IBRD) is a global development cooperative owned by 189 member countries. The foremost objective of the IBRD is to reduce poverty in middle-income and creditworthy poorer countries by promoting sustainable development through loans, guarantees, risk management products, and analytical and advisory services. Therefore, the correct answer is 'help promote private and public investments'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2020>50", "subject": "Economics", "year": "2020", "type": "Objective", "topic": "THEORY OF PRODUCTION : INTRODUCTION", "question": "The exploitation of mineral resources constitutes which form of production?", "images": [], "options": {"A": "primary production", "B": "secondary production", "C": "tertiary production", "D": "services production"}, "answer": "A", "explanation": "The exploitation of mineral resources is a form of primary production. Primary production refers to the sector of an economy that involves the extraction and harvesting of natural resources. It includes activities such as mining, agriculture, forestry, fishing, and quarrying. Therefore, the correct answer is 'primary production'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2021>1", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The study of economics is important to every society because it", "images": [], "options": {"A": "enables individuals to satisfy all their wants", "B": "helps in the utilization of scarce resources", "C": "helps producers to know what to produce", "D": "restore equilibrium between producers and consumers"}, "answer": "B", "explanation": "Economics is the study of how societies, governments, businesses, households, and individuals allocate their scarce resources. It helps in the utilization of scarce resources by determining what to produce, how to produce, and for whom to produce. The other options are not entirely correct because economics does not enable individuals to satisfy all their wants due to the concept of scarcity, it does not directly help producers to know what to produce, and it does not restore equilibrium between producers and consumers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2021>2", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT", "question": "A consumer with $10 needs a dress, a pair of shoes, a handbag and jewellery costing $20, $10, $7 and $3 respectively. The opportunity cost of buying the pair of shoes is the", "images": [], "options": {"A": "dress", "B": "jewellery", "C": "handbag and jewellery", "D": "dress and jewellery"}, "answer": "C", "explanation": "Opportunity cost in economics refers to the value of the next best alternative that must be given up to obtain something else. If the consumer chooses to buy the pair of shoes costing $10, they will be left with no money, thus giving up the opportunity to buy the handbag and jewellery which together cost $10. The other options are not correct because the dress costs $20 which is more than the consumer's budget, and the dress and jewellery together also cost more than the consumer's budget.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>3", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "The distinguishing function of an entrepreneur is", "images": [], "options": {"A": "planning", "B": "control", "C": "risk-bearing", "D": "management"}, "answer": "C", "explanation": "The distinguishing function of an entrepreneur is risk-bearing. Entrepreneurs are individuals who, rather than working as an employee, found and run small businesses, assuming all the risks and rewards of the venture. The other options such as planning, control, and management are functions that can be performed by managers and do not specifically distinguish an entrepreneur.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2021>4", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET", "question": "When a commodity market operates without government interference, commodities are distributed through", "images": [], "options": {"A": "government distribution agencies", "B": "the operation of price mechanism", "C": "a central planning committee", "D": "retailers only"}, "answer": "B", "explanation": "In a free market economy, where there is no government interference, commodities are distributed through the operation of price mechanism. The price mechanism is a system where the forces of supply and demand interact to determine the price of a commodity. When demand for a commodity is high, the price increases and when the supply of a commodity is high, the price decreases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>5", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "One way of obtaining the median of a given data is to", "images": [], "options": {"A": "sum the value and divide by the number of items", "B": "arrange the data in ascending order and subtract each item from the mean", "C": "arrange the data in descending order and add each item to the least", "D": "arrange the data in either ascending or descending order and find what item divides the set in two equal parts"}, "answer": "D", "explanation": "The median of a given data set is the middle value when the data is arranged in either ascending or descending order. If the data set has an odd number of observations, the median is the middle value. If the data set has an even number of observations, the median is the average of the two middle values.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>6", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "An increase in rice harvest, all things being equal, may cause", "images": [], "options": {"A": "price to increase substantially", "B": "price to fall substantially", "C": "demand to fall substantially", "D": "farmer's incomes to be more than doubled"}, "answer": "B", "explanation": "In economics, when the supply of a commodity increases, all other things being equal, the price of the commodity tends to fall. This is because the increased supply creates a surplus in the market, which puts downward pressure on the price. Therefore, an increase in rice harvest would likely cause the price of rice to fall substantially.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>7", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "The demand for wood and labour is an example of", "images": [], "options": {"A": "effective demand", "B": "complementary demand", "C": "derived demand", "D": "competitive demand"}, "answer": "C", "explanation": "The demand for wood and labour is an example of derived demand. Derived demand refers to the demand for goods and services that arises not for its own sake but due to the demand for another good or service. For instance, the demand for wood and labour arises due to the demand for furniture, construction, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>8", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "What will be the reaction of consumers in a market if there is a fall in the price of the substitute of commodity X?", "images": [], "options": {"A": "Price of commodity X will increase", "B": "Demand for the substitute of commodity X will decrease", "C": "Demand for commodity X will decrease", "D": "Supply of both commodity X and its substitute will increase"}, "answer": "C", "explanation": "If there is a fall in the price of the substitute of commodity X, consumers will likely switch to the substitute because it's now cheaper. This will cause the demand for commodity X to decrease.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2021>9", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "An increase in market supply is caused by the following factors except", "images": [], "options": {"A": "an improvement in innovation and technology", "B": "an increase in the price of the commodity", "C": "a reduction in the cost of raw materials", "D": "a favourable weather condition"}, "answer": "B", "explanation": "An increase in the price of the commodity does not cause an increase in market supply. In fact, it's the opposite. An increase in the price of a commodity can lead to an increase in the quantity supplied (as suppliers are willing to supply more at higher prices), but it does not shift the supply curve or increase market supply. The other options (improvement in innovation and technology, reduction in the cost of raw materials, and favourable weather conditions) can all lead to an increase in market supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>10", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "The coefficient of price elasticity of supply of land is usually", "images": [], "options": {"A": "one", "B": "greater than one", "C": "zero", "D": "less than one"}, "answer": "C", "explanation": "The coefficient of price elasticity of supply of land is usually zero. This is because the supply of land is perfectly inelastic, meaning it does not respond to changes in price. The quantity of land is fixed and cannot be increased or decreased in response to changes in price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>11", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "The price of soap rose from $10 to $20, causing a trader to increase her supply from 50 to 120 boxes per week. This makes supply", "images": [], "options": {"A": "unitary elastic", "B": "perfectly inelastic", "C": "fairly elastic", "D": "inelastic"}, "answer": "C", "explanation": "The price elasticity of supply can be calculated using the formula: % change in quantity supplied / % change in price. In this case, the % change in quantity supplied is (120-50)/50 = 1.4 and the % change in price is (20-10)/10 = 1. Therefore, the price elasticity of supply is 1.4/1 = 1.4, which is greater than 1. This means the supply is fairly elastic, meaning that the quantity supplied is responsive to changes in price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>12", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "A leftward shift in the supply curve for a commodity indicates", "images": [], "options": {"A": "an increase in quantity supplied", "B": "a decrease in supply", "C": "a reduction in quantity supplied", "D": "an increase in supply"}, "answer": "B", "explanation": "A leftward shift in the supply curve for a commodity indicates a decrease in supply. This could be due to a number of factors such as an increase in production costs, a decrease in technology, or a decrease in the number of suppliers. This shift means that at every price level, the quantity supplied is less than before.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>13", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Market supply may increase if there is an increase in the", "images": [], "options": {"A": "price of the product", "B": "prices of factors of production", "C": "tax paid on raw materials", "D": "subsidies on raw materials"}, "answer": "D", "explanation": "Subsidies on raw materials reduce the cost of production, encouraging producers to produce more, hence increasing the market supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>14", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "PUBLIC FINANCE : FISCAL POLICY", "question": "Governments can increase farmers' incomes by", "images": [], "options": {"A": "fixing maximum prices", "B": "fixing minimum price", "C": "encouraging them to produce surplus output", "D": "increasing taxes on inputs"}, "answer": "B", "explanation": "Fixing minimum prices ensures that farmers receive a certain amount of income for their products, regardless of the market conditions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2021>15", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "When market supply increases, the equilibrium price", "images": [], "options": {"A": "rises and quantity falls", "B": "falls and quantity rises", "C": "and quantity increase", "D": "and quantity fall"}, "answer": "B", "explanation": "An increase in supply, with demand remaining constant, leads to a surplus in the market. This surplus puts downward pressure on the price until it falls to a level where the quantity supplied equals the quantity demanded, i.e., the equilibrium point.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>16", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "The supply of mangoes is represented as P = 0.3Q, where P is the price ($) and Q is the quantity. What is P when Q is 50?", "images": [], "options": {"A": "$1.50", "B": "$15.00", "C": "$150.03", "D": "$166.67"}, "answer": "B", "explanation": "The supply of mangoes is represented as P = 0.3Q. To find the price (P) when the quantity (Q) is 50, we substitute Q = 50 into the equation. This gives P = 0.3 * 50 = $15.00. Therefore, the correct answer is $15.00.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>17", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "The output of an extra unit of input is referred to as", "images": [], "options": {"A": "output of the input", "B": "marginal product of the input", "C": "average product of the input", "D": "utility of the input employed"}, "answer": "B", "explanation": "The output of an extra unit of input is referred to as the marginal product of the input. This is a concept in economics that describes the additional output that can be produced by adding one more unit of a specific input, while holding all other inputs constant. Therefore, the correct answer is 'marginal product of the input'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>18", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION", "question": "The law of diminishing returns is applicable to the", "images": [], "options": {"A": "fixed inputs of production", "B": "variable factors of production", "C": "plants and machinery of the firm", "D": "equipment and other capital"}, "answer": "B", "explanation": "The law of diminishing returns, also known as the law of variable proportions, states that if one input in the production of a commodity is increased while all other inputs are held fixed, a point will eventually be reached at which additions of the input yield progressively smaller, or diminishing, increases in output. This law is applicable to the variable factors of production. Therefore, the correct answer is 'variable factors of production'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>19", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : ACCOUNTANTS & ECONOMIST VIEW ON COST", "question": "A firm incurred the following costs in production. Use the information in the table to answer questions below    Output(bags of rice)\t0\t10\t20\t30\t40\t50\t60\tTotal cost$\t100\t200\t300\t380\t440\t520\t600\t    The fixed cost of production is", "images": [], "options": {"A": "$100", "B": "$200", "C": "$300", "D": "$600"}, "answer": "A", "explanation": "Fixed cost is the cost that does not change with the level of output. It is the cost incurred even when the output is zero. From the table, when the output is zero, the total cost is $100. Therefore, the fixed cost of production is $100.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2021>20", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE", "question": "A firm incurred the following costs in production. Use the information in the table to answer questions below    Output(bags of rice)\t0\t10\t20\t30\t40\t50\t60\tTotal cost$\t100\t200\t300\t380\t440\t520\t600\t  The average cost of producing 40 bags of rice is", "images": [], "options": {"A": "$10", "B": "$11", "C": "$60", "D": "$80"}, "answer": "B", "explanation": "Average cost is calculated by dividing the total cost by the quantity of output. From the table, the total cost of producing 40 bags of rice is $440. Therefore, the average cost of producing 40 bags of rice is $440/40 = $11.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2021>21", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "The relationship between the marginal revenue (MR) and the average revenue (AR) of a monopolist is that the marginal revenue curve", "images": [], "options": {"A": "is above the average revenue curve", "B": "slopes down to the right and is below the AR curve", "C": "and the AR curve are downward sloping and are identical", "D": "is vertical while the average revenue curve is horizontal"}, "answer": "B", "explanation": "In a monopoly, the marginal revenue (MR) curve is always below the average revenue (AR) curve and slopes downwards. This is because a monopolist can only sell more by lowering the price, which reduces both the average revenue and the marginal revenue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>22", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS", "question": "A major source of finance to the Railway Corporation in West African countries is", "images": [], "options": {"A": "sale of shares", "B": "government subvention", "C": "trade credit", "D": "surplus"}, "answer": "B", "explanation": "The major source of finance for the Railway Corporation in West African countries is government subvention. Government subvention refers to the financial aid or support that a government provides to a particular entity or a group of entities. In this case, the government provides financial support to the Railway Corporation to ensure its smooth operation and maintenance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>23", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Separation of ownership of resources and their control is mostly found in a", "images": [], "options": {"A": "sole proprietorship", "B": "partnership", "C": "joint stock company", "D": "consumer co-operative"}, "answer": "C", "explanation": "The separation of ownership of resources and their control is mostly found in a joint stock company. In a joint stock company, the shareholders are the owners of the company but the control is in the hands of the board of directors. The shareholders have limited liability and they are not involved in the day-to-day operations of the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>24", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "By-passing the middlemen in the chain of distribution can lead to", "images": [], "options": {"A": "a problem of unemployment of labour", "B": "the creation of artificial scarcity", "C": "high prices of goods and services", "D": "an increase in government tax revenue"}, "answer": "A", "explanation": "By-passing the middlemen in the chain of distribution can lead to a problem of unemployment of labour. Middlemen play a crucial role in the distribution of goods and services from producers to consumers. If they are bypassed, it could lead to unemployment as these middlemen would lose their jobs. This is because the role they play in the distribution chain would be eliminated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>25", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "Two factors which can improve the efficiency of labour are", "images": [], "options": {"A": "population size and age of retirement", "B": "school leaving age and number of disabled workers", "C": "work environment and health status of workers", "D": "school leaving age and number of part-time workers"}, "answer": "C", "explanation": "The efficiency of labour can be improved by enhancing the work environment and the health status of workers. A conducive work environment can boost the morale and productivity of workers. Similarly, a healthy worker is more likely to be productive than an unhealthy one. Therefore, the correct answer is option 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>26", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION", "question": "The age distribution of a country's population is shown below. Use the information to answer questions below  AGE GROUP (YEARS)\tPOPULATION\t0-15\t30%\t16-40\t45%\t41-60\t15%\tOver 60\t10%\t    What is the percentage of the working population?", "images": [], "options": {"A": "75%", "B": "60%", "C": "45%", "D": "15%"}, "answer": "B", "explanation": "16 - 40 and 41 - 60 are working population.   i.e. 45 + 15 = 60%", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2021>27", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION", "question": "The age distribution of a country's population is shown below. Use the information to answer questions below  AGE GROUP (YEARS)\tPOPULATION\t0-15\t30%\t16-40\t45%\t41-60\t15%\tOver 60\t10%\t  What is the dependency ratio?", "images": [], "options": {"A": "2:3", "B": "3:2", "C": "1:2", "D": "6:1"}, "answer": "A", "explanation": "Dependent population = Dependent pop / Independent pop   Dependent pop = 30 + 10 = 40   Independent pop = 45 + 15 = 60   Dep pop = 40/60   = 2:3", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2021>28", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "The supply of land for agricultural purpose can be increased through", "images": [], "options": {"A": "the introduction of mechanized farming", "B": "reclamation and irrigation", "C": "increase in prices of land", "D": "conversion of building sites to farmlands"}, "answer": "B", "explanation": "The supply of land for agricultural purposes can be increased through reclamation and irrigation. Reclamation refers to the process of creating new land from oceans, riverbeds, or lake beds, while irrigation involves the application of controlled amounts of water to plants at needed intervals. Both processes can help increase the amount of land available for agricultural purposes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>29", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Non-economic factors that influence the location of firms include", "images": [], "options": {"A": "the existence of required materials for production", "B": "availability of population of buyers", "C": "adequate supply of power, good road, and rail network", "D": "the activities of politicians in deciding location of firms"}, "answer": "D", "explanation": "Non-economic factors that influence the location of firms include the activities of politicians in deciding the location of firms. This is because political factors such as government policies, regulations, and political stability can significantly influence where a firm chooses to locate its operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>30", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "Which of the following is not an argument for the policy of privatization in West Africa?", "images": [], "options": {"A": "To make businesses more profitable", "B": "Government is able to participate and control the operation of the privatized businesses", "C": "Members of the public are able to acquire shares", "D": "It encourages the inflow of capital and expertise from local and foreign sources"}, "answer": "B", "explanation": "The statement 'Government is able to participate and control the operation of the privatized businesses' is not an argument for the policy of privatization in West Africa. Privatization is the process of transferring an enterprise or industry from the public sector to the private sector. The main idea behind this process is to allow for greater private sector participation and reduce government involvement in the economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>31", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The following data relates to the national income of a country.   Gross domestic product = $2800   Net factor income from abroad =$250   Depreciation = $700   Indirect taxes = $120  Use it to answer questions 31 and 32  What is the country's Gross National Product (GNP)?", "images": [], "options": {"A": "$3,050", "B": "$2,680", "C": "$2,350", "D": "$2,100"}, "answer": "A", "explanation": "Gross National Product (GNP) is calculated by adding the Gross Domestic Product (GDP) and the Net Factor Income from Abroad. So, GNP = GDP + Net Factor Income from Abroad = $2800 + $250 = $3050.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2021>32", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "What is the country's Net National Product (NNP) at factor cost?", "images": [], "options": {"A": "$3,050", "B": "$2,680", "C": "$2,230", "D": "$2,220"}, "answer": "C", "explanation": "Net National Product (NNP) at factor cost is calculated by subtracting Depreciation and Indirect taxes from the GNP. So, NNP at factor cost = GNP - Depreciation - Indirect taxes = $3050 - $700 - $120 = $2230.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2021>33", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "NATIONAL INCOME : DIFFERENCE BETWEEN STANDARD OF LIVING & COST OF LIVING", "question": "The standard of living in two countries can be compared using the", "images": [], "options": {"A": "number of industries in each country", "B": "size of their arms and ammunition", "C": "size of their national incomes only", "D": "gross national product per head"}, "answer": "D", "explanation": "The standard of living in two countries can be compared using the Gross National Product per head. This is because it gives the average income of a citizen in a country, which is a good indicator of the standard of living.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>34", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Government can curb inflation by", "images": [], "options": {"A": "encouraging banks to lend for may purpose", "B": "increasing her own expenditure", "C": "buying treasury bills in the open market", "D": "selling securities in the open market"}, "answer": "D", "explanation": "Inflation can be curbed by the government by selling securities in the open market. This is because when the government sells securities, it reduces the amount of money in circulation, which in turn reduces the demand for goods and services, thereby reducing inflation. This is a monetary policy tool known as open market operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>35", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "Functions of money does not include", "images": [], "options": {"A": "store of value", "B": "medium of exchange", "C": "standard of deferred payment", "D": "general acceptability"}, "answer": "D", "explanation": "The functions of money are:   - store of value   - standard of deferred payment   - medium of exchange   - unit of account", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2021>36", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "Demand -Pull inflation can be as a result of", "images": [], "options": {"A": "increase in the cost of production", "B": "excessive supply of foodstuff", "C": "deficit financing by the government", "D": "increase in import duties"}, "answer": "C", "explanation": "Demand-Pull inflation can be a result of deficit financing by the government. Deficit financing refers to the government's spending more than it collects in revenue. This increases the demand for goods and services, which can lead to inflation if the supply does not keep up with the demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>37", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "An increase in cash ratio by the central bank will", "images": [], "options": {"A": "increase the supply of money", "B": "increase banks' lending", "C": "encourage borrowing", "D": "reduce the supply of money"}, "answer": "D", "explanation": "The cash ratio is a measure of a bank's liquidity and ability to meet its obligations. An increase in the cash ratio by the central bank means that banks are required to hold more reserves and thus, they have less money to lend out. This reduces the supply of money in the economy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2021>38", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL", "question": "When the government cuts down her expenditure to reduce inflation, she has embarked on", "images": [], "options": {"A": "a restrictive fiscal policy", "B": "an expansionary monetary policy", "C": "physical policy", "D": "implementing budget deficit"}, "answer": "A", "explanation": "A restrictive fiscal policy is a type of policy that is used to combat inflation. It involves reducing government spending and/or increasing taxes. This reduces the amount of money in circulation, which can help to reduce inflation. Therefore, when the government cuts down her expenditure to reduce inflation, she has embarked on a restrictive fiscal policy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>39", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "In order to enable the government of a country to increase its tax revenue, it will be advisable for it to increase taxes on", "images": [], "options": {"A": "textile materials with elastic demand", "B": "alcoholic beverages with inelastic demand", "C": "agricultural products with inelastic supply", "D": "luxury goods with elastic supply"}, "answer": "B", "explanation": "Inelastic demand refers to a situation where the demand for a product does not change significantly with changes in price. Therefore, increasing taxes on goods with inelastic demand, such as alcoholic beverages, would not significantly affect their consumption but would increase the government's tax revenue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>40", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "People who dispose of their assets are expected to pay", "images": [], "options": {"A": "value added tax", "B": "capital gains tax", "C": "expenditure tax", "D": "sales tax"}, "answer": "B", "explanation": "People who dispose of their assets are expected to pay capital gains tax. Capital gains tax is a tax on the profit when you sell (or 'dispose of') something (an 'asset') that's increased in value. It's the gain you make that's taxed, not the amount of money you receive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>41", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "A floating exchange rate means that the exchange rate is fixed by the", "images": [], "options": {"A": "central bank of the country", "B": "forces of demand of supply", "C": "International Monetary Fund(IMF)", "D": "Ministry of Finance"}, "answer": "B", "explanation": "A floating exchange rate means that the exchange rate is determined by the forces of demand and supply. In a floating exchange rate system, when the demand for a currency is low, its value decreases just as with any other product or service. But when the demand is high, the value increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>42", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "A measure that can be adopted to correct a country's balance of payments deficit is to", "images": [], "options": {"A": "allow the currency to appreciate to encourage inports", "B": "allow the currency to depreciate to encourage imports", "C": "adopt import substitution strategy", "D": "restrict trade with all countries"}, "answer": "C", "explanation": "A measure that can be adopted to correct a country's balance of payments deficit is to adopt import substitution strategy. Import substitution industrialization (ISI) is a trade and economic policy which advocates replacing foreign imports with domestic production. It is based on the premise that a country should attempt to reduce its foreign dependency through the local production of industrialized products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>43", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Records of a country's invisible trade are recorded in her", "images": [], "options": {"A": "trade account", "B": "capital account", "C": "current account", "D": "financial account"}, "answer": "C", "explanation": "Invisible trade refers to the trading of services and other non-tangible goods, which are recorded in the current account of a country's balance of payments. The current account includes transactions in goods, services, income, and current transfers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>44", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "If a country's import bill is high, she can encourage exports by", "images": [], "options": {"A": "allowing her currency to depreciate", "B": "allowing her currency to appreciate", "C": "liberalizing importation", "D": "increasing taxes on all locally produced goods"}, "answer": "A", "explanation": "When a country's currency depreciates, its goods and services become cheaper for foreign buyers, which can increase demand for its exports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>45", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "If a country's imposes a barrier on trade, the resultant effect will be", "images": [], "options": {"A": "a halt in buying and selling", "B": "high quality goods from local industries", "C": "an increase in the demand for locally produced goods", "D": "shutdown of infant industries"}, "answer": "C", "explanation": "Trade barriers, such as tariffs and quotas, make imported goods more expensive, which can increase demand for cheaper, locally produced goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>46", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "A country may be able to earn more from exports if she", "images": [], "options": {"A": "increases her export", "B": "devalues her currency", "C": "increases her import duty", "D": "allows her currency to appreciate"}, "answer": "B", "explanation": "Devaluing a country's currency can make its exports cheaper and more attractive to foreign buyers, potentially leading to an increase in export earnings. This is because when a country devalues its currency, the price of its goods and services decreases in terms of foreign currency, making them more competitive in the global market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>47", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "A customs union is an economic grouping which has", "images": [], "options": {"A": "free movement of factors of production", "B": "common tariffs against non-members", "C": "common currency for trading", "D": "common military defence"}, "answer": "B", "explanation": "A customs union is a type of trade bloc which is composed of a free trade area with a common external tariff. The participant countries set up common external trade policy, but in some cases they use different import quotas. Common competition policy is also helpful to avoid competition deficiency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>48", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "Balance of payments and trade problems that arose after the world wars were resolved by the", "images": [], "options": {"A": "International Bank for Reconstruction and Development", "B": "International Monetary Fund", "C": "African Development Bank", "D": "Organization of Petroleum Exporting Countries"}, "answer": "B", "explanation": "The International Monetary Fund (IMF) was created in 1944 to help manage and stabilize the global monetary system, particularly in the aftermath of World War II. It provides financial assistance to countries facing balance of payments problems, helping to stabilize international exchange rates and facilitate global trade.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2021>49", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "Examples of land that are non-renewable include", "images": [], "options": {"A": "marshy and water-logged land", "B": "farmlands already used for many years", "C": "some natural resources such as natural gas", "D": "oxygen and carbon dioxide in the atmosphere"}, "answer": "C", "explanation": "Land in economics refers to all naturally occurring resources. Natural gas is a naturally occurring resource that is non-renewable because once it is used, it cannot be replenished. Therefore, it is an example of non-renewable land.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2021>50", "subject": "Economics", "year": "2021", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Abundant natural resources do not contribute to economic growth in developing countries because of", "images": [], "options": {"A": "high rate of inflation", "B": "urban congestion", "C": "over-reliance on multiple commodities", "D": "mismanagement and corruption"}, "answer": "D", "explanation": "Abundant natural resources do not contribute to economic growth in developing countries mainly due to mismanagement and corruption. These factors prevent the efficient use and allocation of these resources, thereby hindering economic growth.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>1", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT", "question": "Scale of preference shows", "images": [], "options": {"A": "incomes of consumers in order of size", "B": "utilities enjoyed by consumers", "C": "opportunity cost of goods consumed", "D": "consumer's wants in order of priority"}, "answer": "D", "explanation": "A scale of preference is an economic concept that refers to listing of wants (needs or desires) in order of importance or priority. It helps consumers make decisions about how to allocate their resources (like time or money) among these wants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2022>2", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE", "question": "There is unemployment of resources when production is", "images": [], "options": {"A": "within the production possibility curve", "B": "outside the production possibility curve", "C": "along the production possibility curve", "D": "adequate to meet market demand"}, "answer": "A", "explanation": "Unemployment of resources occurs when production is within the production possibility curve. The production possibility curve represents the maximum output that an economy can produce with its available resources and technology. If production is within the curve, it means that some resources are not being fully utilized, hence there is unemployment of resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>3", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "A major characteristic of natural resources is that they", "images": [], "options": {"A": "are unlimited in supply", "B": "have high cost of production", "C": "are free gifts of nature", "D": "do not command any price"}, "answer": "C", "explanation": "Natural resources are free gifts of nature. They are not created by human beings but are naturally occurring substances that are considered valuable in their relatively unmodified (natural) form. A natural resource's value rests in the amount and extractability of the material available and the demand for it on the open market.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2022>4", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "A major disadvantage of a capitalist economy is that it", "images": [], "options": {"A": "leads to low production of goods and services", "B": "requires large number of officials to operate", "C": "considers individual consumers' satisfaction", "D": "worsens income inequality among the citizens"}, "answer": "D", "explanation": "A major disadvantage of a capitalist economy is that it worsens income inequality among the citizens. In a capitalist economy, the means of production are privately owned and operated for profit. This often leads to wealth accumulation by a small group of people, thereby creating a wide gap between the rich and the poor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>5", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The mining sector of an economy contributes 60% to the Gross Domestic Product(GDP). If the GDP is $540, what is the contribution of the mining sector?", "images": [], "options": {"A": "$ 90.00", "B": "$ 180.00", "C": "$ 324.00", "D": "$ 350.00"}, "answer": "C", "explanation": "The contribution of the mining sector to the GDP is calculated by multiplying the percentage contribution by the GDP. In this case, 60% of $540 is $324. Therefore, the correct answer is $324.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>6", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "The increase in the demand for a commodity may lead to a decrease in the demand for another if both are", "images": [], "options": {"A": "in complementary demand", "B": "of the same quality", "C": "in composite demand", "D": "in competitive demand"}, "answer": "D", "explanation": "The increase in the demand for a commodity may lead to a decrease in the demand for another if both are in competitive demand. Competitive demand refers to goods that can be used as substitutes for each other. When the demand for one increases, the demand for the other decreases because consumers choose one over the other.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>7", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "The demand curve for goods of ostentation is usually", "images": [], "options": {"A": "negatively sloped", "B": "positively sloped", "C": "vertical", "D": "horizontal"}, "answer": "B", "explanation": "The demand curve for goods of ostentation is usually positively sloped. Goods of ostentation, also known as Veblen goods, are luxury items for which the quantity demanded increases as the price increases, contrary to the law of demand. This is because these goods are perceived as being more valuable when their price is higher, hence the positive slope.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>8", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "Which of the following factors is not a cause of change in demand? Changes in", "images": [], "options": {"A": "taste and fashion", "B": "income distribution", "C": "price of the commodity", "D": "the size of the population"}, "answer": "C", "explanation": "The price of the commodity is not a cause of change in demand but rather it is a determinant of quantity demanded. Changes in demand are caused by non-price factors such as changes in taste and fashion, income distribution, and the size of the population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>9", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If the quantity demanded of a commodity increases from 20 units to 30 units when there is an increase in price from $4.00 to $5.00, the elasticity of demand is", "images": [], "options": {"A": "0.50", "B": "0.65", "C": "2.00", "D": "2.50"}, "answer": "C", "explanation": "e = ∆Qd/∆P   x P/Qd    =  30 - 20/ 5 - 4   x   4/ 20     = 10/1   x  4/20    =  2", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>10", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "The supply curve of a locally-produced good may shift to the right if", "images": [], "options": {"A": "there is an increase in taxes on inputs", "B": "government increases subsidies", "C": "rural-urban migration is encouraged", "D": "the price of the commodity increases"}, "answer": "B", "explanation": "The supply curve of a locally-produced good may shift to the right if there is an increase in subsidies. Subsidies reduce the cost of production, encouraging producers to produce more, hence increasing the supply. An increase in taxes on inputs, rural-urban migration, or the price of the commodity would not cause the supply curve to shift to the right.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>11", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "In perfectly elastic supply, the supply curve", "images": [], "options": {"A": "is vertical", "B": "is horizontal", "C": "slopes upward", "D": "slopes downward"}, "answer": "B", "explanation": "In economics, a perfectly elastic supply means that the quantity supplied can change by a large amount even if the price changes by a very small amount. This is represented by a horizontal supply curve, as any change in price, no matter how small, can lead to a significant change in the quantity supplied.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>12", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THEORY OF SUPPLY : TYPES OF SUPPLY", "question": "An increase in the price of commodity X led to a fall in the supply of commodity Y. Commodities X and Y are", "images": [], "options": {"A": "competitive goods", "B": "composite goods", "C": "jointly supplied", "D": "derived goods"}, "answer": "C", "explanation": "If an increase in the price of commodity X leads to a fall in the supply of commodity Y, it means that commodities X and Y are jointly supplied. Joint supply is a term used in economics to describe a situation where an increase in the supply of one good leads to an increase in the supply of another good. In this case, if the price of commodity X increases, producers may choose to produce more of X and less of Y, leading to a fall in the supply of Y.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>13", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "The production of rice and yam on the same farmland is an example of", "images": [], "options": {"A": "joint supply", "B": "composite supply", "C": "competitive supply", "D": "market supply"}, "answer": "C", "explanation": "The production of rice and yam on the same farmland is an example of competitive supply. Competitive supply refers to a situation where the production of one good competes with the production of another good for the same resources. In this case, the production of rice and yam are competing for the same farmland resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>14", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "A consumer of a single commodity is in equilibrium when", "images": [], "options": {"A": "he can equate his demand with price", "B": "he equates marginal utility and price", "C": "he can equate his marginal and total utilities", "D": "his marginal utility is equal to zero"}, "answer": "B", "explanation": "A consumer of a single commodity is in equilibrium when the marginal utility of the commodity is equal to its price. This is because the consumer will continue to consume the commodity until the satisfaction (utility) derived from the last unit consumed (marginal utility) is equal to the price paid for it. This is known as the law of equi-marginal utility.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>15", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION", "question": "If the government imposes a minimum price on a commodity", "images": [], "options": {"A": "market surplus occurs", "B": "the market will be cleared in the short-run", "C": "excess demand occurs", "D": "government regulation is no longer needed"}, "answer": "A", "explanation": "When the government imposes a minimum price on a commodity, it means that the price of the commodity cannot fall below a certain level. This often leads to a situation where the quantity supplied of the commodity exceeds the quantity demanded, resulting in a market surplus. This is because at a higher price, producers are willing to supply more of the commodity, but consumers are willing to buy less.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>16", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION", "question": "A minimum price legislation is also called", "images": [], "options": {"A": "price ceiling", "B": "price floor", "C": "price control", "D": "price mechanism"}, "answer": "B", "explanation": "A minimum price legislation is also called a price floor. A price floor is a government- or group-imposed price control or limit on how low a price can be charged for a product. A price floor must be higher than the equilibrium price in order to be effective. The equilibrium price, also known as the market price, is the price where economic forces such as supply and demand are balanced and in the absence of external influences the values of economic variables will not change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>17", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION", "question": "Which of the following factors is not a cause of diminishing returns?", "images": [], "options": {"A": "Increase in variable inputs", "B": "Land fragmentation", "C": "Constant technology", "D": "Technological innovations"}, "answer": "D", "explanation": "The law of diminishing returns states that if one input in the production of a commodity is increased while all other inputs are held fixed, a point will eventually be reached at which additions of the input yield progressively smaller, or diminishing, increases in output. Technological innovations, however, can increase the productivity of inputs, thereby offsetting the law of diminishing returns. Therefore, technological innovations are not a cause of diminishing returns.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>18", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION", "question": "In manufacturing, division of labour may be hindered by", "images": [], "options": {"A": "excessive demand for the product", "B": "low level of technology", "C": "excess supply of labour", "D": "increase in the export of goods"}, "answer": "B", "explanation": "Division of labour refers to the assignment of different parts of a manufacturing process or task to different individuals in order to improve efficiency. A low level of technology can hinder the division of labour because it may limit the ability to automate tasks or processes, which can reduce efficiency and productivity. Therefore, a low level of technology can hinder the division of labour in manufacturing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>19", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM", "question": "The production cost that varies inversely with output is the", "images": [], "options": {"A": "total fixed cost", "B": "marginal cost", "C": "average fixed cost", "D": "average cost"}, "answer": "C", "explanation": "Average fixed cost is the total fixed cost per unit of output. As output increases, average fixed cost decreases because the same total fixed cost is spread over a larger number of units of output. Therefore, average fixed cost varies inversely with output.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>20", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS", "question": "A firm that closes down will still incur", "images": [], "options": {"A": "variable cost", "B": "fixed cost", "C": "total cost", "D": "marginal cost"}, "answer": "B", "explanation": "Even if a firm closes down, it will still incur fixed costs. Fixed costs are costs that do not change with the level of output. They are incurred even when the firm is not producing anything. Examples include rent, salaries, and insurance. Variable costs, on the other hand, change with the level of output and will not be incurred if the firm is not producing anything.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>21", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION", "question": "The sufficient condition for a firm to be in equilibrium is that the", "images": [], "options": {"A": "firm must show that it is profitable", "B": "marginal cost must be equal to average revenue", "C": "marginal revenue curve is above the average revenue curve", "D": "marginal cost curve cuts the marginal revenue curve from below"}, "answer": "D", "explanation": "The sufficient condition for a firm to be in equilibrium is that the marginal cost curve cuts the marginal revenue curve from below. This is because at the point where marginal cost equals marginal revenue, the firm maximizes its profit. If the marginal cost is below the marginal revenue, the firm can increase profit by producing more. If the marginal cost is above the marginal revenue, the firm can increase profit by producing less.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>22", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES", "question": "Cooperative societies are formed mainly to", "images": [], "options": {"A": "assist producers to maximize their profits", "B": "encourage thrift and credit among members", "C": "promote and maintain the welfare of members", "D": "break the monopolies of private companies"}, "answer": "C", "explanation": "Cooperative societies are formed mainly to promote and maintain the welfare of members. They are organizations owned and operated by a group of individuals who share the profits and benefits. The main aim is not to maximize profits but to provide services and benefits to members. While they may also encourage thrift and credit among members, assist producers, and break monopolies, their primary purpose is to promote the welfare of their members.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2022>23", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "A disadvantage of a jont-stock company is", "images": [], "options": {"A": "unlimited liability", "B": "limited liability", "C": "lack of continuity when a shareholder dies", "D": "limited control in management by shareholders"}, "answer": "D", "explanation": "A joint-stock company is a type of business entity where the company's stock is owned jointly by shareholders. Each shareholder has limited liability for the company's debt. One disadvantage of a joint-stock company is that shareholders have limited control in the management of the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>24", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN", "question": "The middlemen is responsible for", "images": [], "options": {"A": "providing research facilities", "B": "purchasing raw materials", "C": "designing the product", "D": "breaking the bulk"}, "answer": "D", "explanation": "A middleman in economics refers to an intermediary between the producer and the consumer. One of the main functions of a middleman is to break the bulk, i.e., to buy goods in large quantities from producers and sell them in smaller quantities to consumers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2022>25", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE RETAILER", "question": "A major function of the retailer is to", "images": [], "options": {"A": "grant credit to the wholesaler", "B": "break bulk and sell products in small units", "C": "reduce cost of distribution", "D": "generate demand for products through advertisement"}, "answer": "B", "explanation": "A retailer is a business or person that sells goods to the consumer. One of the main functions of a retailer is to break bulk and sell products in small units.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2022>26", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "A positive effect of a rapid population increase is", "images": [], "options": {"A": "an excessive budget deficit", "B": "a reduction in standard of living", "C": "a wider market for goods and services", "D": "a higher dependency ratio"}, "answer": "C", "explanation": "A rapid population increase can lead to a wider market for goods and services. This is because as the population increases, the demand for goods and services also increases, creating a larger market. This can stimulate economic growth and development. The other options are generally considered negative effects of rapid population increase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>27", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "Which of the following factors may not affect the efficiency of labour?", "images": [], "options": {"A": "Education and training", "B": "Provision of welfare service", "C": "Race and colour of workforce", "D": "Quality of other factor inputs"}, "answer": "C", "explanation": "The efficiency of labour is generally not affected by the race and colour of the workforce. Efficiency is more likely to be influenced by factors such as education and training, provision of welfare services, and the quality of other factor inputs. These factors can directly impact the skills, motivation, and productivity of the workforce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>28", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "The type of unemployment found among workers who leave their jobs in search of other jobs is termed", "images": [], "options": {"A": "seasonal unemployment", "B": "structural unemployment", "C": "frictional unemployment", "D": "cyclical unemployment"}, "answer": "C", "explanation": "Frictional unemployment refers to the type of unemployment that occurs when workers leave their jobs to find other jobs. This can occur for various reasons, such as dissatisfaction with the current job, better opportunities elsewhere, or relocation to a new area. The other types of unemployment listed refer to different circumstances: seasonal unemployment occurs when workers are out of work at certain times of the year, structural unemployment occurs when there is a mismatch between the skills workers have and the skills needed in the job market, and cyclical unemployment occurs during periods of economic downturn.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>29", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS", "question": "The main objective of marketing boards is to", "images": [], "options": {"A": "accumulate revenue for government", "B": "educate farmers on pricing of cash crops", "C": "stabilize the incomes of cash crop farmers", "D": "provide warehousing facilities"}, "answer": "C", "explanation": "Marketing boards are established with the primary objective of stabilizing the incomes of cash crop farmers. They do this by buying the crops from the farmers at a fixed price, thereby protecting them from price fluctuations in the market. While they may also perform other functions such as providing warehousing facilities or educating farmers, their main objective is income stabilization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2022>30", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "MARKET STRUCTURE : FORMS OF MARKET STRUCTURE", "question": "The use of mass advertising media enable a firm to enjoy", "images": [], "options": {"A": "managerial economies", "B": "financial economies", "C": "marketing economies", "D": "welfare economies"}, "answer": "C", "explanation": "The use of mass advertising media allows a firm to enjoy marketing economies. Marketing economies are a type of external economies of scale, which occur when a firm's costs per unit decrease due to an increase in the size of the market for its product. By using mass advertising media, a firm can reach a larger audience, potentially increasing its sales and lowering its average cost per unit sold.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>31", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Which of the following industries will add more value to primary products?", "images": [], "options": {"A": "Service industry", "B": "Construction industry", "C": "Mining industry", "D": "Processing industry"}, "answer": "D", "explanation": "The processing industry will add more value to primary products. This is because the processing industry involves transforming raw materials into finished or semi-finished goods. For example, a processing industry might turn wheat into flour, or milk into cheese. This transformation process adds value to the primary products, making them more useful or desirable to consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>32", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "Gross National Product (GNP) less the provision  for the wear and tear of assets is the", "images": [], "options": {"A": "net present value", "B": "net national product", "C": "net factor income", "D": "net indirect taxes"}, "answer": "B", "explanation": "Gross National Product (GNP) less the provision for the wear and tear of assets is known as Net National Product (NNP). The wear and tear of assets is also known as depreciation. Therefore, when we subtract the depreciation from GNP, we get NNP. This is a basic concept in economics that helps in understanding the actual productivity of a nation after considering the depreciation of its assets.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>33", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "An example of transfer payments in national income accounting is", "images": [], "options": {"A": "money transferred to another country", "B": "unemployment allowance paid to the citizens", "C": "the amount paid to a worker on transfer", "D": "transfer of funds from one bank to another"}, "answer": "B", "explanation": "Transfer payments are payments made by the government to individuals for which no current goods or services are exchanged. Unemployment allowance paid to the citizens is an example of transfer payments in national income accounting. These payments are made to individuals who are currently unemployed and are not contributing to the production of goods and services. Therefore, these payments are considered as transfer payments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>34", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION", "question": "Increasing national income without effective control of population size in a country can lead to", "images": [], "options": {"A": "higher per capita income", "B": "increase in poverty", "C": "increased outflow of aid", "D": "underutilization of resources"}, "answer": "B", "explanation": "If national income increases without effective control of population size, it can lead to an increase in poverty. This is because the increase in national income may not be sufficient to cater to the needs of the growing population. As a result, the per capita income, which is the average income per person, may decrease leading to an increase in poverty. This concept is important in understanding the relationship between population growth and economic development.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>35", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "MONEY : TYPES OF MONEY", "question": "An example of  commodity money is", "images": [], "options": {"A": "currency note", "B": "mobile money", "C": "cheques", "D": "silver"}, "answer": "D", "explanation": "Commodity money is a type of good that functions as currency. In this case, silver is an example of commodity money because it has intrinsic value; that is, it is valuable in itself. Currency notes, mobile money, and cheques are examples of fiat money, which has value because a government maintains its value, or because parties engaging in exchange agree on its value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>36", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "If inflation is anticipated, people may", "images": [], "options": {"A": "save more money", "B": "spend more money", "C": "give out more loans", "D": "spend less money"}, "answer": "B", "explanation": "Inflation is a general increase in prices and fall in the purchasing value of money. If inflation is anticipated, people may spend more money. This is because the value of money decreases during inflation, so people tend to buy goods and services before their prices rise. Saving more money, giving out more loans, or spending less money are not typical reactions to anticipated inflation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>37", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "If the Central Bank increases its bank rate", "images": [], "options": {"A": "many banks will shut down their operations", "B": "customers will borrow more from banks", "C": "the supply of money may be reduced", "D": "interest charges by banks will fall"}, "answer": "C", "explanation": "The bank rate is the interest rate that a nation's central bank charges domestic banks to borrow funds. If the Central Bank increases its bank rate, the cost of borrowing for banks increases. As a result, banks may reduce the amount of loans they give out, which may reduce the supply of money in the economy. The other options are incorrect because an increase in the bank rate does not necessarily lead to banks shutting down their operations, customers borrowing more from banks, or a fall in interest charges by banks.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>38", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Commercial banks are different from development banks in that the latter", "images": [], "options": {"A": "lend on short-term basis", "B": "pay interest on current accounts only", "C": "are mostly joint-stock companies", "D": "do not deal in foreign currencies"}, "answer": "A", "explanation": "Development banks are different from commercial banks in that they lend on a long-term basis, not short-term. They provide capital for long-term projects and infrastructure development, unlike commercial banks that provide short-term loans for businesses and individuals.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>39", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "The use of the bank rate, cash ratio and open market operations constitute", "images": [], "options": {"A": "fiscal policy", "B": "monetary policy", "C": "import policy", "D": "export policy"}, "answer": "B", "explanation": "The use of the bank rate, cash ratio, and open market operations constitute monetary policy. Monetary policy is the policy adopted by the monetary authority of a country that controls either the interest rate payable on very short-term borrowing or the money supply, often targeting inflation or the interest rate to ensure price stability and general trust in the currency.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>40", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "PUBLIC FINANCE : FISCAL POLICY", "question": "Fiscal policy measures imply a change in", "images": [], "options": {"A": "only taxation to control aggregate demand", "B": "bank rate to infulence lending", "C": "only government expenditure to regulate an economy", "D": "government revenue and expenditure to regulate an economy"}, "answer": "D", "explanation": "Fiscal policy measures imply a change in government revenue and expenditure to regulate an economy. Fiscal policy is the means by which a government adjusts its spending levels and tax rates to monitor and influence a nation's economy. It is the sister strategy to monetary policy through which a central bank influences a nation's money supply.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>41", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If demand is perfectly inelastic, a tax imposed", "images": [], "options": {"A": "is borne only by the producer", "B": "is borne only by the consumer", "C": "will have greater impact on the seller", "D": "will have no impact on the buyer"}, "answer": "B", "explanation": "When demand is perfectly inelastic, consumers are willing to pay any price for a good or service. This means that if a tax is imposed, the consumer will bear the entire burden of the tax because they are still willing to buy the good or service at the higher price. The concept of elasticity measures how much the quantity demanded of a good responds to a change in the price of that good.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>42", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Development planning focuses mainly on", "images": [], "options": {"A": "allocation of resources by the entrepreneurs", "B": "mapping out strategies by the government", "C": "developing some areas of the country by the government", "D": "deciding on which types of homes to build"}, "answer": "B", "explanation": "Development planning is a strategic effort by the government to promote national economic growth and development. It involves mapping out strategies by the government to allocate resources, develop infrastructure, and implement policies that will stimulate economic growth and improve the standard of living of its citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>43", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INTRODUCTION", "question": "Political instability hinders economic growth because it", "images": [], "options": {"A": "scares many people from politics", "B": "prevent politicians from playing effective politics", "C": "discourage entrepreneurs generally", "D": "encourages urban-rural migration"}, "answer": "C", "explanation": "Political instability can hinder economic growth because it creates an uncertain environment that may discourage entrepreneurs from investing or expanding their businesses. This is because the risk associated with their investments becomes too high due to the potential for sudden changes in government policy, civil unrest, or other forms of instability.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>44", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Foreign investment and long term securities in the balance of payment accounts are recorded as", "images": [], "options": {"A": "current account transaction", "B": "capital account transaction", "C": "balance of trade account transaction", "D": "invisible balance account transaction"}, "answer": "B", "explanation": "Foreign investment and long term securities are recorded in the capital account of the balance of payments because the capital account records all international capital transfers, including investments and loans.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>45", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "An argument for the use of commercial policy rest on the need to", "images": [], "options": {"A": "make imported goods affordable", "B": "reduce domestic unemployment", "C": "encourage the importation of non-essential goods", "D": "make a country enjoy absolute advantage in production of all goods"}, "answer": "B", "explanation": "Commercial policy can be used to reduce domestic unemployment by implementing protectionist measures such as tariffs and quotas to protect domestic industries from foreign competition, thereby preserving jobs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>46", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Which of the following measures can lead to an increase in exports?", "images": [], "options": {"A": "Increase in export duties", "B": "Increase in excise duties", "C": "Depreciation of currency", "D": "Total ban on imports"}, "answer": "C", "explanation": "An increase in exports can be achieved through the depreciation of currency. When a country's currency depreciates, its goods and services become cheaper for foreign buyers, which can lead to an increase in exports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>47", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "Given that a country's index of export price is 180 and that of import is 200, the terms of trade is", "images": [], "options": {"A": "0.09", "B": "2.00", "C": "90.00", "D": "380.00"}, "answer": "C", "explanation": "The term of trade is calculated by dividing the index of export prices by the index of import prices and multiplying by 100. Therefore, the term of trade is (180/200)*100 = 90.00.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2022>48", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "A benefit that is present in all forms of economic integration is that", "images": [], "options": {"A": "factors of production are free  to move and be moved", "B": "common currency is in use", "C": "common agricultural policy is in place", "D": "the size of the market is widened"}, "answer": "D", "explanation": "Economic integration, in its various forms, allows for the expansion of the market size. This is because it involves the combination of several national markets into one large regional market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>49", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "The main function of the African Development Bank (AFDB) is to", "images": [], "options": {"A": "promote free trade and development among members", "B": "provide loans to finance balance of payment problems", "C": "provide loans to members to finance viable projects", "D": "help members overcome their internal problems"}, "answer": "C", "explanation": "The main function of the African Development Bank (AFDB) is to provide loans to members to finance viable projects. The bank's primary purpose is to promote sustainable economic growth and reduce poverty in Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2022>50", "subject": "Economics", "year": "2022", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : ONSHORE & OFFSHORE OF THE OIL SECTOR", "question": "If petrol is no longer needed to produce energy, then demand for crude oil", "images": [], "options": {"A": "will increase", "B": "will remain constant", "C": "may be limited to chemical industries", "D": "will make producing countries richer"}, "answer": "C", "explanation": "If petrol is no longer needed to produce energy, the demand for crude oil may be limited to other industries that still require it, such as the chemical industry. Crude oil is used in the production of many chemical products, including pharmaceuticals, solvents, fertilizers, pesticides, and plastics.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>1", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "The study of economics is mainly concerned with how to", "images": [], "options": {"A": "rank individuals' wants given the abundant resources", "B": "make choice when resources are inadequate", "C": "satisfy every member of all societies", "D": "produce all the goods needed by everyone"}, "answer": "B", "explanation": "The study of economics is mainly concerned with how to make choices when resources are inadequate. This is because economics is the study of how individuals, firms, governments, and nations make choices on allocating resources to satisfy their unlimited wants. Economics can help us answer these questions: What should be produced? How should it be produced? Who should it be produced for?", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2023>2", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : INTRODUCTION", "question": "Warehousing is an economic activity that falls under", "images": [], "options": {"A": "tertiary production", "B": "intermediate production", "C": "secondary production", "D": "primary production"}, "answer": "A", "explanation": "Warehousing is an economic activity that falls under tertiary production. Tertiary production involves the provision of services that support primary and secondary production. These services include transportation, banking, insurance, advertising, retailing, wholesaling, and warehousing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>3", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "Which of the following items is not classified as working capital?", "images": [], "options": {"A": "Equipment", "B": "Fuel", "C": "Money to pay wages", "D": "Semi-finished goods"}, "answer": "A", "explanation": "Working capital refers to the funds a company uses for day-to-day operations, such as paying wages, purchasing raw materials, and covering other immediate expenses. It does not include long-term assets or fixed assets such as equipment. Therefore, 'Equipment' is not classified as working capital.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>4", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY", "question": "An economy system is mainly concerned with", "images": [], "options": {"A": "handling situations of abudant resources", "B": "studying the relationship between ends and means", "C": "the establishment of economic laws", "D": "the allocation of scarce resources between alternative ends"}, "answer": "D", "explanation": "An economic system is primarily concerned with the allocation of scarce resources between alternative ends. This involves making decisions about what to produce, how to produce it, and for whom it should be produced. The other options do not accurately describe the main concern of an economic system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2023>5", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY", "question": "The marks obtained by 9 students in a class test are recorded below: 9, 8, 7, 5,7, 6, 8, 9 and 7. What is the median mark?", "images": [], "options": {"A": "7", "B": "7.5", "C": "8", "D": "8.5"}, "answer": "A", "explanation": "The median is the middle number in a sorted list of numbers. In this case, when the marks are arranged in ascending order (5, 6, 7, 7, 7, 8, 8, 9, 9), the median mark is 7, which is the middle number.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>6", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "The demand for a factor input as a result of the demand for its output is known as", "images": [], "options": {"A": "complementary demand", "B": "competitive demand", "C": "derived demand", "D": "market demand"}, "answer": "C", "explanation": "The demand for a factor input as a result of the demand for its output is known as derived demand. This is because the demand for the input is 'derived' from the demand for the output it helps to produce. For example, the demand for coal (input) is derived from the demand for electricity (output) that it helps to produce.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>7", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If the demand for a commodity remains constant as price increases, the commodity is said to be", "images": [], "options": {"A": "price elastic", "B": "unit price elastic", "C": "price inelastic", "D": "perfectly price inelastic"}, "answer": "D", "explanation": "If the demand for a commodity remains constant as price increases, the commodity is said to be perfectly price inelastic. Price elasticity of demand measures the responsiveness of the quantity demanded of a good to a change in its price. If the quantity demanded remains unchanged with a change in price, the demand is perfectly inelastic.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>8", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "When more of tax on a product is borne by the buyer than the seller, the commodity involved has", "images": [], "options": {"A": "elastic demand", "B": "fairly inelastic demand", "C": "perfectly elastic demand", "D": "perfectly inelastic demand"}, "answer": "B", "explanation": "When more of tax on a product is borne by the buyer than the seller, the commodity involved has fairly inelastic demand. This is because when demand is inelastic, buyers are less responsive to price changes, so they will continue to buy the product even if the price increases due to the tax. Therefore, the burden of the tax falls more heavily on the buyer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>9", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "A fall in the price of a normal commodity which has elastic demand will result in", "images": [], "options": {"A": "a fall in quantity demanded", "B": "an increase in revenue", "C": "a fall in demand", "D": "a decrease in revenue"}, "answer": "B", "explanation": "The price elasticity of demand measures how much the quantity demanded responds to a change in price. Demand for a good is said to be elastic if the quantity demanded responds substantially to changes in the price. If a good has elastic demand, then the revenue will increase when the price decreases. This is because the percentage change in quantity demanded is greater than the percentage change in price.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>10", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "THEORY OF SUPPLY : TYPES OF SUPPLY", "question": "The supply of light could be met using a candle, lantern and gas lamp. This is an example of a", "images": [], "options": {"A": "complementary supply", "B": "joint supply", "C": "composite supply", "D": "abnormal supply"}, "answer": "C", "explanation": "Composite supply refers to a situation where a commodity can be produced from different sources. In this case, light can be produced from different sources such as a candle, lantern, and gas lamp. Therefore, the supply of light is a composite supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>11", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Petrol and Kerosene are jointly obtained from crude oil. If the supply of petrol increases, the", "images": [], "options": {"A": "supply of kerosene will fall", "B": "cost of crude oil production has increased", "C": "supply of kerosene will rise", "D": "supply of kerosene will remain unchanged"}, "answer": "C", "explanation": "Petrol and Kerosene are jointly obtained from crude oil. This means that an increase in the supply of one will lead to an increase in the supply of the other. Therefore, if the supply of petrol increases, the supply of kerosene will also rise.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>12", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "If the government stops subsidy on cocoa production, the supply curve of cocoa will", "images": [], "options": {"A": "shift to the right", "B": "become vertical", "C": "shift to the left", "D": "remain unchanged"}, "answer": "C", "explanation": "If the government stops subsidy on cocoa production, the cost of production for cocoa farmers will increase. This will lead to a decrease in the quantity of cocoa that farmers are willing to supply at each price, causing the supply curve to shift to the left. The supply curve shifting to the left means that less quantity will be supplied at the same price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>13", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "When the marginal utility from the consumption of commodity X (Mux) is greater than the price commodity X (Px), a rational consumer should", "images": [], "options": {"A": "consume more of commodity X", "B": "reduce consumption of commodity X", "C": "consume the same quantity of commodity X", "D": "strive to remain in disequilibrium"}, "answer": "A", "explanation": "Marginal utility refers to the additional satisfaction a consumer gets from consuming one more unit of a good or service. If the marginal utility of a commodity is greater than its price, it means the consumer is getting more satisfaction from the commodity than what they're paying for it. Therefore, a rational consumer should consume more of that commodity to maximize their total utility.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>14", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "When the demand for a commodity increases while supply remains unchanged, the equilibrium price and quantity will", "images": [], "options": {"A": "remain constant", "B": "decrease", "C": "increase", "D": "turn negative"}, "answer": "C", "explanation": "When the demand for a commodity increases while supply remains unchanged, the equilibrium price and quantity will increase. This is because the increase in demand creates a shortage at the original price, causing the price to rise. As the price rises, the quantity supplied also increases until it reaches a new equilibrium where quantity demanded equals quantity supplied.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>15", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION", "question": "The fixing of maximum prices by government is mainly on", "images": [], "options": {"A": "inferior goods", "B": "luxury goods", "C": "imported capital goods", "D": "selected essential goods"}, "answer": "D", "explanation": "The government usually fixes maximum prices for selected essential goods. This is done to make these goods affordable for everyone, especially the low-income earners. This practice is known as price ceiling. Inferior goods, luxury goods, and imported capital goods are not typically subject to price ceilings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>16", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION", "question": "At what point on the total product curve shown below will marginal product be negative?", "images": ["Economics/imgs/2023/016.png"], "options": {"A": "P", "B": "Q", "C": "R", "D": "S"}, "answer": "D", "explanation": "Marginal product is negative at point S on the total product curve. This is because the total product curve is decreasing at point S. When the total product curve is decreasing, the marginal product is negative.    The marginal product is the additional output that is produced when one additional unit of input is added. In this case, the additional output is decreasing, so the marginal product is negative.    The other points on the total product curve, P, Q, and R, are all increasing. Therefore, the marginal product is positive at these points.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>17", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "A small scale firm located within an industrial estate will enjoy", "images": [], "options": {"A": "government protection and funding", "B": "technological economies of scale", "C": "external economies of scale", "D": "financial economies of scale"}, "answer": "C", "explanation": "A small scale firm located within an industrial estate will enjoy external economies of scale. External economies of scale occur when a company's costs per unit decrease due to an increase in the size of the industry, not the firm. This could be due to factors such as improved transportation systems, a skilled labor force, and technological advancements that benefit all firms in the industry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>18", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "The total fixed cost curve is", "images": [], "options": {"A": "vertical", "B": "horizontal", "C": "downward sloping", "D": "upward sloping"}, "answer": "B", "explanation": "The total fixed cost curve is horizontal. Fixed costs are costs that do not change with the level of output. Therefore, regardless of the quantity produced, the total fixed cost remains the same, resulting in a horizontal curve.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>19", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS", "question": "If a firm retrenches some of its factory workers its", "images": [], "options": {"A": "fixed cost is likely to increase", "B": "marginal cost may increase", "C": "average fixed cost may increase", "D": "variable cost will decline"}, "answer": "D", "explanation": "If a firm retrenches some of its factory workers, its variable cost will decline. Variable costs are those costs that vary with the level of output, and labor is a variable cost. If the firm reduces its labor force, it reduces its variable costs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>20", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "A monopolist may enjoy abnormal profit only if its", "images": [], "options": {"A": "marginal cost exceeds marginal revenue", "B": "demand curve is perfectly elastic", "C": "price exceeds average total cost", "D": "expenditure on advertisement increases"}, "answer": "C", "explanation": "A monopolist may enjoy abnormal profit only if its price exceeds average total cost. This is because the difference between price and average total cost represents profit per unit. If the price is higher than the average total cost, the firm is making a profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>21", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "MARKET STRUCTURE : PERFECT MARKET", "question": "The average revenue curve of a firm in a perfect market is the same as the", "images": [], "options": {"A": "supply curve of the firm", "B": "demand curve of the firm", "C": "total revenue curve of the firm", "D": "average cost curve of the firm"}, "answer": "B", "explanation": "The average revenue curve of a firm in a perfect market is the same as the demand curve of the firm. In a perfect market, the price is determined by the market and is the same for all firms. Therefore, the average revenue, which is the total revenue divided by the quantity sold, is the same as the price, which is determined by the demand curve.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>22", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES", "question": "Resources are pooled for the mutual benefit of its members mainly in a", "images": [], "options": {"A": "joint stock company", "B": "partnership", "C": "private company", "D": "cooperative society"}, "answer": "D", "explanation": "A cooperative society is a form of organization where individuals come together to pool their resources for mutual benefit. The main aim of a cooperative society is to serve the interest of its members rather than to earn profits. This is different from a joint stock company, partnership, or private company where the main aim is usually to earn profits.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2023>23", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "A joint stock company enjoys perpetual existence because", "images": [], "options": {"A": "it is formed by a minimum of seven members", "B": "it is a corporate entity", "C": "its shares are easily", "D": "there is a higher degree of specialization"}, "answer": "B", "explanation": "A joint stock company enjoys perpetual existence because it is a corporate entity. This means that the company has a separate legal identity from its members. Therefore, the company can continue to exist even if its members change. This is a concept known as 'perpetual succession'. The other options do not directly relate to the company's perpetual existence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>24", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE RETAILER", "question": "Consumers have access to a variety of goods through the activities of the", "images": [], "options": {"A": "advertising agencies", "B": "wholesalers", "C": "retailers", "D": "mass media"}, "answer": "C", "explanation": "Consumers have access to a variety of goods mainly through the activities of the retailers. Retailers are the final link in the supply chain between manufacturers and consumers. They stock a variety of goods from different manufacturers and wholesalers, providing consumers with a wide range of products to choose from. While advertising agencies and mass media can promote goods, and wholesalers can distribute goods, it is the retailers who provide direct access to these goods for consumers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2023>25", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "The rate of growth of population is", "images": [], "options": {"A": "the difference between birth rate and death rate", "B": "birth rate less death rate plus net migration", "C": "initial population plus number of births and net migration", "D": "the number of immigrants plus number of births"}, "answer": "B", "explanation": "The rate of growth of a population is determined by the birth rate minus the death rate plus net migration. This is because the population increases with births and immigration (people moving into the area) and decreases with deaths and emigration (people moving out of the area).", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>26", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "POPULATION : THEORIES OF POPULATION", "question": "The malthusian theory of population is best illustrated when", "images": [], "options": {"A": "both population and food supply increase at the same rate", "B": "population increases much faster than food supply", "C": "the size of the population and available resources are equal", "D": "food supply increases much faster than population growth"}, "answer": "B", "explanation": "The Malthusian theory of population posits that population growth is potentially exponential while the growth of the food supply or other resources is linear. It postulates that only natural causes (like diseases, wars, disasters) or self-imposed ones (like moral restraint) can check excessive population growth. Therefore, it is best illustrated when population increases much faster than food supply.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>27", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION", "question": "The dependency ratio of a country is the", "images": [], "options": {"A": "total active population who depend on government for survival", "B": "number of children who depend on their parents for survival", "C": "the children and aged who rely on the active population for support", "D": "people who are cared for by their extended families"}, "answer": "C", "explanation": "The dependency ratio of a country is the ratio of the non-working age population (both the young and the old) to the working-age population. It is the number of individuals who are not in the labor force (the dependents) compared with the number of individuals who are in the labor force (the productive population). Therefore, it is the children and aged who rely on the active population for support.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>28", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "When job vacancies are publicized, the government is mainly trying to solve the problem of", "images": [], "options": {"A": "residual unemployment", "B": "frictional unemployment", "C": "technological unemployment", "D": "cyclical unemployment"}, "answer": "B", "explanation": "Frictional unemployment refers to the period of time between jobs when a worker is searching for, or transitioning from one job to another. It is a natural form of unemployment in an economy. When job vacancies are publicized, the government is mainly trying to reduce this type of unemployment by making it easier for job seekers to find employment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>29", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "Many workers are employed in the agricultural sector of developing countries because", "images": [], "options": {"A": "they practice mechanized system of farming", "B": "labour intensive method is mostly adopted", "C": "wages in the sector is high", "D": "abnormal profits are made"}, "answer": "B", "explanation": "In developing countries, the agricultural sector is often labor-intensive. This means that it requires a large amount of labor to produce goods or services. This is due to the lack of advanced machinery and technology, which would otherwise reduce the need for manual labor. Therefore, many workers are employed in the agricultural sector of developing countries because labor-intensive methods are mostly adopted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>30", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Industries are sometimes located in areas which are not profitable so as to", "images": [], "options": {"A": "encourage rural-urban migration", "B": "be able to reap internal economies of scale", "C": "be able to even-out development", "D": "bring about external economies of scale"}, "answer": "C", "explanation": "Industries are sometimes located in areas which are not profitable in order to even out development. This is a strategy used by governments to promote economic growth and development in less developed or rural areas. By attracting industries to these areas, it can stimulate local economies, create jobs, and reduce regional inequalities.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>31", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "One of the factor that may not promote industrial development is", "images": [], "options": {"A": "granting old firms tax exemptions", "B": "local firms entering into partnerships with foreign firms", "C": "setting up industrial estates with modern amenities", "D": "granting capital to firms at reasonable interest rates"}, "answer": "B", "explanation": "Local firms entering into partnerships with foreign firms is a factor that promotes industrial development, not hinder it. This is because such partnerships often bring in foreign direct investment, advanced technology, and expertise, which can boost the growth and competitiveness of local industries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>32", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "NATIONAL INCOME : USES & REASONS FOR MEASURING NATIONAL INCOME", "question": "National income is calculated mainly to", "images": [], "options": {"A": "determine how income is to shared", "B": "help firms generate more funds", "C": "determine the level of sectoral performance", "D": "determine aid to to be received from other nations"}, "answer": "C", "explanation": "National income is calculated mainly to determine the level of sectoral performance. National income accounting provides a measure of the economic activities of a country, including the performance of various sectors. It helps in assessing the contribution of different sectors to the national income, thereby indicating their performance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>33", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "To overcome the problem of double counting under the expenditure approach,", "images": [], "options": {"A": "valued added method is used", "B": "only spending on final goods are considered", "C": "proper accounting standards must be used", "D": "spending on intermediate goods and inputs are considered"}, "answer": "B", "explanation": "To overcome the problem of double counting under the expenditure approach, only spending on final goods are considered. Double counting occurs when the same good is counted more than once in the calculation of national income. To avoid this, only the value of final goods and services, which are the end products of the production process, are considered in the expenditure approach. Intermediate goods, which are used in the production of final goods, are not counted separately as their value is already included in the value of the final goods.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>34", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "NATIONAL INCOME : CONCEPT", "question": "The Net National Product (NNP) of a country is $50m while the depreciation allowance is $10m. The Gross National Product (GNP) is", "images": [], "options": {"A": "$30m", "B": "$40m", "C": "$60m", "D": "$500m"}, "answer": "C", "explanation": "The Gross National Product (GNP) is calculated by adding the Net National Product (NNP) and the depreciation. In this case, the NNP is $50m and the depreciation is $10m. Therefore, the GNP is $50m + $10m = $60m. Hence, the correct option is $60m.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>35", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "MONEY : VALUE OF MONEY", "question": "The price level and the value of money are", "images": [], "options": {"A": "inversely related", "B": "directly related", "C": "not related", "D": "positively related"}, "answer": "A", "explanation": "The price level and the value of money are inversely related. This means that when the price level increases, the value of money decreases and vice versa. This is because as prices increase, the purchasing power of money decreases, hence the value of money decreases. Conversely, when prices decrease, the purchasing power of money increases, hence the value of money increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>36", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "Money is able to function more as a medium of exchange when", "images": [], "options": {"A": "more prople engage in subsistence production", "B": "there is a fall in production", "C": "there is specialization of labour", "D": "individuals and nations are self-sufficient"}, "answer": "C", "explanation": "Money functions more as a medium of exchange when there is specialization of labour. This is because specialization of labour leads to increased production and efficiency, which in turn increases the need for a medium of exchange. When individuals or nations are self-sufficient or engage in subsistence production, they have less need for a medium of exchange because they produce what they consume and consume what they produce. Similarly, a fall in production reduces the need for a medium of exchange.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>37", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "An indication that there is inflation in a country is that", "images": [], "options": {"A": "there is a decrease in the demand for goods and services", "B": "there are too many goods in circulation", "C": "the same amount of money buys lower quantity of goods", "D": "people prefer to lend than to borrow"}, "answer": "C", "explanation": "Inflation is a general increase in prices and fall in the purchasing value of money. Therefore, when there is inflation, the same amount of money buys a lower quantity of goods because the value of money has fallen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>38", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "MONEY : TYPES OF MONEY", "question": "The most liquid asset among the following is", "images": [], "options": {"A": "shares", "B": "bonds", "C": "cash", "D": "cheque"}, "answer": "C", "explanation": "Liquidity refers to how quickly an asset can be converted into cash without affecting its market price. Cash is the most liquid asset because it is already in its most liquid form.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2023>39", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Commericial banks help in economic development mainly by", "images": [], "options": {"A": "acting as intermediaries between government and borowers", "B": "giving financial advice to the government", "C": "acting as trustees and executors of wills", "D": "serving as custodians of valuables"}, "answer": "D", "explanation": "Commercial banks collect deposits from savers and lend these deposits to borrowers. This process of intermediation allows savers to earn interest on their deposits and borrowers to obtain the funds they need to invest in businesses and other productive activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>40", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Taxes levied on goods and services by government  are called", "images": [], "options": {"A": "direct taxes", "B": "coporate taxes", "C": "indirect taxes", "D": "poll taxes"}, "answer": "C", "explanation": "Taxes levied on goods and services by the government are called indirect taxes. This is because the burden of these taxes can be shifted from one person to another. For example, a tax on a product bought by a consumer can be shifted to the consumer by the seller in the form of a higher price.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2023>41", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "Use the graph below to answer the question      The curve labelled W shows the", "images": ["Economics/imgs/2023/017.png"], "options": {"A": "proportional tax", "B": "progressive tax", "C": "specific tax", "D": "regressive tax"}, "answer": "B", "explanation": "A progressive tax is a tax system in which the tax rate increases as the amount of taxable income increases. This means that people with higher incomes pay a higher percentage of their income in taxes than people with lower incomes.    The curve labeled W shows that the tax rate increases as the amount of taxable income increases. This is the defining characteristic of a progressive tax system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>42", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "An example of government's recurrent expenditure is", "images": [], "options": {"A": "the cost of building a school", "B": "paying salaries of workers", "C": "purchase of new vehicles", "D": "electrification projects in rural areas"}, "answer": "B", "explanation": "Government's recurrent expenditure refers to the spending on the day-to-day running of government. This includes salaries of government workers, maintenance of government properties, etc. Therefore, paying salaries of workers is an example of government's recurrent expenditure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>43", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "A country is described as developing if", "images": [], "options": {"A": "the population is decreasing", "B": "there is low labour supply", "C": "the contribution of tertiary sector to national income is high", "D": "the income per head is low"}, "answer": "D", "explanation": "A country is described as developing if the income per head is low. This is because one of the key indicators of a country's development is its Gross Domestic Product (GDP) per capita, which is the value of all goods and services produced in a country in a given year divided by the population. If this figure is low, it suggests that the country is not producing enough wealth to provide a high standard of living for its citizens, hence it is considered as developing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>44", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Tariffs, quotas and embargoes are examples of", "images": [], "options": {"A": "foreign exchange policies", "B": "trade restriction policies", "C": "fiscal policies", "D": "monetary policies"}, "answer": "B", "explanation": "Tariffs, quotas, and embargoes are all tools used by governments to restrict trade with other countries. Therefore, they are examples of trade restriction policies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2023>45", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : DEVELOPMENT PLANNING", "question": "Trade protection will assit economic growth in developing countries if it can", "images": [], "options": {"A": "eliminate importation of all commodities", "B": "generate enough revenue through export duties", "C": "effectively safeguard newly established firms", "D": "allow the importation of cheaper goods people want"}, "answer": "C", "explanation": "Trade protection can help economic growth if it can effectively safeguard newly established firms. This is because it can protect these firms from competition from foreign firms, allowing them to grow and develop.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>46", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "A government may cause a favourable change in her invisible trade account by", "images": [], "options": {"A": "increasing the export of her primary products", "B": "imposing high tariff on exports", "C": "developing tourism and other services", "D": "encouraging people to go for medical treatment abroad"}, "answer": "C", "explanation": "Invisible trade refers to the trade of services, rather than goods. Therefore, a government can cause a favourable change in her invisible trade account by developing tourism and other services.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>47", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE", "question": "Country M enjoys absolute advantage over country  N  in the production of commodities X and Y, if country M", "images": [], "options": {"A": "can produce only commodity Y cheaper than country  N", "B": "is more efficient than country  N  in producing both commodities X and Y", "C": "is inefficient in the production of both commodities X and Y", "D": "and country  N  are efficient in the production of both goods"}, "answer": "B", "explanation": "Absolute advantage is an economic concept that refers to the ability of a country, individual, company or region to produce a good or service at a lower cost per unit than the cost at which any other entity produces that good or service. Entities with absolute advantages can produce a product or service using a smaller number of inputs or a more efficient process than another entity producing the same product or service. Therefore, if country M enjoys absolute advantage over country N in the production of commodities X and Y, it means country M is more efficient than country N in producing both commodities X and Y.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>48", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "ECONOMIC INTEGRATION : PROBLEMS OF ECONOMIC INTEGRATION IN WEST AFRICA- ECOWAS", "question": "Which of the following is not a problem facing Economic Community of West African States (ECOWAS)?", "images": [], "options": {"A": "Language barriers", "B": "Production of the same commodities", "C": "Poor transportation and communication", "D": "Inadequate supply of labour"}, "answer": "D", "explanation": "The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. Some of the problems facing ECOWAS include language barriers, production of the same commodities, and poor transportation and communication. However, inadequate supply of labour is not a problem facing ECOWAS. The region has a large and youthful population which provides a substantial labour force.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>49", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC", "question": "Assisting members to solve temporary balance of payments problems is the reasons for the establishment of the", "images": [], "options": {"A": "World Bank", "B": "International Monetary Fund", "C": "African Development Bank", "D": "Economic Commission for Africa"}, "answer": "B", "explanation": "The International Monetary Fund (IMF) is an international organization that aims to promote global economic growth and financial stability, to encourage international trade, and to reduce poverty. One of the key roles of the IMF is to provide loans to member countries experiencing balance of payments problems. This helps countries stabilize their economies by restoring their balance of payments equilibrium.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2023>50", "subject": "Economics", "year": "2023", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "Which of the following is a non-renewable natural resources?", "images": [], "options": {"A": "Cocoa", "B": "Oil palm", "C": "Coal", "D": "Rubber"}, "answer": "C", "explanation": "Non-renewable resources are resources that do not renew themselves at a sufficient rate for sustainable economic extraction in meaningful human timeframes. Coal is a non-renewable resource because it cannot be replenished on a human time scale, it takes millions of years to create coal. Cocoa, Oil palm and Rubber are all renewable resources because they can be replanted and regrown in a human's lifespan.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2024>1", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "There is scarcity when", "images": [], "options": {"A": "the means exceed society's want", "B": "demand for resources is greater than its supply", "C": "productive resources are in excess", "D": "supply of resources is greater than its demand"}, "answer": "B", "explanation": "Scarcity refers to the condition where human wants or desires exceed the available resources to satisfy those wants. In other words, it occurs when the demand for goods and services exceeds their supply. This fundamental economic problem necessitates choices about how to allocate limited resources efficiently to fulfill unlimited human wants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>2", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE", "question": "Points within a Production Possibilities Curve (PPC) indicate", "images": [], "options": {"A": "optimum production levels", "B": "attainable but inefficient production levels", "C": "unattainable production levels", "D": "attainable and efficient production levels"}, "answer": "D", "explanation": "A Production Possibilities Curve (PPC) illustrates the maximum output combinations of two goods that can be produced given current resources and technology. Points within the PPC represent combinations of goods that are attainable with available resources and technology. Efficiency on the PPC means using resources in the best possible way to maximize output, indicating that points within the curve represent attainable and efficient production levels.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>3", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION", "question": "Which of the following is not a feature of labour?", "images": [], "options": {"A": "It is an active factor", "B": "It is highly mobile", "C": "Its reward is wages or salaries", "D": "Its efficiency depends on its size"}, "answer": "D", "explanation": "Labor efficiency typically does not depend on its size but rather on factors such as skills, training, experience, and motivation of the labor force. The effectiveness and productivity of labor are influenced by these factors rather than by physical size alone.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>4", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "The pursuit of private profits is a feature of", "images": [], "options": {"A": "command economies", "B": "socialist economies", "C": "capitalist economies", "D": "statutory corporations"}, "answer": "C", "explanation": "In capitalist economies, private individuals and businesses own and control the factors of production (such as capital, land, and labor) and engage in economic activities primarily to generate profits. The pursuit of private profits drives decisions regarding production, investment, pricing, and resource allocation within the framework of market mechanisms. This characteristic contrasts with command economies (where economic activities are centrally planned by the government) and socialist economies (which emphasize collective or state ownership of resources).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>5", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "A major feature of the socialist economic system is", "images": [], "options": {"A": "setting of production targets by public authorities", "B": "freedom of choice for consumers", "C": "determination of price by market forces", "D": "private ownership of productive inputs"}, "answer": "A", "explanation": "In a socialist economic system, production targets and economic planning are typically set and controlled by public authorities or the state. This centralized planning aims to achieve specific social and economic objectives, such as equitable distribution of resources, social welfare, and economic stability. It contrasts with capitalist economies where production decisions are primarily driven by market forces and private enterprises.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>6", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS: REPRESENTATION OF DATA", "question": "If the  budget on education is $50m out of an annual national budget of $300m. The sector of a pie chart representing education is", "images": [], "options": {"A": "16.6o", "B": "60o", "C": "150o", "D": "300o"}, "answer": "B", "explanation": "Calculate the percentage contribution:    50300x100  = 16.67%    Convert to degree    =16.67100x360  = 60o", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>7", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "Price elasticity of demand is the responsiveness of quantity demanded to a change in", "images": [], "options": {"A": "demand for the product", "B": "price of another product", "C": "income of the buyer", "D": "price of the product"}, "answer": "D", "explanation": "Price elasticity of demand measures how sensitive the quantity demanded of a product is to a change in its price. It quantifies the percentage change in quantity demanded in response to a percentage change in the price of the product. This concept helps to understand consumer behavior and market dynamics, particularly how changes in price affect the demand for goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>8", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : APPLICATION OF ELASTICITY ON REVENUE", "question": "When total revenue increases as price falls, the coefficient of price elasticity of demand is", "images": [], "options": {"A": "greater than one", "B": "one", "C": "less than one", "D": "zero"}, "answer": "A", "explanation": "If total revenue (TR) increases as price (P) falls, it indicates that demand is elastic. In elastic demand, the percentage change in quantity demanded is proportionately greater than the percentage change in price. Mathematically, this corresponds to a price elasticity of demand (PED) greater than 1 (|PED| > 1).    If PED > 1, demand is elastic. A decrease in price leads to a more than proportionate increase in quantity demanded, resulting in an increase in total revenue.  If PED = 1, demand is unit elastic. A decrease in price leads to a proportionate increase in quantity demanded, resulting in no change in total revenue.  If PED", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>9", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "If the quantity demanded of rice decreased from 150 bags to 100 bags, the percentage change in quantity demanded is", "images": [], "options": {"A": "30.0%", "B": "33.3%", "C": "50.0%", "D": "66.7%"}, "answer": "B", "explanation": "Given:  Old Quantity (Q1) = 150 bags  New Quantity (Q2) = 100 bags    New quantity - Old quantityOld quantityx100    =100 - 150150x100    The negative sign indicates a decrease in quantity demanded. To find the positive percentage change:    Percentage Change =33.3%", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>10", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "The law of demand will not hold when", "images": [], "options": {"A": "normal goods are involved", "B": "size of the population changes", "C": "rare commodities are involved", "D": "incomes of consumers increase"}, "answer": "C", "explanation": "The law of demand states that, all else being equal, when the price of a good or service increases, the quantity demanded decreases, and when the price decreases, the quantity demanded increases. This principle generally holds true in most situations but may not hold under certain condition like when rare commodities are involved. For rare commodities, which have unique characteristics like collectability or limited availability, traditional demand patterns might not strictly follow the law of demand due to their scarcity and specialized demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>11", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND", "question": "The diagram below shows the demand for milk. Use it to answer the question.      The movement from points x to z might have been caused by", "images": ["Economics/imgs/2024/B2WDY6.jpg"], "options": {"A": "a change in taste in favour of milk", "B": "a decrease in price of milk", "C": "an increase in income of consumers", "D": "a favourable weather condition"}, "answer": "A", "explanation": "A demand curve shows the relationship between the price of a good (milk in this case) and the quantity demanded by consumers.  It typically slopes downwards, indicating that as the price goes up, consumers tend to buy less, and vice versa (assuming other factors remain constant).    The movement from x to z in the diagram signifies:  -  Quantity demanded increases: We see a higher quantity of milk being demanded (moving to the right on the x-axis).  -  Price stays the same: We stay at the same price level (same y-axis value) as point x.    Since the price remains constant, this indicates a shift in consumer preferences, not just a movement along the existing curve due to price changes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>12", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND", "question": "If demand for postal services decline as a result of increased use of e-mails, then the two services are in", "images": [], "options": {"A": "composite demand", "B": "derived demand", "C": "competitive demand", "D": "complementary demand"}, "answer": "C", "explanation": "When two goods satisfy similar needs and an increase in the demand for one leads to a decrease in the demand for the other, they are considered competitive goods.  In this scenario: Increased use of emails (a substitute for traditional mail) reduces the demand for postal services. This perfectly exemplifies competitive demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>13", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY", "question": "Other things being equal, an increase in the demand for land in the short -run will cause an increase in the", "images": [], "options": {"A": "price only", "B": "price and supply", "C": "quantity supplied only", "D": "supply only"}, "answer": "A", "explanation": "In the short run, the supply of land is relatively fixed. Land cannot be easily created or expanded quickly to meet an increased demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>14", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "If the coefficient of price elasticity of supply of a commodity is 0.8, then supply is", "images": [], "options": {"A": "perfectly elastic", "B": "fairly inelastic", "C": "perfectly inelastic", "D": "fairly elastic"}, "answer": "B", "explanation": "If the coefficient of price elasticity of supply of a commodity is 0.8, the supply is considered to be fairly inelastic. This means that the percentage change in quantity supplied is less than the percentage change in price.    A coefficient of 0.8 indicates that the supply is inelastic, meaning that the quantity supplied changes by a smaller percentage than the change in price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>15", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND", "question": "The negative slope of the demand curve is best explained by", "images": [], "options": {"A": "consumer's choice", "B": "increasing returns to scale", "C": "diminishing returns to scale", "D": "diminishing marginal utility"}, "answer": "D", "explanation": "As consumers consume more of a good, the additional satisfaction (marginal utility) they get from consuming each additional unit decreases. Therefore, consumers are only willing to buy more at lower prices, which results in the negative slope of the demand curve.    The negative slope of the demand curve is best explained by the principle of diminishing marginal utility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>16", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION", "question": "Minimum price legislation is used to protect the interests of", "images": [], "options": {"A": "small scale producers", "B": "foreign companies", "C": "government", "D": "consumers"}, "answer": "A", "explanation": "Minimum price legislation ensures that prices do not fall below a certain level, which helps small-scale producers cover their costs and stay in business.    By ensuring a minimum price, the government helps small-scale producers recover their costs and potentially earn a profit. This can be particularly beneficial for industries facing competition from cheaper imports.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>17", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET", "question": "The table below shows the supply and demand schedule for applies. Use it to answer the question.  Price($) Quantity demanded Quantity supplied10502520353530204540555    At what price is excess supply equal to 25?", "images": [], "options": {"A": "$10", "B": "$20", "C": "$30", "D": "$40"}, "answer": "C", "explanation": "Excess supply occurs when the quantity supplied is greater than the quantity demanded.  Therefore, at    Price 30: 45 - 20  = 25    Price 40: 55 - 5  = 50    Therefore, at price 30, there is excess supply", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>18", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THEORY OF PRODUCTION : SCALE OF PRODUCTION", "question": "Which of the following best explains diseconomies of scale? Increase in output causes the", "images": [], "options": {"A": "average cost to rise", "B": "marginal revenue to fall", "C": "marginal cost to fall", "D": "firm to be destabilized"}, "answer": "A", "explanation": "Diseconomies of scale occur when a firm experiences an increase in the average cost of production as it increases its output. This can happen for several reasons, such as management inefficiencies, overextension of resources, or other operational challenges that arise with increased production. As a result, each additional unit of output becomes more expensive to produce.    Diseconomies of scale refer to the situation where, as the scale of production increases, the average cost per unit also increases. This rise in average cost is typically due to inefficiencies that occur when a firm becomes too large, such as difficulties in managing a larger workforce, increased complexity in logistics, or higher administrative overheads.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>19", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST", "question": "In the short-run, a firm can increase output by", "images": [], "options": {"A": "increasing the size of its machines", "B": "purchasing more equipment", "C": "changing its organizational structure", "D": "increasing the quantity of raw materials"}, "answer": "D", "explanation": "In the short-run, the firm can increase output by utilizing more of the variable inputs such as raw materials, labor, and other resources that can be adjusted without making significant changes to the fixed inputs. While increasing the size of machines or purchasing more equipment would generally be considered long-term strategies, increasing the quantity of raw materials is a short-term adjustment that can lead to higher production levels.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>20", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "The fixed cost of producing 100units of a goods is $600. If the variable cost is $400, the average total cost of one unit of the good is", "images": [], "options": {"A": "$4", "B": "$6", "C": "$8", "D": "$10"}, "answer": "D", "explanation": "TC = TFC + TVC  = 600 + 400  = 1000    ATC/AC = TC/Q    = 1000/100    = $10", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>21", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "MARKET STRUCTURE : PERFECT MARKET", "question": "Firms in perfect competition break even in the long-run because", "images": [], "options": {"A": "new firms can not enter the market due to copyright laws", "B": "more firms can enter the industry due to attractive profits", "C": "marginal revenue is greater than marginal cost at all levels", "D": "profits are not enough to repay traders' loans"}, "answer": "B", "explanation": "In perfect competition, if firms are making profits in the short run, new firms will enter the market, increasing the supply and driving down prices until firms are just covering their costs, including normal profit. Thus, firms break even in the long run.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>22", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION", "question": "The government policy that encourages public corporations to operate profitably is", "images": [], "options": {"A": "liberalization", "B": "nationalization", "C": "commercialization", "D": "indigenization"}, "answer": "C", "explanation": "This policy aims to make public corporations operate more like private businesses, focusing on efficiency and profitability. This aligns with the objective of encouraging public corporations to generate a profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>23", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "Separation of ownership from control is more pronounced in a", "images": [], "options": {"A": "partnership", "B": "joint-stock company", "C": "sole-proprietorship", "D": "consumer coopertative society"}, "answer": "B", "explanation": "In a joint-stock company, shareholders own the company but often delegate control to a board of directors and professional managers. This separation of ownership (shareholders) from control (managers) is a hallmark of corporations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>24", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER", "question": "Warehousing of goods in the process of distribution is the function of", "images": [], "options": {"A": "supermarkets", "B": "departmental stores", "C": "retailers", "D": "wholesalers"}, "answer": "D", "explanation": "Wholesalers purchase goods from manufacturers or distributors in large quantities and store them in warehouses. They then sell these goods in smaller quantities to retailers or other businesses. Warehousing is a key function of wholesalers as they consolidate goods from different suppliers and distribute them efficiently to retailers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>25", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR", "question": "The supply of labour to an occupation will tend to rise when", "images": [], "options": {"A": "there are less monetary benefits", "B": "holiday entitlement is cut", "C": "welfare packages improve", "D": "unemployment benefit rises"}, "answer": "C", "explanation": "Improving welfare packages, such as offering better health insurance, retirement benefits, or other non-wage perks, can attract more people to an occupation, thereby increasing labor supply.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>26", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "POPULATION : THEORIES OF POPULATION", "question": "Malthus' predictions did not come to pass mainly because", "images": [], "options": {"A": "food supply and population grew at the same rate", "B": "the use of machines in agriculture was discouraged", "C": "a lot of people died during epidemics", "D": "many people emigrated to the new lands"}, "answer": "D", "explanation": "Malthus did not foresee the significant migration of people to new lands, which provided opportunities for settlement and economic development that could support growing populations. Emigration helped alleviate population pressures in some regions, thereby contradicting Malthus' dire predictions of unchecked population growth leading to widespread famine and misery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>27", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE", "question": "In determining the growth of a country's population, infant mortality is a component of", "images": [], "options": {"A": "immigration rate", "B": "fertility rate", "C": "net migration", "D": "death rate"}, "answer": "D", "explanation": "Death rate, also known as mortality rate, is the number of deaths per 1,000 people in a population over a given period of time. Infant mortality, which is the number of deaths of infants under one year old per 1,000 live births, is a component of the overall death rate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>28", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION", "question": "The low productivity per worker in agriculture experienced in West African countries is due to", "images": [], "options": {"A": "laziness on the part of farmers", "B": "the use of simple traditional implements", "C": "the presence of many extension workers", "D": "the law of increasing returns to scale"}, "answer": "B", "explanation": "Agriculture in many West African countries still relies heavily on traditional farming methods and simple tools. These traditional implements are often less efficient compared to modern agricultural machinery and techniques used in more developed regions. As a result, farmers in West Africa may face challenges in achieving higher productivity per worker due to the limitations imposed by the use of these simple tools and methods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>29", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : ROLES", "question": "What will be the likely effect if agriculture is fully mechanized in West Africa?", "images": [], "options": {"A": "More jobs will be available for farm labourers", "B": "Labour intensive method of farming will still be dominant", "C": "Less labour will be required on the farms", "D": "Governments will no longer be involved in agriculture"}, "answer": "C", "explanation": "Fully mechanizing agriculture means that tasks traditionally performed by human labor, such as planting, harvesting, and processing, would be automated using machinery and technology. This would reduce the need for manual labor on farms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>30", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "Locating firms in urban areas may", "images": [], "options": {"A": "reduce rural-urban migration", "B": "ensure balanced development of rural areas", "C": "make a firm enjoy the benefits of the existence of other firms", "D": "inrease urban-rural migration"}, "answer": "C", "explanation": "When firms are located in urban areas, they benefit from agglomeration economies, which include access to a larger labor pool, suppliers, customers, and other firms in related industries. This clustering effect can lead to increased efficiency, innovation, and overall competitiveness for the firms involved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>31", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "BUSINESS ORGANISATION : INTRODUCTION", "question": "An advantage a small firm has over a large firm is that the former can better", "images": [], "options": {"A": "enjoy financial economies of scale", "B": "satisfy individual tastes", "C": "enjoy internal economies of scale", "D": "attract huge discounts on inputs"}, "answer": "B", "explanation": "Small firms often have the flexibility and agility to cater to niche markets and satisfy specific individual tastes or preferences. They can adapt quickly to changing consumer demands and provide personalized services that may be challenging for larger firms with more standardized operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>32", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "National income estimates will be understated as a result of the activities of", "images": [], "options": {"A": "subsistence farmers", "B": "musicians", "C": "laundry women", "D": "housekeepers"}, "answer": "A", "explanation": "Subsistence farmers typically produce goods for their own consumption rather than for sale in markets. Since their production is not captured in market transactions, it often goes unreported in national income estimates. As a result, the economic value generated by subsistence farming activities is not fully reflected in the GDP (Gross Domestic Product) calculations, leading to understated national income estimates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>33", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "Use the table below to answer the question  Gross National product $400mDepreciation $100mTotal population 25m    The value of Net National Product is", "images": [], "options": {"A": "$100m", "B": "$275m", "C": "$300m", "D": "$500m"}, "answer": "C", "explanation": "Net National Product = GNP - Depreciation  = 400 - 100  = $300m", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>34", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME", "question": "Use the table below to answer the question  Gross National product $400mDepreciation $100mTotal population 25m  The value of per capita income is", "images": [], "options": {"A": "$20", "B": "$16", "C": "$8", "D": "$4"}, "answer": "B", "explanation": "Per capita income=GNPTotal Population    = 400/25    = $16", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>35", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "One effect of inflation is that", "images": [], "options": {"A": "money's purchasing power will increase", "B": "the real incomes of workers will rise", "C": "both borrowers and lenders benefit from it", "D": "money's purchasing power will fall"}, "answer": "D", "explanation": "Inflation refers to the general increase in prices of goods and services over time, leading to a decrease in the value of money. As inflation occurs, each unit of currency buys fewer goods and services, reducing the purchasing power of money. This means that with the same amount of money, people can purchase fewer goods than they could before the inflationary period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>36", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "MONEY : FUNCTIONS OF MONEY", "question": "The function of money that enables credit purchases of goods and services is", "images": [], "options": {"A": "unit of account", "B": "store of value", "C": "standard for deferred payment", "D": "relative scarcity"}, "answer": "C", "explanation": "Money serves as a standard for deferred payment, meaning it allows transactions to be made with the promise of payment in the future. This function of money is crucial for credit purchases, where goods and services are acquired now with an agreement to pay for them at a later date. Deferred payments rely on the acceptance of money as a future medium of exchange.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>37", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "MONEY : SUPPLY OF MONEY", "question": "Supply of money is best defined as the", "images": [], "options": {"A": "money in circulation plus bank deposits", "B": "money given out loans to members of the public", "C": "amount of currency printed annually by the government", "D": "amount of money spent on consumer goods"}, "answer": "A", "explanation": "The supply of money in an economy includes all the physical currency in circulation (coins and banknotes) as well as the deposits held in banks that can be used for transactions. This includes checking accounts and savings accounts, which are readily accessible for spending and investment. The money supply is a broader measure than just physical currency; it encompasses all liquid assets that can be quickly converted to cash for purchasing goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>38", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "FINANCIAL INSTITUTION : INTRODUCTION", "question": "Capital market operators deal in the", "images": [], "options": {"A": "supply of and demand for short term loans only", "B": "supply of and demand for log term loans for investment", "C": "sales and purchases of treasury bills", "D": "sales and purchases of capital equipment"}, "answer": "B", "explanation": "The capital market is a financial market where long-term debt or equity-backed securities are bought and sold. This includes instruments such as stocks, bonds, and long-term loans. Capital markets are essential for raising capital for long-term investments, allowing companies and governments to finance projects and operations through the issuance of equity (shares) or long-term debt (bonds).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>39", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK", "question": "Money supply will increase when the Central Bank", "images": [], "options": {"A": "buys securities from the public", "B": "increases the reserve requirements", "C": "increases the bank rate", "D": "sells securities to the public"}, "answer": "A", "explanation": "When the Central Bank buys securities from the public (such as government bonds), it pays for these securities with money, which is then deposited into the sellers' bank accounts. This process increases the amount of money in circulation and thus raises the overall money supply in the economy. This is a part of the Central Bank's open market operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>40", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "PUBLIC FINANCE : FISCAL POLICY", "question": "Expansionary fiscal policy implies", "images": [], "options": {"A": "decreasing bank loans", "B": "raising tax rates", "C": "increasing the bank rate", "D": "decreasing tax rates"}, "answer": "D", "explanation": "Expansionary fiscal policy is aimed at stimulating economic growth, particularly during periods of economic downturn or recession. It involves increasing government spending and/or decreasing tax rates to increase aggregate demand. By decreasing tax rates, individuals and businesses have more disposable income to spend and invest, which can help boost economic activity and increase overall demand in the economy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>41", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX", "question": "A commodity with perfectly inelastic demand has the burden of tax borne by", "images": [], "options": {"A": "both the sellers and the buyers", "B": "the buyers alone", "C": "the government alone", "D": "both the buyers and the government"}, "answer": "B", "explanation": "When demand for a commodity is perfectly inelastic, the quantity demanded does not change regardless of changes in price. This means that consumers will buy the same amount of the commodity even if its price increases due to a tax. In such cases, sellers can pass the entire tax burden onto buyers because the demand remains constant regardless of the price change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>42", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INTRODUCTION", "question": "An increase in a country's production capacity usually leads to economic", "images": [], "options": {"A": "development", "B": "stability", "C": "growth", "D": "efficiency"}, "answer": "C", "explanation": "Economic growth is typically measured by the increase in a country's output of goods and services over time, usually reflected in the rise of Gross Domestic Product (GDP). When a country's production capacity increases, it can produce more goods and services, leading to higher levels of economic activity and, consequently, economic growth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>43", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT", "question": "One indicator of the low level of capital formation in developing countries is", "images": [], "options": {"A": "low per capita income", "B": "high rate of investment", "C": "low importation of consumer goods", "D": "high rate of household savings"}, "answer": "A", "explanation": "Low per capita income in developing countries often indicates a lack of sufficient capital formation. Capital formation refers to the process of increasing the stock of capital goods through investment, which is crucial for long-term economic growth. Low per capita income suggests limited savings and investment opportunities, which in turn restricts the ability to accumulate physical capital (such as infrastructure, machinery, and technology) necessary for economic development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>44", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Balance of payments is defined as the", "images": [], "options": {"A": "difference between the values of visible imports and visible exports", "B": "record of financial transactions between a country and the rest of the world", "C": "relationship between prices of exports and prices of imports", "D": "difference between a country's expected revenue and proposed expenditure"}, "answer": "B", "explanation": "The balance of payments (BoP) is a systematic record of all economic transactions between residents of a country and the rest of the world over a specified period. It includes transactions in goods, services, income, and financial assets between a country and foreign residents. The BoP is divided into the current account (which includes trade in goods and services) and the capital and financial account (which includes transactions in financial assets and liabilities).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>45", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE", "question": "Devaluation of currency will help to correct balance of payments deficit if a country's", "images": [], "options": {"A": "exports have perfectly inelastic demand", "B": "imports have inelastic demand", "C": "exports have elastic demand", "D": "productivity is low"}, "answer": "C", "explanation": "When a country devalues its currency, the prices of its exports become relatively cheaper for foreign buyers. If the demand for these exports is elastic (meaning that the quantity demanded is sensitive to price changes), then lower prices resulting from devaluation can lead to a significant increase in export volume. This increase in export volume can help to improve the balance of payments by increasing export earnings and narrowing the trade deficit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>46", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE", "question": "Terms of trade is favourable when the", "images": [], "options": {"A": "value of visible imports is greater than that of visible exports", "B": "price of imports is greater than that of exports", "C": "payments on imports is greater than receipts from exports", "D": "price of exports is rising faster than that of imports"}, "answer": "D", "explanation": "Terms of trade refer to the ratio of export prices to import prices. They are favorable when the prices a country receives for its exports (in terms of money or goods) rise at a faster rate than the prices it pays for imports. This means that a country can purchase more imports for a given quantity of exports, improving its economic welfare.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>47", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "Short-term deficits in the current account of the balance of payments can be financed by balancing with the", "images": [], "options": {"A": "invisible account", "B": "capital account", "C": "visible account", "D": "national income account"}, "answer": "B", "explanation": "The capital account of the balance of payments records financial transactions that involve assets and liabilities between residents of a country and the rest of the world. Short-term deficits in the current account, which includes trade in goods and services, can be financed by inflows from the capital account. Capital account transactions include foreign direct investment, portfolio investment, loans, and other financial flows that provide funds to offset current account deficits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>48", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "Harmonised monetary and fiscal policies is a feature of", "images": [], "options": {"A": "a free trade area", "B": "an economic union", "C": "a customs union", "D": "a common market"}, "answer": "B", "explanation": "An economic union involves a deeper level of integration than a free trade area, customs union, or common market. In an economic union, member countries harmonize their monetary (related to currency and central banking) and fiscal policies (related to government spending and taxation). This coordination aims to achieve common economic objectives, such as stable prices, sustainable economic growth, and reduced economic disparities among member states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>49", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "One major achievement of the Economic Commission for Africa (ECA) is the", "images": [], "options": {"A": "setting up of the African Development Bank (AFDB)", "B": "provision of long term loans to non-members", "C": "reduction of balance of payments problems in Africa", "D": "removing the gap between African countries and the rich nations"}, "answer": "A", "explanation": "The Economic Commission for Africa (ECA) played a pivotal role in the establishment of the African Development Bank (AfDB) in 1964. The AfDB is a multilateral development finance institution that supports economic and social development in Africa by providing loans, grants, and technical assistance to African countries and regional member countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2024>50", "subject": "Economics", "year": "2024", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : INTRODUCTION", "question": "Exploitation of solid minerals in developing countries can stabilize their revenue  base mainly because it helps in", "images": [], "options": {"A": "promoting a mono-economy", "B": "the transfer of technology", "C": "the diversification of the economy", "D": "the provision of energy"}, "answer": "C", "explanation": "Solid minerals exploitation can contribute to economic diversification by creating new sectors outside of traditional ones like agriculture. This diversification can stabilize a country's revenue base by reducing dependence on a single sector or commodity for income. It allows for revenue streams from mining activities, which can be less volatile compared to agricultural products or other sectors affected by weather conditions or market fluctuations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>1", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "In Economics, it is necessary that choice be made mainly because", "images": [], "options": {"A": "goods are of various qualities", "B": "goods have different prices", "C": "resources are inadequate", "D": "consumer's wants differ"}, "answer": "C", "explanation": "In Economics, choices must be made primarily because resources are inadequate. This concept is known as scarcity, which refers to the limited availability of resources to meet unlimited wants. Therefore, the correct option is that resources are inadequate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>2", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS", "question": "If the production of 5 bags of rice are given up by a farmer in order to produce 1 bag of maize, this implies that, to the farmer,", "images": [], "options": {"A": "rice has a greater opportunity cost of production than maize", "B": "maize has a higher opportunity cost of production than rice", "C": "both rice and maize have no opportunity costs of production", "D": "rice and maize have equal opportunity costs of production"}, "answer": "A", "explanation": "The opportunity cost is defined as the value of the next best alternative that is forgone when making a choice. In this case, if the farmer gives up 5 bags of rice to produce 1 bag of maize, it indicates that rice has a greater opportunity cost of production than maize, as the farmer is sacrificing more rice to produce maize.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>3", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "One of the distinguishing features of land is that it is fixed in supply. This means that", "images": [], "options": {"A": "its quality is the same everywhere", "B": "it can be put to unlimited use", "C": "it is free gift of nature", "D": "its total surface area cannot be changed"}, "answer": "D", "explanation": "The statement that land is fixed in supply means that its total surface area cannot be changed. Unlike other factors of production, the quantity of land available is constant, which is a fundamental characteristic of land in economics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>4", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "One advantage of a free market economy is that it", "images": [], "options": {"A": "guarantees full employment of labour", "B": "gives incentives for innovation", "C": "guarantees income equally", "D": "allocates resources to produce public goods"}, "answer": "B", "explanation": "One advantage of a free market economy is that it gives incentives for innovation. In a free market, competition encourages businesses to innovate and improve their products and services to attract consumers, leading to economic growth and efficiency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>5", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM", "question": "In a command economy, wages are determined by", "images": [], "options": {"A": "the employers", "B": "trade unions", "C": "central planning committee", "D": "forces of demand and supply"}, "answer": "C", "explanation": "In a command economy, wages are determined by a central planning committee. This is because the government or central authority makes decisions regarding the allocation of resources, including labor, rather than allowing market forces to dictate wages.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>6", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "TOOLS FOR ECONOMIC ANALYSIS: REPRESENTATION OF DATA", "question": "Use the diagram below to answer the question      What name is given to the diagram in Figure 1?", "images": ["Economics/imgs/2025/WDLGH9.jpg"], "options": {"A": "Multiple bar graph", "B": "Simple bar chart", "C": "Component bar chart", "D": "Three-column bar graph"}, "answer": "C", "explanation": "The diagram above represent a component bar chart. A componet bar chart is used to represent data in which the total magnitude is divided into different or components.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2025>7", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "A rational consumer of a normal good, ceteris paribus, will do the following except", "images": [], "options": {"A": "ensuring marginal utility is equal to its price", "B": "buying more as income rises", "C": "maximizing his satisfaction", "D": "buying more at a higher price"}, "answer": "D", "explanation": "A rational consumer of a normal good will typically buy more as income rises and maximize satisfaction by ensuring that the marginal utility per dollar spent is equal across all goods. However, buying more at a higher price contradicts the law of demand, which states that, ceteris paribus, as the price of a good increases, the quantity demanded decreases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>8", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "Commodities with negative income elasticities of demand are categorized as", "images": [], "options": {"A": "inferior goods", "B": "normal goods", "C": "substitute goods", "D": "complementary goods"}, "answer": "A", "explanation": "Commodities with negative income elasticities of demand are classified as inferior goods. This means that as consumer income rises, the demand for these goods decreases, as consumers tend to buy higher-quality substitutes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>9", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "The demand for a box of matches by a rich consumer is most likely to be", "images": [], "options": {"A": "price elastic", "B": "perfectly price elastic", "C": "price inelastic", "D": "income elastic"}, "answer": "C", "explanation": "The demand for a box of matches by a rich consumer is most likely to be price inelastic. This is because matches are a low-cost item, and a rich consumer is unlikely to change their quantity demanded significantly in response to price changes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>10", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND", "question": "Good X has a price elasticity of demand of 0.25. This means it", "images": [], "options": {"A": "has many close substitutes", "B": "is a luxury good", "C": "is not purchased our of habit", "D": "has few substitutes"}, "answer": "D", "explanation": "A price elasticity of demand of 0.25 indicates that the good is inelastic, meaning that the quantity demanded changes very little in response to price changes. This typically occurs with goods that have few substitutes, as consumers are less sensitive to price changes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>11", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS", "question": "The demand curve for necessary good without any substitute is usually", "images": [], "options": {"A": "vertically sloped", "B": "negatively sloped", "C": "horizontally sloped", "D": "positively sloped"}, "answer": "A", "explanation": "The demand curve for a necessary good without any substitutes is usually vertically sloped, indicating perfectly inelastic demand. This means that consumers will buy the same quantity regardless of price changes, as they need the good for survival or essential use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>12", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "A rightward shift of the supply curve of cocoa implies that", "images": [], "options": {"A": "the price of cocoa has increased", "B": "subsidy on farm equipment has increased", "C": "the weather condition has worsened", "D": "the number of farmers has reduced"}, "answer": "B", "explanation": "A rightward shift of the supply curve indicates an increase in supply. This can occur due to factors such as a subsidy on farm equipment, which lowers production costs and encourages more supply. Therefore, the correct option is that a subsidy on farm equipment has increased.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>13", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "Which of the following factors is not a determinant of price elasticity of supply?", "images": [], "options": {"A": "Availability of labour", "B": "Cost of production", "C": "Consumers' income level", "D": "Government policy"}, "answer": "C", "explanation": "Price elasticity of supply is influenced by factors such as availability of labor, cost of production, and government policy. However, consumers' income level is not a determinant of price elasticity of supply; it affects demand elasticity instead. Thus, the correct option is that consumers' income level is not a determinant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>14", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS", "question": "An increase in the price of a factor of production in an industry may cause", "images": [], "options": {"A": "supply of goods to decrease", "B": "more firms to enter the market", "C": "the government to increase taxes", "D": "the quantity supplied of a factor input to decrease"}, "answer": "A", "explanation": "An increase in the price of a factor of production typically leads to a decrease in the supply of goods, as higher costs can reduce profitability and discourage production. Therefore, the correct option is that the supply of goods to decrease.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>15", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND", "question": "At a point where marginal utility is negative, total utility", "images": [], "options": {"A": "is zero", "B": "increases", "C": "is constant", "D": "decreases"}, "answer": "D", "explanation": "When marginal utility is negative, it means that consuming an additional unit of a good decreases total utility. Therefore, total utility decreases when marginal utility is negative, making the correct option that total utility decreases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>16", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM", "question": "If the price of a commodity is higher than its marginal utility, the consumer will", "images": [], "options": {"A": "consume more to increase total utility", "B": "consume less to increase marginal utility", "C": "buy more to minimise total utility", "D": "buy more to add to average utility"}, "answer": "B", "explanation": "If the price of a commodity is higher than its marginal utility, the consumer will consume less to increase marginal utility. This is because consumers aim to maximize their utility, and consuming less of a good that provides less utility than its price will help achieve that. Thus, the correct option is to consume less to increase marginal utility.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>17", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS", "question": "If the price of cassava is fixed above the equilibrium, this policy is meant to", "images": [], "options": {"A": "discourage cassava farmers", "B": "favour consumers of cassava", "C": "encourage cassava farmers", "D": "reduce the quantity of cassava supplied"}, "answer": "C", "explanation": "If the price of cassava is fixed above the equilibrium price, it creates a price floor. This policy is intended to encourage cassava farmers by ensuring they receive a higher price for their product, which can lead to increased production. Therefore, the correct option is 'encourage cassava farmers'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>18", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY", "question": "If the supply of a product with a perfectly elastic demand increases, there will be", "images": [], "options": {"A": "an increase in equilibrium price and quantity", "B": "a fall in equilibrium price and an increase in equilibrium quantity", "C": "a fall in equilibrium quantity while equilibrium price remains constant", "D": "an increase in equilibrium quantity while equilibrium price is fixed"}, "answer": "D", "explanation": "In a perfectly elastic demand scenario, the price remains constant regardless of the quantity supplied. Therefore, if the supply increases, the equilibrium quantity will increase while the equilibrium price remains fixed. Thus, the correct option is 'an increase in equilibrium quantity while equilibrium price is fixed'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>19", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "A firm can increase production in the short-run by", "images": [], "options": {"A": "increasing its fixed assets", "B": "buying more raw materials", "C": "employing skilled managers", "D": "building a new factory"}, "answer": "B", "explanation": "In the short run, a firm can increase production by buying more raw materials, as this allows for the utilization of existing fixed assets to produce more output. Therefore, the correct option is 'buying more raw materials'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>20", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF PRODUCTION : FACTORS OF PRODUCTION", "question": "By installing a larger and more efficient production plant, a firm enjoys", "images": [], "options": {"A": "managerial economies", "B": "financial economies", "C": "technical economies", "D": "marketing economies"}, "answer": "C", "explanation": "By installing a larger and more efficient production plant, a firm benefits from technical economies of scale. This means that as production increases, the cost per unit of output decreases due to more efficient production techniques. Thus, the correct option is 'technical economies'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>21", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION", "question": "When a firm increases the quantities of its variable factor given a fixed factor, the", "images": [], "options": {"A": "marginal product of the variable factor will decrease continuously", "B": "marginal product of the variable factor rises and later falls", "C": "total product will rise continuously", "D": "average product will decline and later increase"}, "answer": "B", "explanation": "When a firm increases the quantities of its variable factor while keeping a fixed factor constant, it typically experiences the law of diminishing returns. Initially, the marginal product of the variable factor may rise, but eventually, it will start to fall as more of the variable factor is added. Therefore, the correct option is 'marginal product of the variable factor rises and later falls'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>22", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "Use figure 2 to answer the question        The curve labelled Z is", "images": ["Economics/imgs/2025/99AGLF.jpg"], "options": {"A": "average cost curve", "B": "marginal cost curve", "C": "average variable cost curve", "D": "average fixed cost curve"}, "answer": "C", "explanation": "Curve Z represent the average variabe cost curve. The AVC is the variable cost per unit of output. It is calculated as TVC/Q.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>23", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM", "question": "Use figure 2 to answer the question      The equilibrium output level is at output", "images": ["Economics/imgs/2025/99AGLF.jpg"], "options": {"A": "Q", "B": "R", "C": "S", "D": "T"}, "answer": "A", "explanation": "The equilibrium output level is at output Q where curve X which represent the Marginal cost curve cuts the AR which is also the MR from below.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>24", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT", "question": "Use figure 2 to answer the question      The interval between curves Y and Z represents", "images": ["Economics/imgs/2025/99AGLF.jpg"], "options": {"A": "total fixed cost", "B": "average fixed cost", "C": "average total cost", "D": "total cost"}, "answer": "B", "explanation": "The vertical distance between curves Y and Z represents the difference in values between these two cost curves at each output level.    Curve Y typically represents Average Total cost while curve Z represent Average Variable cost. The difference between ATC and AVC at each level of output is Average Fixed Cost i.e AFC = ATC - AVC", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>25", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION", "question": "If a firm's minimum average variable cost exceeds its average revenue, the firm must", "images": [], "options": {"A": "employ more labour", "B": "increase its production capacity", "C": "shut down completely", "D": "pay new allowances to its workers"}, "answer": "C", "explanation": "If a firm's minimum average variable cost exceeds its average revenue, it means that the firm is unable to cover its variable costs. In such a situation, the firm should shut down completely in the short run to minimize losses, as continuing to operate would only increase its losses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>26", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY", "question": "The monopolist's price is always", "images": [], "options": {"A": "lower than average revenue", "B": "lower than his production cost per unit", "C": "higher than average revenue", "D": "higher than marginal revenue"}, "answer": "C", "explanation": "This is because a monopolist can only sell more output by lowering the price, and that price reduction applies to all units sold, not just the additional one. Therefore, the revenue gained from selling one unit (marginal revenue) will be less than the price of that unit (average revenue).", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>27", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES", "question": "A business is a separate legal person if", "images": [], "options": {"A": "the business shares its liabilities with the owners", "B": "it has all features of a human being", "C": "it is governed by a Deed of partnership", "D": "it is recognized as a corporate entity"}, "answer": "D", "explanation": "A business is considered a separate legal person when it is recognized as a corporate entity. This means it can own property, enter contracts, and be liable for debts independently of its owners.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>28", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "FINANCIAL INSTITUTION : STOCK EXCHANGE", "question": "Which of the following statements is true of a debenture?", "images": [], "options": {"A": "It is a type of share with variable rate of dividend", "B": "Its holders are creditors to the company", "C": "It is available to all business organizations", "D": "Its interest rate increases with profit"}, "answer": "B", "explanation": "A debenture is a type of debt instrument that is not secured by physical assets or collateral. Its holders are creditors to the company, meaning they have lent money to the company and are entitled to receive interest payments and the return of principal upon maturity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>29", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR", "question": "If an individual refuses a lucrative jon in another town because of ties to his family, this reason can be seen as an impediment to", "images": [], "options": {"A": "geographical mobility of labour", "B": "occupational mobility of labour", "C": "vertical mobility of labour", "D": "horizontal mobility of labour"}, "answer": "A", "explanation": "Refusing a lucrative job in another town due to family ties is an impediment to geographical mobility of labor. Geographical mobility refers to the ability of workers to move to different locations for employment opportunities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>30", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT", "question": "If a typist is laid-off because he is not computer literate then he is facing", "images": [], "options": {"A": "cyclical unemployment", "B": "seasonal unemployment", "C": "structural unemployment", "D": "frictional unemployment"}, "answer": "C", "explanation": "The typist is facing structural unemployment because this type of unemployment occurs when there is a mismatch between the skills of the workers and the skills needed for available jobs. In this case, the typist's lack of computer literacy makes him unsuitable for jobs that require such skills.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>31", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES", "question": "Capital intensive production method is least adopted in", "images": [], "options": {"A": "peasant farming", "B": "plantation agriculture", "C": "state farming", "D": "commercial farming"}, "answer": "A", "explanation": "Capital intensive production methods are least adopted in peasant farming because this type of farming typically relies on manual labor and traditional methods rather than heavy machinery or technology, which characterizes capital-intensive production.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>32", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INTRODUCTION", "question": "Diversification of the economies of developing countries will enable them to", "images": [], "options": {"A": "lay emphasis on export of one primary agricultural product", "B": "offer more than one product from various sectors for export", "C": "export only industrial products", "D": "reduce domination of the economies by foreigners"}, "answer": "B", "explanation": "Diversification of the economies of developing countries will enable them to offer more than one product from various sectors for export. This reduces reliance on a single product and helps stabilize the economy by spreading risk across different sectors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>33", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION", "question": "An industry whose products lose considerable weight after processing must be sited close to the", "images": [], "options": {"A": "market", "B": "source of raw material", "C": "source of power", "D": "skilled labour"}, "answer": "B", "explanation": "An industry whose products lose considerable weight after processing must be sited close to the source of raw material. This is because transporting heavy raw materials to a distant processing facility would be inefficient and costly, so proximity to the raw material source is crucial.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>34", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "NATIONAL INCOME : PROBLEMS OF NATIONAL INCOME", "question": "A factor that may cause the national income to be overstated is the", "images": [], "options": {"A": "inclusion of wages of house-keepers", "B": "inclusion of the output of subsistence producers", "C": "use of value-added method for its calculation", "D": "inclusion of pension payments to retirees"}, "answer": "D", "explanation": "Inclusion of pension payment to retirees overstate national income because pension payments are transfer payments, not payments for current production of goods or services. Including them would inflate national income without corresponding output.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2025>35", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "NATIONAL INCOME : USES & REASONS FOR MEASURING NATIONAL INCOME", "question": "The national income figure is limited as a measure of standard of living because the", "images": [], "options": {"A": "prices of commodities remain stable", "B": "value of money is constant", "C": "real composition of output is not fully known", "D": "working conditions are uniform in all countries"}, "answer": "C", "explanation": "The national income figure is limited as a measure of standard of living because the real composition of output is not fully known. National income accounts aggregate various goods and services, but they do not account for the distribution of income or the quality of goods and services. Therefore, even if the national income is high, it does not necessarily reflect a high standard of living if the output is not diverse or if income is unevenly distributed.", "marks": "1", "difficulty": "3"}, {"id": "objective>Economics>2025>36", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "MONEY : SUPPLY OF MONEY", "question": "Other things being equal, a contraction in the amount of money in circulation will", "images": [], "options": {"A": "increase aggregate demand for commodities", "B": "lead to fall in the value of money", "C": "result in an increase in price level", "D": "cause the value of money to rise"}, "answer": "D", "explanation": "A contraction in the amount of money in circulation will cause the value of money to rise. When there is less money available, each unit of currency becomes more valuable, leading to deflationary pressures. This is because the same amount of goods and services is being chased by fewer dollars, increasing the purchasing power of money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>37", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "INFLATION & DEFLATION : EFFECT", "question": "Inflation will usually have a negative effect on", "images": [], "options": {"A": "borrowers", "B": "balance of payments", "C": "shareholders' dividends", "D": "sales revenue of firms"}, "answer": "B", "explanation": "Inflation makes a country's goods and service more expensive relative to foreign goods. they typical leads to decreased exports, increased import. This worsens the current account and therefore negatively affects the BOP", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>38", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "MONEY : DEMAND FOR MONEY", "question": "A factor that positively influences the precautionary motive for holding money is", "images": [], "options": {"A": "high rate of interest", "B": "convenient system of payment", "C": "short interval between paydays", "D": "high degree of uncertainty"}, "answer": "D", "explanation": "A factor that positively influences the precautionary motive for holding money is a high degree of uncertainty. When individuals or businesses face uncertainty about future income or expenses, they are more likely to hold onto cash as a safeguard against unforeseen circumstances, rather than investing or spending it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>39", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "MONEY : TYPES OF MONEY", "question": "Which of the following is not a form of money?", "images": [], "options": {"A": "Bank notes", "B": "Current account deposits", "C": "Promissory notes", "D": "Fiat coins"}, "answer": "C", "explanation": "Promissory notes are not considered a form of money in the traditional sense. While they can represent a promise to pay a certain amount, they are not universally accepted as a medium of exchange like bank notes, current account deposits, or fiat coins. Money must be widely accepted and easily transferable, which promissory notes are not.", "marks": "1", "difficulty": "1"}, {"id": "objective>Economics>2025>40", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS", "question": "Which of the following items is not an asset to commercial banks?", "images": [], "options": {"A": "Shareholders' funds", "B": "Physical buildings and equipment", "C": "Loans granted to customers", "D": "Vehicle and office equipment"}, "answer": "A", "explanation": "Shareholders' funds are not considered an asset to commercial banks; rather, they represent the equity or net worth of the bank. Assets are resources owned by the bank that can generate future economic benefits, such as loans and physical equipment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>41", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "PUBLIC FINANCE : BUDGET", "question": "In a deficit budget, the expected revenue would be", "images": [], "options": {"A": "higher than proposed expenditure", "B": "lower than proposed expenditure", "C": "equal to proposed expenditure", "D": "falling as consumers' incomes increases"}, "answer": "B", "explanation": "In a deficit budget, the expected revenue is lower than proposed expenditure. This means that the government anticipates spending more than it will earn, leading to a budget deficit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>42", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "A flat tax rate of 10% levied per unit of a commodity is an example of", "images": [], "options": {"A": "specific tax", "B": "progressive tax", "C": "regressive tax", "D": "ad valorem tax"}, "answer": "A", "explanation": "A flat tax rate of 10% levied per unit of a commodity is an example of a specific tax. Specific taxes are fixed amounts charged per unit of a good or service, regardless of its price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>43", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "PUBLIC FINANCE : TAX", "question": "Tax avoidance best refers to attempts by a tax payer to", "images": [], "options": {"A": "conceal income deliberately thereby paying no tax", "B": "always seek for tax holidays during which he will not pay tax", "C": "legally exploit the loopholes in tax laws to pay less tax", "D": "escape illegally from the tax net thereby paying no tax at all"}, "answer": "C", "explanation": "Tax avoidance refers to the legal strategies that taxpayers use to minimize their tax liabilities, often by exploiting loopholes in tax laws. This is different from tax evasion, which is illegal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>44", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "PUBLIC FINANCE : TAX", "question": "If governments in developing countries want to raise revenue, then the major source to rely on is", "images": [], "options": {"A": "royalties and rent", "B": "grants and loans", "C": "sale of government assets", "D": "indirect taxes"}, "answer": "D", "explanation": "In developing countries, indirect taxes are often a major source of revenue for governments. These taxes are levied on goods and services rather than on income, making them a significant source of funding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>45", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT", "question": "In which section of a country's balance of payments account will the inflow of long-term investments be recorded?", "images": [], "options": {"A": "Balance of trade section", "B": "Current account section", "C": "Capital account section", "D": "Official financing section"}, "answer": "C", "explanation": "The inflow of long-term investments is recorded in the Capital account section of a country's balance of payments. The Capital account includes transactions that involve the purchase and sale of assets, such as investments in businesses or real estate, which are considered long-term investments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>46", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX", "question": "The table below shows the percentage paid as tax on different income levels. Use it to answer the question    Tax System $100$500$1000Q 10% 10% 10%T 90% 70% 30%S 20% 65% 40%R 10% 40% 70%    Which tax system is progressive? Tax system", "images": [], "options": {"A": "Q", "B": "T", "C": "S", "D": "R"}, "answer": "C", "explanation": "A progressive tax system is one where the tax rate increases as the income level increases. In the table provided, Tax system S shows increasing tax rates as income rises (20% on $100, 65% on $500, and 40% on $1000), indicating that it is a progressive tax system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>47", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "INTERNATIONAL TRADE : INTRODUCTION", "question": "Dumping of goods is not desirable since it leads to", "images": [], "options": {"A": "an increase in the wage bill of the importing country", "B": "unemployment in the importing country", "C": "production of more local goods", "D": "an increase in tax revenue from local industries"}, "answer": "B", "explanation": "Dumping of goods, which refers to selling products in a foreign market at a price lower than their normal value, can lead to unemployment in the importing country. This occurs because local industries may struggle to compete with the lower-priced imported goods, potentially leading to job losses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>48", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES", "question": "A long-term adverse balance of payments can be corrected by", "images": [], "options": {"A": "reducing or removing export duties", "B": "revaluing the domestic currency", "C": "using up foreign currency reserves", "D": "receiving gifts from other countries"}, "answer": "B", "explanation": "A long-term adverse balance of payments can be corrected by revaluing the domestic currency. Revaluation makes exports more expensive and imports cheaper, which can help to balance the payments by reducing the trade deficit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>49", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "ECONOMIC INTEGRATION : PROBLEMS OF ECONOMIC INTEGRATION IN WEST AFRICA- ECOWAS", "question": "Which of the following benefits is not applicable to economic integration?", "images": [], "options": {"A": "Availability of variety of commodities", "B": "Free mobility of factors of production", "C": "Expansion of market size", "D": "Complete independence of each nation"}, "answer": "D", "explanation": "Complete independence of each nation is not a benefit of economic integration. Economic integration typically involves countries working together to reduce trade barriers and increase cooperation, which inherently requires some level of interdependence among the nations involved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Economics>2025>50", "subject": "Economics", "year": "2025", "type": "Objective", "topic": "MAJOR NATURAL RESOURCES : OPEC", "question": "The Organization of Petroleum Exporting Countries (OPEC) prevents excess global supply of crude oil by", "images": [], "options": {"A": "buying up the extra volume produced by members of the oil market", "B": "fixing production quotas for all member countries", "C": "expelling erring members countries from the organization", "D": "taking legal actions against members at the world court"}, "answer": "B", "explanation": "The Organization of the Petroleum Exporting Countries (OPEC) aims to manage the supply of oil in the global market to stabilize prices. One of the primary methods OPEC uses to achieve this is by fixing production quotas for its member countries. By setting limits on how much oil each member can produce, OPEC can prevent excess supply that could lead to lower prices. This approach helps maintain a balance between supply and demand in the oil market.", "marks": "1", "difficulty": "2"}];